# ════════════════════════════════════════════════════════
#  🎹 REAL BEAT ENGINE — synthesises actual beats/instruments
#  using only Python stdlib (math, wave, struct, random)
#  then mixes with the user's voice via ffmpeg amix.
# ════════════════════════════════════════════════════════
_VB_SR = 44100

def _vb_place(buf, sample, pos, vol=1.0):
    for i, v in enumerate(sample):
        idx = pos + i
        if idx < len(buf):
            buf[idx] = max(-1.0, min(1.0, buf[idx] + v * vol))

def _vb_kick(fs=180, fe=45, decay=18, dur=0.35):
    n = int(_VB_SR * dur)
    return [math.sin(2*math.pi*(fe+(fs-fe)*math.exp(-decay*i/_VB_SR))*i/_VB_SR)*math.exp(-decay*i/_VB_SR) for i in range(n)]

def _vb_snare(dur=0.15, nv=0.55, tv=0.45, tf=240, decay=28):
    n = int(_VB_SR * dur); rng = random.Random(42)
    return [(nv*(rng.random()*2-1)+tv*math.sin(2*math.pi*tf*i/_VB_SR))*math.exp(-decay*i/_VB_SR) for i in range(n)]

def _vb_hihat(dur=0.04, decay=70):
    n = int(_VB_SR * dur); rng = random.Random(99)
    return [(rng.random()*2-1)*math.exp(-decay*i/_VB_SR) for i in range(n)]

def _vb_openhat(dur=0.18, decay=12): return _vb_hihat(dur, decay)

def _vb_bass(freq=80, dur=0.35, decay=6):
    n = int(_VB_SR * dur)
    return [(math.sin(2*math.pi*freq*i/_VB_SR)+0.3*math.sin(2*math.pi*freq*2*i/_VB_SR))*math.exp(-decay*i/_VB_SR)*0.85 for i in range(n)]

def _vb_piano(freq, dur=0.5, decay=3.5):
    n = int(_VB_SR * dur)
    return [(0.55*math.sin(2*math.pi*freq*i/_VB_SR)+0.25*math.sin(2*math.pi*freq*2*i/_VB_SR)+0.12*math.sin(2*math.pi*freq*3*i/_VB_SR)+0.06*math.sin(2*math.pi*freq*4*i/_VB_SR))*math.exp(-decay*i/_VB_SR) for i in range(n)]

def _vb_chord(freqs, dur=0.08, decay=22):
    n = int(_VB_SR * dur)
    return [sum(math.sin(2*math.pi*f*i/_VB_SR) for f in freqs)/len(freqs)*math.exp(-decay*i/_VB_SR) for i in range(n)]

def _vb_organ_pad(freqs, n_samples):
    buf = [0.0]*n_samples
    for f in freqs:
        for i in range(n_samples):
            t = i/_VB_SR; atk = min(1.0, t/0.4)
            buf[i] += (math.sin(2*math.pi*f*t)+0.5*math.sin(2*math.pi*f*2*t)+0.25*math.sin(2*math.pi*f*3*t))*atk/len(freqs)
    return buf

def _vb_noise(n, seed=7, vol=0.04):
    rng = random.Random(seed); return [rng.random()*2*vol-vol for _ in range(n)]

def _vb_gen_trap(dur):
    bpm=140; bp=int(_VB_SR*60/bpm); buf=[0.0]*int(_VB_SR*dur)
    k=_vb_kick(220,38,20); sn=_vb_snare(nv=0.7,tf=200); hh=_vb_hihat(0.025,90); oh=_vb_openhat()
    for b in range(int(len(buf)/bp)+1):
        p=b*bp; _vb_place(buf,k,p,0.85)
        if b%2==0: _vb_place(buf,k,p+bp//2,0.5)
        if b%2==1: _vb_place(buf,sn,p,0.9)
        for h in range(4): _vb_place(buf,hh,p+h*bp//4,0.6)
        if b%4==3: _vb_place(buf,oh,p+bp*3//4,0.5)
    return buf

def _vb_gen_hiphop(dur):
    bpm=90; bp=int(_VB_SR*60/bpm); buf=[0.0]*int(_VB_SR*dur)
    k=_vb_kick(160,50,14); sn=_vb_snare(0.2,0.65,0.35,210,28); hh=_vb_hihat(0.05)
    for b in range(int(len(buf)/bp)+1):
        p=b*bp
        if b%4 in (0,2): _vb_place(buf,k,p,0.8)
        if b%4==2: _vb_place(buf,k,p+int(bp*0.5),0.45)
        if b%2==1: _vb_place(buf,sn,p,0.85)
        _vb_place(buf,hh,p,0.5); _vb_place(buf,hh,p+int(bp*0.6),0.35)
    return buf

def _vb_gen_afrobeats(dur):
    bpm=102; bp=int(_VB_SR*60/bpm); buf=[0.0]*int(_VB_SR*dur)
    k=_vb_kick(150,55,16); sn=_vb_snare(0.12,0.5,0.5,280,30); hh=_vb_hihat(0.03); cga=_vb_hihat(0.07,45)
    for b in range(int(len(buf)/bp)+1):
        p=b*bp
        if b%4 in (0,2,3): _vb_place(buf,k,p,0.8)
        if b%4==1: _vb_place(buf,sn,p,0.7); _vb_place(buf,sn,p+bp//2,0.5)
        for h in range(4): _vb_place(buf,hh,p+h*bp//4,0.55)
        _vb_place(buf,cga,p+bp//3,0.5); _vb_place(buf,cga,p+bp*2//3,0.45)
    return buf

def _vb_gen_rnb(dur):
    bpm=82; bp=int(_VB_SR*60/bpm); buf=[0.0]*int(_VB_SR*dur)
    k=_vb_kick(140,45,13); sn=_vb_snare(0.18,0.5,0.5,240,28); hh=_vb_hihat(0.04); bn=[82.41,82.41,98.00,82.41]
    for b in range(int(len(buf)/bp)+1):
        p=b*bp
        if b%4 in (0,2): _vb_place(buf,k,p,0.8)
        if b%4 in (1,3): _vb_place(buf,sn,p,0.8)
        _vb_place(buf,_vb_bass(bn[b%4],0.38),p,0.55)
        for h in range(2): _vb_place(buf,hh,p+h*bp//2,0.45)
    return buf

def _vb_gen_gospel(dur):
    bpm=75; bp=int(_VB_SR*60/bpm); buf=[0.0]*int(_VB_SR*dur)
    k=_vb_kick(120,45,11,0.42); sn=_vb_snare(0.28,0.45,0.55,180,22); cf=[130.81,164.81,196.00]
    for b in range(int(len(buf)/bp)+1):
        p=b*bp
        if b%4==0: _vb_place(buf,k,p,0.85); pad=_vb_organ_pad(cf,min(bp*4,len(buf)-p)); _vb_place(buf,pad,p,0.3)
        if b%4 in (1,3): _vb_place(buf,sn,p,0.7)
    return buf

def _vb_gen_reggae(dur):
    bpm=80; bp=int(_VB_SR*60/bpm); buf=[0.0]*int(_VB_SR*dur)
    k=_vb_kick(130,40,12); sn=_vb_snare(0.2); hh=_vb_hihat(0.07); sk=[130.81,164.81,196.00]
    for b in range(int(len(buf)/bp)+1):
        p=b*bp
        if b%4==0: _vb_place(buf,k,p,0.85)
        if b%4==2: _vb_place(buf,sn,p,0.75)
        _vb_place(buf,_vb_chord(sk,0.06,24),p+bp//2,0.55); _vb_place(buf,hh,p,0.4)
    return buf

def _vb_gen_pop(dur):
    bpm=120; bp=int(_VB_SR*60/bpm); buf=[0.0]*int(_VB_SR*dur)
    k=_vb_kick(); sn=_vb_snare(); hh=_vb_hihat(0.035); oh=_vb_openhat(0.12)
    for b in range(int(len(buf)/bp)+1):
        p=b*bp; _vb_place(buf,k,p,0.9)
        if b%2==1: _vb_place(buf,sn,p,0.85)
        for h in range(2): _vb_place(buf,hh,p+h*bp//2,0.5)
        if b%4==3: _vb_place(buf,oh,p+bp//2,0.4)
    return buf

def _vb_gen_lofi(dur):
    bpm=75; bp=int(_VB_SR*60/bpm); buf=_vb_noise(int(_VB_SR*dur),7,0.025)
    k=_vb_kick(100,50,10); sn=_vb_snare(0.18,0.4,0.6,200,28); hh=_vb_hihat(0.06,55)
    for b in range(int(len(buf)/bp)+1):
        p=b*bp
        if b%4 in (0,2): _vb_place(buf,k,p,0.75)
        if b%2==1: _vb_place(buf,sn,p,0.65)
        _vb_place(buf,hh,p,0.45); _vb_place(buf,hh,p+int(bp*0.65),0.3)
    return buf

def _vb_gen_drill(dur):
    bpm=140; bp=int(_VB_SR*60/bpm); buf=[0.0]*int(_VB_SR*dur)
    k=_vb_kick(250,32,7,0.55); sn=_vb_snare(0.11,0.8,0.2,180,30); hh=_vb_hihat(0.018,110)
    for b in range(int(len(buf)/bp)+1):
        p=b*bp
        if b%4 in (0,3): _vb_place(buf,k,p,0.9)
        if b%4 in (1,2): _vb_place(buf,sn,p,0.85)
        for h in range(8): _vb_place(buf,hh,p+h*bp//8,0.5)
    return buf

def _vb_gen_highlife(dur):
    bpm=115; bp=int(_VB_SR*60/bpm); buf=[0.0]*int(_VB_SR*dur)
    k=_vb_kick(130,50); sn=_vb_snare(0.1,0.4,0.6,300,30); hh=_vb_hihat(0.04)
    arp=[261.63,329.63,392.00,523.25,392.00,329.63]
    for b in range(int(len(buf)/bp)+1):
        p=b*bp
        if b%4 in (0,2): _vb_place(buf,k,p,0.8)
        if b%4==2: _vb_place(buf,sn,p,0.7)
        for h in range(4): _vb_place(buf,hh,p+h*bp//4,0.4)
        _vb_place(buf,_vb_piano(arp[(b*2)%len(arp)],0.15,8),p,0.5)
        _vb_place(buf,_vb_piano(arp[(b*2+1)%len(arp)],0.15,8),p+bp//2,0.5)
    return buf

def _vb_gen_studio_reverb(dur):
    bpm=100; bp=int(_VB_SR*60/bpm); buf=[0.0]*int(_VB_SR*dur)
    k=_vb_kick(); sn=_vb_snare(); hh=_vb_hihat()
    for b in range(int(len(buf)/bp)+1):
        p=b*bp
        if b%4==0: _vb_place(buf,k,p,0.85)
        if b%2==1: _vb_place(buf,sn,p,0.8)
        for h in range(4): _vb_place(buf,hh,p+h*bp//4,0.45)
    return buf

def _vb_gen_autotune(dur):
    notes=[261.63,293.66,329.63,349.23,392.00,440.00]
    bpm=110; bp=int(_VB_SR*60/bpm); buf=[0.0]*int(_VB_SR*dur)
    k=_vb_kick(); hh=_vb_hihat()
    for b in range(int(len(buf)/bp)+1):
        p=b*bp; f=notes[b%len(notes)]; n_len=min(bp+bp//4,len(buf)-p)
        if n_len>0:
            note=[0.42*math.sin(2*math.pi*f*i/_VB_SR*(1+0.002*math.sin(2*math.pi*7*i/_VB_SR)))*math.exp(-2*i/_VB_SR) for i in range(n_len)]
            _vb_place(buf,note,p,0.6)
        if b%4 in (0,2): _vb_place(buf,k,p,0.55)
        _vb_place(buf,hh,p,0.4); _vb_place(buf,hh,p+bp//2,0.4)
    return buf

def _vb_gen_deep_bass(dur):
    bpm=130; bp=int(_VB_SR*60/bpm); n=int(_VB_SR*dur)
    buf=[0.38*math.sin(2*math.pi*40*i/_VB_SR)+0.18*math.sin(2*math.pi*80*i/_VB_SR) for i in range(n)]
    k=_vb_kick(200,28,9,0.55); sn=_vb_snare(nv=0.7)
    for b in range(int(n/bp)+1):
        p=b*bp; _vb_place(buf,k,p,0.8)
        if b%4 in (2,3): _vb_place(buf,k,p+bp//3,0.5)
        if b%2==1: _vb_place(buf,sn,p,0.75)
    return buf

def _vb_gen_concert(dur):
    n=int(_VB_SR*dur); buf=_vb_noise(n,13,0.04)
    bpm=120; bp=int(_VB_SR*60/bpm); k=_vb_kick(); sn=_vb_snare(); hh=_vb_hihat()
    for b in range(int(n/bp)+1):
        p=b*bp; _vb_place(buf,k,p,0.85)
        if b%2==1: _vb_place(buf,sn,p,0.8)
        for h in range(2): _vb_place(buf,hh,p+h*bp//2,0.45)
    return buf

def _vb_gen_church(dur):
    bpm=65; bp=int(_VB_SR*60/bpm); n=int(_VB_SR*dur)
    buf=[s*0.35 for s in _vb_organ_pad([130.81,164.81,196.00,261.63,329.63],n)]
    k=_vb_kick(100,40,10,0.5); sn=_vb_snare(0.3,0.3,0.7)
    for b in range(int(n/bp)+1):
        p=b*bp
        if b%4==0: _vb_place(buf,k,p,0.8)
        if b%4==2: _vb_place(buf,sn,p,0.6)
    return buf

def _vb_gen_piano(dur):
    notes=[261.63,293.66,329.63,349.23,392.00,440.00,493.88,523.25,440.00,392.00,349.23,329.63,293.66,261.63,293.66,329.63]
    bpm=100; bp=int(_VB_SR*60/bpm); buf=[0.0]*int(_VB_SR*dur)
    k=_vb_kick(110,45,11); hh=_vb_hihat(0.04)
    for b in range(int(len(buf)/bp)+1):
        p=b*bp; _vb_place(buf,_vb_piano(notes[b%len(notes)],0.42),p,0.7)
        if b%4 in (0,2): _vb_place(buf,k,p,0.55)
        _vb_place(buf,hh,p,0.3); _vb_place(buf,hh,p+bp//2,0.3)
    return buf

def _vb_gen_guitar(dur):
    bpm=95; bp=int(_VB_SR*60/bpm); buf=[0.0]*int(_VB_SR*dur)
    strings=[196.00,246.94,293.66,392.00,493.88]; k=_vb_kick(); sn=_vb_snare()
    for b in range(int(len(buf)/bp)+1):
        p=b*bp
        for j,freq in enumerate(strings):
            sp=p+j*180; nl=min(int(_VB_SR*0.48),len(buf)-sp)
            if nl>0:
                s=[(math.sin(2*math.pi*freq*i/_VB_SR)+0.28*math.sin(2*math.pi*freq*2*i/_VB_SR))*math.exp(-4*i/_VB_SR)*0.38 for i in range(nl)]
                _vb_place(buf,s,sp)
        if b%4 in (0,2): _vb_place(buf,k,p,0.5)
        if b%2==1: _vb_place(buf,sn,p,0.5)
    return buf

def _vb_gen_strings(dur):
    freqs=[130.81,155.56,196.00,261.63]; n=int(_VB_SR*dur); buf=[0.0]*n
    for f in freqs:
        for i in range(n):
            t=i/_VB_SR; atk=min(1.0,t/0.35); vib=0.25*math.sin(2*math.pi*5.2*t)
            buf[i]+=0.18*atk*math.sin(2*math.pi*f*t+vib)
    return buf

def _vb_gen_flute(dur):
    notes=[523.25,587.33,659.25,698.46,783.99,880.00,783.99,659.25,587.33,523.25,587.33,659.25,523.25,659.25,783.99,880.00]
    bpm=100; bp=int(_VB_SR*60/bpm); buf=[0.0]*int(_VB_SR*dur)
    for b in range(int(len(buf)/bp)+1):
        p=b*bp; f=notes[b%len(notes)]; nl=min(bp-200,len(buf)-p)
        if nl>0:
            rng=random.Random(b+1)
            _vb_place(buf,[(0.68*math.sin(2*math.pi*f*i/_VB_SR)+0.04*(rng.random()*2-1))*math.exp(-1.8*i/_VB_SR) for i in range(nl)],p,0.55)
    return buf

def _vb_gen_sax(dur):
    notes=[220.00,246.94,261.63,293.66,329.63,349.23,392.00,440.00,392.00,349.23,329.63,293.66,261.63,220.00,246.94,293.66]
    bpm=95; bp=int(_VB_SR*60/bpm); buf=[0.0]*int(_VB_SR*dur)
    for b in range(int(len(buf)/bp)+1):
        p=b*bp; f=notes[b%len(notes)]; nl=min(int(bp*1.15),len(buf)-p)
        if nl>0:
            _vb_place(buf,[(0.48*math.sin(2*math.pi*f*i/_VB_SR)+0.28*math.sin(2*math.pi*f*3*i/_VB_SR)+0.14*math.sin(2*math.pi*f*5*i/_VB_SR))*max(0.0,1.0-1.8*i/nl) for i in range(nl)],p,0.5)
    return buf

_VB_GENERATORS = {
    "trap": _vb_gen_trap, "hiphop": _vb_gen_hiphop, "afrobeats": _vb_gen_afrobeats,
    "rnb": _vb_gen_rnb, "gospel": _vb_gen_gospel, "reggae": _vb_gen_reggae,
    "pop": _vb_gen_pop, "lofi": _vb_gen_lofi, "drill": _vb_gen_drill,
    "highlife": _vb_gen_highlife, "studio_verb": _vb_gen_studio_reverb,
    "autotune": _vb_gen_autotune, "deep_bass": _vb_gen_deep_bass,
    "concert": _vb_gen_concert, "church": _vb_gen_church,
    "piano": _vb_gen_piano, "guitar": _vb_gen_guitar, "violin": _vb_gen_strings,
    "flute": _vb_gen_flute, "saxophone": _vb_gen_sax,
}

def _vb_float_to_wav(samples) -> bytes:
    ints = [max(-32767, min(32767, int(s * 32767))) for s in samples]
    buf = io.BytesIO()
    import wave as _wave, struct as _struct
    with _wave.open(buf, 'wb') as wf:
        wf.setnchannels(1); wf.setsampwidth(2); wf.setframerate(_VB_SR)
        wf.writeframes(_struct.pack(f'<{len(ints)}h', *ints))
    return buf.getvalue()

def _vb_get_duration(path: str) -> float:
    try:
        r = subprocess.run(["ffprobe","-v","error","-show_entries","format=duration","-of","default=noprint_wrappers=1:nokey=1",path], capture_output=True, timeout=10)
        return float(r.stdout.decode().strip())
    except Exception:
        return 10.0

def _vb_mix_blocking(voice_bytes: bytes, beat_key: str):
    tmp = tempfile.mkdtemp()
    try:
        vp = os.path.join(tmp, "voice.oga")
        bp2 = os.path.join(tmp, "beat.wav")
        om  = os.path.join(tmp, "out.mp3")
        oo  = os.path.join(tmp, "out.ogg")
        with open(vp, "wb") as f: f.write(voice_bytes)
        dur = _vb_get_duration(vp) + 0.5
        gen = _VB_GENERATORS.get(beat_key, _vb_gen_trap)
        with open(bp2, "wb") as f: f.write(_vb_float_to_wav(gen(dur)))
        fc = "[0:a]volume=1.0[v];[1:a]volume=0.45[b];[v][b]amix=inputs=2:duration=first:dropout_transition=1[aout]"
        r1 = subprocess.run(["ffmpeg","-y","-i",vp,"-i",bp2,"-filter_complex",fc,"-map","[aout]","-ar","44100","-ac","1","-b:a","128k",om], capture_output=True, timeout=120)
        if r1.returncode==0 and os.path.getsize(om)>500:
            return open(om,"rb").read(), "mp3", None
        r2 = subprocess.run(["ffmpeg","-y","-i",vp,"-i",bp2,"-filter_complex",fc,"-map","[aout]","-ar","44100","-ac","1","-c:a","libvorbis","-q:a","4",oo], capture_output=True, timeout=120)
        if r2.returncode==0 and os.path.getsize(oo)>500:
            return open(oo,"rb").read(), "ogg", None
        return None, None, r1.stderr.decode(errors="ignore")[-300:]
    except Exception as e:
        return None, None, str(e)
    finally:
        for f in os.listdir(tmp):
            try: os.remove(os.path.join(tmp,f))
            except: pass
        try: os.rmdir(tmp)
        except: pass

def _vb_main_keyboard():
    """Build beat selection keyboard (2 per row)."""
    buttons = []
    row = []
    for key, (label, _) in VB_BEATS.items():
        row.append(InlineKeyboardButton(label, callback_data=f"vbeat:{key}"))
        if len(row) == 2:
            buttons.append(row)
            row = []
    if row:
        buttons.append(row)
    buttons.append([InlineKeyboardButton("❌ Cancel", callback_data="vbeat:cancel")])
    return InlineKeyboardMarkup(buttons)

async def _vb_apply(bot, chat_id, file_id, beat_key):
    """Download voice, synthesise real beat, mix and send back."""
    if not _FFMPEG_OK:
        await bot.send_message(chat_id, "❌ FFmpeg not found!\n\nInstall: `pkg install ffmpeg`", parse_mode="Markdown")
        return

    beat_label = VB_BEATS.get(beat_key, ("Beat",))[0]

    try:
        file_info = await bot.get_file(file_id)
        voice_bytes = bytes(await file_info.download_as_bytearray())
    except Exception:
        await bot.send_message(chat_id, "❌ Voice message expired. Please send a new one 🎤")
        return

    if len(voice_bytes) < 100:
        await bot.send_message(chat_id, "❌ Audio too small or corrupted.")
        return

    await bot.send_message(chat_id, f"🎵 Generating *{beat_label}* and mixing… please wait ⏳", parse_mode="Markdown")

    try:
        loop = asyncio.get_running_loop()
        audio_out, fmt, warn = await loop.run_in_executor(None, _vb_mix_blocking, voice_bytes, beat_key)
    except Exception as e:
        await bot.send_message(chat_id, f"❌ Error: `{str(e)[:150]}`", parse_mode="Markdown")
        return

    if audio_out is None:
        await bot.send_message(chat_id, f"❌ Failed to apply *{beat_label}*.\n`{str(warn)[:300]}`", parse_mode="Markdown")
        return

    buf = io.BytesIO(audio_out)
    buf.name = f"voice_beat_{beat_key}.{fmt}"
    await bot.send_voice(chat_id, buf, caption=f"{beat_label} ✅\n🎤 Your voice + real beat mixed in!")
    await bot.send_message(
        chat_id,
        "🎵 Try another beat or send a new voice message!",
        reply_markup=_vb_main_keyboard()
    )

async def cmd_voicebeat(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """/voicebeat or /vb — Voice Beat Studio entry point"""
    if not _FFMPEG_OK:
        await update.message.reply_text(
            "⚠️ *FFmpeg not installed!*\n\nInstall it:\n```\npkg install ffmpeg\n```\nThen restart the bot.",
            parse_mode="Markdown"
        )
        return
    await update.message.reply_text(
        "🎤 *Voice Beat Studio!*\n\n"
        "Send me a *voice message* 🎙️ and I'll add your chosen beat or instrument style to it!\n\n"
        "🔥 *20 styles:* Trap, Afrobeats, Gospel, Highlife, R&B, Reggae, Drill, Lo-Fi, Piano, Guitar & more!\n\n"
        "👉 Send a voice note to get started!",
        parse_mode="Markdown"
    )

# ── Check ffmpeg once at startup ──
def _vc_check_ffmpeg() -> bool:
    """Return True if ffmpeg is available on this system."""
    try:
        r = subprocess.run(["ffmpeg", "-version"], capture_output=True, timeout=5)
        return r.returncode == 0
    except (subprocess.SubprocessError, FileNotFoundError, OSError):
        return False

_FFMPEG_OK = _vc_check_ffmpeg()

def _vc_main_keyboard():
    """Build the 23-category main menu keyboard (3 buttons per row)."""
    buttons = []
    row = []
    for key, (label, _) in VC_CATEGORIES.items():
        row.append(InlineKeyboardButton(label, callback_data=f"vccat:{key}"))
        if len(row) == 3:
            buttons.append(row)
            row = []
    if row:
        buttons.append(row)
    buttons.append([InlineKeyboardButton("❌ Cancel", callback_data="vccat:cancel")])
    return InlineKeyboardMarkup(buttons)

def _vc_sub_keyboard(cat_key):
    """Build the 12-sub-variant keyboard for a category (2 per row)."""
    subs = VC_SUBS.get(cat_key, [])
    if not subs:
        return _vc_main_keyboard()  # fallback to main menu
    emoji = VC_CATEGORIES.get(cat_key, ("", "🎙️"))[1]
    buttons = []
    row = []
    for i, (name, _) in enumerate(subs):
        row.append(InlineKeyboardButton(
            f"{emoji} {name}", callback_data=f"vcsub:{cat_key}:{i}"
        ))
        if len(row) == 2:
            buttons.append(row)
            row = []
    if row:
        buttons.append(row)
    buttons.append([InlineKeyboardButton("⬅️ Back to Categories", callback_data="vccat:back")])
    return InlineKeyboardMarkup(buttons)

async def _vc_apply(bot, chat_id, file_id, cat_key, sub_idx, msg_id=None):
    """Download voice, apply ffmpeg effect, send back. All Termux-compatible."""

    # ── 1. ffmpeg availability ──
    if not _FFMPEG_OK:
        await bot.send_message(
            chat_id,
            "❌ *FFmpeg not found!*\n\n"
            "Install it in Termux:\n`pkg install ffmpeg`\n\n"
            "Then restart the bot.",
            parse_mode="Markdown"
        )
        return

    # ── 2. Validate category / sub index ──
    cat_label = VC_CATEGORIES.get(cat_key, ("Unknown",))[0]
    subs = VC_SUBS.get(cat_key, [])
    if not subs or sub_idx >= len(subs):
        await bot.send_message(chat_id, "❌ Invalid effect selection. Please try again.")
        return
    sub_name, af_filter = subs[sub_idx]

    # ── 3. Download file with expiry check ──
    try:
        file_info = await bot.get_file(file_id)
        audio_bytes = await file_info.download_as_bytearray()
    except Exception:
        await bot.send_message(
            chat_id,
            "❌ Voice message expired or invalid.\n"
            "Please send a new voice message 🎤",
        )
        return

    if len(audio_bytes) < 100:
        await bot.send_message(chat_id, "❌ Audio file too small or corrupted.")
        return

    # ── 4. Run ffmpeg in executor (non-blocking) ──
    def run_ffmpeg():
        tmp_dir = tempfile.mkdtemp()
        inp     = os.path.join(tmp_dir, "in.oga")
        out_mp3 = os.path.join(tmp_dir, "out.mp3")
        out_ogg = os.path.join(tmp_dir, "out.ogg")

        with open(inp, "wb") as f:
            f.write(audio_bytes)

        # ── Attempt 1: mp3 (most compatible on Android) ──
        r1 = subprocess.run(
            ["ffmpeg", "-y", "-i", inp,
             "-af", af_filter,
             "-ar", "44100", "-ac", "1",
             "-b:a", "128k", out_mp3],
            capture_output=True, timeout=90
        )
        if r1.returncode == 0 and os.path.exists(out_mp3) and os.path.getsize(out_mp3) > 500:
            return open(out_mp3, "rb").read(), "mp3", None
        err1 = r1.stderr.decode(errors="ignore")[-400:]

        # ── Attempt 2: ogg vorbis ──
        r2 = subprocess.run(
            ["ffmpeg", "-y", "-i", inp,
             "-af", af_filter,
             "-ar", "44100", "-ac", "1",
             "-c:a", "libvorbis", "-q:a", "4", out_ogg],
            capture_output=True, timeout=90
        )
        if r2.returncode == 0 and os.path.exists(out_ogg) and os.path.getsize(out_ogg) > 500:
            return open(out_ogg, "rb").read(), "ogg", None
        err2 = r2.stderr.decode(errors="ignore")[-400:]

        # ── Attempt 3: use only the FIRST filter token (safest fallback) ──
        first_filter = af_filter.split(",")[0].strip()
        out_fb = os.path.join(tmp_dir, "fb.mp3")
        r3 = subprocess.run(
            ["ffmpeg", "-y", "-i", inp,
             "-af", first_filter,
             "-ar", "44100", "-ac", "1", out_fb],
            capture_output=True, timeout=90
        )
        if r3.returncode == 0 and os.path.exists(out_fb) and os.path.getsize(out_fb) > 500:
            return open(out_fb, "rb").read(), "mp3", f"⚠️ Used simplified filter: `{first_filter}`"
        err3 = r3.stderr.decode(errors="ignore")[-200:]

        return None, None, f"All attempts failed:\n• mp3: {err1}\n• ogg: {err2}\n• fallback: {err3}"

    try:
        loop = asyncio.get_running_loop()
        audio_out, fmt, warn = await loop.run_in_executor(None, run_ffmpeg)
    except subprocess.TimeoutExpired:
        await bot.send_message(chat_id, "⏰ Timeout! Voice message is too long.")
        return
    except Exception as e:
        await bot.send_message(chat_id, f"❌ Processing error: `{str(e)[:150]}`", parse_mode="Markdown")
        return

    # ── 5. Send result or report failure ──
    if audio_out is None:
        await bot.send_message(
            chat_id,
            f"❌ *Failed:* {cat_label} — {sub_name}\n\n`{warn[:300]}`",
            parse_mode="Markdown"
        )
        return

    buf = io.BytesIO(audio_out)
    buf.name = f"voice_{cat_key}.{fmt}"
    caption = f"{cat_label} — {sub_name} ✅"
    if warn:
        caption += f"\n{warn}"
    await bot.send_voice(chat_id, buf, caption=caption)

async def cmd_voicechanger(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Entry point: /voicechanger or /vc"""
    allowed, deny_msg = check_advanced_access(update.effective_user.id, "voice_changer")
    if not allowed:
        await update.message.reply_text(f"🔒 {deny_msg}", parse_mode="Markdown"); return
    log_feature_usage(update.effective_user.id, "voice_changer")
    if not _FFMPEG_OK:
        await update.message.reply_text(
            "⚠️ *FFmpeg not installed!*\n\n"
            "The voice changer needs FFmpeg. Install it:\n"
            "```\npkg install ffmpeg\n```\n"
            "Then restart the bot.",
            parse_mode="Markdown"
        )
        return
    await update.message.reply_text(
        "🎙️ *Voice Changer — 23 Effects × 12 Styles!*\n\n"
        "Just send me a *voice message* 🎤\n"
        "Then pick your effect from the menu!\n\n"
        "276 total voice styles available 🔥",
        parse_mode="Markdown"
    )

# ── Helper: parse percentage strings like "+15%" → 15 ──
def parse_pct(s):
    """Convert rate string like '+15%' or '-10%' to int."""
    return int(str(s).replace("%", "").replace("+", "").strip() or "0")


