def check_advanced_access(user_id, feature_key: str) -> tuple:
    """
    Returns (allowed: bool, deny_message: str).
    Owner (ADMIN_ID) is always allowed — for free.
    """
    if str(user_id) == str(ADMIN_ID):
        return True, ""
    user = get_user(user_id)
    sub  = user.get("subscription", "free")
    label = _FEATURE_LABELS.get(feature_key, feature_key.replace("_", " ").title())

    if feature_key in ULTIMATE_FEATURES:
        if sub != "ultimate":
            return False, (
                f"👑 *{label}* is an *Ultimate* exclusive feature!\n\n"
                f"🔒 Upgrade to *Ultimate* plan — GHS {SUBSCRIPTION_TIERS['ultimate']['price_ghs']}/month\n\n"
                f"📲 Pay via MoMo: `{MOMO_NUMBER}` ({MOMO_NAME})\n"
                f"Then send proof to @{ADMIN_USERNAME} with your Telegram ID: `{user_id}`"
            )

    if feature_key in PRO_FEATURES:
        if sub not in ("pro", "ultimate"):
            return False, (
                f"💎 *{label}* requires a *Pro* or *Ultimate* subscription!\n\n"
                f"📦 *Pro Plan* — GHS {SUBSCRIPTION_TIERS['pro']['price_ghs']}/month\n"
                f"👑 *Ultimate Plan* — GHS {SUBSCRIPTION_TIERS['ultimate']['price_ghs']}/month\n\n"
                f"📲 Pay via MoMo: `{MOMO_NUMBER}` ({MOMO_NAME})\n"
                f"Send payment proof to @{ADMIN_USERNAME} with your Telegram ID: `{user_id}`"
            )

    if feature_key in BASIC_FEATURES:
        if sub == "free":
            return False, (
                f"⭐ *{label}* requires at least a *Basic* subscription!\n\n"
                f"📦 *Basic Plan* — GHS {SUBSCRIPTION_TIERS['basic']['price_ghs']}/month\n"
                f"💎 *Pro Plan* — GHS {SUBSCRIPTION_TIERS['pro']['price_ghs']}/month\n\n"
                f"📲 Pay via MoMo: `{MOMO_NUMBER}` ({MOMO_NAME})\n"
                f"Send payment proof to @{ADMIN_USERNAME} with your Telegram ID: `{user_id}`"
            )
    return True, ""


# ── Feature usage logger ──
def log_feature_usage(user_id, feature: str, detail: str = ""):
    """Record every time a user uses a feature — visible to admin via /activity."""
    try:
        now = datetime.datetime.now().isoformat()
        db_execute(
            "INSERT INTO feature_usage (user_id, feature, detail, used_at) VALUES (?,?,?,?)",
            (str(user_id), feature, detail[:200], now)
        )
    except Exception:
        pass  # Non-fatal

def init_feature_usage_table():
    """Create the feature_usage table if it doesn't exist."""
    db_execute("""
        CREATE TABLE IF NOT EXISTS feature_usage (
            id       INTEGER PRIMARY KEY AUTOINCREMENT,
            user_id  TEXT,
            feature  TEXT,
            detail   TEXT,
            used_at  TEXT
        )
    """)
