# ─────────────────────────────────────────────
#  CACHE & RATE LIMITING
# ─────────────────────────────────────────────
_response_cache = {}
_user_request_times = defaultdict(list)

def get_cache_key(prompt, model, system):
    return hashlib.md5(f"{model}:{system}:{prompt}".encode()).hexdigest()

def get_cached_response(prompt, model, system):
    key = get_cache_key(prompt, model, system)
    if key in _response_cache:
        if time.time() - _response_cache[key]["timestamp"] < 3600:
            return _response_cache[key]["response"]
    return None

def cache_response(prompt, model, system, response):
    key = get_cache_key(prompt, model, system)
    _response_cache[key] = {"response": response, "timestamp": time.time()}
    if len(_response_cache) > 500:
        oldest = sorted(_response_cache, key=lambda k: _response_cache[k]["timestamp"])[:100]
        for k in oldest:
            del _response_cache[k]

def check_rate_limit(user_id, max_per_minute=10):
    # Admin never rate limited
    if str(user_id) == str(ADMIN_ID):
        return True
    now = time.time()
    uid = str(user_id)
    _user_request_times[uid] = [t for t in _user_request_times[uid] if now - t < 60]
    if len(_user_request_times[uid]) >= max_per_minute:
        return False
    _user_request_times[uid].append(now)
    return True

# ─────────────────────────────────────────────
#  GROQ API (retry + fallback)
# ─────────────────────────────────────────────
def _build_messages(prompt, system, history):
    """Build clean message list for any OpenAI-compatible API."""
    messages = []
    if system:
        messages.append({"role": "system", "content": str(system)[:2000]})
    if history:
        for h in history[-6:]:
            role = h["role"] if h["role"] in ("user", "assistant") else "user"
            content_str = str(h.get("content", ""))[:1000]
            if content_str:
                messages.append({"role": role, "content": content_str})
    # No consecutive same-role messages
    cleaned = []
    for msg in messages:
        if cleaned and cleaned[-1]["role"] == msg["role"]:
            cleaned[-1]["content"] += " " + msg["content"]
        else:
            cleaned.append(msg)
    cleaned.append({"role": "user", "content": str(prompt)[:4000]})
    return cleaned


def call_gemini_api(prompt, mode="default", system=None, history=None, retries=3):
    """Call Google Gemini API — free, fast, very smart."""
    model = GEMINI_MODEL_THINK if mode in ("math", "think", "superai") else GEMINI_MODEL
    url   = f"{GEMINI_BASE}/{model}:generateContent?key={GEMINI_API_KEY2}"
    contents = []
    if history:
        for h in history[-6:]:
            role = "user" if h.get("role") == "user" else "model"
            contents.append({"role": role, "parts": [{"text": str(h.get("content",""))[:1000]}]})
    contents.append({"role": "user", "parts": [{"text": str(prompt)[:4000]}]})
    payload = {
        "contents": contents,
        "generationConfig": {"maxOutputTokens": 4096, "temperature": 0.7},
    }
    if system:
        payload["systemInstruction"] = {"parts": [{"text": str(system)[:2000]}]}
    for attempt in range(retries):
        try:
            r = requests.post(url, json=payload, timeout=60)
            if r.status_code == 429:
                time.sleep(15 * (attempt + 1)); continue
            r.raise_for_status()
            data = r.json()
            candidates = data.get("candidates", [])
            if candidates:
                parts = candidates[0].get("content", {}).get("parts", [])
                text  = "".join(p.get("text","") for p in parts).strip()
                if text:
                    logger.info(f"Gemini handled mode: {mode}")
                    return text
        except requests.exceptions.Timeout:
            logger.error(f"Gemini timeout attempt {attempt+1}")
            time.sleep(5 * (attempt + 1))
        except Exception as e:
            logger.error(f"Gemini error attempt {attempt+1}: {e}")
            time.sleep(5 * (attempt + 1))
    return None


def call_openrouter(prompt, mode="default", system=None, history=None, retries=3):
    """Call OpenRouter free DeepSeek as fallback."""
    model    = OPENROUTER_MODEL_CODE if mode in ("math","think","superai","programmer","developer") else OPENROUTER_MODEL
    messages = _build_messages(prompt, system, history)
    payload  = {"model": model, "messages": messages, "max_tokens": 4096}
    for attempt in range(retries):
        try:
            r = requests.post(OPENROUTER_BASE, headers=OPENROUTER_HEADERS, json=payload, timeout=60)
            if r.status_code == 429:
                time.sleep(15 * (attempt + 1)); continue
            r.raise_for_status()
            data   = r.json()
            result = data["choices"][0]["message"]["content"]
            if result:
                logger.info(f"OpenRouter handled mode: {mode}")
                return result
        except requests.exceptions.Timeout:
            logger.error(f"OpenRouter timeout attempt {attempt+1}")
            time.sleep(5 * (attempt + 1))
        except Exception as e:
            logger.error(f"OpenRouter error attempt {attempt+1}: {e}")
            time.sleep(5 * (attempt + 1))
    return None



def call_gemini(prompt, model=None, system=None, system_override=None, history=None,
                image_b64=None, image_mime="image/jpeg", use_cache=True, retries=3,
                mode=None):
    """Main AI call — routes to DeepSeek for smart modes, Groq for everything else."""
    if system_override:
        system = system_override
    if model is None:
        model = DEFAULT_MODEL

    # ── Route smart modes to Gemini (free) then OpenRouter (free fallback) ──
    current_mode = mode or ""
    if current_mode in SMART_MODES and not image_b64:
        # Try Gemini first
        result = call_gemini_api(prompt, mode=current_mode, system=system, history=history)
        if result:
            return result
        # Fallback to OpenRouter (free DeepSeek)
        logger.warning("Gemini failed — trying OpenRouter fallback")
        result = call_openrouter(prompt, mode=current_mode, system=system, history=history)
        if result:
            return result
        logger.warning("OpenRouter failed — falling back to Groq")

    if use_cache and not image_b64:
        cached = get_cached_response(prompt, model, system or "")
        if cached:
            return cached

    messages = _build_messages(prompt, system, history)
    models_to_try = [model]
    if model != FALLBACK_MODEL:
        models_to_try.append(FALLBACK_MODEL)

    for attempt_model in models_to_try:
        payload = {"model": attempt_model, "messages": messages, "max_tokens": 4096}
        for attempt in range(retries):
            try:
                r = requests.post(GROQ_BASE, headers=GROQ_HEADERS, json=payload, timeout=45)
                if r.status_code == 429:
                    wait = 15 * (attempt + 1)
                    logger.warning(f"Rate limited on {attempt_model}, waiting {wait}s")
                    time.sleep(wait)
                    continue
                r.raise_for_status()
                data = r.json()
                result = data["choices"][0]["message"]["content"]
                if use_cache and not image_b64:
                    cache_response(prompt, model, system or "", result)
                return result
            except requests.exceptions.Timeout:
                logger.error(f"Timeout [{attempt_model}] attempt {attempt+1}")
                time.sleep(5 * (attempt + 1))
            except Exception as e:
                logger.error(f"Groq error [{attempt_model}] attempt {attempt+1}: {e}")
                time.sleep(5 * (attempt + 1))

    return "⚠️ AI is temporarily unavailable. Please try again in a moment."

def ask_ai(prompt: str, system: str = None) -> str:
    """Simple synchronous wrapper around call_gemini for use in run_in_executor lambdas."""
    return call_gemini(prompt, system=system)

# ─────────────────────────────────────────────
#  GROK AI (xAI) — Real-time, bold, powerful
# ─────────────────────────────────────────────
def call_grok(prompt: str, system: str = None, model: str = None,
              image_b64: str = None, heavy: bool = False) -> str:
    """Call xAI Grok API — real-time knowledge, bold & witty personality."""
    try:
        use_model = model or (GROK_MODEL_HEAVY if heavy else GROK_MODEL)
        headers = {
            "Authorization": f"Bearer {XAI_API_KEY}",
            "Content-Type":  "application/json",
        }
        messages = []
        if system:
            messages.append({"role": "system", "content": system})
        else:
            messages.append({"role": "system", "content":
                "You are Grok — an AI with real-time knowledge, witty personality, "
                "bold honesty, and zero tolerance for boring answers. Be direct, "
                "helpful, and occasionally humorous. Access latest information freely."})

        if image_b64:
            messages.append({"role": "user", "content": [
                {"type": "image_url", "image_url": {"url": f"data:image/jpeg;base64,{image_b64}"}},
                {"type": "text", "text": prompt},
            ]})
        else:
            messages.append({"role": "user", "content": prompt})

        payload = {
            "model":       use_model,
            "messages":    messages,
            "max_tokens":  2048,
            "temperature": 0.7,
            "stream":      False,
        }
        r = requests.post(f"{XAI_BASE_URL}/chat/completions",
                          headers=headers, json=payload, timeout=30)
        if r.status_code == 200:
            return r.json()["choices"][0]["message"]["content"].strip()
        elif r.status_code == 401:
            # No valid key — fall back to Gemini with Grok personality
            grok_system = (
                "You are Grok — an AI inspired by The Hitchhiker's Guide to the Galaxy. "
                "Be bold, witty, brutally honest, occasionally sarcastic and humorous. "
                "Give direct answers without excessive caveats. "
                "Be like JARVIS — smart, quick, with personality."
            )
            return call_gemini(prompt, system=grok_system, mode="grok")
        else:
            return call_gemini(prompt, system=system or "Be bold, witty and direct.", mode="grok")
    except Exception as e:
        logger.error(f"Grok API error: {e}")
        return call_gemini(prompt, system="Be bold, witty and direct like Grok AI.", mode="grok")

def call_grok_search(query: str) -> str:
    """Grok with real-time search — gets latest info from web + X."""
    system = (
        "You are Grok with real-time search. Provide the most current, accurate information. "
        "Include relevant facts, recent developments, and be direct. "
        "If you have real-time data, use it. Format clearly."
    )
    prompt = f"Search and answer: {query}. Provide the latest information available including recent news, facts, and data."
    return call_grok(prompt, system=system, heavy=True)


def call_openai(prompt: str, system: str = None, pro: bool = False) -> str:
    """Call OpenAI GPT API, fallback to Gemini if error."""
    try:
        model = OPENAI_MODEL_PRO if pro else OPENAI_MODEL
        r = requests.post(
            f"{OPENAI_BASE_URL}/chat/completions",
            headers={"Authorization": f"Bearer {OPENAI_API_KEY}", "Content-Type": "application/json"},
            json={
                "model": model,
                "messages": [
                    {"role": "system", "content": system or "You are a helpful smart AI assistant."},
                    {"role": "user",   "content": prompt},
                ],
                "max_tokens": 2048,
                "temperature": 0.7,
            },
            timeout=30,
        )
        if r.status_code == 200:
            return r.json()["choices"][0]["message"]["content"].strip()
        return call_gemini(prompt, system=system)
    except Exception as e:
        logger.error(f"OpenAI: {e}")
        return call_gemini(prompt, system=system)

