# ─────────────────────────────────────────────
#  MTN MoMo API — Collections (Receive Payments)
# ─────────────────────────────────────────────
import uuid as _uuid

def mtn_get_token() -> str:
    """Get MTN MoMo access token using API User + API Key."""
    try:
        import base64 as _b64
        creds = _b64.b64encode(f"{MTN_API_USER}:{MTN_API_KEY}".encode()).decode()
        url = f"{MTN_BASE_URL}/collection/token/"
        headers = {
            "Authorization": f"Basic {creds}",
            "Ocp-Apim-Subscription-Key": MTN_SUBSCRIPTION_KEY,
        }
        r = requests.post(url, headers=headers, timeout=30)
        if r.status_code == 200:
            return r.json().get("access_token", "")
        logger.error(f"MTN token error: {r.status_code} — {r.text[:200]}")
        return ""
    except Exception as e:
        logger.error(f"MTN token exception: {e}")
        return ""

def mtn_request_payment(phone: str, amount: float, reference: str, note: str = "CineMagic Payment") -> dict:
    """Request a MoMo payment from a user's phone number."""
    try:
        token = mtn_get_token()
        if not token:
            return {"success": False, "error": "Could not get MTN access token. Check API credentials."}

        ref_id = str(_uuid.uuid4())
        url = f"{MTN_BASE_URL}/collection/v1_0/requesttopay"
        headers = {
            "Authorization": f"Bearer {token}",
            "X-Reference-Id": ref_id,
            "X-Target-Environment": MTN_ENVIRONMENT,
            "Ocp-Apim-Subscription-Key": MTN_SUBSCRIPTION_KEY,
            "Content-Type": "application/json",
        }
        # Format phone — remove leading 0, add Ghana code
        clean_phone = phone.strip().replace(" ", "").replace("+", "").replace("-", "")
        if clean_phone.startswith("0"):
            clean_phone = "233" + clean_phone[1:]
        elif not clean_phone.startswith("233"):
            clean_phone = "233" + clean_phone

        payload = {
            "amount": str(int(amount)),
            "currency": "GHS",
            "externalId": reference,
            "payer": {"partyIdType": "MSISDN", "partyId": clean_phone},
            "payerMessage": note,
            "payeeNote": note,
        }
        r = requests.post(url, headers=headers, json=payload, timeout=30)
        if r.status_code == 202:
            return {"success": True, "reference_id": ref_id, "phone": clean_phone}
        logger.error(f"MTN payment request error: {r.status_code} — {r.text[:200]}")
        return {"success": False, "error": f"MTN error {r.status_code}: {r.text[:100]}"}
    except Exception as e:
        logger.error(f"MTN payment exception: {e}")
        return {"success": False, "error": str(e)}

def mtn_check_payment(reference_id: str) -> dict:
    """Check the status of a MoMo payment request."""
    try:
        token = mtn_get_token()
        if not token:
            return {"status": "UNKNOWN", "error": "Token failed"}

        url = f"{MTN_BASE_URL}/collection/v1_0/requesttopay/{reference_id}"
        headers = {
            "Authorization": f"Bearer {token}",
            "X-Target-Environment": MTN_ENVIRONMENT,
            "Ocp-Apim-Subscription-Key": MTN_SUBSCRIPTION_KEY,
        }
        r = requests.get(url, headers=headers, timeout=30)
        if r.status_code == 200:
            data = r.json()
            return {
                "status": data.get("status", "UNKNOWN"),  # PENDING, SUCCESSFUL, FAILED
                "amount": data.get("amount", "0"),
                "currency": data.get("currency", "GHS"),
                "payer": data.get("payer", {}).get("partyId", ""),
                "reason": data.get("reason", ""),
            }
        return {"status": "UNKNOWN", "error": f"HTTP {r.status_code}"}
    except Exception as e:
        logger.error(f"MTN check payment exception: {e}")
        return {"status": "UNKNOWN", "error": str(e)}

def mtn_get_balance() -> dict:
    """Get your MTN MoMo account balance."""
    try:
        token = mtn_get_token()
        if not token:
            return {"success": False, "error": "Token failed"}
        url = f"{MTN_BASE_URL}/collection/v1_0/account/balance"
        headers = {
            "Authorization": f"Bearer {token}",
            "X-Target-Environment": MTN_ENVIRONMENT,
            "Ocp-Apim-Subscription-Key": MTN_SUBSCRIPTION_KEY,
        }
        r = requests.get(url, headers=headers, timeout=30)
        if r.status_code == 200:
            data = r.json()
            return {"success": True, "balance": data.get("availableBalance", "0"), "currency": data.get("currency", "GHS")}
        return {"success": False, "error": f"HTTP {r.status_code}: {r.text[:100]}"}
    except Exception as e:
        return {"success": False, "error": str(e)}



async def transcribe_voice(file_bytes: bytes, filename: str = "voice.ogg") -> str:
    """Transcribe voice audio using Groq Whisper API (free)."""
    try:
        # Auto-detect MIME type from file magic bytes
        _mime = "audio/ogg"
        if file_bytes[:3] == b"ID3" or file_bytes[:2] == b"\xff\xfb":
            _mime = "audio/mpeg"
        elif file_bytes[:4] == b"fLaC":
            _mime = "audio/flac"
        elif file_bytes[:4] == b"RIFF":
            _mime = "audio/wav"
        files = {
            "file": (filename, file_bytes, _mime),
            "model": (None, "whisper-large-v3"),
            "response_format": (None, "text"),
            "language": (None, "en"),
        }
        headers = {"Authorization": f"Bearer {GROQ_API_KEY}"}
        loop = asyncio.get_running_loop()
        resp = await loop.run_in_executor(None, lambda: requests.post(
            "https://api.groq.com/openai/v1/audio/transcriptions",
            headers=headers, files=files, timeout=30
        ))
        if resp.status_code == 200:
            return resp.text.strip()
        logger.error(f"Whisper error {resp.status_code}: {resp.text}")
        return ""
    except Exception as e:
        logger.error(f"Transcription error: {e}")
        return ""

def estimate_tokens(text):
    return max(1, len(text) // 4)

def estimate_cost(prompt, response, model):
    tokens = estimate_tokens(prompt + response)
    return (tokens / 1000) * TOKEN_COSTS.get(model, 0.000075)

def summarize_history(history):
    if len(history) < 6:
        return history
    old = history[:-4]
    recent = history[-4:]
    text = "\n".join([f"{h['role']}: {h['content']}" for h in old])
    summary = call_gemini(f"Summarize this conversation in 3-4 sentences:\n{text}", model=FALLBACK_MODEL, use_cache=False)
    return [{"role": "system", "content": f"[Summary: {summary}]"}] + recent

