def db_execute(query, params=(), fetch=False):
    conn = None
    try:
        conn = sqlite3.connect(SQLITE_DB)
        conn.row_factory = sqlite3.Row
        c = conn.cursor()
        c.execute(query, params)
        result = [dict(row) for row in c.fetchall()] if fetch else None
        conn.commit()
        return result
    except sqlite3.Error as e:
        logger.error(f"DB error: {e}")
        return None
    finally:
        if conn:
            conn.close()

def db_fetchone(query, params=()):
    conn = None
    try:
        conn = sqlite3.connect(SQLITE_DB)
        conn.row_factory = sqlite3.Row
        c = conn.cursor()
        c.execute(query, params)
        row = c.fetchone()
        return dict(row) if row else None
    except sqlite3.Error as e:
        logger.error(f"DB fetchone error: {e}")
        return None
    finally:
        if conn:
            conn.close()

def log_token_usage(user_id, model, prompt, response):
    tokens = estimate_tokens(prompt + response)
    cost = estimate_cost(prompt, response, model)
    now = datetime.datetime.now().isoformat()
    db_execute("INSERT INTO token_usage (user_id, model, tokens_used, cost_usd, created_at) VALUES (?,?,?,?,?)",
               (str(user_id), model, tokens, cost, now))

