def save_memory(user_id, key, value):
    uid = str(user_id)
    now = datetime.datetime.now().isoformat()
    existing = db_fetchone("SELECT id FROM memory WHERE user_id=? AND key=?", (uid, key))
    if existing:
        db_execute("UPDATE memory SET value=?, updated_at=? WHERE user_id=? AND key=?", (value, now, uid, key))
    else:
        db_execute("INSERT INTO memory (user_id, key, value, updated_at) VALUES (?,?,?,?)", (uid, key, value, now))

def get_all_memory(user_id):
    return db_execute("SELECT key, value FROM memory WHERE user_id=?", (str(user_id),), fetch=True) or []

def build_memory_context(user_id):
    memories = get_all_memory(user_id)
    if not memories:
        return ""
    lines = ["[User Memory:]"] + [f"- {m['key']}: {m['value']}" for m in memories[:15]]
    return "\n".join(lines)

def auto_extract_memory(user_id, message):
    keywords = {
        "my name is": "name", "i work as": "job", "i live in": "location",
        "my goal is": "goal", "i love": "interest", "i'm studying": "study_topic",
    }
    msg_lower = message.lower()
    for kw, mem_key in keywords.items():
        if kw in msg_lower:
            idx = msg_lower.index(kw) + len(kw)
            value = message[idx:idx+80].strip().split(".")[0]
            if len(value) > 3:
                save_memory(user_id, mem_key, value)

