def is_realtime_query(text: str) -> bool:
    """Returns True if the query needs real-time/live data."""
    t = text.lower()
    return any(kw in t for kw in REALTIME_KEYWORDS)

def sanitize_cutoff_response(response: str) -> str:
    """Remove any knowledge-cutoff phrases the AI sneaks into responses."""
    import re
    cutoff_phrases = [
        r"as of my (knowledge |training |last )?cutoff.*?.",
        r"my (knowledge |training )?cutoff (date |is |was ).*?.",
        r"(as of |until |up to |through )?(my )?(knowledge |training )?(cutoff|cut-off).*?.",
        r"i (don\'t|do not|cannot|can\'t) have (access to |)(real.?time|live|current|up.to.date).*?.",
        r"please note that my knowledge.*?.",
        r"i recommend checking.*?for (the most |more |)up.to.date.*?.",
        r"as of (january|february|march|april|may|june|july|august|september|october|november|december) 20(2[0-4]|1[0-9]).*?.",
        r"my (last |)(knowledge|training) (update|cutoff|data) (is|was).*?.",
        r"(information|data|knowledge) (is |)(only |)available (until|up to|through) .*?.",
    ]
    for pattern in cutoff_phrases:
        response = re.sub(pattern, "", response, flags=re.IGNORECASE | re.DOTALL)
    # Also replace specific year mentions implying old cutoff
    response = re.sub(r"knowledge cutoff (is |was |)(in |)(december |june |january )?202[0-3]", 
                      "knowledge up to 2026", response, flags=re.IGNORECASE)
    # Clean up double spaces/newlines left behind
    response = re.sub(r"\n{3,}", "\n\n", response)
    response = re.sub(r"  +", " ", response)
    return response.strip()

def web_search_summarize(query):
    try:
        snippets = []
        # ── Try DuckDuckGo Instant Answer API ──
        try:
            url = f"https://api.duckduckgo.com/?q={quote(query)}&format=json&no_html=1&skip_disambig=1"
            r = requests.get(url, timeout=10)
            data = r.json()
            if data.get("AbstractText"):
                snippets.append(data["AbstractText"])
            for topic in data.get("RelatedTopics", [])[:5]:
                if isinstance(topic, dict) and topic.get("Text"):
                    snippets.append(topic["Text"])
        except Exception as e:
            logger.warning(f"DuckDuckGo API error: {e}")
        # ── Try DuckDuckGo HTML search as fallback ──
        if not snippets:
            try:
                hdrs = {"User-Agent": "Mozilla/5.0 (compatible; CineMagicBot/1.0)"}
                r2 = requests.get(f"https://html.duckduckgo.com/html/?q={quote(query)}", headers=hdrs, timeout=12)
                results = re.findall(r'class="result__snippet"[^>]*>(.*?)</a>', r2.text, re.DOTALL)
                for s in results[:5]:
                    clean = re.sub(r'<[^>]+>', '', s).strip()
                    if clean:
                        snippets.append(clean)
            except Exception as e:
                logger.warning(f"DDG HTML search error: {e}")
        # ── If still nothing, AI answers directly ──
        if not snippets:
            result = call_gemini(
                f"Provide a comprehensive, accurate, up-to-date answer about: {query}\nInclude key facts and latest developments.",
                system="You are a knowledgeable research assistant.", use_cache=False)
            return f"🔍 *Web Search: {query}*\n\n{result}"
        combined = "\n\n".join(snippets[:6])
        summary = call_gemini(
            f"Based on these search results about '{query}', give a clear organised summary with key facts:\n\n{combined}",
            use_cache=False)
        return f"🔍 *Web Search: {query}*\n\n{summary}"
    except Exception as e:
        logger.error(f"Web search error: {e}")
        result = call_gemini(f"Answer this query with your best knowledge: {query}", use_cache=False)
        return f"🔍 *{query}*\n\n{result}"


# ─────────────────────────────────────────────
#  HD IMAGE GENERATION — Multi-API with fallback
# ─────────────────────────────────────────────
def generate_image_4k(prompt: str, style_suffix: str = "", model: str = "flux", width: int = 1024, height: int = 1024) -> bytes | None:
    """Generate HD image using multiple free APIs with automatic fallback."""
    clean_prompt = prompt.strip()[:300]
    if style_suffix:
        clean_prompt = f"{clean_prompt}{style_suffix}"
    seed = random.randint(1, 999999)
    safe_p  = quote(clean_prompt, safe="")
    short_p = quote(clean_prompt[:120], safe="")
    ua = "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 Chrome/120.0.0.0 Safari/537.36"
    img_h = {"User-Agent": ua, "Accept": "image/webp,image/apng,image/*,*/*;q=0.8"}

    # ── API 1: Pollinations.ai (no key, most reliable) ──
    for pm in [model, "flux", "turbo"]:
        for attempt in range(2):
            try:
                url = (f"https://image.pollinations.ai/prompt/{safe_p}"
                       f"?model={pm}&width=1024&height=1024&seed={seed+attempt}&nologo=true")
                r = requests.get(url, timeout=60, headers=img_h, allow_redirects=True)
                ct = r.headers.get("content-type","")
                if r.status_code == 200 and ("image" in ct or len(r.content) > 5000):
                    logger.info(f"Pollinations {pm} OK ({len(r.content)} bytes)")
                    return r.content
            except Exception as e:
                logger.warning(f"Pollinations {pm} attempt {attempt}: {e}")

    # ── API 2: Prodia free SDXL (no key) ──
    try:
        import time as _t
        pdm_map = {
            "flux":         "sd_xl_base_1.0.safetensors [be9edd61]",
            "flux-realism": "dreamshaperXL10_alpha2.safetensors [c8afe2ef]",
            "flux-anime":   "sd_xl_base_1.0.safetensors [be9edd61]",
            "turbo":        "sdxl-turbo_fp16_vae.safetensors [235745af]",
            "portrait":     "dreamshaperXL10_alpha2.safetensors [c8afe2ef]",
            "realistic":    "dreamshaperXL10_alpha2.safetensors [c8afe2ef]",
        }
        pdm = pdm_map.get(model, "sd_xl_base_1.0.safetensors [be9edd61]")
        jr = requests.get("https://api.prodia.com/generate",
            params={"new":"true", "prompt": clean_prompt[:300] + ", high quality",
                    "model": pdm, "steps":"20", "cfg":"7", "seed": str(seed),
                    "sampler":"DPM++ 2M Karras", "width":"1024", "height":"1024"},
            headers={"Accept":"application/json"}, timeout=30)
        if jr.status_code == 200:
            jid = jr.json().get("job","")
            if jid:
                for _ in range(15):
                    _t.sleep(3)
                    st = requests.get(f"https://api.prodia.com/job/{jid}",
                                      headers={"Accept":"application/json"}, timeout=15)
                    if st.status_code == 200:
                        sd2 = st.json()
                        if sd2.get("status") == "succeeded":
                            iu = sd2.get("imageUrl","")
                            if iu:
                                ir = requests.get(iu, timeout=30, headers=img_h)
                                if ir.status_code == 200 and len(ir.content) > 5000:
                                    logger.info(f"Prodia OK ({len(ir.content)} bytes)")
                                    return ir.content
                            break
                        elif sd2.get("status") == "failed":
                            break
    except Exception as e:
        logger.warning(f"Prodia: {e}")

    # ── API 3: HuggingFace (free, no key) ──
    try:
        hf_h = {"Content-Type":"application/json","User-Agent": ua}
        for hm in ["black-forest-labs/FLUX.1-schnell",
                   "stabilityai/stable-diffusion-xl-base-1.0",
                   "stabilityai/stable-diffusion-2-1"]:
            r = requests.post(f"https://api-inference.huggingface.co/models/{hm}",
                headers=hf_h,
                json={"inputs": clean_prompt[:300],
                      "parameters":{"num_inference_steps":4,"seed":seed}},
                timeout=60)
            if r.status_code == 200 and len(r.content) > 5000:
                logger.info(f"HuggingFace {hm} OK")
                return r.content
    except Exception as e:
        logger.warning(f"HuggingFace: {e}")

    logger.error("All image generation APIs failed")
    return None

def generate_image(prompt: str, model: str = "flux") -> bytes | None:
    return generate_image_4k(prompt, model=model)

