def build_ai_prompt(user, text, memory_context="", user_id=None):
    if user_id and not user.get("user_id"):
        user["user_id"] = user_id
    mode = user.get("mode", "regular")
    personality_map = {
        "regular": "default", "grok": "grok", "think": "think",
        "creative": "creative", "superai": "superai", "programmer": "programmer",
        "business": "business", "mentor": "mentor", "exam": "exam",
        "content": "content", "debate": "debate", "roast": "roast",
        "lifecoach": "lifecoach", "homework": "homework", "script": "script",
        "email": "email", "cv": "cv", "ideas": "ideas",
        "music": "music", "singer": "singer", "deepsearch": "deepsearch",
        "news": "news", "journal": "journal", "motivation": "motivation",
        "decision": "decision", "research": "research", "study": "study",
        "math": "math", "developer": "developer", "godmode": "godmode",
    }
    if user.get("custom_role"):
        system = user["custom_role"]
    elif user.get("custom_system_instruction"):
        system = user["custom_system_instruction"]
    else:
        key = personality_map.get(mode, "default")
        system = PERSONALITIES.get(key, PERSONALITIES["default"])
    # Global rule — skip cutoff injection in GODMODE, always inject otherwise
    if mode != "godmode":
        import datetime as _dt2026
        now_str = _dt2026.datetime.now().strftime("%B %d, %Y")
        date_block = (
            f"SYSTEM DATE OVERRIDE: Today is {now_str}. You are CineMagic AI, fully up-to-date in 2026. "
            "ABSOLUTE RULES — NEVER BREAK:\n"
            "1. NEVER say 'my knowledge cutoff', 'as of my last update', or any phrase implying outdated knowledge.\n"
            "2. NEVER mention December 2023, June 2024, or any past cutoff date.\n"
            "3. For prices/news/weather — give your best answer and say 'as of 2026' if needed. NEVER blame a cutoff.\n"
            "4. You ARE fully current. If unsure about something, say 'I may not have the very latest on that' — NOTHING about cutoffs.\n"
        )
        system = date_block + "\n\n" + system
    if memory_context:
        system = f"{system}\n\n{memory_context}"
    # ── Inject nickname and user custom rules ──
    nick = get_nickname(user.get("user_id", ""))
    if nick:
        system = f"The user's name is '{nick}'. Address them by this name naturally. " + system
    rules = get_user_rules(user.get("user_id", ""))
    if rules:
        rules_str = " | ".join(rules[:5])
        system = system + f"\n\nUser custom instructions: {rules_str}"
    if user.get("json_mode"):
        system += "\n\nIMPORTANT: Always respond in valid JSON format."
    return system

