def _char_browse_keyboard(page=0):
    chars = list(AI_CHARACTERS.items())
    per_page = 3
    total_pages = (len(chars) + per_page - 1) // per_page
    page = max(0, min(page, total_pages - 1))
    chunk = chars[page * per_page: page * per_page + per_page]
    rows = [[InlineKeyboardButton(
        f"{c['emoji']} {c['name']}, {c['age']} — {c['vibe'].split('·')[0].strip()}",
        callback_data=f"char:view:{key}")] for key, c in chunk]
    nav = []
    if page > 0: nav.append(InlineKeyboardButton("◀️ Prev", callback_data=f"char:page:{page-1}"))
    if page < total_pages - 1: nav.append(InlineKeyboardButton("Next ▶️", callback_data=f"char:page:{page+1}"))
    if nav: rows.append(nav)
    rows.append([InlineKeyboardButton("❌ Close", callback_data="char:close")])
    return InlineKeyboardMarkup(rows)

