async def cb_characters(update: Update, context: ContextTypes.DEFAULT_TYPE):
    query = update.callback_query
    await query.answer()
    user_id = query.from_user.id
    parts = query.data.split(":", 2)
    action = parts[1] if len(parts) > 1 else ""
    arg    = parts[2] if len(parts) > 2 else ""
    if action == "page":
        await query.edit_message_reply_markup(_char_browse_keyboard(int(arg) if arg.isdigit() else 0))
    elif action == "view":
        c = AI_CHARACTERS.get(arg)
        if not c:
            await query.edit_message_text("❌ Not found."); return
        tags = "  ".join(c["tags"])
        await query.edit_message_text(
            f"{c['emoji']} *{c['name']}, {c['age']}*\n_{c['vibe']}_\n\n{c['bio']}\n\n{tags}",
            parse_mode="Markdown",
            reply_markup=InlineKeyboardMarkup([
                [InlineKeyboardButton(f"💬 Chat with {c['name']}", callback_data=f"char:start:{arg}")],
                [InlineKeyboardButton("◀️ Back", callback_data="char:page:0")],
            ]))
    elif action == "start":
        c = AI_CHARACTERS.get(arg)
        if not c:
            await query.edit_message_text("❌ Not found."); return
        _char_active[user_id] = arg
        _char_histories.pop(user_id, None)
        await query.edit_message_text(
            f"{c['emoji']} *{c['name']}* is ready!\n\n_{c['bio'].splitlines()[0]}_\n\n💬 Just send a message!",
            parse_mode="Markdown",
            reply_markup=InlineKeyboardMarkup([[
                InlineKeyboardButton("🔄 Switch", callback_data="char:page:0"),
                InlineKeyboardButton("🛑 End", callback_data="char:end:x"),
            ]]))
    elif action == "end":
        _char_active.pop(user_id, None); _char_histories.pop(user_id, None)
        await query.edit_message_text("👋 Chat ended. /characters to start again!")
    elif action == "close":
        await query.edit_message_text("🎭 Closed. /characters anytime!")

async def _handle_character_chat(update: Update, context: ContextTypes.DEFAULT_TYPE) -> bool:
    user_id = update.effective_user.id
    char_key = _char_active.get(user_id)
    if not char_key: return False
    c = AI_CHARACTERS.get(char_key)
    if not c: _char_active.pop(user_id, None); return False
    text = (update.message.text or "").strip()
    if not text or text.startswith("/"): return False
    _char_history_add(user_id, "user", text)
    await context.bot.send_chat_action(update.effective_chat.id, "typing")
    history = _char_histories.get(user_id, [])
    try:
        reply = await asyncio.get_running_loop().run_in_executor(
            None, lambda: call_gemini(text, system=c["system"], history=history[:-1], use_cache=False))
    except Exception:
        reply = None
    if not reply:
        reply = f"_{c['name']} is thinking… try again!_ 🤔"
    _char_history_add(user_id, "assistant", reply)
    await update.message.reply_text(
        f"{c['emoji']} *{c['name']}*\n\n{reply}", parse_mode="Markdown",
        reply_markup=InlineKeyboardMarkup([[
            InlineKeyboardButton("🔄 Switch", callback_data="char:page:0"),
            InlineKeyboardButton("🛑 End", callback_data="char:end:x"),
        ]]))
    return True


