#  SIGN-IN / ACCOUNT SYSTEM
# ─────────────────────────────────────────────
def hash_password(password: str) -> str:
    return hashlib.sha256(password.encode()).hexdigest()

def is_signed_in(user_id) -> bool:
    row = db_fetchone("SELECT id FROM accounts WHERE user_id=?", (str(user_id),))
    return row is not None

# ─────────────────────────────────────────────
#  SECRET PIN SYSTEM
# ─────────────────────────────────────────────
def hash_pin(pin: str) -> str:
    """Hash a PIN with SHA-256 + salt for secure storage."""
    salt = "CineMagic_SecurePIN_2026"
    return hashlib.sha256(f"{salt}:{pin}".encode()).hexdigest()

def user_has_pin(user_id) -> bool:
    user = get_user(user_id)
    return bool(user.get("private_pin"))

def verify_user_pin(user_id, pin: str) -> bool:
    user = get_user(user_id)
    stored = user.get("private_pin")
    if not stored:
        return False
    return stored == hash_pin(pin)

def set_user_pin(user_id, pin: str) -> bool:
    """Set or change a user's secret PIN."""
    if len(pin) < 4 or not pin.isdigit():
        return False
    user = get_user(user_id)
    user["private_pin"] = hash_pin(pin)
    update_user(user_id, user)
    return True

