# ─────────────────────────────────────────────
#  PAYSTACK PAYMENT FUNCTIONS
# ─────────────────────────────────────────────
def paystack_initiate_momo(
    amount_ghs: float, phone: str, network: str,
    email: str, reference: str, description: str = "CineMagic Send"
) -> dict:
    """
    Initiate a Ghana Mobile Money charge via Paystack.
    Returns dict with keys: success, reference, status, message, auth_url
    """
    try:
        amount_pesewas = int(amount_ghs * 100)  # Paystack uses pesewas (1 GHS = 100 pesewas)
        network_code   = GH_NETWORKS.get(network, {}).get("paystack_code", "mtn")

        payload = {
            "amount":    amount_pesewas,
            "email":     email or f"{phone}@cinemagic.ai",
            "currency":  "GHS",
            "mobile_money": {
                "phone":    phone,
                "provider": network_code,
            },
            "reference":   reference,
            "metadata": {
                "custom_fields": [
                    {"display_name": "Service", "variable_name": "service", "value": description}
                ]
            }
        }
        r = requests.post(
            f"{PAYSTACK_BASE}/charge",
            headers=PAYSTACK_HEADERS,
            json=payload,
            timeout=30
        )
        data = r.json()
        if r.status_code == 200 and data.get("status"):
            charge_data = data.get("data", {})
            return {
                "success":   True,
                "reference": charge_data.get("reference", reference),
                "status":    charge_data.get("status", "pending"),
                "message":   data.get("message", "Charge initiated"),
                "auth_url":  charge_data.get("authorization_url", ""),
                "raw":       charge_data,
            }
        return {
            "success": False,
            "message": data.get("message", "Paystack charge failed"),
            "raw":     data,
        }
    except Exception as e:
        logger.error(f"Paystack MoMo error: {e}")
        return {"success": False, "message": str(e)}


def paystack_verify_transaction(reference: str) -> dict:
    """Verify a Paystack transaction by reference."""
    try:
        r = requests.get(
            f"{PAYSTACK_BASE}/transaction/verify/{reference}",
            headers=PAYSTACK_HEADERS,
            timeout=20
        )
        data = r.json()
        if r.status_code == 200 and data.get("status"):
            tx = data.get("data", {})
            return {
                "success":  True,
                "paid":     tx.get("status") == "success",
                "amount":   tx.get("amount", 0) / 100,
                "currency": tx.get("currency", "GHS"),
                "channel":  tx.get("channel", ""),
                "ref":      tx.get("reference", reference),
                "raw":      tx,
            }
        return {"success": False, "paid": False, "message": data.get("message", "Verification failed")}
    except Exception as e:
        logger.error(f"Paystack verify error: {e}")
        return {"success": False, "paid": False, "message": str(e)}


def paystack_transfer_recipient(name: str, account_number: str, bank_code: str = "MTN") -> dict:
    """Create a transfer recipient on Paystack for bank/MoMo payout."""
    try:
        payload = {
            "type":           "mobile_money",
            "name":           name,
            "account_number": account_number,
            "bank_code":      bank_code,
            "currency":       "GHS",
        }
        r = requests.post(
            f"{PAYSTACK_BASE}/transferrecipient",
            headers=PAYSTACK_HEADERS,
            json=payload,
            timeout=20
        )
        data = r.json()
        if r.status_code == 201 and data.get("status"):
            return {"success": True, "recipient_code": data["data"]["recipient_code"]}
        return {"success": False, "message": data.get("message", "Failed to create recipient")}
    except Exception as e:
        return {"success": False, "message": str(e)}


def paystack_send_transfer(recipient_code: str, amount_ghs: float, reference: str, reason: str = "CineMagic Transfer") -> dict:
    """Send money to a recipient via Paystack Transfer."""
    try:
        payload = {
            "source":    "balance",
            "amount":    int(amount_ghs * 100),
            "recipient": recipient_code,
            "reason":    reason,
            "reference": reference,
            "currency":  "GHS",
        }
        r = requests.post(
            f"{PAYSTACK_BASE}/transfer",
            headers=PAYSTACK_HEADERS,
            json=payload,
            timeout=30
        )
        data = r.json()
        if r.status_code == 200 and data.get("status"):
            return {"success": True, "transfer_code": data["data"].get("transfer_code",""), "status": data["data"].get("status","")}
        return {"success": False, "message": data.get("message", "Transfer failed")}
    except Exception as e:
        return {"success": False, "message": str(e)}


def generate_payment_reference(user_id, prefix="CM") -> str:
    """Generate a unique payment reference."""
    ts   = int(time.time())
    rand = random.randint(1000, 9999)
    return f"{prefix}-{user_id}-{ts}-{rand}"


