_pending_verifications = {}  # {user_id: {"code": "123456", "email": "x@y.com", "expires": timestamp, "data": {...}}}

def generate_verification_code() -> str:
    return str(random.randint(100000, 999999))

def send_verification_email(to_email: str, code: str, name: str = "User") -> bool:
    """Send a 6-digit verification code to the user's email via Gmail SMTP."""
    try:
        msg = MIMEMultipart("alternative")
        msg["Subject"] = "🎬 CineMagic AI — Email Verification Code"
        msg["From"]    = f"{EMAIL_SENDER_NAME} <{EMAIL_SENDER}>"
        msg["To"]      = to_email

        html = f"""
        <div style="font-family:Arial,sans-serif;max-width:480px;margin:auto;padding:30px;
                    background:#0f0f0f;color:#fff;border-radius:16px;">
          <h2 style="color:#e91e63;text-align:center;">🎬 CineMagic AI</h2>
          <p style="font-size:16px;">Hi <b>{name}</b> 👋</p>
          <p>Your email verification code is:</p>
          <div style="font-size:40px;font-weight:bold;letter-spacing:12px;
                      text-align:center;color:#e91e63;padding:20px;
                      background:#1a1a1a;border-radius:12px;margin:20px 0;">
            {code}
          </div>
          <p style="color:#aaa;font-size:13px;">
            ⏰ This code expires in <b>{VERIFY_CODE_EXPIRY} minutes</b>.<br>
            If you didn't request this, just ignore it.
          </p>
          <p style="color:#555;font-size:11px;text-align:center;">© CineMagic AI Bot</p>
        </div>
        """
        plain = f"CineMagic AI Verification Code: {code}\nExpires in {VERIFY_CODE_EXPIRY} minutes."
        msg.attach(MIMEText(plain, "plain"))
        msg.attach(MIMEText(html, "html"))

        with smtplib.SMTP_SSL("smtp.gmail.com", 465, timeout=15) as server:
            server.login(EMAIL_SENDER, EMAIL_PASSWORD)
            server.sendmail(EMAIL_SENDER, to_email, msg.as_string())
        logger.info(f"Verification email sent to {to_email}")
        return True
    except Exception as e:
        logger.error(f"Email send error: {e}")
        return False

def send_verification_sms(to_phone: str, code: str) -> bool:
    """Send a 6-digit verification code via SMS using Africa's Talking."""
    try:
        body = f"CineMagic AI verification code: {code}. Expires in {VERIFY_CODE_EXPIRY} mins."
        result = send_sms_message(to_phone, body)
        return result.get("success", False)
    except Exception as e:
        logger.error(f"SMS send error: {e}")
        return False

def send_verification_whatsapp(to_phone: str, code: str) -> bool:
    """Send a 6-digit verification code via WhatsApp using Twilio."""
    try:
        import urllib.request, urllib.parse, base64 as b64
        url = f"https://api.twilio.com/2010-04-01/Accounts/{TWILIO_ACCOUNT_SID}/Messages.json"
        body = f"🎬 *CineMagic AI* verification code:\n\n*{code}*\n\nExpires in {VERIFY_CODE_EXPIRY} minutes."
        wa_to = f"whatsapp:{to_phone}"
        data = urllib.parse.urlencode({"From": TWILIO_WHATSAPP, "To": wa_to, "Body": body}).encode()
        creds = b64.b64encode(f"{TWILIO_ACCOUNT_SID}:{TWILIO_AUTH_TOKEN}".encode()).decode()
        req = urllib.request.Request(url, data=data,
                                     headers={"Authorization": f"Basic {creds}",
                                              "Content-Type": "application/x-www-form-urlencoded"})
        urllib.request.urlopen(req, timeout=15)
        return True
    except Exception as e:
        logger.error(f"WhatsApp send error: {e}")
        return False

def store_pending_verification(user_id, contact, code, reg_data: dict, method: str = "email"):
    """Store verification code temporarily in memory."""
    expires = time.time() + (VERIFY_CODE_EXPIRY * 60)
    _pending_verifications[str(user_id)] = {
        "code": code, "email": contact, "contact": contact,
        "method": method, "expires": expires, "data": reg_data
    }

def check_verification_code(user_id, entered_code: str) -> str:
    """Returns: 'ok', 'expired', 'wrong', 'not_found'"""
    uid = str(user_id)
    if uid not in _pending_verifications:
        return "not_found"
    entry = _pending_verifications[uid]
    if time.time() > entry["expires"]:
        del _pending_verifications[uid]
        return "expired"
    if entry["code"] != entered_code.strip():
        return "wrong"
    return "ok"

def consume_pending_verification(user_id) -> dict:
    """Remove and return the pending verification entry."""
    uid = str(user_id)
    return _pending_verifications.pop(uid, {})

