def search_game_files(query: str, platform_id: str = "android") -> list:
    """Search for real game download links using web scraping."""
    results = []
    headers = {
        "User-Agent": "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36"
    }

    # APKPure for Android
    if platform_id == "android":
        try:
            url = f"https://apkpure.com/search?q={quote(query)}"
            r = requests.get(url, headers=headers, timeout=15)
            matches = re.findall(
                r'href="(https://apkpure.com/[^"]+)"[^>]*>.*?<p[^>]*>([^<]+)</p>',
                r.text, re.DOTALL)
            for href, name in matches[:6]:
                name = re.sub(r'\s+', ' ', name).strip()
                if name and len(name) > 2:
                    results.append({
                        "title": name,
                        "url": href,
                        "platform": "Android APK",
                        "source": "APKPure",
                        "direct": False,
                    })
        except Exception as e:
            logger.warning(f"APKPure search failed: {e}")

        # Fallback: APKMirror
        if not results:
            try:
                url = f"https://www.apkmirror.com/?post_type=app_release&searchtype=app&s={quote(query)}"
                r = requests.get(url, headers=headers, timeout=15)
                titles = re.findall(r'class="fontBlack">([^<]+)</a>', r.text)
                links = re.findall(r'href="(/apk/[^"]+)"', r.text)
                for t, l in zip(titles[:5], links[:5]):
                    results.append({
                        "title": t.strip(),
                        "url": f"https://www.apkmirror.com{l}",
                        "platform": "Android APK",
                        "source": "APKMirror",
                        "direct": False,
                    })
            except Exception as e:
                logger.warning(f"APKMirror search failed: {e}")

    # Emulator games for PSP/PS2/ROM
    elif platform_id in ("psp", "ps2", "rom", "emu"):
        try:
            site_map = {"psp": "psp", "ps2": "ps2", "rom": "gba", "emu": "snes"}
            cat = site_map.get(platform_id, "psp")
            url = f"https://www.emulatorgames.net/{cat}-games/?search={quote(query)}"
            r = requests.get(url, headers=headers, timeout=15)
            # Find game cards
            titles = re.findall(r'<h4[^>]*>([^<]+)</h4>', r.text)
            links = re.findall(r'href="(https://www.emulatorgames.net/[^"]+/)"', r.text)
            for t, l in zip(titles[:6], links[:6]):
                results.append({
                    "title": t.strip(),
                    "url": l,
                    "platform": platform_id.upper(),
                    "source": "EmuGames",
                    "direct": False,
                })
        except Exception as e:
            logger.warning(f"EmuGames search failed: {e}")

    # PC Games
    elif platform_id == "pc":
        try:
            url = f"https://steamunlocked.net/?s={quote(query)}"
            r = requests.get(url, headers=headers, timeout=15)
            titles = re.findall(r'<h3[^>]*class="[^"]*entry-title[^"]*"[^>]*><a[^>]*>([^<]+)</a>', r.text)
            links = re.findall(r'<h3[^>]*class="[^"]*entry-title[^"]*"[^>]*><a href="([^"]+)"', r.text)
            for t, l in zip(titles[:6], links[:6]):
                results.append({
                    "title": t.strip(),
                    "url": l,
                    "platform": "PC",
                    "source": "SteamUnlocked",
                    "direct": False,
                })
        except Exception as e:
            logger.warning(f"SteamUnlocked search failed: {e}")

    # Switch games
    elif platform_id == "switch":
        try:
            url = f"https://nxbrew.net/?s={quote(query)}"
            r = requests.get(url, headers=headers, timeout=15)
            titles = re.findall(r'<h2[^>]*class="[^"]*entry-title[^"]*"[^>]*><a[^>]*>([^<]+)</a>', r.text)
            links = re.findall(r'<h2[^>]*class="[^"]*entry-title[^"]*"[^>]*><a href="([^"]+)"', r.text)
            for t, l in zip(titles[:6], links[:6]):
                results.append({
                    "title": t.strip(),
                    "url": l,
                    "platform": "Switch",
                    "source": "NXBrew",
                    "direct": False,
                })
        except Exception as e:
            logger.warning(f"NXBrew search failed: {e}")

    # If no results found from scraping, return search page links
    if not results:
        fallback_urls = {
            "android": f"https://apkpure.com/search?q={quote(query)}",
            "pc":      f"https://steamunlocked.net/?s={quote(query)}",
            "psp":     f"https://www.emulatorgames.net/psp-games/?search={quote(query)}",
            "ps2":     f"https://www.emulatorgames.net/ps2-games/?search={quote(query)}",
            "ps3":     f"https://www.consolegames.ro/search?q={quote(query)}",
            "xbox":    f"https://www.consolegames.ro/search?q={quote(query)}",
            "switch":  f"https://nxbrew.net/?s={quote(query)}",
            "rom":     f"https://www.emulatorgames.net/search/?search={quote(query)}",
        }
        results.append({
            "title": f"🔍 Search '{query}' on game site",
            "url": fallback_urls.get(platform_id, f"https://apkpure.com/search?q={quote(query)}"),
            "platform": platform_id.upper(),
            "source": "Web Search",
            "direct": False,
        })

    return results[:8]

async def download_and_send_game(update_or_query, context, url: str, title: str, platform: str = "Game"):
    """Try to download real game file and send it. Falls back to sending download link."""
    if hasattr(update_or_query, 'effective_user'):
        user_id = update_or_query.effective_user.id
        chat_id = update_or_query.effective_chat.id
    else:
        user_id = update_or_query.from_user.id
        chat_id = update_or_query.message.chat_id

    fname = f"game_{user_id}_{int(time.time())}"
    headers = {
        "User-Agent": "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36"
    }

    status_msg = await context.bot.send_message(
        chat_id,
        f"🎮 *Finding:* _{title}_\n"
        f"🕹️ Platform: {platform}\n\n"
        f"⏳ Searching for download link...",
        parse_mode="Markdown")

    downloaded_file = None
    direct_url = None

    # Try to find a direct download link from the page
    try:
        r = await asyncio.get_running_loop().run_in_executor(None, lambda: requests.get(url, headers=headers, timeout=20))
        page = r.text

        # Look for direct APK/ZIP/ISO/ROM download links
        patterns = [
            r'(https?://[^\s"\'<>]+.apk[^\s"\'<>]*)',
            r'(https?://[^\s"\'<>]+.zip[^\s"\'<>]*)',
            r'(https?://[^\s"\'<>]+.iso[^\s"\'<>]*)',
            r'(https?://[^\s"\'<>]+.rar[^\s"\'<>]*)',
            r'(https?://[^\s"\'<>]+.7z[^\s"\'<>]*)',
            r'(https?://[^\s"\'<>]+.xci[^\s"\'<>]*)',
            r'(https?://[^\s"\'<>]+.nsp[^\s"\'<>]*)',
            r'href="(https?://[^\s"\'<>]+download[^\s"\'<>]*)"',
            r'href="(https?://[^\s"\'<>]+.apk)"',
        ]
        for pat in patterns:
            found = re.findall(pat, page, re.IGNORECASE)
            if found:
                direct_url = found[0]
                break
    except Exception as e:
        logger.warning(f"Page scrape failed: {e}")

    # If we found a direct file URL, try to download it
    if direct_url:
        try:
            await context.bot.edit_message_text(
                f"⬇️ *Downloading game file...*\n_{title}_\n\n⏳ Please wait...",
                chat_id=chat_id, message_id=status_msg.message_id, parse_mode="Markdown")

            fpath = DOWNLOAD_DIR / f"{fname}.apk"
            loop = asyncio.get_running_loop()
            def _dl_direct():
                with requests.get(direct_url, headers=headers, stream=True, timeout=120) as resp:
                    if resp.status_code == 200:
                        with open(fpath, "wb") as f:
                            for chunk in resp.iter_content(chunk_size=1024*1024):
                                f.write(chunk)
                        return fpath
                return None
            result = await loop.run_in_executor(None, _dl_direct)
            if result and result.exists() and result.stat().st_size > 0:
                downloaded_file = result
        except Exception as e:
            logger.warning(f"Direct download failed: {e}")

    # If file was downloaded, send it
    if downloaded_file and downloaded_file.exists():
        size_mb = downloaded_file.stat().st_size / (1024 * 1024)
        if size_mb <= 50:
            await context.bot.edit_message_text(
                f"✅ *Downloaded!* ({size_mb:.1f}MB) Sending file...\n"
                f"⚠️ _Auto-deletes in 3 minutes — save it now!_",
                chat_id=chat_id, message_id=status_msg.message_id, parse_mode="Markdown")
            try:
                with open(downloaded_file, "rb") as f:
                    sent = await context.bot.send_document(
                        chat_id, f,
                        caption=f"🎮 *{title}*\n🕹️ {platform}\n\n"
                                f"⚠️ _Deletes in 3 minutes! Save now!_ 💾",
                        parse_mode="Markdown",
                        read_timeout=120, write_timeout=120)
                await asyncio.sleep(GAME_DELETE_SECONDS)
                try:
                    await context.bot.delete_message(chat_id, sent.message_id)
                    await context.bot.send_message(
                        chat_id,
                        f"🗑️ *Deleted:* _{title}_\n\nSearch another with 🎮 Game Downloader!",
                        parse_mode="Markdown")
                except Exception:
                    pass
            except Exception as ex:
                logger.error(f"Game send error: {ex}")
                await context.bot.send_message(chat_id,
                    f"⚠️ Downloaded but failed to send. Error: {str(ex)[:80]}")
        else:
            # File too big — send the link instead
            await context.bot.edit_message_text(
                f"⚠️ File is {size_mb:.1f}MB — too large for Telegram.\n\n"
                f"📥 *Download it directly here:*\n{direct_url or url}",
                chat_id=chat_id, message_id=status_msg.message_id)
    else:
        # Could not download directly — send the page link with instructions
        await context.bot.edit_message_text(
            f"🎮 *{title}*\n"
            f"🕹️ Platform: {platform}\n\n"
            f"📥 *Tap the link below to download:*\n"
            f"{url}\n\n"
            f"📌 *How to install:*\n"
            f"• Android APK: Enable 'Unknown sources' in settings, then install\n"
            f"• PC: Extract the zip and run setup\n"
            f"• PSP/PS2: Use PPSSPP or AetherSX2 emulator\n"
            f"• ROM: Use any emulator app",
            chat_id=chat_id, message_id=status_msg.message_id)

    # Cleanup
    for f in DOWNLOAD_DIR.glob(f"{fname}.*"):
        try: f.unlink()
        except: pass


def search_movie_links(query: str) -> list:
    """Search for movie/video links using yt-dlp search."""
    results = []
    try:
        ydl_opts = {
            "quiet": True, "no_warnings": True,
            "extract_flat": True, "default_search": "ytsearch5",
        }
        with yt_dlp.YoutubeDL(ydl_opts) as ydl:
            info = ydl.extract_info(f"ytsearch5:{query} full movie", download=False)
            if info and "entries" in info:
                for e in info["entries"][:5]:
                    if e:
                        results.append({
                            "title": e.get("title", "Unknown"),
                            "url":   e.get("url") or e.get("webpage_url", ""),
                            "duration": e.get("duration", 0),
                            "uploader": e.get("uploader", "Unknown"),
                        })
    except Exception as ex:
        logger.error(f"Movie search error: {ex}")
    return results

def compress_video(input_path: Path, output_path: Path, target_mb: int = 45) -> bool:
    """Compress video to fit under target_mb using ffmpeg."""
    try:
        # Check if ffmpeg is available
        result = os.popen("which ffmpeg").read().strip()
        if not result:
            return False
        # Get video duration first
        import subprocess
        probe = subprocess.run(
            ["ffprobe", "-v", "error", "-show_entries", "format=duration",
             "-of", "default=noprint_wrappers=1:nokey=1", str(input_path)],
            capture_output=True, text=True, timeout=30)
        duration = float(probe.stdout.strip() or "0")
        if duration <= 0:
            return False
        # Calculate target bitrate (bits per second)
        target_bits = target_mb * 8 * 1024 * 1024
        bitrate = int(target_bits / duration)
        video_bitrate = int(bitrate * 0.85)
        audio_bitrate = min(128000, int(bitrate * 0.15))
        compress = subprocess.run([
            "ffmpeg", "-i", str(input_path),
            "-c:v", "libx264", "-b:v", f"{video_bitrate}",
            "-c:a", "aac", "-b:a", f"{audio_bitrate}",
            "-vf", "scale=-2:480",  # max 480p
            "-preset", "ultrafast",
            "-y", str(output_path)
        ], capture_output=True, timeout=300)
        return output_path.exists() and output_path.stat().st_size > 0
    except Exception as e:
        logger.error(f"Compression error: {e}")
        return False

async def download_and_send_movie(update_or_query, context, url: str, title: str):
    """Download a video via yt-dlp, compress if needed, send and auto-delete after 2 min."""
    if hasattr(update_or_query, 'effective_user'):
        user_id = update_or_query.effective_user.id
        chat_id = update_or_query.effective_chat.id
    else:
        user_id = update_or_query.from_user.id
        chat_id = update_or_query.message.chat_id

    fname = f"movie_{user_id}_{int(time.time())}"
    fpath_template = str(DOWNLOAD_DIR / (fname + ".%(ext)s"))

    status_msg = await context.bot.send_message(
        chat_id,
        f"⬇️ *Downloading:* _{title}_\n\n⏳ Please wait 1-3 minutes...",
        parse_mode="Markdown")

    # Try formats from smallest to largest
    format_attempts = [
        "worst[ext=mp4]/worst",
        "best[height<=360][ext=mp4]/best[height<=360]",
        "best[height<=480][ext=mp4]/best[height<=480]",
        "18",   # YouTube 360p mp4
        "17",   # YouTube 144p 3gp
        "best",
    ]

    downloaded_file = None

    for fmt in format_attempts:
        try:
            ydl_opts = {
                "format": fmt,
                "outtmpl": fpath_template,
                "quiet": True,
                "no_warnings": True,
                "noplaylist": True,
                "merge_output_format": "mp4",
            }
            loop = asyncio.get_running_loop()
            def _download(opts=ydl_opts):
                with yt_dlp.YoutubeDL(opts) as ydl:
                    info = ydl.extract_info(url, download=True)
                    return ydl.prepare_filename(info)
            result_path = await loop.run_in_executor(None, _download)

            for ext in ["mp4", "mkv", "webm", "3gp", "avi", "mov"]:
                candidate = DOWNLOAD_DIR / f"{fname}.{ext}"
                if candidate.exists() and candidate.stat().st_size > 0:
                    downloaded_file = candidate
                    break
            if not downloaded_file:
                rp = Path(result_path)
                if rp.exists() and rp.stat().st_size > 0:
                    downloaded_file = rp

            if downloaded_file:
                size_mb = downloaded_file.stat().st_size / (1024 * 1024)
                # If this format is already small enough, stop trying
                if size_mb <= 49:
                    break
                # Too big — try next format
                logger.info(f"Format {fmt} gave {size_mb:.1f}MB, trying smaller...")
                for f in DOWNLOAD_DIR.glob(f"{fname}.*"):
                    try: f.unlink()
                    except: pass
                downloaded_file = None
                continue
        except Exception as ex:
            logger.warning(f"Format {fmt} failed: {ex}")
            for f in DOWNLOAD_DIR.glob(f"{fname}.*"):
                try: f.unlink()
                except: pass
            downloaded_file = None
            continue

    if downloaded_file and downloaded_file.exists():
        size_mb = downloaded_file.stat().st_size / (1024 * 1024)

        # If still too big, try to compress with ffmpeg
        if size_mb > 49:
            await context.bot.edit_message_text(
                f"📦 *File is {size_mb:.1f}MB — compressing to fit Telegram...*\n⏳ Please wait...",
                chat_id=chat_id, message_id=status_msg.message_id, parse_mode="Markdown")
            compressed_path = DOWNLOAD_DIR / f"{fname}_compressed.mp4"
            success = await asyncio.get_running_loop().run_in_executor(
                None, compress_video, downloaded_file, compressed_path)
            if success:
                try: downloaded_file.unlink()
                except: pass
                downloaded_file = compressed_path
                size_mb = downloaded_file.stat().st_size / (1024 * 1024)
            else:
                # ffmpeg not available or failed
                await context.bot.edit_message_text(
                    f"⚠️ *File too large ({size_mb:.1f}MB)*\n\n"
                    f"Install ffmpeg for auto-compression:\n"
                    f"`pkg install ffmpeg`\n\n"
                    f"Or try a different shorter result. 🔄",
                    chat_id=chat_id, message_id=status_msg.message_id, parse_mode="Markdown")
                try: downloaded_file.unlink()
                except: pass
                return

        if size_mb > 50:
            await context.bot.edit_message_text(
                f"⚠️ Still {size_mb:.1f}MB after compression. Try a different result.",
                chat_id=chat_id, message_id=status_msg.message_id)
            try: downloaded_file.unlink()
            except: pass
            return

        await context.bot.edit_message_text(
            f"✅ *Downloaded!* ({size_mb:.1f}MB) Sending now...\n"
            f"⚠️ _Auto-deletes in 2 minutes — save it now!_",
            chat_id=chat_id, message_id=status_msg.message_id, parse_mode="Markdown")

        try:
            with open(downloaded_file, "rb") as f:
                sent = await context.bot.send_video(
                    chat_id, f,
                    caption=f"🎬 *{title}*\n\n⚠️ _Deletes in 2 minutes! Save now!_ 💾",
                    parse_mode="Markdown",
                    supports_streaming=True,
                    read_timeout=120, write_timeout=120)

            db_execute(
                "INSERT INTO movie_downloads (user_id,title,file_path,message_id,chat_id,created_at) VALUES (?,?,?,?,?,?)",
                (str(user_id), title, str(downloaded_file), sent.message_id, chat_id,
                 datetime.datetime.now().isoformat()))

            await asyncio.sleep(MOVIE_DELETE_SECONDS)
            try:
                await context.bot.delete_message(chat_id, sent.message_id)
                await context.bot.send_message(
                    chat_id,
                    f"🗑️ *Deleted:* _{title}_\n\nSearch another with 🎬 Movie Downloader!",
                    parse_mode="Markdown")
            except Exception:
                pass
        except Exception as ex:
            logger.error(f"Send error: {ex}")
            try:
                await context.bot.send_message(
                    chat_id,
                    f"⚠️ Downloaded ({size_mb:.1f}MB) but failed to send.\nError: {str(ex)[:80]}")
            except: pass
    else:
        try:
            await context.bot.edit_message_text(
                "⚠️ *Download failed.*\n\n"
                "Possible reasons:\n"
                "• Video is private or age-restricted 🔒\n"
                "• Region blocked 🌍\n"
                "• Try a different search result 🔄",
                chat_id=chat_id, message_id=status_msg.message_id, parse_mode="Markdown")
        except: pass

    for f in DOWNLOAD_DIR.glob(f"{fname}.*"):
        try: f.unlink()
        except: pass

# ─────────────────────────────────────────────
#  QR CODE GENERATOR
# ─────────────────────────────────────────────
def generate_qr_code(text: str) -> bytes | None:
    """Generate QR code image using an API."""
    try:
        url = f"https://api.qrserver.com/v1/create-qr-code/?size=500x500&data={quote(text)}"
        r = requests.get(url, timeout=15)
        if r.status_code == 200:
            return r.content
    except Exception as e:
        logger.error(f"QR error: {e}")
    return None

