def claim_daily_bonus(user_id) -> tuple[bool, int]:
    """Returns (already_claimed, credits_earned)."""
    today = datetime.datetime.now().strftime("%Y-%m-%d")
    uid = str(user_id)
    existing = db_fetchone("SELECT id FROM daily_checkin WHERE user_id=? AND checkin_date=?", (uid, today))
    if existing:
        return False, 0
    db_execute("INSERT INTO daily_checkin (user_id, checkin_date, credits_earned) VALUES (?,?,?)",
               (uid, today, DAILY_BONUS_CREDITS))
    user = get_user(user_id)
    user["paid_credits"] = user.get("paid_credits", 0) + DAILY_BONUS_CREDITS
    update_user(user_id, user)
    return True, DAILY_BONUS_CREDITS

