def get_referral_leaderboard() -> list:
    db = load_db()
    leaders = []
    for uid, udata in db.items():
        refs = udata.get("referrals", 0)
        if refs > 0:
            name = udata.get("profile", {}).get("name", "") or f"User{uid[-4:]}"
            leaders.append({"name": name, "referrals": refs, "uid": uid})
    leaders.sort(key=lambda x: x["referrals"], reverse=True)
    return leaders[:LEADERBOARD_TOP]

