def generate_flashcards(topic: str, count: int = 5) -> list:
    prompt = (f"Create {count} flashcards for the topic: '{topic}'.\n"
              f"Return ONLY a JSON array like:\n"
              f'[{{"q":"question","a":"answer"}}, ...]\n'
              f"No extra text, just valid JSON.")
    raw = call_gemini(prompt, model=SMART_MODEL, use_cache=False)
    try:
        match = re.search(r'\[.*\]', raw, re.DOTALL)
        if match:
            return json.loads(match.group())
    except Exception:
        pass
    return []

