# ─────────────────────────────────────────────
#  UNIT CONVERTER
# ─────────────────────────────────────────────
def convert_units(text: str) -> str:
    conversions = {
        "kg to lbs":  lambda x: (x * 2.20462, "lbs"),
        "lbs to kg":  lambda x: (x / 2.20462, "kg"),
        "km to miles": lambda x: (x * 0.621371, "miles"),
        "miles to km": lambda x: (x / 0.621371, "km"),
        "c to f":     lambda x: (x * 9/5 + 32, "°F"),
        "f to c":     lambda x: ((x - 32) * 5/9, "°C"),
        "m to ft":    lambda x: (x * 3.28084, "ft"),
        "ft to m":    lambda x: (x / 3.28084, "m"),
        "l to gal":   lambda x: (x * 0.264172, "gallons"),
        "gal to l":   lambda x: (x / 0.264172, "liters"),
        "cm to in":   lambda x: (x * 0.393701, "inches"),
        "in to cm":   lambda x: (x / 0.393701, "cm"),
    }
    text_lower = text.lower().strip()
    for key, fn in conversions.items():
        parts = key.split(" to ")
        pattern = rf"([\d.]+)\s*{re.escape(parts[0])}\s*(to\s*{re.escape(parts[1])})?"
        m = re.search(pattern, text_lower)
        if m or key in text_lower:
            nums = re.findall(r"[\d.]+", text)
            if nums:
                val = float(nums[0])
                result, unit = fn(val)
                return f"✅ *{val} {parts[0]} = {result:.4f} {unit}*"
    return call_gemini(f"Convert this unit: {text}. Show the formula and result clearly.", use_cache=False)

# ─────────────────────────────────────────────
#  PASSWORD GENERATOR
# ─────────────────────────────────────────────
def generate_password(length: int = 16, strong: bool = True) -> str:
    chars = string.ascii_letters + string.digits
    if strong:
        chars += "!@#$%^&*()_+-=[]{}|;:,.<>?"
    return ''.join(random.choices(chars, k=max(8, min(length, 64))))

# ─────────────────────────────────────────────
#  AGE CALCULATOR
# ─────────────────────────────────────────────
def calculate_age(dob_str: str) -> str:
    try:
        formats = ["%Y-%m-%d", "%d/%m/%Y", "%d-%m-%Y", "%B %d %Y", "%d %B %Y"]
        dob = None
        for fmt in formats:
            try:
                dob = datetime.datetime.strptime(dob_str.strip(), fmt)
                break
            except ValueError:
                continue
        if not dob:
            return call_gemini(f"Calculate the age for someone born on: {dob_str}. Give years, months, days, and fun facts.", use_cache=False)
        now = datetime.datetime.now()
        years = now.year - dob.year - ((now.month, now.day) < (dob.month, dob.day))
        months = (now.month - dob.month) % 12
        days_lived = (now - dob).days
        next_bday = dob.replace(year=now.year)
        if next_bday < now:
            next_bday = next_bday.replace(year=now.year + 1)
        days_to_bday = (next_bday - now).days
        return (f"🎂 *Age Calculator*\n\n"
                f"📅 Born: {dob.strftime('%B %d, %Y')}\n"
                f"🎉 Age: *{years} years, {months} months*\n"
                f"📆 Days lived: *{days_lived:,}*\n"
                f"⏳ Days to next birthday: *{days_to_bday}*\n"
                f"🌟 Birth day: *{dob.strftime('%A')}*")
    except Exception as e:
        return f"⚠️ Could not parse date: {dob_str}. Try format: YYYY-MM-DD"

# ─────────────────────────────────────────────
#  GHS EXCHANGE RATE
# ─────────────────────────────────────────────
def get_ghs_rates() -> str:
    try:
        r = requests.get("https://api.exchangerate-api.com/v4/latest/GHS", timeout=10)
        data = r.json()
        rates = data.get("rates", {})
        usd = rates.get("USD", 0)
        eur = rates.get("EUR", 0)
        gbp = rates.get("GBP", 0)
        ngn = rates.get("NGN", 0)
        zar = rates.get("ZAR", 0)
        return (f"💱 *Ghana Cedi (GHS) Exchange Rates*\n\n"
                f"🇺🇸 1 GHS = ${usd:.4f} USD\n"
                f"🇪🇺 1 GHS = €{eur:.4f} EUR\n"
                f"🇬🇧 1 GHS = £{gbp:.4f} GBP\n"
                f"🇳🇬 1 GHS = ₦{ngn:.2f} NGN\n"
                f"🇿🇦 1 GHS = R{zar:.2f} ZAR\n\n"
                f"_Rates updated: {data.get('date','now')}_")
    except Exception as e:
        return call_gemini("What is the current Ghana Cedi exchange rate to USD, EUR, GBP? Give approximate rates.", use_cache=False)

# ─────────────────────────────────────────────
#  COUNTDOWN / EVENT TRACKER
# ─────────────────────────────────────────────
def countdown_to(event_name: str, date_str: str) -> str:
    try:
        formats = ["%Y-%m-%d", "%d/%m/%Y", "%d-%m-%Y"]
        target = None
        for fmt in formats:
            try:
                target = datetime.datetime.strptime(date_str.strip(), fmt)
                break
            except ValueError:
                continue
        if not target:
            return f"⚠️ Could not parse date. Use format: YYYY-MM-DD"
        now = datetime.datetime.now()
        diff = target - now
        if diff.days < 0:
            return f"⏰ *{event_name}* already passed {abs(diff.days)} days ago!"
        hours, rem = divmod(diff.seconds, 3600)
        minutes = rem // 60
        return (f"⏳ *Countdown: {event_name}*\n\n"
                f"📅 Target: {target.strftime('%B %d, %Y')}\n"
                f"⏱️ *{diff.days} days, {hours} hours, {minutes} minutes* remaining!")
    except Exception:
        return f"⚠️ Use format: event name | YYYY-MM-DD"

