def get_user_free_tracks(user_id) -> int:
    """Return how many free tracks user has left."""
    uid = str(user_id)
    used = db_execute("SELECT COUNT(*) as c FROM music_tracks WHERE user_id=?",
                      (uid,), fetch=True)
    used_count = used[0]["c"] if used else 0
    return max(0, FREE_TRACKS - used_count)

def save_track(user_id, title, prompt, mood, genre, style,
               instruments, lyrics, audio_url="", file_id="") -> int:
    """Save a generated track to DB. Returns track ID."""
    now = datetime.datetime.now().isoformat()
    db_execute(
        "INSERT INTO music_tracks (user_id,title,prompt,mood,genre,style,instruments,lyrics,audio_url,file_id,created_at) "
        "VALUES (?,?,?,?,?,?,?,?,?,?,?)",
        (str(user_id), title, prompt, mood, genre, style, instruments, lyrics, audio_url, file_id, now))
    row = db_fetchone("SELECT id FROM music_tracks WHERE user_id=? ORDER BY id DESC LIMIT 1", (str(user_id),))
    return row["id"] if row else 0

def get_user_tracks(user_id) -> list:
    """Get all tracks for a user."""
    return db_execute("SELECT * FROM music_tracks WHERE user_id=? ORDER BY id DESC",
                      (str(user_id),), fetch=True) or []

def generate_ai_lyrics(prompt: str, mood: str, genre: str, style: str,
                       instruments: str, user_description: str = "") -> dict:
    """Generate full song lyrics + metadata using Groq AI."""
    system = (
        "You are a professional music composer and lyricist. "
        "When given music parameters, create complete, emotionally powerful song lyrics "
        "with a clear structure: Verse 1, Pre-Chorus, Chorus, Verse 2, Bridge, Final Chorus. "
        "Also suggest a title, tempo BPM, key signature, and production notes."
    )
    full_prompt = (
        f"Create a complete original song with these specs:\n"
        f"📝 Description: {prompt}\n"
        f"😊 Mood: {mood}\n"
        f"🎵 Genre: {genre}\n"
        f"🎨 Style: {style}\n"
        f"🎸 Instruments: {instruments}\n"
        f"{'👤 User notes: ' + user_description if user_description else ''}\n\n"
        f"Format your response EXACTLY like this:\n"
        f"TITLE: [Song Title]\n"
        f"BPM: [tempo]\n"
        f"KEY: [musical key]\n"
        f"PRODUCTION: [brief production notes]\n\n"
        f"[VERSE 1]\n[lyrics]\n\n"
        f"[PRE-CHORUS]\n[lyrics]\n\n"
        f"[CHORUS]\n[lyrics]\n\n"
        f"[VERSE 2]\n[lyrics]\n\n"
        f"[BRIDGE]\n[lyrics]\n\n"
        f"[FINAL CHORUS]\n[lyrics]"
    )
    raw = call_gemini(full_prompt, model=SMART_MODEL, system_override=system, use_cache=False)

    # Parse title
    title_match = re.search(r'TITLE:\s*(.+)', raw)
    bpm_match = re.search(r'BPM:\s*(.+)', raw)
    key_match = re.search(r'KEY:\s*(.+)', raw)
    prod_match = re.search(r'PRODUCTION:\s*(.+)', raw)

    return {
        "title": title_match.group(1).strip() if title_match else f"{genre} Song",
        "bpm": bpm_match.group(1).strip() if bpm_match else "120",
        "key": key_match.group(1).strip() if key_match else "C Major",
        "production": prod_match.group(1).strip() if prod_match else "",
        "lyrics": raw,
        "full_text": raw,
    }

def try_generate_audio(prompt: str, title: str) -> str | None:
    """Try to get an audio URL from free music AI APIs."""
    # Try Pollinations AI audio (text-to-music)
    try:
        encoded = quote(f"{title} {prompt}"[:200])
        url = f"https://audio.pollinations.ai/{encoded}"
        r = requests.head(url, timeout=10, allow_redirects=True)
        if r.status_code == 200:
            return url
    except Exception:
        pass
    return None

