def _save_vchat_prefs(user_id, style, pace):
    """Persist voice chat style/pace to database."""
    import datetime
    db_execute(
        "INSERT OR REPLACE INTO vchat_prefs (user_id, style, pace, updated_at) VALUES (?,?,?,?)",
        (str(user_id), style, pace, datetime.datetime.now().isoformat())
    )

def _load_vchat_prefs(user_id):
    """Load saved voice chat prefs from database."""
    row = db_fetchone("SELECT style, pace FROM vchat_prefs WHERE user_id=?", (str(user_id),))
    if row:
        return row.get("style", "mellow"), row.get("pace", "normal")
    return "mellow", "normal"  # user_id -> {style, pace, active, call_active}

def get_vchat_style(user_id):
    s = _vchat_sessions.get(user_id, {})
    style = VOICE_CHAT_STYLES.get(s.get("style", "mellow"), VOICE_CHAT_STYLES["mellow"])
    pace  = VOICE_CHAT_PACE.get(s.get("pace", "normal"),   VOICE_CHAT_PACE["normal"])
    return style, pace

