def safe_md(text: str) -> str:
    """Escape special Markdown v1 characters so Telegram never crashes."""
    if not text:
        return ""
    # Only escape chars that aren't part of intentional formatting
    # We strip all markdown and send as plain text to be safe
    for ch in ['_', '*', '`', '[']:
        text = text.replace(ch, '\\' + ch)
    return text

def safe_reply(text: str) -> str:
    """Truncate to Telegram's 4096 char limit and strip null bytes."""
    return (text or "")[:4096].replace('\x00', '')

