# ── Badge helpers ──
def award_badge(user_id, badge_key: str):
    if badge_key not in BADGE_DEFINITIONS:
        return False
    exists = db_execute("SELECT id FROM badges WHERE user_id=? AND badge_name=?",
                        (str(user_id), badge_key), fetch=True)
    if exists:
        return False
    name, _ = BADGE_DEFINITIONS[badge_key]
    emoji = name.split()[0]
    db_execute("INSERT INTO badges (user_id, badge_name, badge_emoji, earned_at) VALUES (?,?,?,?)",
               (str(user_id), badge_key, emoji, datetime.datetime.now().isoformat()))
    return True

def get_user_badges(user_id) -> list:
    rows = db_execute("SELECT badge_name, badge_emoji, earned_at FROM badges WHERE user_id=?",
                      (str(user_id),), fetch=True)
    return rows or []

def get_user_level(xp: int) -> tuple:
    level, title = 1, "Beginner"
    for lvl, (min_xp, ttl) in XP_LEVELS.items():
        if xp >= min_xp:
            level, title = lvl, ttl
    return level, title

def add_xp(user, amount: int) -> tuple:
    old_xp  = user.get("xp", 0)
    new_xp  = old_xp + amount
    user["xp"] = new_xp
    old_lvl, _ = get_user_level(old_xp)
    new_lvl, new_title = get_user_level(new_xp)
    leveled_up = new_lvl > old_lvl
    return new_xp, leveled_up, new_title

# ── Promo code helpers ──
def redeem_promo(user_id, code: str) -> dict:
    rows = db_execute(
        "SELECT * FROM promo_codes WHERE code=? AND used_count < max_uses",
        (code.upper(),), fetch=True)
    if not rows:
        return {"success": False, "error": "Invalid or expired promo code"}
    promo = rows[0]
    # Check not already used by this user
    used = db_execute(
        "SELECT id FROM referrals WHERE referrer_id=? AND referred_id=?",
        (str(user_id), f"promo_{code}"), fetch=True)
    if used:
        return {"success": False, "error": "You already used this code"}
    credits = promo["credits"]
    db_execute("UPDATE promo_codes SET used_count=used_count+1 WHERE code=?", (code.upper(),))
    db_execute("INSERT INTO referrals (referrer_id, referred_id, credits_earned, created_at) VALUES (?,?,?,?)",
               (str(user_id), f"promo_{code}", credits, datetime.datetime.now().isoformat()))
    return {"success": True, "credits": credits}

def create_promo(code: str, credits: int, max_uses: int = 100) -> bool:
    try:
        db_execute(
            "INSERT INTO promo_codes (code, credits, max_uses, used_count, created_at) VALUES (?,?,?,0,?)",
            (code.upper(), credits, max_uses, datetime.datetime.now().isoformat()))
        return True
    except Exception:
        return False

def get_referral_link(user_id) -> str:
    bot_username = "MoveroomBot"
    return f"https://t.me/{bot_username}?start=ref_{user_id}"

def process_referral(referrer_id, new_user_id) -> int:
    exists = db_execute(
        "SELECT id FROM referrals WHERE referred_id=?", (str(new_user_id),), fetch=True)
    if exists or str(referrer_id) == str(new_user_id):
        return 0
    credits = 15
    db_execute(
        "INSERT INTO referrals (referrer_id, referred_id, credits_earned, created_at) VALUES (?,?,?,?)",
        (str(referrer_id), str(new_user_id), credits, datetime.datetime.now().isoformat()))
    return credits

# ── Anti-spam detection ──
_spam_tracker = {}
def check_spam(user_id) -> bool:
    import time as _t
    now = _t.time()
    uid = str(user_id)
    if uid not in _spam_tracker:
        _spam_tracker[uid] = []
    # Remove old entries outside window
    _spam_tracker[uid] = [t for t in _spam_tracker[uid] if now - t < SPAM_WINDOW_SECS]
    _spam_tracker[uid].append(now)
    return len(_spam_tracker[uid]) > SPAM_MSG_LIMIT

def scan_links(text: str) -> list:
    import re
    urls = re.findall(r'https?://[^\s]+|www\.[^\s]+', text)
    suspicious = []
    for url in urls:
        for domain in BANNED_LINK_DOMAINS:
            if domain in url.lower():
                suspicious.append(url)
    return suspicious

def check_badge_triggers(user, user_id):
    awarded = []
    msgs = user.get("total_messages", 0)
    xp   = user.get("xp", 0)
    if msgs >= 1    and award_badge(user_id, "first_message"): awarded.append("first_message")
    if msgs >= 10   and award_badge(user_id, "chat_10"):       awarded.append("chat_10")
    if msgs >= 100  and award_badge(user_id, "chat_100"):      awarded.append("chat_100")
    if msgs >= 1000 and award_badge(user_id, "chat_1000"):     awarded.append("chat_1000")
    imgs = user.get("images_generated", 0)
    if imgs >= 1    and award_badge(user_id, "image_gen"):     awarded.append("image_gen")
    return awarded

async def safe_send(message, text: str, parse_mode: str = "Markdown", **kwargs):
    """
    Send a message safely — if Markdown crashes, auto-retry as plain text.
    This fixes the 'Can't parse entities' error permanently.
    """
    text = safe_reply(text)
    try:
        return await message.reply_text(text, parse_mode=parse_mode, **kwargs)
    except Exception as e:
        if "parse" in str(e).lower() or "entity" in str(e).lower() or "markdown" in str(e).lower():
            # Strip all markdown and retry as plain text
            plain = text.replace("*", "").replace("_", "").replace("`", "")
            plain = plain.replace("[", "").replace("]", "").replace("\\", "")
            try:
                return await message.reply_text(plain, **kwargs)
            except Exception as e2:
                logger.error(f"safe_send plain retry failed: {e2}")
        else:
            logger.error(f"safe_send error: {e}")
        return None

def _clean_text_for_tts(text):
    """Convert ALL expressions to natural human speech for TTS."""
    import re as _re
    clean = text or ""

    # ── Laughing ──
    clean = _re.sub(r"hahaha+", "ha ha ha!", clean, flags=_re.IGNORECASE)
    clean = _re.sub(r"haha", "ha ha!", clean, flags=_re.IGNORECASE)
    clean = _re.sub(r"hehe+", "heh heh!", clean, flags=_re.IGNORECASE)
    clean = _re.sub(r"hihi+", "hee hee!", clean, flags=_re.IGNORECASE)
    clean = _re.sub(r"lmao+", "ha ha ha!", clean, flags=_re.IGNORECASE)
    clean = _re.sub(r"lol+", "ha!", clean, flags=_re.IGNORECASE)
    clean = _re.sub(r"rofl", "ha ha ha ha!", clean, flags=_re.IGNORECASE)
    clean = _re.sub(r"xd+", "ha ha!", clean, flags=_re.IGNORECASE)

    # ── Crying / Sadness ──
    clean = _re.sub(r"awww+", "aww!", clean, flags=_re.IGNORECASE)
    clean = _re.sub(r"aww", "aw!", clean, flags=_re.IGNORECASE)
    clean = _re.sub(r"nooo+", "no!", clean, flags=_re.IGNORECASE)
    clean = _re.sub(r"whyyy+", "why!", clean, flags=_re.IGNORECASE)
    clean = _re.sub(r"wahhh+", "waaah!", clean, flags=_re.IGNORECASE)

    # ── Surprise / Shock ──
    clean = _re.sub(r"omg+", "oh my God!", clean, flags=_re.IGNORECASE)
    clean = _re.sub(r"woww+", "wow!", clean, flags=_re.IGNORECASE)
    clean = _re.sub(r"woah|whoa+", "whoa!", clean, flags=_re.IGNORECASE)
    clean = _re.sub(r"oooh+", "ooh!", clean, flags=_re.IGNORECASE)
    clean = _re.sub(r"ohhh+", "oh!", clean, flags=_re.IGNORECASE)

    # ── Thinking / Hesitation ──
    clean = _re.sub(r"hmmm+", "hmm...", clean, flags=_re.IGNORECASE)
    clean = _re.sub(r"hmm", "hmm,", clean, flags=_re.IGNORECASE)
    clean = _re.sub(r"uhhh+", "uh...", clean, flags=_re.IGNORECASE)
    clean = _re.sub(r"umm+", "um...", clean, flags=_re.IGNORECASE)
    clean = _re.sub(r"errr+", "err...", clean, flags=_re.IGNORECASE)

    # ── Internet slang ──
    clean = _re.sub(r"\bsmh\b", "shaking my head.", clean, flags=_re.IGNORECASE)
    clean = _re.sub(r"\btbh\b", "to be honest,", clean, flags=_re.IGNORECASE)
    clean = _re.sub(r"\bngl\b", "not gonna lie,", clean, flags=_re.IGNORECASE)
    clean = _re.sub(r"\bidk\b", "I do not know,", clean, flags=_re.IGNORECASE)
    clean = _re.sub(r"\bikr\b", "I know right!", clean, flags=_re.IGNORECASE)
    clean = _re.sub(r"\bimo\b", "in my opinion,", clean, flags=_re.IGNORECASE)
    clean = _re.sub(r"\bfr\b", "for real,", clean, flags=_re.IGNORECASE)
    clean = _re.sub(r"\bbruh\b", "bro,", clean, flags=_re.IGNORECASE)
    clean = _re.sub(r"\bnah\b", "no,", clean, flags=_re.IGNORECASE)
    clean = _re.sub(r"\byass+\b", "yes!", clean, flags=_re.IGNORECASE)
    clean = _re.sub(r"\byess+\b", "yes!", clean, flags=_re.IGNORECASE)
    clean = _re.sub(r"\bzzzz+\b", "yawning", clean, flags=_re.IGNORECASE)
    clean = _re.sub(r"\bewww+\b", "ew!", clean, flags=_re.IGNORECASE)
    clean = _re.sub(r"\bouch\b", "ouch!", clean, flags=_re.IGNORECASE)

    # ── Emojis to natural words ──
    emoji_map = {
        "😂": " ha ha! ", "🤣": " ha ha ha! ", "😭": " oh no! ",
        "😱": " oh my! ", "😮": " wow! ", "🤯": " unbelievable! ",
        "🤔": " hmm, ", "😍": " amazing! ", "🥺": " please, ",
        "😤": " hmph! ", "😠": " ugh! ", "😎": " cool. ",
        "❤️": " ", "🥰": " ", "😘": " ", "💕": " ", "💔": " heartbroken. ",
        "🔥": " ", "💪": " ", "🚀": " ", "⚡": " ",
        "👏": " ", "🎉": " ", "🥳": " yay! ", "💯": " absolutely! ",
        "✅": " yes, ", "❌": " no, ", "🙏": " please, ",
        "😴": " yawning. ", "🥱": " yawns. ", "💀": " dying of laughter! ",
        "👍": " ", "👎": " ", "🤝": " ", "👑": " ", "⭐": " ",
    }
    for emoji, word in emoji_map.items():
        clean = clean.replace(emoji, word)

    # ── Strip markdown and leftover non-ASCII ──
    clean = clean.replace("*", "").replace("_", "").replace("`", "")
    clean = clean.replace("#", "").replace(">", "").replace("~", "")
    # Only strip leftover emoji-like symbols, keep non-English text (Arabic, French etc.)
    clean = _re.sub(r"[\U0001F000-\U0001FFFF]", " ", clean)  # Remove leftover emoji blocks
    clean = _re.sub(r"[\u2600-\u27BF]", " ", clean)          # Remove symbol blocks
    clean = _re.sub(r"\s+", " ", clean).strip()
    return clean[:2500] if clean else "Hello from CineMagic AI!"

async def _try_gtts(text, voice_key="female_us"):
    """Try Google TTS — works great on mobile, no Azure dependency."""
    if not GTTS_AVAILABLE:
        return None
    try:
        lang, tld = GTTS_VOICE_MAP.get(voice_key, ("en", "us"))
        loop = asyncio.get_running_loop()
        def _generate():
            tts = gTTS(text=text, lang=lang, tld=tld, slow=False)
            buf = io.BytesIO()
            tts.write_to_fp(buf)
            buf.seek(0)
            return buf.read()
        # Timeout after 20 seconds — prevents hanging
        audio = await asyncio.wait_for(
            loop.run_in_executor(None, _generate),
            timeout=20.0
        )
        if audio and len(audio) > 100:
            logger.info(f"gTTS success: {len(audio)} bytes")
            return audio
    except asyncio.TimeoutError:
        logger.warning("gTTS timeout — taking too long")
    except Exception as e:
        logger.error(f"gTTS error: {e}")
    return None

async def _try_edge_tts(text, voice_name="en-US-JennyNeural"):
    """Try Microsoft edge-tts with timeout to prevent hanging."""
    if not EDGE_TTS_AVAILABLE:
        return None
    try:
        import edge_tts
        communicate = edge_tts.Communicate(text, voice_name)
        audio_chunks = []

        async def _stream():
            async for chunk in communicate.stream():
                if chunk["type"] == "audio":
                    audio_chunks.append(chunk["data"])

        # Timeout after 15 seconds — prevents hanging on slow connections
        # Dynamic timeout: ~1s per 20 chars, min 15s max 45s
        _timeout = max(15, min(45, len(text) // 20))
        await asyncio.wait_for(_stream(), timeout=_timeout)

        if audio_chunks:
            audio = b"".join(audio_chunks)
            if len(audio) > 100:
                logger.info(f"edge-tts success: {len(audio)} bytes")
                return audio
    except asyncio.TimeoutError:
        logger.warning(f"edge-tts timeout for voice: {voice_name}")
    except Exception as e:
        logger.error(f"edge-tts error: {e}")
    return None

