# Global async lock — prevents race conditions in voice generation
_voice_lock = None

def _get_voice_lock():
    global _voice_lock
    if _voice_lock is None:
        _voice_lock = asyncio.Lock()
    return _voice_lock

async def text_to_voice(text, voice_name="en-US-JennyNeural"):
    """
    1st: Microsoft edge-tts with selected voice
    2nd: If Indian/African voice fails, try confirmed fallbacks
    3rd: gTTS with accent
    4th: gTTS default (ALWAYS works — no internet needed)
    """
    clean = _clean_text_for_tts(text)

    # Resolve voice key from name or key
    voice_key = None
    for k, v in EDGE_VOICE_MAP.items():
        if v == voice_name or k == voice_name:
            voice_key = k
            break
    if not voice_key:
        voice_key = "female_us"

    edge_voice = EDGE_VOICE_MAP.get(voice_key, "en-US-JennyNeural")

    # Step 1: Try edge-tts with selected voice
    if EDGE_TTS_AVAILABLE:
        audio = await _try_edge_tts(clean, edge_voice)
        if audio:
            return audio

        # Step 2: Fallback for non-US voices (Indian, African, Irish, Australian)
        NON_US_KEYS = {
            "ghana_female", "ghana_male", "nigeria_female", "nigeria_male",
            "kenya_female", "kenya_male", "sa_female", "sa_male",
            "tanzania_female", "tanzania_male", "ethiopia_female", "ethiopia_male",
            "female_india", "male_india", "male_ireland",
            "female_au", "male_au",
        }
        SAFE_FALLBACKS = [
            "en-US-JennyNeural",
            "en-US-GuyNeural",
            "en-GB-SoniaNeural",
        ]
        if voice_key in NON_US_KEYS:
            for fb_voice in SAFE_FALLBACKS:
                audio = await _try_edge_tts(clean, fb_voice)
                if audio:
                    logger.info(f"Voice fallback used: {fb_voice} (original: {edge_voice})")
                    return audio

    # Step 3: gTTS with accent — works on mobile, no Microsoft needed
    logger.warning(f"edge-tts failed for {edge_voice}, trying gTTS...")
    if GTTS_AVAILABLE:
        audio = await _try_gtts(clean, voice_key)
        if audio:
            return audio

        # Step 4: gTTS US English — ALWAYS works
        logger.warning("gTTS accent failed, trying gTTS default...")
        audio = await _try_gtts(clean, "female_us")
        if audio:
            return audio

    logger.error("TTS: All methods failed.")
    return None

async def send_voice_reply(update, context, text, voice_name):
    """Send a voice message reply — tries gTTS first, edge-tts second."""
    try:
        await context.bot.send_chat_action(update.effective_chat.id, "record_voice")
        audio = await text_to_voice(text, voice_name)
        if audio and len(audio) > 100:
            await update.message.reply_voice(voice=io.BytesIO(audio), caption="🎙️ Voice Reply")
            return True
        return False
    except Exception as e:
        logger.error(f"Voice send error: {e}")
        return False

