def extract_code_blocks(text):
    """Extract all code blocks from a markdown response."""
    import re
    # Match ```lang\ncode``` or ```\ncode```
    pattern = r"```(\w*)\n([\s\S]*?)```"
    matches = re.findall(pattern, text)
    return matches  # list of (language, code)

def get_file_extension(lang):
    """Map language name to file extension."""
    lang = lang.lower().strip()
    ext_map = {
        "python": "py", "py": "py",
        "javascript": "js", "js": "js",
        "typescript": "ts", "ts": "ts",
        "html": "html", "css": "css",
        "java": "java", "kotlin": "kt",
        "cpp": "cpp", "c": "c",
        "csharp": "cs", "cs": "cs",
        "php": "php", "ruby": "rb",
        "swift": "swift", "go": "go",
        "rust": "rs", "bash": "sh",
        "shell": "sh", "sh": "sh",
        "sql": "sql", "json": "json",
        "xml": "xml", "yaml": "yml",
        "dart": "dart", "r": "r",
    }
    return ext_map.get(lang, "txt")

async def send_code_as_file(update, response_text, prompt_text):
    """If response contains code blocks, send them as downloadable files."""
    blocks = extract_code_blocks(response_text)
    if not blocks:
        return False  # No code blocks found

    files_sent = 0
    for i, (lang, code) in enumerate(blocks[:3]):  # max 3 files
        code = code.strip()
        if len(code) < 20:  # skip tiny snippets
            continue
        ext  = get_file_extension(lang)
        lang_label = lang.upper() if lang else "CODE"
        # Generate a smart filename from the prompt
        import re
        safe_name = re.sub(r"[^a-zA-Z0-9_]", "_", prompt_text[:30]).strip("_").lower()
        filename  = f"{safe_name or 'cinemagic_code'}_{i+1}.{ext}" if len(blocks) > 1 else f"{safe_name or 'cinemagic_code'}.{ext}"
        file_bytes = io.BytesIO(code.encode("utf-8"))
        file_bytes.name = filename
        try:
            await update.message.reply_document(
                document=file_bytes,
                filename=filename,
                caption=f"📄 *{lang_label} File*\n`{filename}`\n\n💾 Tap to download & open!",
                parse_mode="Markdown"
            )
            files_sent += 1
        except Exception as e:
            logger.error(f"Failed to send code file: {e}")

    return files_sent > 0

async def handle_message(update: Update, context: ContextTypes.DEFAULT_TYPE):
    user_id = update.effective_user.id
    text = update.message.text or ""

    # ── Group moderation hook (runs before everything else in groups) ──
    if update.effective_chat and update.effective_chat.type != "private":
        try:
            if await handle_group_message(update, context):
                return
        except Exception as _gme:
            logger.warning(f"Group mod error: {_gme}")

    # ── AWAY MODE — auto-reply if admin is not around ──
    if await _handle_away_reply(update, context):
        return  # Away reply sent, skip normal processing

    # ── INTEGRATION HUB: token paste & action input ──
    if await _handle_int_action_input(update, context):
        return
    if await _handle_int_token_input(update, context):
        return

    # ── 🎭 CHARACTER CHAT — intercept first ──
    if _char_active.get(user_id):
        if await _handle_character_chat(update, context):
            return

    # ── MATCH SETUP — must be FIRST before AI intercepts ──
    if context.user_data.get("match_state") is not None:
        handled = await handle_match_setup(update, context)
        if handled:
            return

    user = get_user(user_id)
    awaiting = (user.get("awaiting") or "")

    # ── ADMIN PANEL ──
    if str(user_id) == ADMIN_ID:
        if text == "🔧 Admin Panel":
            await cmd_admin(update, context)
            return
        if await handle_admin_message(update, context):
            return

    if text == "🌐 Web App":
        await cmd_webapp(update, context)
        return

    # ── ANTI-SPAM CHECK ──
    if check_spam(user_id) and str(user_id) != ADMIN_ID:
        await update.message.reply_text(
            "⚠️ *Slow down!* You're sending messages too fast.\n"
            "Please wait a moment before continuing. ⏳",
            parse_mode="Markdown")
        return

    # ── LINK SCANNER ──
    if text:
        bad_links = scan_links(text)
        if bad_links:
            await update.message.reply_text(
                "🛡️ *Security Alert!*\n\n"
                "A suspicious link was detected in your message.\n"
                "This has been blocked for your safety. ⚠️",
                parse_mode="Markdown")
            return

    # ── BAN CHECK ──
    if user.get("banned"):
        await update.message.reply_text("⛔ Your account has been banned. Contact @Theolicarl.")
        return

    # ── TRADING BOT ──
    if await handle_trading_message(update, context):
        return

    # ── SIGN-IN GATE — Admin bypasses completely ──
    signin_step = context.user_data.get("signin_step")

    if str(user_id) != ADMIN_ID and not is_signed_in(user_id) and signin_step not in (
            "register_name", "register_age",
            "register_user", "register_pass", "register_email",
            "register_verify_method", "register_enter_phone",
            "register_verify", "login_user", "login_pass"):
        _g_url2 = f"{BASE_URL}/auth/google?state={update.effective_user.id}_tg"
        buttons = InlineKeyboardMarkup([
            [InlineKeyboardButton("🔴 Sign in with Google", url=_g_url2)],
            [InlineKeyboardButton("📝 Create Account", callback_data="auth:register")],
            [InlineKeyboardButton("🔑 Sign In", callback_data="auth:login")],
        ])
        await update.message.reply_text(
            "🔐 *Please sign in first!*\n\nTap a button below:",
            parse_mode="Markdown", reply_markup=buttons)
        return

    # ── REGISTRATION FLOW ──
    if signin_step == "register_name":
        name_input = text.strip()
        if len(name_input) < 2:
            await update.message.reply_text("⚠️ Name too short! Please enter your real name:")
            return
        context.user_data["reg_fullname"] = name_input
        context.user_data["signin_step"] = "register_age"
        await update.message.reply_text(
            f"👋 Hi *{name_input}*!\n\n"
            f"Step 2 of 2 — How old are you?\n"
            f"_(You must be 13 or older to use CineMagic)_",
            parse_mode="Markdown")
        return

    if signin_step == "register_age":
        age_input = text.strip()
        if not age_input.isdigit():
            await update.message.reply_text("⚠️ Please enter your age as a number (e.g. `16`):", parse_mode="Markdown")
            return
        age = int(age_input)
        if age < 13:
            await update.message.reply_text(
                "🚫 *Sorry!* You must be *13 or older* to use CineMagic.\n\n"
                "Come back when you're older! 👋",
                parse_mode="Markdown")
            context.user_data["signin_step"] = None
            return
        if age > 120:
            await update.message.reply_text("⚠️ Please enter a valid age:", parse_mode="Markdown")
            return
        full_name = context.user_data.get("reg_fullname", "User")
        # Auto-generate username from name
        import re as _re
        base_user = _re.sub(r'[^a-z0-9]', '', full_name.lower().replace(' ', '_'))[:12] or "user"
        username = base_user + str(random.randint(100, 999))
        password = str(random.randint(100000, 999999))  # auto password
        context.user_data["signin_step"] = None
        success, msg_code = register_account(user_id, username, password, full_name, "")
        if success:
            get_user(user_id)
            u = get_user(user_id)
            u["paid_credits"] = u.get("paid_credits", 0) + 10
            u["profile"] = u.get("profile", {})
            u["profile"]["age"] = age
            update_user(user_id, u)
            await update.message.reply_text(
                f"🎉 *Welcome to CineMagic, {full_name}!*\n\n"
                f"✅ Account created successfully!\n"
                f"🎁 Welcome bonus: *+10 credits* added!\n\n"
                f"You're all set — enjoy! 🚀",
                parse_mode="Markdown", reply_markup=get_main_keyboard(user_id))
        else:
            # username collision — retry with different number
            username = base_user + str(random.randint(1000, 9999))
            success, _ = register_account(user_id, username, password, full_name, "")
            if success:
                get_user(user_id)
                u = get_user(user_id)
                u["paid_credits"] = u.get("paid_credits", 0) + 10
                update_user(user_id, u)
                await update.message.reply_text(
                    f"🎉 *Welcome to CineMagic, {full_name}!*\n\n"
                    f"✅ Account created successfully!\n"
                    f"🎁 Welcome bonus: *+10 credits* added!\n\n"
                    f"You're all set — enjoy! 🚀",
                    parse_mode="Markdown", reply_markup=get_main_keyboard(user_id))
            else:
                await update.message.reply_text("⚠️ Registration failed. Please type /start to try again.")
        return

    if signin_step == "register_enter_phone":
        # User typed their phone number for SMS or WhatsApp
        phone_input = text.strip().replace(" ", "").replace("-", "")
