            # Send as file if code is detected
            sent_as_file = await send_code_as_file(update, response, text)
            if not sent_as_file:
                await update.message.reply_text(response[:4000], parse_mode="Markdown")
            else:
                # Also send short text summary above the file
                summary = response.split("```")[0].strip()
                if summary:
                    await update.message.reply_text(summary[:1500], parse_mode="Markdown")
            return

