async def cmd_labs(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Project Builder — generates full deliverables from an idea."""
    user_id = update.effective_user.id
    if not is_signed_in(user_id):
        await update.message.reply_text("🔐 Please sign in first! Type /start")
        return
    if context.args:
        idea = " ".join(context.args)
    else:
        context.user_data["awaiting"] = "labs_idea"
        await update.message.reply_text(
            "🔬 *CineMagic Labs — Project Builder*\n\n"
            "Tell me what you want to build and I'll generate the full project for you!\n\n"
            "Examples:\n"
            "• `A landing page for a bakery`\n"
            "• `A Python script that tracks expenses`\n"
            "• `A simple quiz app in HTML`\n"
            "• `A business plan for a food delivery startup`\n\n"
            "✍️ *What's your idea?*",
            parse_mode="Markdown")
        return
    await _run_labs(update, context, idea)

async def _run_labs(update, context, idea):
    user_id = update.effective_user.id
    user = get_user(user_id)
    thinking = await update.message.reply_text("🔬 *Labs is building your project...*\n\n⚙️ Analyzing idea...\n🧩 Planning structure...\n✍️ Generating deliverables...", parse_mode="Markdown")
    system = (
        "You are CineMagic Labs — an expert full-stack developer and project architect. "
        "When given an idea, you produce a COMPLETE, ready-to-use deliverable. "
        "Structure your output clearly with sections: "
        "📋 PROJECT OVERVIEW → 🏗️ STRUCTURE → 💻 FULL CODE/CONTENT → 🚀 HOW TO USE → 💡 NEXT STEPS. "
        "For web projects output complete HTML/CSS/JS in one file. "
        "For scripts output complete working code. "
        "For business plans output full structured document. "
        "Always produce something the user can use immediately."
    )
    prompt = f"Build this for me completely: {idea}"
    model = user.get("ai_model", DEFAULT_MODEL)
    result = call_gemini(prompt, model=model, system=system, use_cache=False)
    await thinking.delete()
    # Split long responses
    if len(result) > 4000:
        parts = [result[i:i+4000] for i in range(0, len(result), 4000)]
        for i, part in enumerate(parts):
            await update.message.reply_text(part, parse_mode="Markdown")
    else:
        await update.message.reply_text(result, parse_mode="Markdown")

async def cmd_image(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Generate an AI image from a text prompt."""
    user_id = update.effective_user.id
    if not is_signed_in(user_id):
        await update.message.reply_text("🔐 Please sign in first! Type /start")
        return
    if not context.args:
        await update.message.reply_text(
            "🖼️ *AI Image Generator*\n\n"
            "Usage: `/image <your prompt>`\n\n"
            "Examples:\n"
            "• `/image a sunset over the ocean, photorealistic`\n"
            "• `/image anime girl with blue hair`\n"
            "• `/image futuristic city at night, cyberpunk`",
            parse_mode="Markdown")
        return
    prompt = " ".join(context.args)
    await context.bot.send_chat_action(update.effective_chat.id, "upload_photo")
    thinking = await update.message.reply_text("🖼️ Generating your image... ⏳")
