async def cmd_voice(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """/voice <text> — send as voice instantly. /voice alone — show style picker."""
    user_id = update.effective_user.id
    user = get_user(user_id)
    if context.args:
        text_to_speak = " ".join(context.args)
        voice_key = user.get("voice", DEFAULT_VOICE)
        voice_label, voice_name = VOICE_OPTIONS.get(voice_key, VOICE_OPTIONS[DEFAULT_VOICE])
        await update.message.reply_text(f"🎙️ Generating with *{voice_label}*...", parse_mode="Markdown")
        await context.bot.send_chat_action(update.effective_chat.id, "record_voice")
        audio = await text_to_voice(text_to_speak, voice_name)
        if audio and len(audio) > 100:
            await update.message.reply_voice(voice=io.BytesIO(audio), caption=f"🎙️ {voice_label}")
