    """/activity — Admin: View recent feature usage log."""
    if str(update.effective_user.id) != ADMIN_ID:
        await update.message.reply_text("⛔ Admin only.")
        return
    rows = db_execute(
        "SELECT user_id, feature, detail, used_at FROM feature_usage ORDER BY id DESC LIMIT 50",
        fetch=True
    ) or []
    if not rows:
        await update.message.reply_text("📡 No activity recorded yet.")
        return
    msg = "📡 *Bot Activity Log* (last 50 actions)\n\n"
