async def handle_admin_message(update: Update, context: ContextTypes.DEFAULT_TYPE) -> bool:
    """Handle admin panel messages. Returns True if handled."""
    user_id = update.effective_user.id
    if str(user_id) != ADMIN_ID:
        return False
    text = update.message.text or ""

    if text == "🔙 Exit Admin":
        await update.message.reply_text("✅ Exited admin panel.", reply_markup=get_main_keyboard(user_id))
        context.user_data.pop("admin_step", None)
        return True

    # ── 📡 ACTIVITY LOG (v16 addition) ──
    if text == "📡 Activity Log":
        rows = db_execute(
            "SELECT user_id, feature, detail, used_at FROM feature_usage ORDER BY id DESC LIMIT 40",
            fetch=True
        ) or []
        if not rows:
            await update.message.reply_text("📡 No activity recorded yet.")
            return True
        msg = "📡 *Recent Activity Log* (last 40)\n\n"
        for r in rows:
            uid     = r["user_id"]
            feat    = r["feature"]
            detail  = r["detail"] or ""
            when    = r["used_at"][:16] if r["used_at"] else "?"
            detail_str = f" — _{detail[:30]}_" if detail else ""
            msg += f"`{when}` • `{uid}` → *{feat}*{detail_str}\n"
        await update.message.reply_text(msg[:4000], parse_mode="Markdown")
        return True

    # ── 💹 REVENUE STATS (v16 addition) ──
    if text == "💹 Revenue Stats":
        db = load_db()
        tier_counts = {"free": 0, "basic": 0, "pro": 0, "ultimate": 0}
        for u in db.values():
            t = u.get("subscription", "free")
            tier_counts[t] = tier_counts.get(t, 0) + 1
        revenue_basic    = tier_counts["basic"]    * SUBSCRIPTION_TIERS["basic"]["price_ghs"]
        revenue_pro      = tier_counts["pro"]      * SUBSCRIPTION_TIERS["pro"]["price_ghs"]
        revenue_ultimate = tier_counts["ultimate"] * SUBSCRIPTION_TIERS["ultimate"]["price_ghs"]
        total_rev        = revenue_basic + revenue_pro + revenue_ultimate
        # Top feature usage
