async def check_reminders(context: ContextTypes.DEFAULT_TYPE):
    now = datetime.datetime.now().isoformat()[:16]
    reminders = db_execute("SELECT * FROM reminders WHERE sent=0 AND remind_at<=?", (now,), fetch=True) or []
