        try:
            await context.bot.send_message(chat_id=int(rem["user_id"]),
                                           text=f"⏰ *Reminder:* {rem['title']}", parse_mode="Markdown")
            db_execute("UPDATE reminders SET sent=1 WHERE id=?", (rem["id"],))
        except Exception as e:
            logger.error(f"Reminder error: {e}")

