import hmac
from urllib.parse import urlencode

BINANCE_BASE     = "https://api.binance.com"
BINANCE_TESTNET  = "https://testnet.binance.vision"

_auto_trade_jobs = {}  # {user_id: job_object}

def get_trader(user_id):
    uid = str(user_id)
    db = load_db()
    user = db.get(uid, {})
    return user.get("trader", {
        "api_key": "", "api_secret": "", "connected": False,
        "auto_trade": False, "trade_amount": 10.0,
        "risk_level": "medium", "pairs": ["BTCUSDT"],
        "trade_history": [], "total_profit": 0.0,
        "stop_loss": 2.0, "take_profit": 4.0,
        "testnet": True,
    })

def save_trader(user_id, trader_data):
    uid = str(user_id)
    db = load_db()
    if uid not in db:
        db[uid] = {}
    db[uid]["trader"] = trader_data
    save_db(db)

def binance_request(api_key, api_secret, method, endpoint, params=None, testnet=True):
    """Make authenticated Binance API request."""
    base = BINANCE_TESTNET if testnet else BINANCE_BASE
    params = params or {}
    params["timestamp"] = int(time.time() * 1000)
    query = urlencode(params)
    signature = hmac.new(api_secret.encode(), query.encode(), hashlib.sha256).hexdigest()
    params["signature"] = signature
    headers = {"X-MBX-APIKEY": api_key}
    url = f"{base}{endpoint}"
    try:
        if method == "GET":
            r = requests.get(url, headers=headers, params=params, timeout=15)
        elif method == "POST":
            r = requests.post(url, headers=headers, params=params, timeout=15)
        elif method == "DELETE":
            r = requests.delete(url, headers=headers, params=params, timeout=15)
        r.raise_for_status()
        return r.json()
    except Exception as e:
        logger.error(f"Binance API error: {e}")
        return {"error": str(e)}

def get_crypto_price(symbol="BTCUSDT"):
    """Get current price from Binance public API."""
    try:
        r = requests.get(f"{BINANCE_BASE}/api/v3/ticker/price", params={"symbol": symbol}, timeout=10)
        data = r.json()
        return float(data.get("price", 0))
    except Exception as e:
        logger.error(f"Price fetch error: {e}")
        return 0.0

