def format_signal_message(sig):
    """Format a signal dict into a nice Telegram message."""
    if not sig:
        return "⚠️ Could not fetch market data right now."
    emoji = sig.get("emoji") or ("🟢" if sig["signal"] == "BUY" else ("🔴" if sig["signal"] == "SELL" else "🟡"))
    symbol = sig.get("symbol", "CRYPTO")
    price  = sig.get("current_price") or sig.get("price", 0)
    ma7    = sig.get("ma7", sig.get("ema12", 0))
    ma25   = sig.get("ma25", sig.get("ema26", 0))
    now    = sig.get("time", datetime.datetime.now().strftime("%H:%M:%S"))
    return (
        f"{emoji} *{symbol} — {sig['signal']} SIGNAL*\n\n"
        f"💰 Price: *${price:,.4f}*\n"
        f"📊 Confidence: *{sig['confidence']}%*\n"
        f"📈 RSI: *{sig['rsi']}*\n"
        f"📉 MA7: `{ma7}` | MA25: `{ma25}`\n\n"
        f"🧠 *Reasons:*\n" +
        "\n".join([f"  • {r}" for r in sig["reasons"]]) +
        f"\n\n⏰ Time: {now}"
    )

