async def auto_trade_job(context: ContextTypes.DEFAULT_TYPE):
    """Background job — runs every 30 mins, checks signals and auto trades."""
    db = load_db()
    for uid, user_data in db.items():
        trader = user_data.get("trader", {})
        if not trader.get("auto_trade") or not trader.get("connected"):
            continue
        api_key    = trader.get("api_key", "")
        api_secret = trader.get("api_secret", "")
        if not api_key or not api_secret:
            continue
        for pair in trader.get("pairs", ["BTCUSDT"])[:2]:
            try:
                sig = generate_trading_signal(pair)
                if not sig or sig["confidence"] < 70:
                    continue
                amount  = trader.get("trade_amount", 10.0)
                testnet = trader.get("testnet", True)
                if sig["signal"] == "BUY":
                    result = binance_request(api_key, api_secret, "POST", "/api/v3/order", {
                        "symbol": pair, "side": "BUY", "type": "MARKET", "quoteOrderQty": amount
                    }, testnet=testnet)
                    if "orderId" in result:
                        price = float(result.get("fills", [{}])[0].get("price", 0)) if result.get("fills") else sig["price"]
                        trader.setdefault("trade_history", []).append({
                            "type": "BUY", "symbol": pair, "amount": amount,
                            "price": price, "auto": True,
                            "time": datetime.datetime.now().isoformat(), "orderId": result["orderId"]
                        })
                        db[uid]["trader"] = trader
                        save_db(db)
                        try:
                            await context.bot.send_message(
                                int(uid),
                                f"🤖 *Auto Trade Executed!*\n\n"
                                f"🟢 BUY *{pair}*\n"
                                f"💰 Amount: *${amount} USDT*\n"
                                f"💲 Price: *${price:.4f}*\n"
                                f"📊 Confidence: *{sig['confidence']}%*\n"
                                f"🆔 Order: `{result['orderId']}`",
                                parse_mode="Markdown")
                        except Exception:
                            pass
            except Exception as e:
                logger.error(f"Auto trade error for {uid}: {e}")

async def handle_trade_callback(query, context):
    """Handle inline keyboard callbacks for trading."""
    data    = query.data
    user_id = query.from_user.id
    trader  = get_trader(user_id)

    if data == "trade:refresh_signals":
        await query.answer("🔄 Refreshing...")
        pairs = trader.get("pairs", ["BTCUSDT", "ETHUSDT"])
        all_signals = ""
        for pair in pairs[:3]:
            sig = generate_trading_signal(pair)
            all_signals += format_signal_message(sig) + "\n\n─────────────\n\n"
        keyboard = InlineKeyboardMarkup([
            [InlineKeyboardButton("🔄 Refresh Signals", callback_data="trade:refresh_signals")],
        ])
        await query.edit_message_text(all_signals[:4000], parse_mode="Markdown", reply_markup=keyboard)

    elif data == "trade:set_amount":
        await query.answer()
        context.user_data["trade_step"] = "set_amount"
        await query.message.reply_text("💰 Enter new trade amount in USDT (e.g. `10` or `25`):", parse_mode="Markdown")

    elif data == "trade:set_sl":
        await query.answer()
        context.user_data["trade_step"] = "set_sl"
        await query.message.reply_text("⚠️ Enter Stop Loss percentage (e.g. `2` for 2%):", parse_mode="Markdown")

    elif data == "trade:set_tp":
        await query.answer()
        context.user_data["trade_step"] = "set_tp"
        await query.message.reply_text("🎯 Enter Take Profit percentage (e.g. `4` for 4%):", parse_mode="Markdown")

    elif data == "trade:toggle_testnet":
        await query.answer()
        trader["testnet"] = not trader["testnet"]
        save_trader(user_id, trader)
        mode = "Testnet (Safe)" if trader["testnet"] else "🔴 LIVE TRADING"
        await query.message.reply_text(f"🌐 Mode switched to: *{mode}*\n\n{'⚠️ WARNING: You are now trading with REAL money!' if not trader['testnet'] else '✅ Safe testnet mode active.'}", parse_mode="Markdown")

    elif data == "trade:set_pairs":
        await query.answer()
        keyboard = InlineKeyboardMarkup([
            [InlineKeyboardButton("₿ BTCUSDT", callback_data="tradepair:BTCUSDT"),
             InlineKeyboardButton("Ξ ETHUSDT", callback_data="tradepair:ETHUSDT")],
            [InlineKeyboardButton("🔶 BNBUSDT", callback_data="tradepair:BNBUSDT"),
             InlineKeyboardButton("🔵 SOLUSDT", callback_data="tradepair:SOLUSDT")],
            [InlineKeyboardButton("🐶 DOGEUSDT", callback_data="tradepair:DOGEUSDT"),
             InlineKeyboardButton("🔷 ADAUSDT", callback_data="tradepair:ADAUSDT")],
            [InlineKeyboardButton("✅ Done", callback_data="tradepair:done")],
        ])
        current = ", ".join(trader.get("pairs", []))
        await query.message.reply_text(
            f"🪙 *Select Trading Pairs*\nCurrently: *{current}*\nTap to toggle:",
            parse_mode="Markdown", reply_markup=keyboard)

    elif data == "trade:back":
        await query.answer()
        await query.edit_message_text(
            "📊 *Trading Hub*\n\nUse the keyboard below to navigate.",
            parse_mode="Markdown")

    elif data == "trade:pair":
        await query.answer()
        keyboard = InlineKeyboardMarkup([
            [InlineKeyboardButton("₿ BTCUSDT", callback_data="tradepair:BTCUSDT"),
             InlineKeyboardButton("Ξ ETHUSDT", callback_data="tradepair:ETHUSDT")],
            [InlineKeyboardButton("🔶 BNBUSDT", callback_data="tradepair:BNBUSDT"),
             InlineKeyboardButton("🔵 SOLUSDT", callback_data="tradepair:SOLUSDT")],
            [InlineKeyboardButton("🐶 DOGEUSDT", callback_data="tradepair:DOGEUSDT"),
             InlineKeyboardButton("🔷 ADAUSDT", callback_data="tradepair:ADAUSDT")],
            [InlineKeyboardButton("✅ Done", callback_data="tradepair:done")],
        ])
        current = ", ".join(trader.get("pairs", ["BTCUSDT"]))
        await query.message.reply_text(
            f"🪙 *Select Trading Pairs*\nCurrently: *{current}*\nTap to toggle:",
            parse_mode="Markdown", reply_markup=keyboard)

    elif data == "trade:amount":
        await query.answer()
        context.user_data["trade_step"] = "set_amount"
        await query.message.reply_text("💰 Enter new trade amount in USDT (e.g. `10` or `25`):", parse_mode="Markdown")

    elif data == "trade:stoploss":
        await query.answer()
        context.user_data["trade_step"] = "set_sl"
        await query.message.reply_text("🛑 Enter Stop Loss % (e.g. `2` for 2%):", parse_mode="Markdown")

    elif data == "trade:takeprofit":
        await query.answer()
        context.user_data["trade_step"] = "set_tp"
        await query.message.reply_text("✅ Enter Take Profit % (e.g. `4` for 4%):", parse_mode="Markdown")

    elif data.startswith("tradepair:"):
        pair = data.split(":")[1]
        if pair == "done":
            await query.answer("✅ Pairs saved!")
            await query.edit_message_text(f"✅ Trading pairs saved: *{', '.join(trader['pairs'])}*", parse_mode="Markdown")
            return
        pairs = trader.get("pairs", [])
        if pair in pairs:
            pairs.remove(pair)
            await query.answer(f"❌ Removed {pair}")
        else:
            pairs.append(pair)
            await query.answer(f"✅ Added {pair}")
        trader["pairs"] = pairs
        save_trader(user_id, trader)

