_auto_trade_tasks = {}  # {user_id: asyncio.Task}

def get_binance_price(symbol: str) -> dict:
    try:
        url = f"https://api.binance.com/api/v3/ticker/24hr?symbol={symbol}"
        r = requests.get(url, timeout=10)
        if r.status_code == 200:
            d = r.json()
            return {
                "symbol": symbol,
                "price": float(d["lastPrice"]),
                "change": float(d["priceChangePercent"]),
                "high": float(d["highPrice"]),
                "low": float(d["lowPrice"]),
            }
    except Exception as e:
        logger.error(f"Binance price error: {e}")
    return {}

def get_binance_klines(symbol: str, interval: str = "1h", limit: int = 60) -> list:
    try:
        url = f"https://api.binance.com/api/v3/klines?symbol={symbol}&interval={interval}&limit={limit}"
        r = requests.get(url, timeout=10)
        if r.status_code == 200:
            return [float(c[4]) for c in r.json()]  # close prices
    except Exception as e:
        logger.error(f"Klines error: {e}")
    return []

def calculate_rsi(closes: list, period: int = 14) -> float:
    if len(closes) < period + 1:
        return 50.0
    gains, losses = [], []
    for i in range(1, len(closes)):
        diff = closes[i] - closes[i - 1]
        gains.append(max(diff, 0))
        losses.append(max(-diff, 0))
    avg_gain = sum(gains[-period:]) / period
    avg_loss = sum(losses[-period:]) / period
    if avg_loss == 0:
        return 100.0
    rs = avg_gain / avg_loss
    return round(100 - (100 / (1 + rs)), 2)

def calculate_ma(closes: list, period: int) -> float:
    if len(closes) < period:
        return closes[-1] if closes else 0
    return round(sum(closes[-period:]) / period, 6)

def generate_trading_signal(symbol: str) -> dict:
    closes = get_binance_klines(symbol, "1h", 60)
    if not closes:
        return {"signal": "HOLD", "emoji": "🟡", "confidence": 0, "rsi": 50,
                "ma7": 0, "ma25": 0, "current_price": 0, "price": 0,
                "symbol": symbol, "time": datetime.datetime.now().strftime("%H:%M:%S"),
                "reasons": ["No data"]}
    current = closes[-1]
    rsi  = calculate_rsi(closes)
    ma7  = calculate_ma(closes, 7)
    ma25 = calculate_ma(closes, 25)
    ma99 = calculate_ma(closes, 99)
    signal = "HOLD"
    reasons = []
    confidence = 50
    if rsi < 30:
        signal = "BUY"; reasons.append(f"RSI oversold ({rsi})"); confidence += 20
    elif rsi > 70:
        signal = "SELL"; reasons.append(f"RSI overbought ({rsi})"); confidence += 20
    if ma7 > ma25:
        if signal != "SELL": signal = "BUY"
        reasons.append("MA7 > MA25 (bullish)"); confidence += 15
    elif ma7 < ma25:
        if signal != "BUY": signal = "SELL"
        reasons.append("MA7 < MA25 (bearish)"); confidence += 15
    if current > ma99:
        reasons.append("Above MA99 (uptrend)")
        if signal == "BUY": confidence += 10
    else:
        reasons.append("Below MA99 (downtrend)")
        if signal == "SELL": confidence += 10
    emoji = "🟢" if signal == "BUY" else "🔴" if signal == "SELL" else "🟡"
    return {"signal": signal, "emoji": emoji, "confidence": min(confidence, 95),
            "rsi": rsi, "ma7": ma7, "ma25": ma25,
            "current_price": current, "price": current,
            "symbol": symbol, "time": datetime.datetime.now().strftime("%H:%M:%S"),
            "reasons": reasons}

def get_trade_settings(user_id) -> dict:
    defaults = {"trade_pair": "BTCUSDT", "trade_amount": 10.0, "stop_loss": 2.0,
                "take_profit": 5.0, "binance_api_key": "", "binance_secret": ""}
    row = db_fetchone("SELECT trading_settings FROM accounts WHERE user_id=?", (str(user_id),))
    if row and row.get("trading_settings"):
        try:
            s = json.loads(row["trading_settings"])
            for k, v in defaults.items():
                if k not in s: s[k] = v
            return s
        except Exception:
            pass
    return defaults

def save_trade_settings(user_id, settings: dict):
    db_execute("UPDATE accounts SET trading_settings=? WHERE user_id=?",
               (json.dumps(settings), str(user_id)))

def log_trade(user_id, symbol, action, price, amount, reason=""):
    now = datetime.datetime.now().isoformat()
    try:
        db_execute("INSERT INTO trade_log (user_id,symbol,action,price,amount,reason,created_at) VALUES (?,?,?,?,?,?,?)",
                   (str(user_id), symbol, action, price, amount, reason, now))
    except Exception:
        pass

def get_trade_history(user_id, limit=10) -> list:
    try:
        return db_execute("SELECT * FROM trade_log WHERE user_id=? ORDER BY id DESC LIMIT ?",
                          (str(user_id), limit), fetch=True) or []
    except Exception:
        return []

def place_binance_order(api_key, secret, symbol, side, quantity) -> dict:
    try:
        import hmac as hmaclib
        timestamp = int(time.time() * 1000)
        params = f"symbol={symbol}&side={side}&type=MARKET&quantity={quantity}&timestamp={timestamp}"
        sig = hmaclib.new(secret.encode(), params.encode(), hashlib.sha256).hexdigest()
        url = f"https://api.binance.com/api/v3/order?{params}&signature={sig}"
        r = requests.post(url, headers={"X-MBX-APIKEY": api_key}, timeout=15)
        return r.json()
    except Exception as e:
        return {"error": str(e)}

async def auto_trade_loop(context, user_id: int, settings: dict):
    symbol  = settings.get("trade_pair", "BTCUSDT")
    amount  = settings.get("trade_amount", 10.0)
    api_key = settings.get("binance_api_key", "")
    secret  = settings.get("binance_secret", "")
    sl_pct  = settings.get("stop_loss", 2.0)
    tp_pct  = settings.get("take_profit", 5.0)
    last_signal = None
    entry_price = None
    await context.bot.send_message(user_id,
        f"🤖 *Auto Trading Bot Started!*\n\n📊 Pair: `{symbol}`\n💰 Amount: `${amount}`\n"
        f"🛑 Stop Loss: `{sl_pct}%` | ✅ Take Profit: `{tp_pct}%`\n\n_Checking every 5 minutes..._",
        parse_mode="Markdown")
    while True:
        try:
            sig = generate_trading_signal(symbol)
            d = get_binance_price(symbol)
            current = d.get("price", sig.get("current_price", 0))
            if entry_price and last_signal == "BUY" and current:
                chg = ((current - entry_price) / entry_price) * 100
                if chg <= -sl_pct:
                    await context.bot.send_message(user_id,
                        f"🛑 *STOP LOSS HIT!*\n📉 {symbol}: `${current:,.4f}`\nLoss: `{chg:.2f}%`",
                        parse_mode="Markdown")
                    if api_key and secret:
                        place_binance_order(api_key, secret, symbol, "SELL", round(amount/current, 6))
                    log_trade(user_id, symbol, "SELL(SL)", current, amount, "Stop loss")
                    entry_price = None; last_signal = None
                elif chg >= tp_pct:
                    await context.bot.send_message(user_id,
                        f"✅ *TAKE PROFIT HIT!*\n📈 {symbol}: `${current:,.4f}`\nProfit: `+{chg:.2f}%`",
                        parse_mode="Markdown")
                    if api_key and secret:
                        place_binance_order(api_key, secret, symbol, "SELL", round(amount/current, 6))
                    log_trade(user_id, symbol, "SELL(TP)", current, amount, "Take profit")
                    entry_price = None; last_signal = None
            if sig["signal"] != last_signal and sig["signal"] != "HOLD":
                action = sig["signal"]
                reason = ", ".join(sig["reasons"])
                msg = (f"{sig['emoji']} *{action} SIGNAL — {symbol}*\n\n"
                       f"💵 Price: `${current:,.4f}`\n📊 RSI: `{sig['rsi']}`\n"
                       f"🎯 Confidence: `{sig['confidence']}%`\n💡 _{reason}_\n\n")
                if api_key and secret:
                    qty = round(amount / current, 6)
                    res = place_binance_order(api_key, secret, symbol, action, qty)
                    if "orderId" in res:
                        msg += f"✅ Order placed! ID: `{res['orderId']}`"
                        if action == "BUY": entry_price = current
                    else:
                        msg += f"⚠️ Order failed: `{res.get('msg', 'Error')}`"
                else:
                    msg += "_Signal only — connect Binance for real trading_"
                    if action == "BUY": entry_price = current
                log_trade(user_id, symbol, action, current, amount, reason)
                await context.bot.send_message(user_id, msg, parse_mode="Markdown")
                last_signal = sig["signal"]
        except asyncio.CancelledError:
            await context.bot.send_message(user_id, "🛑 *Auto Trading Bot stopped.*", parse_mode="Markdown")
            return
        except Exception as e:
            logger.error(f"Auto trade loop error: {e}")
        await asyncio.sleep(300)

async def handle_trading(update: Update, context: ContextTypes.DEFAULT_TYPE, text: str) -> bool:
    user_id  = update.effective_user.id
    settings = get_trade_settings(user_id)

    if text == "🤖 Trading Bot":
        await update.message.reply_text(
            "🤖 *CineMagic Trading Bot*\n\n"
            "Auto-trade Crypto on Binance with AI signals!\n\n"
            "📌 *Features:*\n• Live market prices\n• AI signals (RSI + MA)\n"
            "• Auto trading on Binance\n• Stop Loss & Take Profit\n• Trade history\n\n"
            "Choose an option 👇", parse_mode="Markdown", reply_markup=get_trading_keyboard())
        return True

    if text == "📊 Market Prices":
        await cmd_market_prices(update, context)
        return True

    if text == "📈 Trading Signals":
        await cmd_trading_signals(update, context)
        return True

    if text == "🤖 Auto Trade":
        uid = str(user_id)
        if uid in _auto_trade_tasks and not _auto_trade_tasks[uid].done():
            await update.message.reply_text("⚠️ Already running! Tap *📉 Stop Bot* first.", parse_mode="Markdown")
        else:
            task = asyncio.create_task(auto_trade_loop(context, user_id, settings))
            _auto_trade_tasks[uid] = task
        return True

    if text == "📉 Stop Bot":
        uid = str(user_id)
        if uid in _auto_trade_tasks and not _auto_trade_tasks[uid].done():
            _auto_trade_tasks[uid].cancel()
            del _auto_trade_tasks[uid]
            await update.message.reply_text("🛑 *Bot stopped!*", parse_mode="Markdown")
        else:
            await update.message.reply_text("ℹ️ No bot is running.")
        return True

    if text == "📋 My Trades":
        trades = get_trade_history(user_id)
        if not trades:
            await update.message.reply_text("📋 No trades yet!")
            return True
        msg = "📋 *Recent Trades*\n\n"
        for t in trades:
            e = "🟢" if "BUY" in t["action"] else "🔴"
            msg += f"{e} *{t['action']}* `{t['symbol']}` — `${t['price']:,.4f}`\n📅 {t['created_at'][:16]}\n\n"
        await update.message.reply_text(msg[:4000], parse_mode="Markdown")
        return True

    if text == "💰 Portfolio":
        d = get_binance_price(settings.get("trade_pair","BTCUSDT"))
        trades = get_trade_history(user_id, 50)
        buys  = sum(t["amount"] for t in trades if "BUY" in t["action"])
        sells = sum(t["amount"] for t in trades if "SELL" in t["action"])
        await update.message.reply_text(
            f"💰 *Portfolio*\n\n📊 Pair: `{settings.get('trade_pair','BTCUSDT')}`\n"
            f"💵 Price: `${d.get('price',0):,.4f}` ({d.get('change',0):+.2f}%)\n\n"
            f"🟢 Bought: `${buys:.2f}` | 🔴 Sold: `${sells:.2f}`\n"
            f"💹 Net P/L: `${sells-buys:.2f}`",
            parse_mode="Markdown")
        return True

    if text in ("🔑 Connect Broker", "🔑 Connect Binance"):
        await cmd_broker_connect(update, context)
        return True

    if text == "🏦 My Brokers":
        await cmd_my_brokers(update, context)
        return True

    if text == "📱 Broker Accounts":
        await cmd_my_brokers(update, context)
        return True

    if text == "⚙️ Trading Settings":
        buttons = InlineKeyboardMarkup([
            [InlineKeyboardButton("📊 Change Pair", callback_data="trade:pair"),
             InlineKeyboardButton("💰 Set Amount", callback_data="trade:amount")],
            [InlineKeyboardButton("🛑 Stop Loss", callback_data="trade:stoploss"),
             InlineKeyboardButton("✅ Take Profit", callback_data="trade:takeprofit")],
        ])
        await update.message.reply_text(
            f"⚙️ *Trading Settings*\n\n"
            f"📊 Pair: `{settings.get('trade_pair','BTCUSDT')}`\n"
            f"💰 Amount: `${settings.get('trade_amount',10)}`\n"
            f"🛑 Stop Loss: `{settings.get('stop_loss',2)}%`\n"
            f"✅ Take Profit: `{settings.get('take_profit',5)}%`\n"
            f"🔑 Binance: `{'✅ Connected' if settings.get('binance_api_key') else '❌ Not connected'}`",
            parse_mode="Markdown", reply_markup=buttons)
        return True

    trade_step = context.user_data.get("trade_step")
    if trade_step == "binance_api":
        context.user_data["_binance_api_key"] = text.strip()
        context.user_data["trade_step"] = "binance_secret"
        await update.message.reply_text("✅ API Key saved! Now enter your *Secret Key*:", parse_mode="Markdown")
        return True
    if trade_step == "binance_secret":
        api_key = context.user_data.pop("_binance_api_key", "")
        settings["binance_api_key"] = api_key
        settings["binance_secret"]  = text.strip()
        context.user_data.pop("trade_step", None)
        save_trade_settings(user_id, settings)
        await update.message.reply_text("✅ *Binance Connected!* You can now use Auto Trading 🚀",
                                        parse_mode="Markdown", reply_markup=get_trading_keyboard())
        return True
    if trade_step == "set_amount":
        try:
            settings["trade_amount"] = float(text.strip().replace("$",""))
            save_trade_settings(user_id, settings)
            context.user_data.pop("trade_step", None)
            await update.message.reply_text(f"✅ Amount set to `${settings['trade_amount']}`", parse_mode="Markdown")
        except ValueError:
            await update.message.reply_text("⚠️ Enter a number like `50`")
        return True
    if trade_step == "set_stoploss":
        try:
            settings["stop_loss"] = float(text.strip().replace("%",""))
            save_trade_settings(user_id, settings)
            context.user_data.pop("trade_step", None)
            await update.message.reply_text(f"✅ Stop Loss set to `{settings['stop_loss']}%`", parse_mode="Markdown")
        except ValueError:
            await update.message.reply_text("⚠️ Enter a number like `2`")
        return True
    if trade_step == "set_takeprofit":
        try:
            settings["take_profit"] = float(text.strip().replace("%",""))
            save_trade_settings(user_id, settings)
            context.user_data.pop("trade_step", None)
            await update.message.reply_text(f"✅ Take Profit set to `{settings['take_profit']}%`", parse_mode="Markdown")
        except ValueError:
            await update.message.reply_text("⚠️ Enter a number like `5`")
        return True
    return False


