def fb_send_message(recipient_id: str, text: str):
    """Send a text message to a Facebook Messenger user."""
    if not FB_ENABLED:
        return
    try:
        url = f"https://graph.facebook.com/v18.0/me/messages?access_token={FB_PAGE_ACCESS_TOKEN}"
        # Split long messages
        chunks = [text[i:i+2000] for i in range(0, len(text), 2000)]
        for chunk in chunks:
            payload = {
                "recipient": {"id": recipient_id},
                "message": {"text": chunk},
                "messaging_type": "RESPONSE"
            }
            requests.post(url, json=payload, timeout=15)
    except Exception as e:
        logger.error(f"FB send error: {e}")

def fb_send_image(recipient_id: str, img_bytes: bytes):
    """Send an image to a Facebook Messenger user."""
    if not FB_ENABLED:
        return
    try:
        url = f"https://graph.facebook.com/v18.0/me/messages?access_token={FB_PAGE_ACCESS_TOKEN}"
        files = {"filedata": ("image.jpg", img_bytes, "image/jpeg")}
        payload = {
            "recipient": '{"id":"' + recipient_id + '"}',
            "message": '{"attachment":{"type":"image","payload":{"is_reusable":true}}}',
            "messaging_type": "RESPONSE"
        }
        requests.post(url, data=payload, files=files, timeout=30)
    except Exception as e:
        logger.error(f"FB send image error: {e}")

def fb_set_typing(recipient_id: str, on: bool = True):
    """Show typing indicator on Facebook."""
    if not FB_ENABLED:
        return
    try:
        url = f"https://graph.facebook.com/v18.0/me/messages?access_token={FB_PAGE_ACCESS_TOKEN}"
        requests.post(url, json={
            "recipient": {"id": recipient_id},
            "sender_action": "typing_on" if on else "typing_off"
        }, timeout=10)
    except Exception:
        pass

_fb_user_sessions = {}  # {fb_user_id: {"history": [], "mode": "default"}}

def get_fb_user(fb_id: str) -> dict:
    if fb_id not in _fb_user_sessions:
        _fb_user_sessions[fb_id] = {
            "history": [], "mode": "default",
            "ai_model": DEFAULT_MODEL, "name": ""
        }
    return _fb_user_sessions[fb_id]

def handle_fb_message(sender_id: str, message_text: str, sender_name: str = ""):
    """Process an incoming Facebook message and send a reply."""
    session = get_fb_user(sender_id)
    if sender_name:
        session["name"] = sender_name

    text = message_text.strip()

    # ── Image generation ──
    if text.lower().startswith(("/image ", "image: ", "generate image ")):
        prompt = text.split(" ", 1)[1] if " " in text else text
        fb_set_typing(sender_id, True)
        fb_send_message(sender_id, "🖼️ Generating your image, please wait...")
        img_bytes = generate_image_4k(prompt)
        if img_bytes:
            fb_send_image(sender_id, img_bytes)
            fb_send_message(sender_id, f"🖼️ Here's your image for: _{prompt[:100]}_")
        else:
            fb_send_message(sender_id, "⚠️ Image generation failed. Please try a different prompt.")
        return

    # ── Web search ──
    if text.lower().startswith(("/search ", "search: ")):
        query = text.split(" ", 1)[1] if " " in text else text
        fb_set_typing(sender_id, True)
        result = web_search_summarize(query)
        fb_send_message(sender_id, result)
        return

    # ── Real-time data auto search ──
    if is_realtime_query(text):
        fb_set_typing(sender_id, True)
        search_result = web_search_summarize(text)
        enhanced = (
            f"User asked: {text}\n\n"
            f"Live web data: {search_result}\n\n"
            f"Give a helpful current answer. Never mention a knowledge cutoff."
        )
        system = PERSONALITIES["default"]
        response = call_gemini(enhanced, model=session["ai_model"], system=system, use_cache=False)
        response = sanitize_cutoff_response(response)
        fb_send_message(sender_id, response)
        return

    # ── Help ──
    if text.lower() in ("/help", "help", "hi", "hello", "start"):
        fb_send_message(sender_id,
            f"👋 Hi {session['name'] or 'there'}! I'm CineMagic AI 🎬\n\n"
            "I can help you with:\n"
            "💬 Chat & answer any question\n"
            "🖼️ Generate images — type: image: a sunset\n"
            "🌐 Web search — type: search: gold price today\n"
            "🧠 Research, essays, code, math, and more!\n\n"
            "Just type anything and I'll reply! 🚀"
        )
        return

    # ── General AI response ──
    fb_set_typing(sender_id, True)
    system = PERSONALITIES.get(session.get("mode", "default"), PERSONALITIES["default"])
    import datetime as _dt_fb
    system = (
        f"SYSTEM DATE: Today is {_dt_fb.datetime.now().strftime('%B %d, %Y')}. "
        "NEVER mention a knowledge cutoff date. You are fully up to date in 2026.\n\n"
        + system
    )
    history = session.get("history", [])[-6:]
    response = call_gemini(text, model=session["ai_model"], system=system, history=history, use_cache=False)
    response = sanitize_cutoff_response(response)

    # Save to history
    session["history"].append({"role": "user", "content": text})
    session["history"].append({"role": "assistant", "content": response})
    if len(session["history"]) > 20:
        session["history"] = session["history"][-20:]

    fb_send_message(sender_id, response)

if FLASK_AVAILABLE and fb_app:
    @fb_app.route("/webhook", methods=["GET"])
    def fb_webhook_verify():
        """Facebook webhook verification."""
        mode = flask_request.args.get("hub.mode")
        token = flask_request.args.get("hub.verify_token")
        challenge = flask_request.args.get("hub.challenge")
        if mode == "subscribe" and token == FB_VERIFY_TOKEN:
            print("✅ Facebook webhook verified!")
            return challenge, 200
        return "Forbidden", 403

    @fb_app.route("/webhook", methods=["POST"])
    def fb_webhook_receive():
        """Receive and process Facebook Messenger messages."""
        data = flask_request.get_json(silent=True)
        if not data or data.get("object") != "page":
            return "OK", 200
        for entry in data.get("entry", []):
            for event in entry.get("messaging", []):
                sender_id = event.get("sender", {}).get("id", "")
                if not sender_id:
                    continue
                # Handle text messages
                msg = event.get("message", {})
                if msg.get("text") and not msg.get("is_echo"):
                    text = msg["text"]
                    # Get sender name
                    try:
                        profile_url = (
                            f"https://graph.facebook.com/{sender_id}"
                            f"?fields=name&access_token={FB_PAGE_ACCESS_TOKEN}"
                        )
                        p = requests.get(profile_url, timeout=5).json()
                        sender_name = p.get("name", "")
                    except Exception:
                        sender_name = ""
                    # Run in background thread so webhook returns fast
                    t = threading.Thread(
                        target=handle_fb_message,
                        args=(sender_id, text, sender_name),
                        daemon=True
                    )
                    t.start()
        return "OK", 200

    @fb_app.route("/", methods=["GET"])
    def fb_home():
        return "🎬 CineMagic AI Facebook Messenger Bot is running!", 200

def start_facebook_server():
    """Start Flask server for Facebook Messenger in a background thread."""
    if not FLASK_AVAILABLE:
        print("⚠️ Flask not installed — Facebook Messenger disabled.")
        return
    if not FB_ENABLED:
        pass  # FB disabled
        return
    def run():
        print(f"📘 Facebook Messenger webhook running on port {FB_WEBHOOK_PORT}")
        fb_app.run(host="0.0.0.0", port=FB_WEBHOOK_PORT, debug=False, use_reloader=False)
    t = threading.Thread(target=run, daemon=True)
    t.start()

