def get_user_brokers(user_id):
    uid = str(user_id)
    db = load_db()
    return db.get(uid, {}).get("brokers", {})

def save_user_broker(user_id, broker_id, data):
    uid = str(user_id)
    db = load_db()
    if uid not in db:
        db[uid] = {}
    if "brokers" not in db[uid]:
        db[uid]["brokers"] = {}
    db[uid]["brokers"][broker_id] = data
    save_db(db)

def get_live_price(symbol):
    """Get live price from CoinGecko for crypto or exchangerate for forex"""
    try:
        symbol = symbol.replace("/", "").replace("-", "").upper()
        # Try crypto first
        crypto_map = {
            "BTCUSDT": "bitcoin", "ETHUSDT": "ethereum", "BNBUSDT": "binancecoin",
            "SOLUSDT": "solana", "XRPUSDT": "ripple", "ADAUSDT": "cardano",
            "DOGEUSDT": "dogecoin", "DOTUSDT": "polkadot", "MATICUSDT": "matic-network",
        }
        if symbol in crypto_map:
            r = requests.get(f"https://api.coingecko.com/api/v3/simple/price?ids={crypto_map[symbol]}&vs_currencies=usd", timeout=8)
            if r.ok:
                data = r.json()
                price = list(data.values())[0]["usd"]
                return {"symbol": symbol, "price": price, "source": "CoinGecko"}
        # Try forex via exchangerate
        if len(symbol) == 6:
            base = symbol[:3]
            quote = symbol[3:]
            r = requests.get(f"https://api.exchangerate-api.com/v4/latest/{base}", timeout=8)
            if r.ok:
                data = r.json()
                price = data.get("rates", {}).get(quote)
                if price:
                    return {"symbol": f"{base}/{quote}", "price": price, "source": "ExchangeRate"}
        # Fallback commodities
        commodities_map = {"XAUUSD": "gold", "XAGUSD": "silver"}
        if symbol in commodities_map:
            r = requests.get(f"https://api.coingecko.com/api/v3/simple/price?ids={commodities_map[symbol]}&vs_currencies=usd", timeout=8)
            if r.ok:
                data = r.json()
                price = list(data.values())[0]["usd"]
                return {"symbol": symbol, "price": price, "source": "CoinGecko"}
    except Exception:
        pass
    return None

def calculate_signal(symbol):
    """Generate AI-based trading signal"""
    try:
        r = requests.get(
            f"https://api.coingecko.com/api/v3/coins/{symbol.lower()}/market_chart?vs_currency=usd&days=1&interval=hourly",
            timeout=10)
        if r.ok:
            prices = [p[1] for p in r.json().get("prices", [])]
            if len(prices) >= 5:
                recent = prices[-1]
                avg = sum(prices[-5:]) / 5
                trend = "📈 BUY" if recent > avg else "📉 SELL"
                change = ((recent - prices[0]) / prices[0]) * 100
                return {"signal": trend, "change": round(change, 2), "price": recent}
    except Exception:
        pass
    return {"signal": "⏸️ HOLD", "change": 0.0, "price": 0.0}

