async def cmd_market_prices(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Show live market prices across all asset classes"""
    await update.message.reply_text("⏳ Fetching live prices...", parse_mode="Markdown")
    msg = "📊 *Live Market Prices*\n\n"

    # Crypto
    msg += "₿ *Crypto*\n"
    crypto_ids = "bitcoin,ethereum,binancecoin,solana,ripple,cardano,dogecoin"
    try:
        r = await asyncio.get_running_loop().run_in_executor(None, lambda: requests.get(f"https://api.coingecko.com/api/v3/simple/price?ids={crypto_ids}&vs_currencies=usd&include_24hr_change=true", timeout=10))
        if r.ok:
            data = r.json()
            names = {"bitcoin":"BTC","ethereum":"ETH","binancecoin":"BNB","solana":"SOL","ripple":"XRP","cardano":"ADA","dogecoin":"DOGE"}
            for cid, cname in names.items():
                if cid in data:
                    price = data[cid]["usd"]
                    change = data[cid].get("usd_24h_change", 0)
                    arrow = "🟢" if change >= 0 else "🔴"
                    msg += f"  {arrow} {cname}: ${price:,.4f} ({change:+.2f}%)\n"
    except Exception:
        msg += "  ⚠️ Could not fetch crypto prices\n"

    # Forex
    msg += "\n💱 *Forex*\n"
    try:
        r = await asyncio.get_running_loop().run_in_executor(None, lambda: requests.get("https://api.exchangerate-api.com/v4/latest/USD", timeout=8))
        if r.ok:
            rates = r.json().get("rates", {})
            pairs = [("EUR", "EUR/USD"), ("GBP", "GBP/USD"), ("JPY", "USD/JPY"),
                     ("AUD", "AUD/USD"), ("CAD", "USD/CAD"), ("CHF", "USD/CHF")]
            for curr, label in pairs:
                rate = rates.get(curr)
                if rate:
                    display = 1/rate if curr not in ["JPY","CAD","CHF"] else rate
                    msg += f"  📌 {label}: {display:.5f}\n"
    except Exception:
        msg += "  ⚠️ Could not fetch forex rates\n"

    # Gold
    msg += "\n🥇 *Commodities*\n"
    try:
        r = await asyncio.get_running_loop().run_in_executor(None, lambda: requests.get("https://api.coingecko.com/api/v3/simple/price?ids=tether-gold&vs_currencies=usd", timeout=8))
        if r.ok:
            gold = r.json().get("tether-gold", {}).get("usd", 0)
            msg += f"  🥇 GOLD: ${gold:,.2f}/oz\n"
    except Exception:
        msg += "  🥇 GOLD: Market closed\n"

    msg += "\n🕒 _Updated just now — prices may vary by broker_"
    await update.message.reply_text(msg, parse_mode="Markdown")

