def make_at_call(to_phone: str, message: str) -> dict:
    try:
        headers = {
            "apiKey": AT_API_KEY,
            "Content-Type": "application/x-www-form-urlencoded",
            "Accept": "application/json"
        }
        data = urllib.parse.urlencode({
            "username": AT_USERNAME,
            "to": to_phone,
            "from": "CineMagic"
        })
        req = requests.post(AT_VOICE_URL, data=data, headers=headers, timeout=15)
        r = req.json()
        entries = r.get("entries", [])
        if entries and entries[0].get("status") in ("Queued", "queued"):
            return {"success": True, "sid": entries[0].get("sessionId", "")}
        return {"success": False, "message": r.get("errorMessage", "Call failed")}
    except Exception as e:
        return {"success": False, "message": str(e)}

def send_sms_message(to_phone: str, body: str) -> dict:
    try:
        headers = {
            "apiKey": AT_API_KEY,
            "Content-Type": "application/x-www-form-urlencoded",
            "Accept": "application/json"
        }
        data = urllib.parse.urlencode({
            "username": AT_USERNAME,
            "to": to_phone,
            "message": body
        })
        req = requests.post(AT_SMS_URL, data=data, headers=headers, timeout=15)
        r = req.json()
        recipients = r.get("SMSMessageData", {}).get("Recipients", [])
        if recipients and recipients[0].get("status") in ("Success", "sent"):
            return {"success": True, "sid": recipients[0].get("messageId", "")}
        msg = r.get("SMSMessageData", {}).get("Message", "SMS failed")
        return {"success": False, "message": msg}
    except Exception as e:
        return {"success": False, "message": str(e)}

def send_gmail(to_email: str, subject: str, body: str) -> dict:
    """Send email via Gmail SMTP with SSL and STARTTLS fallback."""
    try:
        msg = MIMEMultipart("alternative")
        msg["Subject"] = subject
        msg["From"]    = f"{EMAIL_SENDER_NAME} <{EMAIL_SENDER}>"
        msg["To"]      = to_email
        msg.attach(MIMEText(body, "plain"))

        # Try SSL first (port 465)
        try:
            with smtplib.SMTP_SSL("smtp.gmail.com", 465, timeout=20) as server:
                server.login(EMAIL_SENDER, EMAIL_PASSWORD)
                server.sendmail(EMAIL_SENDER, to_email, msg.as_string())
            return {"success": True}
        except smtplib.SMTPAuthenticationError:
            return {"success": False, "message": "Gmail authentication failed. App password may be expired or incorrect."}
        except Exception:
            pass

        # Fallback: STARTTLS (port 587)
        with smtplib.SMTP("smtp.gmail.com", 587, timeout=20) as server:
            server.ehlo()
            server.starttls()
            server.ehlo()
            server.login(EMAIL_SENDER, EMAIL_PASSWORD)
            server.sendmail(EMAIL_SENDER, to_email, msg.as_string())
        return {"success": True}

    except smtplib.SMTPAuthenticationError:
        return {"success": False, "message": "Gmail authentication failed. Check your app password at myaccount.google.com → Security → App passwords."}
    except smtplib.SMTPRecipientsRefused:
        return {"success": False, "message": f"Invalid email address: {to_email}"}
    except Exception as e:
        return {"success": False, "message": str(e)}

