def fetch_crypto_price(symbol: str) -> dict:
    try:
        url = f"https://api.coingecko.com/api/v3/simple/price?ids={symbol}&vs_currencies=usd,ghs&include_24hr_change=true"
        r = requests.get(url, timeout=10).json()
        if symbol in r:
            return {"success": True, "usd": r[symbol].get("usd", 0),
                    "ghs": r[symbol].get("ghs", 0),
                    "change": r[symbol].get("usd_24h_change", 0)}
        return {"success": False}
    except Exception:
        return {"success": False}

def fetch_forex_rate(base: str, target: str) -> dict:
    try:
        url = f"https://api.exchangerate-api.com/v4/latest/{base}"
        r = requests.get(url, timeout=10).json()
        rate = r.get("rates", {}).get(target, 0)
        return {"success": True, "rate": rate} if rate else {"success": False}
    except Exception:
        return {"success": False}

def fetch_fear_greed() -> dict:
    try:
        r = requests.get("https://api.alternative.me/fng/?limit=1", timeout=10).json()
        data = r.get("data", [{}])[0]
        return {"success": True, "value": data.get("value", "?"),
                "classification": data.get("value_classification", "?")}
    except Exception:
        return {"success": False}

