def match_get_profile(user_id: str) -> dict:
    conn = sqlite3.connect(SQLITE_DB)
    c = conn.cursor()
    c.execute("SELECT * FROM match_profiles WHERE user_id=?", (user_id,))
    row = c.fetchone()
    conn.close()
    if not row:
        return {}
    cols = ["id","user_id","name","age","gender","looking_for","bio","location","photo_file_id","interests","is_active","created_at"]
    return dict(zip(cols, row))


def match_save_profile(user_id, name, age, gender, looking_for, bio, location, photo_file_id, interests):
    import datetime as _dt
    db_execute(
        """INSERT INTO match_profiles (user_id,name,age,gender,looking_for,bio,location,photo_file_id,interests,is_active,created_at)
           VALUES (?,?,?,?,?,?,?,?,?,1,?)
           ON CONFLICT(user_id) DO UPDATE SET
           name=excluded.name, age=excluded.age, gender=excluded.gender,
           looking_for=excluded.looking_for, bio=excluded.bio, location=excluded.location,
           photo_file_id=excluded.photo_file_id, interests=excluded.interests, is_active=1""",
        (user_id, name, age, gender, looking_for, bio, location, photo_file_id, interests,
         _dt.datetime.now().isoformat())
    )


def match_get_candidates(user_id: str, gender: str, looking_for: str) -> list:
    """Get profiles user hasn't liked yet."""
    conn = sqlite3.connect(SQLITE_DB)
    c = conn.cursor()
    # Match opposite or any gender based on preference
    if looking_for == "friendship":
        c.execute("""SELECT * FROM match_profiles
                     WHERE user_id != ? AND is_active=1
                     AND user_id NOT IN (SELECT liked_id FROM match_likes WHERE liker_id=?)
                     ORDER BY RANDOM() LIMIT 1""", (user_id, user_id))
    else:
        target_gender = "female" if gender == "male" else "male"
        c.execute("""SELECT * FROM match_profiles
                     WHERE user_id != ? AND is_active=1 AND gender=?
                     AND user_id NOT IN (SELECT liked_id FROM match_likes WHERE liker_id=?)
                     ORDER BY RANDOM() LIMIT 1""", (user_id, target_gender, user_id))
    row = c.fetchone()
    conn.close()
    if not row:
        return []
    cols = ["id","user_id","name","age","gender","looking_for","bio","location","photo_file_id","interests","is_active","created_at"]
    return [dict(zip(cols, row))]


def match_like(liker_id: str, liked_id: str) -> bool:
    """Record a like. Returns True if it's a mutual match."""
    import datetime as _dt
    try:
        db_execute("INSERT OR IGNORE INTO match_likes (liker_id,liked_id,created_at) VALUES (?,?,?)",
                   (liker_id, liked_id, _dt.datetime.now().isoformat()))
    except Exception:
        pass
    # Check if liked_id also liked liker_id
    conn = sqlite3.connect(SQLITE_DB)
    c = conn.cursor()
    c.execute("SELECT 1 FROM match_likes WHERE liker_id=? AND liked_id=?", (liked_id, liker_id))
    mutual = c.fetchone() is not None
    if mutual:
        u1, u2 = sorted([liker_id, liked_id])
        c.execute("INSERT OR IGNORE INTO match_pairs (user1_id,user2_id,matched_at) VALUES (?,?,?)",
                  (u1, u2, _dt.datetime.now().isoformat()))
        conn.commit()
    conn.close()
    return mutual


def match_get_matches(user_id: str) -> list:
    conn = sqlite3.connect(SQLITE_DB)
    c = conn.cursor()
    c.execute("""SELECT * FROM match_profiles WHERE user_id IN (
                    SELECT user2_id FROM match_pairs WHERE user1_id=?
                    UNION
                    SELECT user1_id FROM match_pairs WHERE user2_id=?
                 )""", (user_id, user_id))
    rows = c.fetchall()
    conn.close()
    cols = ["id","user_id","name","age","gender","looking_for","bio","location","photo_file_id","interests","is_active","created_at"]
    return [dict(zip(cols, r)) for r in rows]


def match_format_profile(p: dict) -> str:
    interests = p.get("interests", "") or ""
    gender_icon = "\u2642\ufe0f" if p.get("gender") == "male" else "\u2640\ufe0f"
    look = "\U0001f49e Dating" if p.get("looking_for") == "dating" else "\U0001f91d Friendship"
    return (
        f"\U0001f464 *{p.get('name','?')}*, {p.get('age','?')} yrs\n"
        f"{gender_icon} {p.get('gender','?').title()} \u2022 {look}\n"
        f"\U0001f4cd {p.get('location','Unknown')}\n"
        f"\U0001f4ac {p.get('bio','No bio yet')}\n"
        f"\U0001f3af Interests: {interests or 'Not specified'}"
    )

# ── Match Setup Conversation States ──
MATCH_NAME, MATCH_AGE, MATCH_GENDER, MATCH_LOOKING, MATCH_BIO, MATCH_LOCATION, MATCH_INTERESTS, MATCH_PHOTO = range(200, 208)
match_setup_data = {}


async def cmd_match(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Start matchmaking — /match"""
    user_id = str(update.effective_user.id)
    profile = match_get_profile(user_id)
    kb = InlineKeyboardMarkup([
        [InlineKeyboardButton("💝 Create/Edit Profile", callback_data="match_setup")],
        [InlineKeyboardButton("🔍 Browse Profiles", callback_data="match_browse")],
        [InlineKeyboardButton("💞 My Matches", callback_data="match_mymatches")],
        [InlineKeyboardButton("👤 My Profile", callback_data="match_myprofile")],
        [InlineKeyboardButton("⏸ Pause Profile", callback_data="match_pause")],
    ])
    status = "✅ Profile Active" if profile.get("is_active") else "❌ No Profile Yet"
    await update.message.reply_text(
        "\U0001f498 *Moveroom Match*\n\n"
        "Find friends & partners in our community!\n\n"
        f"Status: {status}\n\n"
        "What would you like to do?",
        reply_markup=kb, parse_mode="Markdown"
    )


async def handle_match_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    query = update.callback_query
    await query.answer()
    user_id = str(query.from_user.id)
    data = query.data

    if data == "match_setup":
        match_setup_data[user_id] = {}
        await query.message.reply_text(
            "\U0001f49d *Let's set up your profile!*\n\nWhat is your name?",
            parse_mode="Markdown"
        )
        context.user_data["match_state"] = MATCH_NAME

    elif data == "match_browse":
        profile = match_get_profile(user_id)
        if not profile:
            await query.message.reply_text("❌ Please create your profile first! Use /match → Create Profile")
            return
        candidates = match_get_candidates(user_id, profile.get("gender",""), profile.get("looking_for","friendship"))
        if not candidates:
            await query.message.reply_text("😔 No more profiles to browse right now. Check back later!")
            return
        p = candidates[0]
        kb = InlineKeyboardMarkup([
            [InlineKeyboardButton("❤️ Like", callback_data=f"match_like_{p['user_id']}"),
             InlineKeyboardButton("👎 Skip", callback_data=f"match_skip_{p['user_id']}")],
            [InlineKeyboardButton("🔍 Browse More", callback_data="match_browse")]
        ])
        text = match_format_profile(p)
        if p.get("photo_file_id"):
            await query.message.reply_photo(photo=p["photo_file_id"], caption=text, parse_mode="Markdown", reply_markup=kb)
        else:
            await query.message.reply_text(text, parse_mode="Markdown", reply_markup=kb)

    elif data.startswith("match_like_"):
        liked_id = data.replace("match_like_", "")
        is_match = match_like(user_id, liked_id)
        if is_match:
            liked_profile = match_get_profile(liked_id)
            my_profile = match_get_profile(user_id)
            await query.message.reply_text(
                "\U0001f389 *It's a Match!*\n\n"
                f"You and *{liked_profile.get('name','?')}* liked each other!\n\n"
                "You can now message each other. Use /mymatch to see all matches.",
                parse_mode="Markdown"
            )
            # Notify the other person
            try:
                await context.bot.send_message(
                    chat_id=int(liked_id),
                    text=f"\U0001f389 *It's a Match!*\n\n*{my_profile.get('name','?')}* liked you back!\n\nUse /mymatch to connect!",
                    parse_mode="Markdown"
                )
            except Exception:
                pass
        else:
            await query.message.reply_text("❤️ Liked! If they like you back, it's a match!")

    elif data.startswith("match_skip_"):
        liked_id = data.replace("match_skip_", "")
        db_execute("INSERT OR IGNORE INTO match_likes (liker_id,liked_id,created_at) VALUES (?,?,?)",
                   (user_id, f"skip_{liked_id}", ""))
        await query.message.reply_text("👎 Skipped! Use /match → Browse to see more.")

    elif data == "match_mymatches":
        matches = match_get_matches(user_id)
        if not matches:
            await query.message.reply_text("💔 No matches yet. Keep browsing!")
            return
        text = "\U0001f49e *Your Matches*\n\n"
        for p in matches:
            text += f"\u2022 *{p['name']}*, {p['age']} \u2014 {p['location']}\n"
        text += "\nTo chat, just message them on Telegram!"
        await query.message.reply_text(text, parse_mode="Markdown")

    elif data == "match_myprofile":
        profile = match_get_profile(user_id)
        if not profile:
            await query.message.reply_text("❌ No profile yet. Use /match → Create Profile")
            return
        text = "\U0001f464 *Your Profile*\n\n" + match_format_profile(profile)
        if profile.get("photo_file_id"):
            await query.message.reply_photo(photo=profile["photo_file_id"], caption=text, parse_mode="Markdown")
        else:
            await query.message.reply_text(text, parse_mode="Markdown")

    elif data == "match_pause":
        db_execute("UPDATE match_profiles SET is_active=0 WHERE user_id=?", (user_id,))
        await query.message.reply_text("⏸ Profile paused. Use /match to reactivate.")


async def handle_match_setup(update: Update, context: ContextTypes.DEFAULT_TYPE) -> bool:
    """Handle match profile setup conversation. Returns True if handled."""
    user_id = str(update.effective_user.id)
    state = context.user_data.get("match_state")
    if state is None:
        return False
    text = update.message.text or ""

    if state == MATCH_NAME:
        match_setup_data[user_id]["name"] = text
        kb = InlineKeyboardMarkup([
            [InlineKeyboardButton("♂️ Male", callback_data="msetup_gender_male"),
             InlineKeyboardButton("♀️ Female", callback_data="msetup_gender_female")],
            [InlineKeyboardButton("🌈 Other", callback_data="msetup_gender_other")]
        ])
        await update.message.reply_text(f"Nice, *{text}*! \U0001f44b\n\nWhat's your *age*?", parse_mode="Markdown")
        context.user_data["match_state"] = MATCH_AGE

    elif state == MATCH_AGE:
        if not text.isdigit() or not (13 <= int(text) <= 100):
            await update.message.reply_text("Please enter a valid age (13-100):")
            return True
        match_setup_data[user_id]["age"] = int(text)
        kb = InlineKeyboardMarkup([
            [InlineKeyboardButton("♂️ Male", callback_data="msetup_gender_male"),
             InlineKeyboardButton("♀️ Female", callback_data="msetup_gender_female")],
            [InlineKeyboardButton("🌈 Other", callback_data="msetup_gender_other")]
        ])
        await update.message.reply_text("What's your *gender*?", parse_mode="Markdown", reply_markup=kb)
        context.user_data["match_state"] = MATCH_GENDER

    elif state == MATCH_BIO:
        match_setup_data[user_id]["bio"] = text
        await update.message.reply_text("📍 What's your *city/location*? (e.g. Accra, London)", parse_mode="Markdown")
        context.user_data["match_state"] = MATCH_LOCATION

    elif state == MATCH_LOCATION:
        match_setup_data[user_id]["location"] = text
        await update.message.reply_text("🎯 What are your *interests*? (e.g. music, movies, football, cooking)", parse_mode="Markdown")
        context.user_data["match_state"] = MATCH_INTERESTS

    elif state == MATCH_INTERESTS:
        match_setup_data[user_id]["interests"] = text
        await update.message.reply_text("📸 Send your *profile photo* (or type /skip to skip):", parse_mode="Markdown")
        context.user_data["match_state"] = MATCH_PHOTO

    elif state == MATCH_PHOTO:
        photo_id = ""
        if update.message.photo:
            photo_id = update.message.photo[-1].file_id
        d = match_setup_data.get(user_id, {})
        match_save_profile(
            user_id, d.get("name",""), d.get("age",0), d.get("gender",""),
            d.get("looking_for","friendship"), d.get("bio",""), d.get("location",""),
            photo_id, d.get("interests","")
        )
        context.user_data.pop("match_state", None)
        match_setup_data.pop(user_id, None)
        await update.message.reply_text(
            "\u2705 *Profile created!* \U0001f389\n\nYou're now visible to others.\nUse /match to browse profiles!",
            parse_mode="Markdown"
        )

    return True


async def handle_msetup_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    query = update.callback_query
    await query.answer()
    user_id = str(query.from_user.id)
    data = query.data

    if data.startswith("msetup_gender_"):
        gender = data.replace("msetup_gender_", "")
        match_setup_data.setdefault(user_id, {})["gender"] = gender
        kb = InlineKeyboardMarkup([
            [InlineKeyboardButton("💞 Dating", callback_data="msetup_looking_dating"),
             InlineKeyboardButton("🤝 Friendship", callback_data="msetup_looking_friendship")],
            [InlineKeyboardButton("💫 Both", callback_data="msetup_looking_both")]
        ])
        await query.message.reply_text("What are you looking for?", reply_markup=kb)
        context.user_data["match_state"] = MATCH_LOOKING

    elif data.startswith("msetup_looking_"):
        looking = data.replace("msetup_looking_", "")
        match_setup_data.setdefault(user_id, {})["looking_for"] = looking
        await query.message.reply_text("✍️ Write a short *bio* about yourself:", parse_mode="Markdown")
        context.user_data["match_state"] = MATCH_BIO


async def cmd_mymatch(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Show matches — /mymatch"""
    user_id = str(update.effective_user.id)
    matches = match_get_matches(user_id)
    if not matches:
        await update.message.reply_text("💔 No matches yet! Use /match to browse profiles.")
        return
    text = "\U0001f49e *Your Matches*\n\n"
    for p in matches:
        text += f"\u2022 *{p['name']}*, {p['age']} yrs \u2014 \U0001f4cd {p['location']}\n"
    text += "\n\U0001f4ac To chat, message them on Telegram!"
    await update.message.reply_text(text, parse_mode="Markdown")


