def fetch_news_headlines() -> list:
    """Fetch latest news from free RSS/API sources."""
    headlines = []
    feeds = [
        ("🌍 World News",    "https://feeds.bbci.co.uk/news/rss.xml"),
        ("🤖 AI & Tech",     "https://feeds.feedburner.com/TechCrunch"),
        ("🎬 Entertainment", "https://feeds.bbci.co.uk/news/entertainment_and_arts/rss.xml"),
    ]
    for label, url in feeds:
        try:
            r = requests.get(url, timeout=10, headers={"User-Agent": "Mozilla/5.0"})
            import re as _re
            titles = _re.findall(r'<title><!\[CDATA\[(.*?)\]\]></title>', r.text)
            if not titles:
                titles = _re.findall(r'<title>(.*?)</title>', r.text)
            # Skip first (feed title) and take top 2
            for t in titles[1:3]:
                if t and len(t) > 10:
                    headlines.append((label, t.strip()))
        except Exception:
            pass
    return headlines


def fetch_crypto_prices() -> str:
    """Fetch top crypto prices."""
    try:
        coins = ["bitcoin", "ethereum", "binancecoin", "solana"]
        r = requests.get(
            f"https://api.coingecko.com/api/v3/simple/price",
            params={"ids": ",".join(coins), "vs_currencies": "usd", "include_24hr_change": "true"},
            timeout=10
        )
        data = r.json()
        lines = []
        symbols = {"bitcoin": "₿ BTC", "ethereum": "Ξ ETH", "binancecoin": "BNB", "solana": "◎ SOL"}
        for coin in coins:
            if coin in data:
                price  = data[coin].get("usd", 0)
                change = data[coin].get("usd_24h_change", 0)
                arrow  = "📈" if change >= 0 else "📉"
                lines.append(f"{arrow} {symbols[coin]}: ${price:,.2f} ({change:+.1f}%)")
        return "\n".join(lines)
    except Exception:
        return ""


