def _save_broadcast_idx():
    """Save index to SQLite database - guaranteed to persist."""
    try:
        conn = sqlite3.connect(SQLITE_DB)
        c = conn.cursor()
        c.execute("CREATE TABLE IF NOT EXISTS bot_state (key TEXT PRIMARY KEY, value TEXT)")
        c.execute("INSERT OR REPLACE INTO bot_state (key,value) VALUES ('broadcast_idx',?)",
                  (str(_broadcast_idx),))
        conn.commit()
        conn.close()
    except Exception as e:
        print(f"Save idx error: {e}")

def _load_broadcast_idx():
    """Load index from SQLite database."""
    global _broadcast_idx
    try:
        conn = sqlite3.connect(SQLITE_DB)
        c = conn.cursor()
        c.execute("CREATE TABLE IF NOT EXISTS bot_state (key TEXT PRIMARY KEY, value TEXT)")
        c.execute("SELECT value FROM bot_state WHERE key='broadcast_idx'")
        row = c.fetchone()
        conn.close()
        if row:
            _broadcast_idx = int(row[0])
            print(f"📡 Loaded broadcast index: {_broadcast_idx}")
    except Exception:
        _broadcast_idx = 0

_load_broadcast_idx()

