def _get_next_unique_image(topic=None):
    """Fetch image from Pexels (primary) — topic matched, never repeats."""
    global _unsplash_topic_idx, _used_unsplash_urls
    import requests as _req
    import random as _rand

    if not topic:
        topic = _UNSPLASH_TOPICS[_unsplash_topic_idx % len(_UNSPLASH_TOPICS)]
        _unsplash_topic_idx += 1

    # PRIMARY: Pexels API
    try:
        r = _req.get(
            "https://api.pexels.com/v1/search",
            params={
                "query": topic,
                "orientation": "landscape",
                "per_page": 15,
                "size": "large"
            },
            headers={"Authorization": PEXELS_API_KEY},
            timeout=8
        )
        if r.status_code == 200:
            photos = r.json().get("photos", [])
            # Pick random unused photo
            _rand.shuffle(photos)
            for photo in photos:
                url = photo["src"]["large"]
                if url not in _used_unsplash_urls:
                    _used_unsplash_urls.add(url)
                    print(f"📸 Pexels [{topic}]: {url[:60]}")
                    return url
    except Exception as e:
        print(f"⚠️ Pexels failed: {e}")

    # FALLBACK: Unsplash
    try:
        r = _req.get(
            "https://api.unsplash.com/photos/random",
            params={"query": topic, "orientation": "landscape"},
            headers={"Authorization": f"Client-ID {UNSPLASH_ACCESS_KEY}"},
            timeout=6
        )
        if r.status_code == 200:
            url = r.json()["urls"]["regular"]
            _used_unsplash_urls.add(url)
            print(f"📸 Unsplash fallback [{topic}]")
            return url
    except Exception as e:
        print(f"⚠️ Unsplash fallback failed: {e}")

    # LAST RESORT: static pool
    _unsplash_topic_idx += 1
    return _ALL_IMAGES[_unsplash_topic_idx % len(_ALL_IMAGES)]


def _pick_image(pool_name=None, pool=None):
    """Always fetch fresh unique image from Unsplash."""
    return _get_next_unique_image()



