def get_broadcast_buttons(buttons: list) -> InlineKeyboardMarkup:
    """Build InlineKeyboardMarkup from button list."""
    if not buttons:
        return None
    kb = [[InlineKeyboardButton(label, url=url)] for label, url in buttons]
    return InlineKeyboardMarkup(kb)



