async def send_broadcast(bot, msg=None):
    """Send professional channel-style broadcast to group and channel."""
    # Run blocking network calls in executor so bot doesn't freeze
    text, image_url, buttons = await asyncio.get_running_loop().run_in_executor(
        None, build_broadcast_message
    )
    kb = get_broadcast_buttons(buttons)
    targets = list({BROADCAST_GROUP, BROADCAST_CHANNEL, BROADCAST_CHANNEL2})
    for target in targets:
        try:
            if image_url:
                await bot.send_photo(
                    chat_id=target,
                    photo=image_url,
                    caption=text,
                    parse_mode="Markdown",
                    reply_markup=kb
                )
            else:
                await bot.send_message(
                    chat_id=target,
                    text=text,
                    parse_mode="Markdown",
                    reply_markup=kb,
                    disable_web_page_preview=True
                )
        except Exception as e:
            print(f"\u26a0\ufe0f Broadcast to {target} failed: {e}")
            try:
                await bot.send_message(
                    chat_id=target,
                    text=text,
                    parse_mode="Markdown",
                    reply_markup=kb,
                    disable_web_page_preview=True
                )
            except Exception as e2:
                print(f"\u26a0\ufe0f Text fallback also failed: {e2}")


async def auto_broadcast_job(context):
    """Job that runs every 15 minutes to post channel-style updates."""
    try:
        await send_broadcast(context.bot)
        print(f"✅ Auto-broadcast sent to {BROADCAST_GROUP}")
    except Exception as e:
        print(f"⚠️ Broadcast error: {e}")


