# ════════════════════════════════════════════════════════
#  DEEPSEEK DIRECT API — Fast Chat + Deep Reasoning (R1)
# ════════════════════════════════════════════════════════

def call_deepseek(prompt: str, model: str = None, system: str = None, history: list = None) -> str:
    """Call DeepSeek API directly. Falls back to OpenRouter DeepSeek if error."""
    if model is None:
        model = DEEPSEEK_MODEL_FAST
    messages = []
    if system:
        messages.append({"role": "system", "content": system})
    if history:
        for h in history[-6:]:
            messages.append({"role": h.get("role","user"), "content": h.get("content","")})
    messages.append({"role": "user", "content": prompt})
    payload = {"model": model, "messages": messages, "max_tokens": 4096, "temperature": 0.7}
    try:
        r = requests.post(DEEPSEEK_BASE, headers=DEEPSEEK_HEADERS, json=payload, timeout=60)
        r.raise_for_status()
        return r.json()["choices"][0]["message"]["content"]
    except Exception as e:
        # Fallback to OpenRouter DeepSeek
        try:
            fallback_payload = {"model": "deepseek/deepseek-r1:free", "messages": messages, "max_tokens": 4096}
            r2 = requests.post(OPENROUTER_BASE, headers=OPENROUTER_HEADERS, json=fallback_payload, timeout=60)
            r2.raise_for_status()
            return r2.json()["choices"][0]["message"]["content"]
        except Exception as e2:
            return f"❌ DeepSeek error: {e2}"


async def cmd_deepseek(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Direct DeepSeek command — /deepseek or /ds for fast chat, /dsr for deep reasoning."""
    user_id  = update.effective_user.id
    allowed, deny_msg = check_advanced_access(user_id, "deepseek_ai")
    if not allowed:
        await update.message.reply_text(f"🔒 {deny_msg}", parse_mode="Markdown"); return
    log_feature_usage(user_id, "deepseek_ai")
    user     = get_user(user_id)
    sub      = user.get("subscription", "free")
    is_admin = str(user_id) == str(ADMIN_ID)

    # Access: Pro+ and admin only for reasoner; Basic+ for chat
    cmd_text = update.message.text or ""
    use_reasoner = cmd_text.startswith("/dsr")

    if use_reasoner:
        if sub not in ("pro", "ultimate") and not is_admin:
            await update.message.reply_text(
                "🔒 *DeepSeek R1 Reasoner* is for Pro & Ultimate subscribers.\n\nUpgrade via /profile or contact @" + ADMIN_USERNAME,
                parse_mode="Markdown")
            return
    else:
        if sub not in ("basic", "pro", "ultimate") and not is_admin:
            await update.message.reply_text(
                "🔒 *DeepSeek AI* is for Basic, Pro & Ultimate subscribers.\n\nUpgrade via /profile or contact @" + ADMIN_USERNAME,
                parse_mode="Markdown")
            return

    prompt = " ".join(context.args).strip() if context.args else ""
    if not prompt:
        if use_reasoner:
            await update.message.reply_text(
                "🧠 *DeepSeek R1 Reasoner*\n\nUsage: `/dsr your question`\n\nBest for: maths, coding, logic, deep analysis.",
                parse_mode="Markdown")
        else:
            await update.message.reply_text(
                "🤖 *DeepSeek AI*\n\nUsage: `/deepseek your question`\n\nFast, smart, great for anything!\n\n💡 Use `/dsr` for deep reasoning mode.",
                parse_mode="Markdown")
        return

    model  = DEEPSEEK_MODEL_THINK if use_reasoner else DEEPSEEK_MODEL_FAST
    label  = "🧠 *DeepSeek R1 Reasoner*" if use_reasoner else "🤖 *DeepSeek AI*"
    thinking = await update.message.reply_text(
        f"{'🧠 Reasoning deeply...' if use_reasoner else '⚡ Thinking...'}")

    history = user.get("history", [])
    result  = await asyncio.get_running_loop().run_in_executor(
        None, lambda: call_deepseek(prompt, model=model, history=history))
    await thinking.delete()

    full_text = f"{label}\n\n{result}"
    if len(full_text) > 4000:
        full_text = full_text[:3990] + "…"
    await update.message.reply_text(full_text, parse_mode="Markdown")
    add_to_history(user, "user", prompt)
    add_to_history(user, "assistant", result)
    update_user(user_id, user)


# ════════════════════════════════════════════════════════
#  PERPLEXITY AI — Real-time Search, Deep Research, Pro AI
# ════════════════════════════════════════════════════════

def _perplexity_access(user: dict, feature: str = "basic") -> tuple[bool, str]:
    """Check if user can access Perplexity features. Admin/owner always allowed."""
    uid = str(user.get("user_id", ""))
    if uid == str(ADMIN_ID):
        return True, ""
    sub = user.get("subscription", "free")
    if feature == "basic":
        if sub in ("basic", "pro", "ultimate"):
            return True, ""
        return False, "🔒 *Perplexity Search* is available for *Basic, Pro & Ultimate* subscribers.\n\nUpgrade via /profile or contact @" + ADMIN_USERNAME
    elif feature == "pro":
        if sub in ("pro", "ultimate"):
            return True, ""
        return False, "💎 *Perplexity Pro Search* is available for *Pro & Ultimate* subscribers.\n\nUpgrade via /profile or contact @" + ADMIN_USERNAME
    elif feature == "deep":
        if sub == "ultimate":
            return True, ""
        return False, "👑 *Deep Research* (100+ sources) is an *Ultimate* subscriber feature.\n\nUpgrade via /profile or contact @" + ADMIN_USERNAME
    return False, "Access denied."


def call_perplexity(query: str, model: str = None, system: str = None) -> dict:
    """
    Call Perplexity API. Returns dict with keys:
      answer, citations, model_used, error
    """
    if model is None:
        model = PERPLEXITY_MODEL_BASIC
    messages = []
    if system:
        messages.append({"role": "system", "content": system})
    messages.append({"role": "user", "content": query})
    payload = {
        "model":       model,
        "messages":    messages,
        "max_tokens":  2048,
        "temperature": 0.2,
    }
    try:
        r = requests.post(PERPLEXITY_BASE, headers=PERPLEXITY_HEADERS, json=payload, timeout=90)
        r.raise_for_status()
        data     = r.json()
        answer   = data["choices"][0]["message"]["content"]
        citations = data.get("citations", [])
        return {"answer": answer, "citations": citations, "model_used": model, "error": None}
    except Exception as e:
        return {"answer": "", "citations": [], "model_used": model, "error": str(e)}


def _format_citations(citations: list) -> str:
    if not citations:
        return ""
    lines = ["\n\n📚 *Sources:*"]
    for i, c in enumerate(citations[:6], 1):
        if isinstance(c, dict):
            title = c.get("title") or c.get("url", f"Source {i}")
            url   = c.get("url", "")
            lines.append(f"{i}. [{title[:60]}]({url})" if url else f"{i}. {title[:60]}")
        elif isinstance(c, str):
            lines.append(f"{i}. {c[:80]}")
    return "\n".join(lines)


# ── /psearch — Perplexity Web Search (Basic+) ──
async def cmd_psearch(update: Update, context: ContextTypes.DEFAULT_TYPE):
    user_id = update.effective_user.id
    allowed, deny_msg = check_advanced_access(user_id, "perplexity_search")
    if not allowed:
        await update.message.reply_text(f"🔒 {deny_msg}", parse_mode="Markdown"); return
    log_feature_usage(user_id, "perplexity_search")
    user    = get_user(user_id)
    ok, msg = _perplexity_access(user, "basic")
    if not ok:
        await update.message.reply_text(msg, parse_mode="Markdown")
        return
    query = " ".join(context.args).strip() if context.args else ""
    if not query:
        await update.message.reply_text(
            "🔍 *Perplexity Real-time Search*\n\nUsage: `/psearch your question`\n\nGet live web answers with citations!",
            parse_mode="Markdown"
        )
        return
    thinking = await update.message.reply_text("🔍 Searching the live web with Perplexity AI...")
    sub      = user.get("subscription", "free")
    model    = PERPLEXITY_MODEL_PRO if sub in ("pro", "ultimate") or str(user_id) == str(ADMIN_ID) else PERPLEXITY_MODEL_BASIC
    result   = await asyncio.get_running_loop().run_in_executor(None, lambda: call_perplexity(query, model=model))
    await thinking.delete()
    if result["error"]:
        await update.message.reply_text(f"❌ Search failed: {result['error']}\n\nTry again shortly.", parse_mode="Markdown")
        return
    answer    = result["answer"]
    citations = _format_citations(result["citations"])
    badge     = "🔍 *Perplexity Search*" if model == PERPLEXITY_MODEL_BASIC else "💎 *Perplexity Pro Search*"
    full_text = f"{badge}\n\n{answer}{citations}"
    if len(full_text) > 4000:
        full_text = full_text[:3990] + "…"
    await update.message.reply_text(full_text, parse_mode="Markdown", disable_web_page_preview=True)


# ── /prosearch — Perplexity Pro Deep Search (Pro+) ──
async def cmd_prosearch(update: Update, context: ContextTypes.DEFAULT_TYPE):
    user_id = update.effective_user.id
    allowed, deny_msg = check_advanced_access(user_id, "perplexity_pro")
    if not allowed:
        await update.message.reply_text(f"🔒 {deny_msg}", parse_mode="Markdown"); return
    log_feature_usage(user_id, "perplexity_pro")
    user    = get_user(user_id)
    ok, msg = _perplexity_access(user, "pro")
    if not ok:
        await update.message.reply_text(msg, parse_mode="Markdown")
        return
    query = " ".join(context.args).strip() if context.args else ""
    if not query:
        await update.message.reply_text(
            "💎 *Perplexity Pro Search*\n\nUsage: `/prosearch your topic`\n\nMulti-step research with deeper analysis and more sources!",
            parse_mode="Markdown"
        )
        return
    thinking = await update.message.reply_text("💎 Running Pro Search — analysing multiple sources...")
    result   = await asyncio.get_running_loop().run_in_executor(
        None, lambda: call_perplexity(query, model=PERPLEXITY_MODEL_PRO,
        system="You are an expert research assistant. Give a thorough, well-structured answer with key facts, numbers, and insights. Use markdown formatting.")
    )
    await thinking.delete()
    if result["error"]:
        await update.message.reply_text(f"❌ Pro Search failed: {result['error']}", parse_mode="Markdown")
        return
    answer    = result["answer"]
    citations = _format_citations(result["citations"])
    full_text = f"💎 *Perplexity Pro Search*\n\n{answer}{citations}"
    if len(full_text) > 4000:
        full_text = full_text[:3990] + "…"
    await update.message.reply_text(full_text, parse_mode="Markdown", disable_web_page_preview=True)


# ── /deepresearch — 100+ Source Analysis (Ultimate only) ──
async def cmd_deepresearch(update: Update, context: ContextTypes.DEFAULT_TYPE):
    user_id = update.effective_user.id
    allowed, deny_msg = check_advanced_access(user_id, "deep_research")
    if not allowed:
        await update.message.reply_text(f"🔒 {deny_msg}", parse_mode="Markdown"); return
    log_feature_usage(user_id, "deep_research")
    user    = get_user(user_id)
    ok, msg = _perplexity_access(user, "deep")
    if not ok:
        await update.message.reply_text(msg, parse_mode="Markdown")
        return
    query = " ".join(context.args).strip() if context.args else ""
    if not query:
        await update.message.reply_text(
            "👑 *Deep Research*\n\nUsage: `/deepresearch your topic`\n\n📊 Analyses 100+ sources and generates a full research report. Takes 1–3 minutes.",
            parse_mode="Markdown"
        )
        return
    thinking = await update.message.reply_text("👑 *Deep Research initiated…*\n\n🔎 Scanning 100+ sources. This takes 1–3 minutes, please wait…", parse_mode="Markdown")
    result   = await asyncio.get_running_loop().run_in_executor(
        None, lambda: call_perplexity(query, model=PERPLEXITY_MODEL_DEEP,
        system="You are an elite research analyst. Produce a comprehensive, structured research report with: Executive Summary, Key Findings, Detailed Analysis, Statistics & Data, Expert Opinions, Conclusion, and Recommendations. Use markdown headers and bullet points.")
    )
    await thinking.delete()
    if result["error"]:
        await update.message.reply_text(f"❌ Deep Research failed: {result['error']}\n\nTry again in a moment.", parse_mode="Markdown")
        return
    answer    = result["answer"]
    citations = _format_citations(result["citations"])
    header    = f"👑 *Deep Research Report*\n📋 Topic: _{query[:80]}_\n{'─'*30}\n\n"
    full_text = f"{header}{answer}{citations}"
    # Send as file if too long
    if len(full_text) > 4000:
        chunks = [full_text[i:i+4000] for i in range(0, len(full_text), 4000)]
        for chunk in chunks[:3]:
            await update.message.reply_text(chunk, parse_mode="Markdown", disable_web_page_preview=True)
    else:
        await update.message.reply_text(full_text, parse_mode="Markdown", disable_web_page_preview=True)


