async def cmd_custom_broadcast(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Admin sends custom text broadcast — /broadcast Your message here"""
    if str(update.effective_user.id) != str(ADMIN_ID):
        await update.message.reply_text("❌ Admin only!")
        return
    text = " ".join(context.args) if context.args else ""
    if not text:
        await update.message.reply_text(
            "📢 *How to broadcast your own message:*\n\n"
            "1️⃣ *Text only:*\n"
            "`/broadcast Hello everyone! Check this out!`\n\n"
            "2️⃣ *With media* — send any of these with caption `/broadcast Your message`:\n"
            "📷 Photo · 🎥 Video · 🎞️ GIF · 📄 Document\n"
            "🎵 Audio · 🎤 Voice · 🎭 Sticker\n\n"
            "I will send it to ALL channels instantly! 🚀",
            parse_mode="Markdown"
        )
        return
    targets = [BROADCAST_GROUP, BROADCAST_CHANNEL, BROADCAST_CHANNEL2]
    # Note: Bot must be admin in all channels above
    success = 0
    for target in targets:
        try:
            await context.bot.send_message(
                chat_id=target,
                text=text,
                parse_mode="Markdown",
                disable_web_page_preview=False
            )
            success += 1
        except Exception as e:
            print(f"⚠️ Custom broadcast to {target} failed: {e}")
    await update.message.reply_text(
        f"✅ Broadcast sent to {success}/{len(targets)} channels!\n\n"
        f"📢 Message:\n{text[:100]}..."
    )


async def cmd_photo_broadcast(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """
    Universal media broadcast — handles Photo, Video, GIF, Document, Audio.
    Usage: Send any media to bot with caption /broadcast Your message
    """
    if str(update.effective_user.id) != str(ADMIN_ID):
        return
    caption = update.message.caption or ""
    if not caption.startswith("/broadcast"):
        return
    msg_text = caption[len("/broadcast"):].strip()
    if not msg_text:
        msg_text = "📢 New update from Moveroom AI Studio!"

    targets = [BROADCAST_GROUP, BROADCAST_CHANNEL, BROADCAST_CHANNEL2]
    msg = update.message
    success = 0
    media_type = "unknown"

    for target in targets:
        try:
            if msg.photo:
                media_type = "photo"
                await context.bot.send_photo(
                    chat_id=target,
                    photo=msg.photo[-1].file_id,
                    caption=msg_text,
                    parse_mode="Markdown"
                )
            elif msg.video:
                media_type = "video"
                await context.bot.send_video(
                    chat_id=target,
                    video=msg.video.file_id,
                    caption=msg_text,
                    parse_mode="Markdown",
                    supports_streaming=True
                )
            elif msg.animation:
                media_type = "GIF"
                await context.bot.send_animation(
                    chat_id=target,
                    animation=msg.animation.file_id,
                    caption=msg_text,
                    parse_mode="Markdown"
                )
            elif msg.document:
                media_type = "document"
                await context.bot.send_document(
                    chat_id=target,
                    document=msg.document.file_id,
                    caption=msg_text,
                    parse_mode="Markdown"
                )
            elif msg.audio:
                media_type = "audio"
                await context.bot.send_audio(
                    chat_id=target,
                    audio=msg.audio.file_id,
                    caption=msg_text,
                    parse_mode="Markdown"
                )
            elif msg.voice:
                media_type = "voice"
                await context.bot.send_voice(
                    chat_id=target,
                    voice=msg.voice.file_id,
                    caption=msg_text,
                    parse_mode="Markdown"
                )
            elif msg.video_note:
                media_type = "video note"
                await context.bot.send_video_note(
                    chat_id=target,
                    video_note=msg.video_note.file_id
                )
            elif msg.sticker:
                media_type = "sticker"
                await context.bot.send_sticker(
                    chat_id=target,
                    sticker=msg.sticker.file_id
                )
            success += 1
        except Exception as e:
            logger.warning(f"⚠️ Media broadcast to {target} failed: {e}")

    await update.message.reply_text(
        f"✅ *{media_type.capitalize()} broadcast sent!*\n\n"
        f"📡 Delivered to {success}/{len(targets)} channels!",
        parse_mode="Markdown"
    )


async def cmd_claude(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Chat with Claude AI — /claude Your question here"""
    user_id = update.effective_user.id
    question = " ".join(context.args) if context.args else ""
    if not question:
        await update.message.reply_text(
            "🧠 *Claude AI — The Smartest AI!*\n\n"
            "Usage: `/claude Your question here`\n\n"
            "Examples:\n"
            "💬 `/claude Write me a poem about Ghana`\n"
            "💬 `/claude Explain quantum physics simply`\n"
            "💬 `/claude Give me business ideas for 2026`\n"
            "💬 `/claude Help me write a love letter`\n\n"
            "✨ Claude is made by Anthropic — the safest & smartest AI!",
            parse_mode="Markdown"
        )
        return

    thinking_msg = await update.message.reply_text("🧠 Claude is thinking...")

    try:
        import requests as _req
        response = _req.post(
            "https://api.anthropic.com/v1/messages",
            headers={
                "Content-Type": "application/json",
                "x-api-key": CLAUDE_API_KEY,
                "anthropic-version": "2023-06-01"
            },
            json={
                "model": "claude-3-5-haiku-20241022",
                "max_tokens": 1024,
                "messages": [
                    {"role": "user", "content": question}
                ]
            },
            timeout=30
        )
        if response.status_code == 200:
            data = response.json()
            answer = data["content"][0]["text"]
            # Split if too long for Telegram
            if len(answer) > 4000:
                answer = answer[:4000] + "..."
            await thinking_msg.edit_text(
                f"🧠 *Claude AI says:*\n\n{answer}",
                parse_mode="Markdown"
            )
        else:
            await thinking_msg.edit_text(
                f"❌ Claude error: {response.status_code}\n{response.text[:200]}"
            )
    except Exception as e:
        await thinking_msg.edit_text(f"❌ Error: {str(e)[:200]}")


