# ══════════════════════════════════════════════════════
#  📞 PHONE CALL SYSTEM (Twilio)
# ══════════════════════════════════════════════════════
def _twilio_client():
    if not TWILIO_ACCOUNT_SID or not TWILIO_AUTH_TOKEN:
        return None
    try:
        from twilio.rest import Client
        return Client(TWILIO_ACCOUNT_SID, TWILIO_AUTH_TOKEN)
    except Exception as e:
        logger.error(f"Twilio client error: {e}")
        return None

async def cmd_callme(update: Update, context: ContextTypes.DEFAULT_TYPE):
    user_id = update.effective_user.id
    if not is_signed_in(user_id):
        await update.message.reply_text("🔐 Sign in first!")
        return
    if not context.args:
        await update.message.reply_text("📲 Usage: `/callme +233XXXXXXXXX`", parse_mode="Markdown")
        return
    if not TWILIO_ACCOUNT_SID:
        await update.message.reply_text("⚙️ Twilio not configured.")
        return
    to_number = context.args[0]
    if not to_number.startswith("+"):
        await update.message.reply_text("❌ Use international format: +233XXXXXXXXX")
        return
    client = _twilio_client()
    if not client:
        await update.message.reply_text("❌ Twilio not available.")
        return
    status_msg = await update.message.reply_text(f"📲 *Calling you at {to_number}...*", parse_mode="Markdown")
    try:
        user = get_user(user_id)
        name = user.get("name", "friend")
        twiml = f'<Response><Say voice="Polly.Joanna">Hello {name}! This is Moveroom AI Bot. Open Telegram and type slash start to explore all features. Have a great day!</Say></Response>'
        call = client.calls.create(twiml=twiml, to=to_number, from_=TWILIO_FROM_NUMBER)
        await status_msg.edit_text(
            f"✅ *Calling you now!*\n\n📞 Number: `{to_number}`\n📊 Status: `{call.status}`\n\nPick up your phone! 📱",
            parse_mode="Markdown"
        )
    except Exception as e:
        await status_msg.edit_text(f"❌ Call failed: {str(e)[:200]}")


# ══════════════════════════════════════════════════════
#  🌙 AWAY MODE — AI Auto-Reply System
# ══════════════════════════════════════════════════════
_away_mode = {
    "active": False,
    "use_ai": True,
    "message": "Hey! I'm not around right now. I'll reply when I'm back. — Powered by @MoveroomBot",
    "replied_users": {},
    "schedule_on":  None,
    "schedule_off": None,
    "max_replies": 3,
}

async def cmd_away(update: Update, context: ContextTypes.DEFAULT_TYPE):
    user_id = update.effective_user.id
    if str(user_id) != str(ADMIN_ID):
        await update.message.reply_text("🔐 Admin only!")
        return
    args = context.args
    if not args:
        status = "🟢 ON" if _away_mode["active"] else "🔴 OFF"
        ai_status = "🤖 AI answers ON" if _away_mode["use_ai"] else "📝 Fixed message"
        replied = len(_away_mode["replied_users"])
        await update.message.reply_text(
            f"🌙 *Away Mode*\n\nStatus: *{status}* | {ai_status}\n"
            f"Replied to: *{replied} users*\n\n"
            f"📝 Message:\n_{_away_mode['message']}_\n\n"
            f"`/away on` · `/away off` · `/away set Msg` · `/away ai on/off`\n"
            f"`/away schedule 22:00 08:00` · `/away limit 5` · `/away reset`",
            parse_mode="Markdown"
        )
        return
    cmd = args[0].lower()
    if cmd == "on":
        _away_mode["active"] = True
        _away_mode["replied_users"] = {}
        ai_status = "🤖 AI answers questions" if _away_mode["use_ai"] else "📝 Fixed message only"
        await update.message.reply_text(
            f"🌙 *Away Mode ON!*\n\nMode: {ai_status}\n\n"
            f"📝 Message:\n_{_away_mode['message']}_\n\nType `/away off` to turn off.",
            parse_mode="Markdown"
        )
    elif cmd == "off":
        _away_mode["active"] = False
        replied = len(_away_mode["replied_users"])
        await update.message.reply_text(f"✅ *Away Mode OFF!*\n\nWelcome back! I replied to *{replied} people* while you were away.", parse_mode="Markdown")
    elif cmd == "set":
        if len(args) < 2:
            await update.message.reply_text("Usage: `/away set Your message`", parse_mode="Markdown")
            return
        _away_mode["message"] = " ".join(args[1:])
        await update.message.reply_text(f"✅ Away message updated!\n\n_{_away_mode['message']}_", parse_mode="Markdown")
    elif cmd == "schedule":
        if len(args) < 3:
            await update.message.reply_text("Usage: `/away schedule 22:00 08:00`", parse_mode="Markdown")
            return
        _away_mode["schedule_on"]  = args[1]
        _away_mode["schedule_off"] = args[2]
        await update.message.reply_text(f"⏰ Schedule: ON at `{args[1]}`, OFF at `{args[2]}`", parse_mode="Markdown")
    elif cmd == "reset":
        _away_mode["replied_users"] = {}
        await update.message.reply_text("✅ Replied users list cleared!")
    elif cmd == "ai":
        sub = args[1].lower() if len(args) > 1 else ""
        if sub == "on":
            _away_mode["use_ai"] = True
            await update.message.reply_text("🤖 *AI mode ON!* Bot fully answers every question when you are away!", parse_mode="Markdown")
        elif sub == "off":
            _away_mode["use_ai"] = False
            await update.message.reply_text("📝 *Fixed message mode.* Bot sends your custom away message only.", parse_mode="Markdown")
        else:
            ai_status = "ON 🟢" if _away_mode["use_ai"] else "OFF 🔴"
            await update.message.reply_text(f"AI mode: *{ai_status}*\nUse `/away ai on` or `/away ai off`", parse_mode="Markdown")
    elif cmd == "limit":
        if len(args) > 1 and args[1].isdigit():
            _away_mode["max_replies"] = int(args[1])
            await update.message.reply_text(f"✅ Max AI replies per user: *{args[1]}*", parse_mode="Markdown")
        else:
            await update.message.reply_text(f"Current limit: *{_away_mode['max_replies']}*\nUsage: `/away limit 5`", parse_mode="Markdown")
    else:
        await update.message.reply_text("Commands: on, off, set, ai on/off, schedule, reset, limit")

async def _check_away_schedule():
    import datetime
    now = datetime.datetime.now().strftime("%H:%M")
    if _away_mode["schedule_on"] and now == _away_mode["schedule_on"] and not _away_mode["active"]:
        _away_mode["active"] = True
        _away_mode["replied_users"] = {}
    if _away_mode["schedule_off"] and now == _away_mode["schedule_off"] and _away_mode["active"]:
        _away_mode["active"] = False

async def _handle_away_reply(update: Update, context: ContextTypes.DEFAULT_TYPE) -> bool:
    if not _away_mode["active"]:
        return False
    user_id = update.effective_user.id
    if str(user_id) == str(ADMIN_ID):
        return False
    if update.effective_user.is_bot:
        return False
    await _check_away_schedule()
    text = (update.message.text or "").strip()
    user_name = update.effective_user.first_name or "there"
    reply_count = _away_mode["replied_users"].get(user_id, 0)
    max_replies = _away_mode.get("max_replies", 3)
    try:
        if reply_count == 0:
            if _away_mode["use_ai"] and text:
                await context.bot.send_chat_action(update.effective_chat.id, "typing")
                ai_answer = call_gemini(
                    f"You are Moveroom AI Bot answering on behalf of the admin who is away. "
                    f"Answer this helpfully and friendly: {text}\n\nMention at the end: The admin will see your message when they return.",
                    model=DEFAULT_MODEL, use_cache=False
                )
                await update.message.reply_text(
                    f"👋 *Hey {user_name}!*\n\n🤖 I'm answering for the admin:\n\n{ai_answer}\n\n_— Auto-reply by @MoveroomBot_",
                    parse_mode="Markdown"
                )
            else:
                await update.message.reply_text(
                    f"👋 *Hey {user_name}!*\n\n{_away_mode['message']}\n\n_— Auto-reply by @MoveroomBot_",
                    parse_mode="Markdown"
                )
            _away_mode["replied_users"][user_id] = 1
        elif reply_count < max_replies and _away_mode["use_ai"] and text:
            await context.bot.send_chat_action(update.effective_chat.id, "typing")
            ai_answer = call_gemini(
                f"You are Moveroom AI Bot answering on behalf of the admin who is away. Answer: {text}",
                model=DEFAULT_MODEL, use_cache=False
            )
            await update.message.reply_text(f"🤖 *Auto-reply:*\n\n{ai_answer}\n\n_— @MoveroomBot_", parse_mode="Markdown")
            _away_mode["replied_users"][user_id] = reply_count + 1
        elif reply_count >= max_replies:
            await update.message.reply_text(
                "🤖 The admin will reply when they return! Meanwhile: /ai /movies /match /crypto",
                parse_mode="Markdown"
            )
        return True
    except Exception as e:
        logger.error(f"Away reply error: {e}")
        return False


