#  🎙️ LIVE VOICE CHAT SYSTEM — /vchat
# ══════════════════════════════════════════════════════
_vchat_sessions = {}

async def cmd_vchat(update: Update, context: ContextTypes.DEFAULT_TYPE):
    user_id = update.effective_user.id
    if not is_signed_in(user_id):
        await update.message.reply_text("🔐 Sign in first! Type /start")
        return
    # Load from DB if not in memory (survives restarts)
    if user_id not in _vchat_sessions:
        saved_style, saved_pace = _load_vchat_prefs(user_id)
        _vchat_sessions[user_id] = {"style": saved_style, "pace": saved_pace, "active": False}
    session    = _vchat_sessions[user_id]
    cur_style  = session.get("style", "mellow")
    cur_pace   = session.get("pace",  "normal")
    cur_active = session.get("active", False)
    user       = get_user(user_id)
    voice_key  = user.get("voice", DEFAULT_VOICE)
    voice_label= VOICE_OPTIONS.get(voice_key, VOICE_OPTIONS[DEFAULT_VOICE])[0]

    style_buttons = [InlineKeyboardButton(("✅ " if k==cur_style else "")+v["label"], callback_data=f"vchat_style_{k}") for k,v in VOICE_CHAT_STYLES.items()]
    pace_buttons  = [InlineKeyboardButton(("✅ " if k==cur_pace  else "")+v["label"], callback_data=f"vchat_pace_{k}")  for k,v in VOICE_CHAT_PACE.items()]
    action_btn    = InlineKeyboardButton("🛑 Stop Voice Chat" if cur_active else "🎙️ Start Voice Chat", callback_data="vchat_stop" if cur_active else "vchat_start")
    keyboard = InlineKeyboardMarkup([style_buttons, pace_buttons, [action_btn], [InlineKeyboardButton("📞 Join Group Voice Call", callback_data="vchat_groupcall")]])

    style_info   = VOICE_CHAT_STYLES[cur_style]
    pace_info    = VOICE_CHAT_PACE[cur_pace]
    status_emoji = "🟢 ACTIVE" if cur_active else "⚫ Inactive"

    await update.message.reply_text(
        f"🎙️ *Live Voice Chat*\n\nStatus: *{status_emoji}*\n\n"
        f"🔊 *Voice:* {voice_label}\n_(change with /voice)_\n\n"
        f"🎨 *Style:* {style_info['label']} — _{style_info['description']}_\n\n"
        f"⏱️ *Pace:* {pace_info['label']}\n\n━━━━━━━━━━━━━━━━━\n"
        f"{'🎤 Send a voice note — I will reply!' if cur_active else '👆 Choose style & pace, then Start!'}",
        parse_mode="Markdown", reply_markup=keyboard
    )

async def handle_vchat_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    query   = update.callback_query
    await query.answer()
    user_id = query.from_user.id
    data    = query.data
    if user_id not in _vchat_sessions:
        _vchat_sessions[user_id] = {"style": "mellow", "pace": "normal", "active": False}
    session = _vchat_sessions[user_id]

    if data.startswith("vchat_style_"):
        key = data.replace("vchat_style_", "")
        if key in VOICE_CHAT_STYLES:
            session["style"] = key
            _save_vchat_prefs(user_id, key, session.get("pace", "normal"))
    elif data.startswith("vchat_pace_"):
        key = data.replace("vchat_pace_", "")
        if key in VOICE_CHAT_PACE:
            session["pace"] = key
            _save_vchat_prefs(user_id, session.get("style", "mellow"), key)
    elif data == "vchat_start":
        session["active"] = True
        user = get_user(user_id)
        user["awaiting"] = "vchat"
        update_user(user_id, user)
    elif data == "vchat_stop":
        session["active"] = False
        user = get_user(user_id)
        if user.get("awaiting") == "vchat":
            user["awaiting"] = None
            update_user(user_id, user)
    elif data == "vchat_groupcall":
        await query.message.reply_text(
            "📞 *Join Group Voice Call*\n\n1️⃣ Add @MoveroomBot to your group\n2️⃣ Start a voice chat\n3️⃣ Use `/joincall` in the group\n\n⚠️ Requires `pip install pytgcalls tgcrypto`",
            parse_mode="Markdown"
        )
        return

    _vchat_sessions[user_id] = session
    cur_style  = session.get("style", "mellow")
    cur_pace   = session.get("pace",  "normal")
    cur_active = session.get("active", False)
    user       = get_user(user_id)
    voice_key  = user.get("voice", DEFAULT_VOICE)
    voice_label= VOICE_OPTIONS.get(voice_key, VOICE_OPTIONS[DEFAULT_VOICE])[0]

    style_buttons = [InlineKeyboardButton(("✅ " if k==cur_style else "")+v["label"], callback_data=f"vchat_style_{k}") for k,v in VOICE_CHAT_STYLES.items()]
    pace_buttons  = [InlineKeyboardButton(("✅ " if k==cur_pace  else "")+v["label"], callback_data=f"vchat_pace_{k}")  for k,v in VOICE_CHAT_PACE.items()]
    action_btn    = InlineKeyboardButton("🛑 Stop Voice Chat" if cur_active else "🎙️ Start Voice Chat", callback_data="vchat_stop" if cur_active else "vchat_start")
    keyboard = InlineKeyboardMarkup([style_buttons, pace_buttons, [action_btn], [InlineKeyboardButton("📞 Join Group Voice Call", callback_data="vchat_groupcall")]])
    style_info   = VOICE_CHAT_STYLES[cur_style]
    pace_info    = VOICE_CHAT_PACE[cur_pace]
    status_emoji = "🟢 ACTIVE" if cur_active else "⚫ Inactive"
    try:
        await query.edit_message_text(
            f"🎙️ *Live Voice Chat*\n\nStatus: *{status_emoji}*\n\n"
            f"🔊 *Voice:* {voice_label}\n_(change with /voice)_\n\n"
            f"🎨 *Style:* {style_info['label']} — _{style_info['description']}_\n\n"
            f"⏱️ *Pace:* {pace_info['label']}\n\n━━━━━━━━━━━━━━━━━\n"
            f"{'🎤 Send a voice note — I will reply!' if cur_active else '👆 Choose style & pace, then Start!'}",
            parse_mode="Markdown", reply_markup=keyboard
        )
    except Exception:
        pass

async def _vchat_tts(text: str, user_id: int) -> bytes | None:
    """
    TTS for voice chat — uses user's chosen voice + style rate + pace rate.
    Fixes: global parse_pct, dynamic timeout, EDGE_TTS_AVAILABLE flag, proper fallback.
    """
    style, pace = get_vchat_style(user_id)
    user       = get_user(user_id)
    voice_key  = user.get("voice", DEFAULT_VOICE)
    edge_voice = EDGE_VOICE_MAP.get(voice_key, "en-US-JennyNeural")

    # Combine style rate + pace rate using global parse_pct
    total_rate = parse_pct(style.get("rate", "+0%")) + parse_pct(pace.get("rate_adjust", "+0%"))
    rate_str   = f"+{total_rate}%" if total_rate >= 0 else f"{total_rate}%"

    clean = _clean_text_for_tts(text)

    # Dynamic timeout: ~1s per 20 chars, min 15s max 45s
    timeout_secs = max(15, min(45, len(clean) // 20))

    # Try edge-tts using availability flag (no double import)
    if EDGE_TTS_AVAILABLE:
        try:
            import edge_tts as _edgetts
            communicate = _edgetts.Communicate(clean, edge_voice, rate=rate_str)
            chunks = []
            async def _stream():
                async for chunk in communicate.stream():
                    if chunk["type"] == "audio":
                        chunks.append(chunk["data"])
            await asyncio.wait_for(_stream(), timeout=timeout_secs)
            if chunks:
                audio = b"".join(chunks)
                if len(audio) > 100:
                    return audio
        except asyncio.TimeoutError:
            logger.warning(f"VChat edge-tts timeout ({timeout_secs}s) for {edge_voice}")
        except Exception as e:
            logger.warning(f"VChat edge-tts failed ({edge_voice}): {e}")

        # African voice fallback
        AFRICAN_KEYS = {"ghana_female","ghana_male","nigeria_female","nigeria_male",
                        "kenya_female","kenya_male","sa_female","sa_male",
                        "tanzania_female","tanzania_male","ethiopia_female","ethiopia_male"}
        if voice_key in AFRICAN_KEYS:
            for fb in ["en-NG-EzinneNeural", "en-ZA-LeahNeural", "en-US-JennyNeural"]:
                if fb == edge_voice:
                    continue
                try:
                    import edge_tts as _edgetts
                    communicate = _edgetts.Communicate(clean, fb, rate=rate_str)
                    chunks = []
                    async def _fb_stream():
                        async for chunk in communicate.stream():
                            if chunk["type"] == "audio":
                                chunks.append(chunk["data"])
                    await asyncio.wait_for(_fb_stream(), timeout=15.0)
                    if chunks:
                        audio = b"".join(chunks)
                        if len(audio) > 100:
                            return audio
                except Exception:
                    continue

    # gTTS fallback
    if GTTS_AVAILABLE:
        try:
            from gtts import gTTS
            import io as _io
            lang, tld = GTTS_VOICE_MAP.get(voice_key, ("en", "us"))
            slow = (total_rate <= -15)
            def _gen():
                tts = gTTS(text=clean, lang=lang, tld=tld, slow=slow)
                buf = _io.BytesIO(); tts.write_to_fp(buf); buf.seek(0); return buf.read()
            loop = asyncio.get_running_loop()
            return await asyncio.wait_for(loop.run_in_executor(None, _gen), timeout=20.0)
        except Exception as e:
            logger.error(f"VChat gTTS failed: {e}")
    return None

async def handle_vchat_voice(update: Update, context: ContextTypes.DEFAULT_TYPE) -> bool:
    user_id = update.effective_user.id
    user    = get_user(user_id)
    if user.get("awaiting") != "vchat":
        return False
    session = _vchat_sessions.get(user_id, {})
    if not session.get("active"):
        return False
    style, pace = get_vchat_style(user_id)
    await context.bot.send_chat_action(update.effective_chat.id, "typing")
    try:
        voice_file  = await update.message.voice.get_file()
        voice_bytes = await voice_file.download_as_bytearray()
        transcribed = await transcribe_voice(bytes(voice_bytes), "voice.ogg")
    except Exception as e:
        logger.error(f"VChat transcription error: {e}")
        transcribed = ""
    if not transcribed:
        await update.message.reply_text("⚠️ Couldn't hear that clearly. Please try again!")
        return True
    await update.message.reply_text(f"🎤 _{transcribed}_", parse_mode="Markdown")
    await context.bot.send_chat_action(update.effective_chat.id, "record_voice")
    personality = style.get("personality", "You are a helpful AI assistant.")
    ai_response = call_gemini(
        f"{personality}\n\nUser said: {transcribed}\n\nReply naturally and conversationally.",
        model=DEFAULT_MODEL, use_cache=False
    )
    audio = await _vchat_tts(ai_response, user_id)
    style_label = style["label"]
    pace_label  = pace["label"]
    if audio and len(audio) > 100:
        caption = f"{style_label} · {pace_label}\n\n💬 _{ai_response[:200]}..._" if len(ai_response) > 200 else f"{style_label} · {pace_label}"
        await update.message.reply_voice(voice=io.BytesIO(audio), caption=caption, parse_mode="Markdown")
    else:
        await update.message.reply_text(f"{style_label} · {pace_label}\n\n{ai_response}", parse_mode="Markdown")
    user["daily_messages"] = user.get("daily_messages", 0) + 1
    update_user(user_id, user)
    return True

async def cmd_joincall(update: Update, context: ContextTypes.DEFAULT_TYPE):
    user_id = update.effective_user.id
    if not is_signed_in(user_id):
        await update.message.reply_text("🔐 Sign in first!")
        return
    try:
        from pytgcalls import PyTgCalls
        tgcalls_available = True
    except ImportError:
        tgcalls_available = False
    if not tgcalls_available:
        await update.message.reply_text(
            "📞 *Group Voice Call Setup*\n\n"
            "Install in Termux first:\n```\npip install pytgcalls tgcrypto\n```\n\n"
            "Then restart the bot and try again!",
            parse_mode="Markdown"
        )
        return
    await update.message.reply_text("📞 *Joining voice call...*\n\n🎙️ Bot is listening! Use `/leavecall` to stop.", parse_mode="Markdown")


def validate_config():
    """Check critical config at startup and warn about missing optional ones."""
    errors   = []
    warnings = []

    if not TELEGRAM_TOKEN or TELEGRAM_TOKEN == "YOUR_BOT_TOKEN":
        errors.append("❌ TELEGRAM_TOKEN not set!")
    if not ADMIN_ID or str(ADMIN_ID) == "0":
        errors.append("❌ ADMIN_ID not set!")
    if not GROQ_API_KEY:
        warnings.append("⚠️ GROQ_API_KEY missing — AI chat will not work")
    if not PEXELS_API_KEY:
        warnings.append("⚠️ PEXELS_API_KEY missing — broadcast images disabled")
    if not NEWS_API_KEY:
        warnings.append("⚠️ NEWS_API_KEY missing — news posts disabled")
    if not GROK_API_KEY:
        warnings.append("⚠️ GROK_API_KEY missing — /grok command disabled")
    if not CLAUDE_API_KEY:
        warnings.append("⚠️ CLAUDE_API_KEY missing — /claude command disabled")
    if not TWILIO_ACCOUNT_SID:
        warnings.append("⚠️ Twilio not configured — /call disabled (optional)")
    if "your_api_user_id_here" in str(MTN_API_USER):
        warnings.append("⚠️ MTN MoMo not configured — /momo disabled (optional)")

    for e in errors:
        print(e)
    for w in warnings:
        print(w)

    if errors:
        print("\n🛑 Fix critical errors above before running!")
        import sys; sys.exit(1)
    print(f"✅ Config OK — {len(warnings)} optional service(s) not configured")



