_GT_HEADERS = {"User-Agent": "Mozilla/5.0 (Linux; Android 10) AppleWebKit/537.36"}

def _gt_dial(number):
    clean = number.lstrip('+')
    for l in [3, 2, 1]:
        code = clean[:l]
        if code in _GT_DIAL_CODES:
            return code, _GT_DIAL_CODES[code]
    return clean[:3], "Unknown Country"

def _gt_scan_one(name, url_pat, no_texts, username):
    url = url_pat.format(username)
    try:
        r = requests.get(url, headers=_GT_HEADERS, timeout=8, allow_redirects=True)
        body = r.text.lower()
        missing = any(t.lower() in body for t in no_texts)
        if r.status_code == 200 and not missing:
            return "found", f"✅ [{name}]({url})"
    except Exception:
        pass
    return "miss", name

def _gt_chunk(chat_id, text, context, parse_mode="Markdown"):
    for i in range(0, len(text), 4000):
        context.bot.send_message(chat_id, text[i:i+4000],
            parse_mode=parse_mode, disable_web_page_preview=True)

