# ── /ip ───────────────────────────────────────────────────
async def cmd_gt_ip(update: Update, context: ContextTypes.DEFAULT_TYPE):
    allowed, msg = check_advanced_access(update.effective_user.id, "osint_ghosttrack")
    if not allowed:
        await update.message.reply_text(f"🔒 {msg}", parse_mode="Markdown"); return
    log_feature_usage(update.effective_user.id, "osint_ghosttrack", "ip_lookup")
    if not context.args:
        await update.message.reply_text("Usage: `/ip 8.8.8.8`", parse_mode="Markdown"); return
    ip = context.args[0].strip()
    await update.message.reply_text(f"🔍 Looking up `{ip}`…", parse_mode="Markdown")
    try:
        r = await asyncio.get_running_loop().run_in_executor(None, lambda: requests.get(f"http://ip-api.com/json/{ip}?fields=66846719", timeout=10).json())
        if r.get("status") == "fail":
            await update.message.reply_text(f"❌ {r.get('message')}"); return
        await update.message.reply_text(
            "🌐 *IP Intelligence Report*\n"
            "━━━━━━━━━━━━━━━━━━━━━━\n"
            f"📍 *IP:*       `{r.get('query')}`\n"
            f"🏳️ *Country:*  {r.get('country')} ({r.get('countryCode')})\n"
            f"🌆 *City:*     {r.get('city')}, {r.get('regionName')}\n"
            f"📮 *ZIP:*      {r.get('zip')}\n"
            f"🗺️ *Coords:*   {r.get('lat')}, {r.get('lon')}\n"
            f"🏢 *ISP:*      {r.get('isp')}\n"
            f"🌍 *Org:*      {r.get('org')}\n"
            f"📡 *ASN:*      {r.get('as')}\n"
            f"🔒 *Proxy:*    {r.get('proxy')}\n"
            f"🖥️ *Hosting:*  {r.get('hosting')}\n"
            f"⏱️ *Timezone:* {r.get('timezone')}",
            parse_mode="Markdown")
    except Exception as e:
        await update.message.reply_text(f"❌ Error: {e}")

# ── /phone ────────────────────────────────────────────────
async def cmd_gt_phone(update: Update, context: ContextTypes.DEFAULT_TYPE):
    allowed, msg = check_advanced_access(update.effective_user.id, "osint_ghosttrack")
    if not allowed:
        await update.message.reply_text(f"🔒 {msg}", parse_mode="Markdown"); return
    log_feature_usage(update.effective_user.id, "osint_ghosttrack", "phone_lookup")
    if not context.args:
        await update.message.reply_text("Usage: `/phone +233241234567`", parse_mode="Markdown"); return
    number = context.args[0].strip()
    if not re.match(r'^\+?[1-9]\d{6,14}$', number):
        await update.message.reply_text("❌ Use E.164 format: `+233241234567`", parse_mode="Markdown"); return
    code, country = _gt_dial(number)
    await update.message.reply_text(
        "📱 *Phone Analysis Report*\n"
        "━━━━━━━━━━━━━━━━━━━━━━\n"
        f"☎️ *Number:*    `{number}`\n"
        f"🌍 *Dial Code:* +{code}\n"
        f"🏳️ *Country:*  {country}\n"
        f"🔢 *Digits:*    {len(number.lstrip('+'))}\n"
        "ℹ️ _Carrier data requires a paid API key._",
        parse_mode="Markdown")

