#  📦  HUB DATABASE
# ══════════════════════════════════════════════════════════════════════════
def init_hub_db():
    conn = sqlite3.connect(HUB_DB)
    c = conn.cursor()
    c.execute("""CREATE TABLE IF NOT EXISTS api_keys (
        id INTEGER PRIMARY KEY AUTOINCREMENT, api_key TEXT UNIQUE NOT NULL,
        user_id INTEGER NOT NULL, username TEXT, tier TEXT NOT NULL,
        features TEXT NOT NULL, requests_per_day INTEGER NOT NULL,
        requests_used_today INTEGER DEFAULT 0, total_requests INTEGER DEFAULT 0,
        last_reset TEXT, created_at TEXT NOT NULL, expires_at TEXT NOT NULL,
        is_active INTEGER DEFAULT 1)""")
    c.execute("""CREATE TABLE IF NOT EXISTS pending_payments (
        id INTEGER PRIMARY KEY AUTOINCREMENT, user_id INTEGER NOT NULL,
        username TEXT, tier TEXT NOT NULL, payment_method TEXT NOT NULL,
        amount TEXT NOT NULL, payment_ref TEXT UNIQUE NOT NULL,
        status TEXT DEFAULT 'pending', created_at TEXT NOT NULL)""")
    c.execute("""CREATE TABLE IF NOT EXISTS user_connections (
        id INTEGER PRIMARY KEY AUTOINCREMENT, user_id INTEGER NOT NULL,
        username TEXT, integration TEXT NOT NULL, access_token TEXT,
        refresh_token TEXT, extra_data TEXT, connected_at TEXT NOT NULL,
        is_active INTEGER DEFAULT 1, UNIQUE(user_id, integration))""")
    c.execute("""CREATE TABLE IF NOT EXISTS oauth_states (
        state TEXT PRIMARY KEY, user_id INTEGER NOT NULL,
        integration TEXT NOT NULL, created_at TEXT NOT NULL)""")
    c.execute("""CREATE TABLE IF NOT EXISTS aviator_players (
        user_id INTEGER PRIMARY KEY, username TEXT, balance REAL DEFAULT 100.0,
        total_bets INTEGER DEFAULT 0, total_wins INTEGER DEFAULT 0,
        total_wagered REAL DEFAULT 0.0, total_won REAL DEFAULT 0.0,
        current_streak INTEGER DEFAULT 0, best_multiplier REAL DEFAULT 0.0,
        auto_bet_active INTEGER DEFAULT 0, auto_bet_amount REAL DEFAULT 1.0,
        auto_bet_cashout REAL DEFAULT 2.0, auto_bet_strategy TEXT DEFAULT 'fixed',
        created_at TEXT NOT NULL)""")
    c.execute("""CREATE TABLE IF NOT EXISTS aviator_history (
        id INTEGER PRIMARY KEY AUTOINCREMENT, user_id INTEGER NOT NULL,
        bet_amount REAL NOT NULL, cashout_at REAL, crash_at REAL NOT NULL,
        profit REAL NOT NULL, balance_after REAL NOT NULL,
        timestamp TEXT NOT NULL)""")
    conn.commit()
    conn.close()

def _hub_conn(): return sqlite3.connect(HUB_DB)

def hub_generate_api_key():
    raw = secrets.token_hex(24)
    return f"CM-{raw[:8]}-{raw[8:16]}-{raw[16:24]}".upper()

def hub_create_api_key(user_id, username, tier):
    from datetime import timedelta
    t = API_TIERS[tier]
    key = hub_generate_api_key()
    now = datetime.datetime.now().isoformat()
    exp = (datetime.datetime.now() + timedelta(days=t["validity_days"])).isoformat()
    conn = _hub_conn()
    c = conn.cursor()
    c.execute("INSERT INTO api_keys (api_key,user_id,username,tier,features,requests_per_day,last_reset,created_at,expires_at) VALUES (?,?,?,?,?,?,?,?,?)",
              (key, user_id, username, tier, ",".join(t["features"]), t["requests_per_day"], now, now, exp))
    conn.commit(); conn.close()
    return key

def hub_get_key_info(api_key):
    conn = _hub_conn(); c = conn.cursor()
    c.execute("SELECT * FROM api_keys WHERE api_key=?", (api_key,))
    row = c.fetchone(); conn.close()
    if not row: return None
    cols = ["id","api_key","user_id","username","tier","features","requests_per_day","requests_used_today","total_requests","last_reset","created_at","expires_at","is_active"]
    return dict(zip(cols, row))

def hub_validate_key(api_key, feature):
    info = hub_get_key_info(api_key)
    if not info: return False, "Invalid API key"
    if not info["is_active"]: return False, "Deactivated"
    if datetime.datetime.fromisoformat(info["expires_at"]) < datetime.datetime.now(): return False, "Expired"
    if feature not in info["features"].split(","): return False, f"Tier doesn't include '{feature}'"
    conn = _hub_conn(); c = conn.cursor()
    lr = datetime.datetime.fromisoformat(info["last_reset"])
    if lr.date() < datetime.datetime.now().date():
        c.execute("UPDATE api_keys SET requests_used_today=0,last_reset=? WHERE api_key=?", (datetime.datetime.now().isoformat(), api_key))
        info["requests_used_today"] = 0
    if info["requests_used_today"] >= info["requests_per_day"]:
        conn.close(); return False, "Daily limit reached"
    c.execute("UPDATE api_keys SET requests_used_today=requests_used_today+1,total_requests=total_requests+1 WHERE api_key=?", (api_key,))
    conn.commit(); conn.close()
    return True, "OK"

def hub_get_user_keys(user_id):
    conn = _hub_conn(); c = conn.cursor()
    c.execute("SELECT api_key,tier,expires_at,requests_used_today,requests_per_day,is_active FROM api_keys WHERE user_id=?", (user_id,))
    rows = c.fetchall(); conn.close(); return rows

def hub_add_pending(user_id, username, tier, method, amount, ref):
    conn = _hub_conn(); c = conn.cursor()
    c.execute("INSERT INTO pending_payments (user_id,username,tier,payment_method,amount,payment_ref,created_at) VALUES (?,?,?,?,?,?,?)",
              (user_id, username, tier, method, amount, ref, datetime.datetime.now().isoformat()))
    conn.commit(); conn.close()

def hub_save_connection(user_id, username, integration, access_token, refresh_token=None, extra=None):
    conn = _hub_conn(); c = conn.cursor()
    c.execute("INSERT OR REPLACE INTO user_connections (user_id,username,integration,access_token,refresh_token,extra_data,connected_at,is_active) VALUES (?,?,?,?,?,?,?,1)",
              (user_id, username, integration, access_token, refresh_token, json.dumps(extra) if extra else None, datetime.datetime.now().isoformat()))
    conn.commit(); conn.close()

def hub_get_connection(user_id, integration):
    conn = _hub_conn(); c = conn.cursor()
    c.execute("SELECT access_token,refresh_token,extra_data FROM user_connections WHERE user_id=? AND integration=? AND is_active=1", (user_id, integration))
    row = c.fetchone(); conn.close()
    if not row: return None
    return {"access_token": row[0], "refresh_token": row[1], "extra_data": json.loads(row[2]) if row[2] else {}}

def hub_get_all_connections(user_id):
    conn = _hub_conn(); c = conn.cursor()
    c.execute("SELECT integration,connected_at FROM user_connections WHERE user_id=? AND is_active=1", (user_id,))
    rows = c.fetchall(); conn.close(); return rows

def hub_disconnect(user_id, integration):
    conn = _hub_conn(); c = conn.cursor()
    c.execute("UPDATE user_connections SET is_active=0 WHERE user_id=? AND integration=?", (user_id, integration))
    conn.commit(); conn.close()

def hub_save_oauth_state(state, user_id, integration):
    conn = _hub_conn(); c = conn.cursor()
    c.execute("INSERT OR REPLACE INTO oauth_states VALUES (?,?,?,?)", (state, user_id, integration, datetime.datetime.now().isoformat()))
    conn.commit(); conn.close()

def hub_get_oauth_state(state):
    conn = _hub_conn(); c = conn.cursor()
    c.execute("SELECT user_id,integration FROM oauth_states WHERE state=?", (state,))
    row = c.fetchone(); conn.close(); return row

