def _connect_menu_keyboard():
    """Build the main /connect app-picker keyboard."""
    keyboard = []
    row = []
    for i, (aid, app) in enumerate(INTEGRATIONS.items()):
        row.append(InlineKeyboardButton(app["name"], callback_data=f"intapp_{aid}"))
        if len(row) == 2:
            keyboard.append(row)
            row = []
    if row:
        keyboard.append(row)
    keyboard.append([InlineKeyboardButton("📋 My Connections", callback_data="int_myconn")])
    return InlineKeyboardMarkup(keyboard)


async def cmd_connect(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """/connect — Show Integration Hub menu."""
    try:
        await update.message.reply_text(
            "🔌 *CineMagic Integration Hub*\n\n"
            "Connect your apps and control everything from Telegram!\n\n"
            "📱 *Available Apps:* " + str(len(INTEGRATIONS)) + "\n"
            "✅ Token-based apps work instantly\n"
            "🔐 OAuth apps need credentials in .env\n\n"
            "👇 Choose an app to connect:",
            reply_markup=_connect_menu_keyboard(),
            parse_mode="Markdown"
        )
    except Exception as e:
        await update.message.reply_text(f"❌ Error opening hub: {e}")


async def cb_intapp(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Show details + connect/use buttons for a specific app."""
    q = update.callback_query
    await q.answer()
    try:
        aid  = q.data.replace("intapp_", "").strip()
        app  = INTEGRATIONS.get(aid)
        if not app:
            await q.edit_message_text("❌ Unknown app. Use /connect to try again.",
                                      reply_markup=InlineKeyboardMarkup([[InlineKeyboardButton("◀️ Back", callback_data="int_back")]]))
            return

        # Safe DB call
        try:
            existing = hub_get_connection(q.from_user.id, aid)
        except Exception:
            existing = None

        status  = "✅ *Connected*" if existing else "❌ Not connected"
        method  = "🔐 OAuth Login" if app["method"] == "oauth" else "🔑 API Token"
        acts    = "\n".join([f"  • {a.replace('_', ' ').title()}" for a in app["actions"]])

        # Determine if OAuth is actually configured
        oauth_ready = False
        if app["method"] == "oauth":
            p = app.get("provider", "")
            if p == "google"   and GOOGLE_CLIENT_ID:   oauth_ready = True
            if p == "facebook" and FB_APP_ID:           oauth_ready = True
            if p == "slack"    and SLACK_CLIENT_ID:     oauth_ready = True
            if p == "spotify"  and SPOTIFY_CLIENT_ID:   oauth_ready = True

        kb = []
        if app["method"] == "oauth":
            if oauth_ready:
                kb.append([InlineKeyboardButton("🔐 Connect via OAuth", callback_data=f"intoauth_{aid}")])
            else:
                kb.append([InlineKeyboardButton("⚠️ OAuth Not Configured", callback_data=f"intoauth_info_{aid}")])
        else:
            kb.append([InlineKeyboardButton("🔑 Connect via Token", callback_data=f"inttoken_{aid}")])

        if existing:
            kb.append([InlineKeyboardButton("⚡ Use This App", callback_data=f"intuse_{aid}")])
            kb.append([InlineKeyboardButton("🗑️ Disconnect", callback_data=f"intdis_{aid}")])

        kb.append([InlineKeyboardButton("◀️ Back to Apps", callback_data="int_back")])

        connected_txt = f"\n\n📅 Connected: {str(existing.get('connected_at',''))[:10]}" if existing and isinstance(existing, dict) else ""
        await q.edit_message_text(
            f"{app['emoji']} *{app['name']}*\n\n"
            f"Status: {status}\n"
            f"Method: {method}\n\n"
            f"📋 *Actions available:*\n{acts}"
            f"{connected_txt}",
            reply_markup=InlineKeyboardMarkup(kb),
            parse_mode="Markdown"
        )
    except Exception as e:
        try:
            await q.edit_message_text(
                f"❌ *Error loading app info*\n\n`{str(e)}`\n\nTry /connect again.",
                reply_markup=InlineKeyboardMarkup([[InlineKeyboardButton("◀️ Back", callback_data="int_back")]]),
                parse_mode="Markdown"
            )
        except Exception:
            pass


async def cb_intoauth(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Handle OAuth connect button."""
    q = update.callback_query
    await q.answer()
    try:
        # Handle info-only (not configured)
        if q.data.startswith("intoauth_info_"):
            aid = q.data.replace("intoauth_info_", "")
            app = INTEGRATIONS.get(aid, {})
            p   = app.get("provider", "")
            env_map = {
                "google":   "GOOGLE_CLIENT_ID + GOOGLE_CLIENT_SECRET",
                "facebook": "FB_APP_ID + FB_APP_SECRET",
                "slack":    "SLACK_CLIENT_ID + SLACK_CLIENT_SECRET",
                "spotify":  "SPOTIFY_CLIENT_ID + SPOTIFY_CLIENT_SECRET",
            }
            needed = env_map.get(p, "credentials")
            await q.edit_message_text(
                f"⚠️ *OAuth Not Configured*\n\n"
                f"{app.get('emoji','')} *{app.get('name',aid)}* uses OAuth login.\n\n"
                f"To enable it, add these to your `.env` file:\n"
                f"`{needed}`\n\n"
                f"Then restart the bot.",
                reply_markup=InlineKeyboardMarkup([[InlineKeyboardButton("◀️ Back", callback_data=f"intapp_{aid}")]]),
                parse_mode="Markdown"
            )
            return

        aid  = q.data.replace("intoauth_", "")
        app  = INTEGRATIONS.get(aid)
        if not app:
            await q.edit_message_text("❌ App not found."); return

        user     = q.from_user
        state    = secrets.token_hex(16)
        hub_save_oauth_state(state, user.id, aid)
        provider = app.get("provider")

        if provider == "google":
            params = {"client_id": GOOGLE_CLIENT_ID,
                      "redirect_uri": f"{BASE_URL}/oauth/google/callback",
                      "response_type": "code", "scope": GOOGLE_SCOPES,
                      "access_type": "offline", "state": state, "prompt": "consent"}
            url = "https://accounts.google.com/o/oauth2/v2/auth?" + urlencode(params)
        elif provider == "facebook":
            params = {"client_id": FB_APP_ID,
                      "redirect_uri": f"{BASE_URL}/oauth/facebook/callback",
                      "response_type": "code", "scope": "email,public_profile", "state": state}
            url = "https://www.facebook.com/v18.0/dialog/oauth?" + urlencode(params)
        elif provider == "slack":
            params = {"client_id": SLACK_CLIENT_ID,
                      "redirect_uri": f"{BASE_URL}/oauth/slack/callback",
                      "scope": "chat:write,channels:read", "state": state}
            url = "https://slack.com/oauth/v2/authorize?" + urlencode(params)
        elif provider == "spotify":
            params = {"client_id": SPOTIFY_CLIENT_ID, "response_type": "code",
                      "redirect_uri": f"{BASE_URL}/oauth/spotify/callback",
                      "scope": "user-read-playback-state user-modify-playback-state user-read-currently-playing",
                      "state": state}
            url = "https://accounts.spotify.com/authorize?" + urlencode(params)
        else:
            await q.edit_message_text(
                f"❌ OAuth not configured for *{app['name']}* yet.\n\nAdd credentials to your .env file.",
                reply_markup=InlineKeyboardMarkup([[InlineKeyboardButton("◀️ Back", callback_data=f"intapp_{aid}")]]),
                parse_mode="Markdown"
            )
            return

        kb = [
            [InlineKeyboardButton(f"🔐 Login with {app['name']}", url=url)],
            [InlineKeyboardButton("◀️ Back", callback_data=f"intapp_{aid}")]
        ]
        await q.edit_message_text(
            f"🔐 *Connect {app['name']}*\n\n"
            f"Tap the button below to securely log in.\n"
            f"You'll be redirected back automatically. ✅",
            reply_markup=InlineKeyboardMarkup(kb),
            parse_mode="Markdown"
        )
    except Exception as e:
        try:
            await q.edit_message_text(f"❌ OAuth error: `{e}`\n\nTry /connect again.",
                                      parse_mode="Markdown")
        except Exception:
            pass


