async def cb_intaction(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Execute an action for a connected app."""
    q = update.callback_query
    await q.answer("⏳ Working...")
    try:
        # callback_data format: intact_<aid>_<action>
        raw    = q.data[len("intact_"):]
        # aid can have underscore (e.g. "gcalendar"), action too — split on first underscore after aid
        # We stored aid without underscores in most cases, but gcalendar has none
        # Best approach: find the aid from INTEGRATIONS keys
        aid    = None
        action = None
        for key in INTEGRATIONS:
            if raw.startswith(key + "_"):
                aid    = key
                action = raw[len(key)+1:]
                break
        if not aid:
            await q.edit_message_text("❌ Could not parse action."); return

        app = INTEGRATIONS[aid]
        try:
            conn_data = hub_get_connection(q.from_user.id, aid)
        except Exception:
            conn_data = None
        token = conn_data.get("access_token") if isinstance(conn_data, dict) else (conn_data[3] if conn_data else None)

        kb_back = [[InlineKeyboardButton("◀️ Back", callback_data=f"intuse_{aid}")]]
        result  = None

        # ── Actions that need user input — store state and ask ──
        INPUT_ACTIONS = {"send_email", "send_message", "post_status", "post_tweet",
                         "post_update", "create_page", "create_event", "create_issue",
                         "send_template", "broadcast", "search_email", "search_music",
                         "search_tweets", "search_videos", "search_pages", "play_song"}
        if action in INPUT_ACTIONS:
            context.user_data[INT_AWAITING_ACTION] = {"aid": aid, "action": action}
            prompts = {
                "send_message":  "✏️ Type the message to send:",
                "send_email":    "✏️ Type: `recipient@email.com | Subject | Message body`",
                "post_status":   "✏️ Type your Facebook post:",
                "post_tweet":    "✏️ Type your tweet (max 280 chars):",
                "post_update":   "✏️ Type your LinkedIn update:",
                "create_page":   "✏️ Type the page title:",
                "create_event":  "✏️ Type: `Event Title | YYYY-MM-DD HH:MM`",
                "create_issue":  "✏️ Type: `repo-name | Issue Title | Description`",
                "send_template": "✏️ Type: `phone_number | template_name`",
                "broadcast":     "✏️ Type the broadcast message:",
                "search_email":  "✏️ Type your search query:",
                "search_music":  "✏️ Type song or artist name:",
                "search_tweets": "✏️ Type your search query:",
                "search_videos": "✏️ Type your search query:",
                "search_pages":  "✏️ Type your search query:",
                "play_song":     "✏️ Type song or artist to play on Spotify:",
            }
            prompt = prompts.get(action, "✏️ Type your input:")
            kb_cancel = [[InlineKeyboardButton("❌ Cancel", callback_data=f"intuse_{aid}")]]
            await q.edit_message_text(
                f"{app['emoji']} *{app['name']}* → *{action.replace('_',' ').title()}*\n\n{prompt}",
                reply_markup=InlineKeyboardMarkup(kb_cancel),
                parse_mode="Markdown"
            )
            return

        # ── Direct actions (read/fetch) ──
        if not token:
            await q.edit_message_text(
                f"❌ *Not connected to {app['name']}*\n\nReconnect via /connect → {app['name']} → Connect.",
                reply_markup=InlineKeyboardMarkup(kb_back), parse_mode="Markdown"
            )
            return

        if aid == "gmail" and action == "read_inbox":
            r    = requests.get("https://gmail.googleapis.com/gmail/v1/users/me/messages?maxResults=5&labelIds=INBOX",
                                headers={"Authorization": f"Bearer {token}"}, timeout=10)
            data = r.json()
            if "error" in data:
                result = f"❌ Gmail error: {data['error'].get('message','Unknown')}"
            else:
                msgs = data.get("messages", [])
                result = f"📧 *Inbox — {len(msgs)} messages*\n\n" + "\n".join([f"• ID: `{m['id']}`" for m in msgs]) if msgs else "📧 Inbox is empty."

        elif aid == "gcalendar" and action == "list_events":
            now  = datetime.datetime.utcnow().isoformat() + "Z"
            r    = requests.get(f"https://www.googleapis.com/calendar/v3/calendars/primary/events?maxResults=5&timeMin={now}&orderBy=startTime&singleEvents=true",
                                headers={"Authorization": f"Bearer {token}"}, timeout=10)
            data = r.json()
            if "error" in data:
                result = f"❌ Calendar error: {data['error'].get('message','Unknown')}"
            else:
                items  = data.get("items", [])
                if items:
                    lines  = [f"• *{e.get('summary','No title')}* — {e.get('start',{}).get('dateTime','?')[:16]}" for e in items]
                    result = "📅 *Upcoming Events:*\n\n" + "\n".join(lines)
                else:
                    result = "📅 No upcoming events found."

        elif aid == "github" and action == "list_repos":
            r     = requests.get("https://api.github.com/user/repos?per_page=8&sort=updated",
                                 headers={"Authorization": f"token {token}", "Accept": "application/vnd.github+json"}, timeout=10)
            repos = r.json()
            if isinstance(repos, dict) and "message" in repos:
                result = f"❌ GitHub: {repos['message']}"
            else:
                result = "🐙 *Your Repositories:*\n\n" + "\n".join([f"• [{r.get('name','?')}]({r.get('html_url','#')}) ⭐{r.get('stargazers_count',0)}" for r in repos[:8]])

        elif aid == "github" and action == "list_issues":
            r      = requests.get("https://api.github.com/issues?state=open&per_page=5",
                                  headers={"Authorization": f"token {token}", "Accept": "application/vnd.github+json"}, timeout=10)
            issues = r.json()
            if isinstance(issues, dict):
                result = f"❌ GitHub: {issues.get('message','Error')}"
            else:
                result = "🐛 *Open Issues:*\n\n" + "\n".join([f"• #{i.get('number')} {i.get('title','?')}" for i in issues[:5]]) if issues else "✅ No open issues."

        elif aid == "spotify" and action == "get_current":
            r = requests.get("https://api.spotify.com/v1/me/player/currently-playing",
                             headers={"Authorization": f"Bearer {token}"}, timeout=10)
            if r.status_code == 204:
                result = "🎵 Nothing is playing right now on Spotify."
            elif r.status_code == 200:
                d      = r.json()
                track  = d.get("item", {})
                artist = track.get("artists", [{}])[0].get("name", "?")
                name   = track.get("name", "?")
                prog   = d.get("progress_ms", 0) // 1000
                result = f"🎵 *Now Playing on Spotify:*\n\n🎤 {name}\n👤 {artist}\n⏱ {prog//60}:{prog%60:02d}"
            else:
                result = f"❌ Spotify error: {r.status_code}"

        elif aid == "discord" and action == "list_servers":
            r     = requests.get("https://discord.com/api/v10/users/@me/guilds",
                                 headers={"Authorization": f"Bot {token}"}, timeout=10)
            guilds = r.json()
            if isinstance(guilds, dict) and "message" in guilds:
                result = f"❌ Discord: {guilds['message']}"
            else:
                result = "🎮 *Your Discord Servers:*\n\n" + "\n".join([f"• {g.get('name','?')}" for g in guilds[:8]])

        elif aid == "discord" and action == "read_messages":
            result = "📨 *Discord Message Reader*\n\nTo read messages, use the send_message action to interact with specific channels."

        elif aid == "notion" and action == "read_pages":
            r     = requests.post("https://api.notion.com/v1/search",
                                  headers={"Authorization": f"Bearer {token}", "Notion-Version": "2022-06-28", "Content-Type": "application/json"},
                                  json={"filter": {"value": "page", "property": "object"}, "page_size": 5}, timeout=10)
            data  = r.json()
            if "object" in data and data["object"] == "error":
                result = f"❌ Notion: {data.get('message','Unknown error')}"
            else:
                pages  = data.get("results", [])
                titles = []
                for p in pages:
                    title_arr = p.get("properties", {}).get("title", {}).get("title", [])
                    title     = title_arr[0]["plain_text"] if title_arr else "Untitled"
                    titles.append(f"• 📄 {title}")
                result = "📓 *Your Notion Pages:*\n\n" + "\n".join(titles) if titles else "📓 No pages found."

        elif aid == "twitter" and action == "read_timeline":
            r    = requests.get("https://api.twitter.com/2/users/me",
                                headers={"Authorization": f"Bearer {token}"}, timeout=10)
            data = r.json()
            if "errors" in data:
                result = f"❌ Twitter: {data['errors'][0].get('detail','Unknown error')}"
            else:
                uid  = data.get("data", {}).get("id")
                name = data.get("data", {}).get("name", "?")
                un   = data.get("data", {}).get("username", "?")
                result = f"🐦 *Connected as:*\n\n👤 {name} (@{un})\nID: `{uid}`\n\n_Use post\\_tweet to tweet from Telegram!_"

        elif aid == "telegram" and action == "get_bot_info":
            r = await asyncio.get_running_loop().run_in_executor(None, lambda: requests.get(f"https://api.telegram.org/bot{token}/getMe", timeout=10))
            data = r.json()
            if data.get("ok"):
                b    = data["result"]
                result = f"✈️ *Bot Info:*\n\n🤖 Name: {b.get('first_name','?')}\n🔗 Username: @{b.get('username','?')}\nID: `{b.get('id','?')}`"
            else:
                result = f"❌ Telegram: {data.get('description','Invalid token')}"

        elif aid == "youtube" and action == "get_trending":
            if not token:
                result = "❌ YouTube API key not set."
            else:
                r = await asyncio.get_running_loop().run_in_executor(None, lambda: requests.get(f"https://www.googleapis.com/youtube/v3/videos?part=snippet&chart=mostPopular&maxResults=5&key={token}", timeout=10))
                data = r.json()
                if "error" in data:
                    result = f"❌ YouTube: {data['error'].get('message','Error')}"
                else:
                    items  = data.get("items", [])
                    result = "▶️ *Trending on YouTube:*\n\n" + "\n".join([f"• {v['snippet']['title']}" for v in items])

        elif aid == "facebook" and action == "get_profile":
            r = await asyncio.get_running_loop().run_in_executor(None, lambda: requests.get(f"https://graph.facebook.com/me?fields=name,email,id&access_token={token}", timeout=10))
            data = r.json()
            if "error" in data:
                result = f"❌ Facebook: {data['error'].get('message','Error')}"
            else:
                result = f"📘 *Facebook Profile:*\n\n👤 {data.get('name','?')}\n📧 {data.get('email','N/A')}\nID: `{data.get('id','?')}`"

        elif aid == "instagram" and action == "get_profile":
            r = await asyncio.get_running_loop().run_in_executor(None, lambda: requests.get(f"https://graph.instagram.com/me?fields=id,username,followers_count,media_count&access_token={token}", timeout=10))
            data = r.json()
            if "error" in data:
                result = f"❌ Instagram: {data['error'].get('message','Error')}"
            else:
                result = (f"📸 *Instagram Profile:*\n\n"
                          f"👤 @{data.get('username','?')}\n"
                          f"👥 Followers: {data.get('followers_count','?')}\n"
                          f"🖼 Posts: {data.get('media_count','?')}")

        elif aid == "linkedin" and action == "get_profile":
            r    = requests.get("https://api.linkedin.com/v2/me",
                                headers={"Authorization": f"Bearer {token}"}, timeout=10)
            data = r.json()
            fname = data.get("localizedFirstName", "?")
            lname = data.get("localizedLastName", "?")
            lid   = data.get("id", "?")
            result = f"🔗 *LinkedIn Profile:*\n\n👤 {fname} {lname}\nID: `{lid}`"

        elif aid == "slack" and action == "list_channels":
            r    = requests.get("https://slack.com/api/conversations.list?limit=8",
                                headers={"Authorization": f"Bearer {token}"}, timeout=10)
            data = r.json()
            if not data.get("ok"):
                result = f"❌ Slack: {data.get('error','Unknown error')}"
            else:
                chans  = data.get("channels", [])
                result = "💼 *Slack Channels:*\n\n" + "\n".join([f"• #{c.get('name','?')}" for c in chans])

        else:
            result = (f"⚡ *{action.replace('_',' ').title()}* — {app['name']}\n\n"
                      f"✅ Connected and ready!\n\n"
                      f"_This action is available. Type your input to proceed._")

        if result:
            await q.edit_message_text(result[:4000], reply_markup=InlineKeyboardMarkup(kb_back), parse_mode="Markdown")

    except Exception as e:
        try:
            await q.edit_message_text(
                f"❌ *Action failed*\n\n`{str(e)[:200]}`\n\nTry reconnecting via /connect.",
                reply_markup=InlineKeyboardMarkup([[InlineKeyboardButton("◀️ Back", callback_data=f"intuse_{q.data.split('_')[1] if '_' in q.data else 'back'}")]]),
                parse_mode="Markdown"
            )
        except Exception:
            pass


async def cb_intdis(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Disconnect an app."""
    q = update.callback_query
    await q.answer()
    try:
        aid  = q.data.replace("intdis_", "").strip()
        app  = INTEGRATIONS.get(aid, {})
        hub_disconnect(q.from_user.id, aid)
        await q.edit_message_text(
            f"🗑️ *{app.get('name', aid)} disconnected.*\n\nYou can reconnect anytime via /connect.",
            reply_markup=InlineKeyboardMarkup([[InlineKeyboardButton("◀️ Back to Apps", callback_data="int_back")]]),
            parse_mode="Markdown"
        )
    except Exception as e:
        try:
            await q.edit_message_text(f"❌ Error disconnecting: `{e}`", parse_mode="Markdown")
        except Exception:
            pass


