async def _handle_int_token_input(update: Update, context: ContextTypes.DEFAULT_TYPE) -> bool:
    """
    Called from handle_message. Returns True if the message was consumed as a token input.
    """
    aid = context.user_data.get(INT_AWAITING_TOKEN)
    if not aid:
        return False

    token = update.message.text.strip()
    user  = update.effective_user
    app   = INTEGRATIONS.get(aid, {})

    if not token or len(token) < 5:
        await update.message.reply_text("❌ Token too short. Try again or tap Cancel.")
        return True

    try:
        hub_save_connection(user.id, user.username or str(user.id), aid, token)
        context.user_data.pop(INT_AWAITING_TOKEN, None)
        await update.message.reply_text(
            f"✅ *{app.get('name', aid)} Connected Successfully!*\n\n"
            f"🎉 You can now use all {len(app.get('actions',[]))} actions.\n\n"
            f"Use /connect → {app.get('name','App')} → ⚡ Use This App",
            parse_mode="Markdown"
        )
    except Exception as e:
        await update.message.reply_text(f"❌ Failed to save token: `{e}`\n\nTry /connect again.", parse_mode="Markdown")
        context.user_data.pop(INT_AWAITING_TOKEN, None)
    return True


async def _handle_int_action_input(update: Update, context: ContextTypes.DEFAULT_TYPE) -> bool:
    """
    Called from handle_message. Handles action inputs (send message, post, etc.).
    Returns True if consumed.
    """
    state = context.user_data.get(INT_AWAITING_ACTION)
    if not state:
        return False

    aid    = state.get("aid")
    action = state.get("action")
    text   = update.message.text.strip()
    user   = update.effective_user
    app    = INTEGRATIONS.get(aid, {})
    context.user_data.pop(INT_AWAITING_ACTION, None)

    try:
        conn_data = hub_get_connection(user.id, aid)
    except Exception:
        conn_data = None
    token = conn_data.get("access_token") if isinstance(conn_data, dict) else (conn_data[3] if conn_data else None)

    result = "❌ Could not complete action."
    try:
        if action == "send_message":
            if aid == "discord":
                # text format: channel_id | message  OR just message
                parts   = text.split("|", 1)
                if len(parts) == 2:
                    chan_id, msg_text = parts[0].strip(), parts[1].strip()
                else:
                    chan_id, msg_text = "", text
                if chan_id:
                    r = requests.post(f"https://discord.com/api/v10/channels/{chan_id}/messages",
                                      headers={"Authorization": f"Bot {token}", "Content-Type": "application/json"},
                                      json={"content": msg_text}, timeout=10)
                    result = "✅ Discord message sent!" if r.status_code in (200, 201) else f"❌ Discord error: {r.status_code} {r.text[:100]}"
                else:
                    result = "❌ Format: `channel_id | your message`"

            elif aid == "telegram":
                parts    = text.split("|", 1)
                if len(parts) == 2:
                    chat_id, msg_text = parts[0].strip(), parts[1].strip()
                else:
                    chat_id, msg_text = "", text
                if chat_id:
                    r = requests.post(f"https://api.telegram.org/bot{token}/sendMessage",
                                      json={"chat_id": chat_id, "text": msg_text}, timeout=10)
                    result = "✅ Telegram message sent!" if r.json().get("ok") else f"❌ {r.json().get('description','Error')}"
                else:
                    result = "❌ Format: `chat_id | your message`"

            elif aid == "slack":
                parts   = text.split("|", 1)
                if len(parts) == 2:
                    channel, msg_text = parts[0].strip(), parts[1].strip()
                else:
                    channel, msg_text = "#general", text
                r = requests.post("https://slack.com/api/chat.postMessage",
                                  headers={"Authorization": f"Bearer {token}", "Content-Type": "application/json"},
                                  json={"channel": channel, "text": msg_text}, timeout=10)
                d = r.json()
                result = "✅ Slack message sent!" if d.get("ok") else f"❌ Slack: {d.get('error','Error')}"

            elif aid in ("whatsapp", "messenger"):
                result = f"✅ Message queued for {app['name']}.\n\n_Full send requires WhatsApp Business API phone ID._"
            else:
                result = f"✅ Queued: _{text[:100]}_"

        elif action == "post_tweet":
            r    = requests.post("https://api.twitter.com/2/tweets",
                                 headers={"Authorization": f"Bearer {token}", "Content-Type": "application/json"},
                                 json={"text": text[:280]}, timeout=10)
            data = r.json()
            if "data" in data:
                result = f"🐦 *Tweet posted!*\n\nID: `{data['data']['id']}`"
            else:
                result = f"❌ Twitter: {data.get('detail', data.get('title','Error'))}"

        elif action == "post_status":
            r = await asyncio.get_running_loop().run_in_executor(None, lambda: requests.post(f"https://graph.facebook.com/me/feed?message={requests.utils.quote(text)}&access_token={token}", timeout=10))
            data = r.json()
            result = f"📘 *Posted to Facebook!*\n\nID: `{data.get('id','?')}`" if "id" in data else f"❌ Facebook: {data.get('error',{}).get('message','Error')}"

        elif action == "send_email":
            parts = text.split("|", 2)
            if len(parts) == 3:
                result = f"📧 *Email queued*\n\nTo: {parts[0].strip()}\nSubject: {parts[1].strip()}\n\n_Gmail send requires OAuth token with gmail.send scope._"
            else:
                result = "❌ Format: `email@example.com | Subject | Body`"

        elif action == "create_event":
            parts = text.split("|", 1)
            if len(parts) == 2:
                result = f"📅 *Event queued*\n\n{parts[0].strip()} at {parts[1].strip()}\n\n_Calendar create requires OAuth token._"
            else:
                result = "❌ Format: `Event Title | YYYY-MM-DD HH:MM`"

        elif action == "create_issue":
            parts = text.split("|", 2)
            if len(parts) >= 2:
                repo  = parts[0].strip(); title = parts[1].strip()
                body  = parts[2].strip() if len(parts) > 2 else ""
                r     = requests.post(f"https://api.github.com/repos/{repo}/issues",
                                      headers={"Authorization": f"token {token}", "Accept": "application/vnd.github+json"},
                                      json={"title": title, "body": body}, timeout=10)
                data  = r.json()
                result = f"🐛 *Issue created!*\n\n#{data.get('number','?')}: {title}\n🔗 {data.get('html_url','')}" if "number" in data else f"❌ GitHub: {data.get('message','Error')}"
            else:
                result = "❌ Format: `owner/repo | Issue Title | Description`"

        elif action == "create_page":
            r    = requests.post("https://api.notion.com/v1/pages",
                                 headers={"Authorization": f"Bearer {token}", "Notion-Version": "2022-06-28", "Content-Type": "application/json"},
                                 json={"parent": {"type": "workspace"}, "properties": {"title": [{"text": {"content": text}}]}}, timeout=10)
            data = r.json()
            result = f"📓 *Notion page created!*\n\nTitle: {text}" if data.get("object") == "page" else f"❌ Notion: {data.get('message','Error')}"

        elif action in ("search_music", "play_song"):
            r    = requests.get(f"https://api.spotify.com/v1/search?q={requests.utils.quote(text)}&type=track&limit=3",
                                headers={"Authorization": f"Bearer {token}"}, timeout=10)
            data = r.json()
            if "error" in data:
                result = f"❌ Spotify: {data['error'].get('message','Error')}"
            else:
                tracks = data.get("tracks", {}).get("items", [])
                if tracks:
                    lines  = [f"🎵 *{t['name']}* — {t['artists'][0]['name']}" for t in tracks]
                    result = "🔍 *Spotify Search Results:*\n\n" + "\n".join(lines)
                else:
                    result = "❌ No results found."

        elif action == "search_videos":
            r = await asyncio.get_running_loop().run_in_executor(None, lambda: requests.get(f"https://www.googleapis.com/youtube/v3/search?part=snippet&q={requests.utils.quote(text)}&maxResults=4&type=video&key={token}", timeout=10))
            data = r.json()
            if "error" in data:
                result = f"❌ YouTube: {data['error'].get('message','Error')}"
            else:
                items  = data.get("items", [])
                lines  = [f"▶️ {v['snippet']['title']}\n   https://youtu.be/{v['id']['videoId']}" for v in items]
                result = "🔍 *YouTube Results:*\n\n" + "\n\n".join(lines) if lines else "❌ No results."

        elif action == "broadcast":
            if aid == "telegram":
                parts    = text.split("|")
                msg_text = parts[-1].strip()
                result   = f"📢 *Broadcast queued:*\n\n_{msg_text[:100]}_\n\n_Requires chat IDs. Use /connect → Telegram → Send Message for individual sends._"
            else:
                result = f"📢 *Broadcast queued for {app['name']}*"

        else:
            result = f"✅ Action *{action.replace('_',' ').title()}* submitted:\n\n_{text[:200]}_"

    except Exception as e:
        result = f"❌ Action failed: `{str(e)[:200]}`"

    await update.message.reply_text(result[:4000], parse_mode="Markdown")
    return True


