# ══════════════════════════════════════════════════════════════════════════
#  🎵  MUSIC GENERATION
# ══════════════════════════════════════════════════════════════════════════
# ── Suno AI Config ────────────────────────────────────────────────────────
SUNO_API_KEY  = os.getenv("SUNO_API_KEY", "")   # Get from suno.com/account
SUNO_BASE_URL = "https://studio-api.suno.ai/api"

def _music_suno(prompt: str, with_lyrics: bool = True) -> tuple:
    """
    Generate real AI song with vocals using Suno AI.
    Returns (audio_bytes, title, tags) or (None, None, None)
    """
    import time as _time
    if not SUNO_API_KEY:
        logging.warning("⚠️ SUNO_API_KEY not set")
        return None, None, None
    try:
        headers = {
            "Authorization": f"Bearer {SUNO_API_KEY}",
            "Content-Type": "application/json"
        }
        # Step 1: Generate song
        payload = {
            "prompt": prompt,
            "make_instrumental": not with_lyrics,
            "wait_audio": False
        }
        resp = requests.post(
            f"{SUNO_BASE_URL}/generate/",
            headers=headers,
            json=payload,
            timeout=30
        )
        if resp.status_code not in (200, 201):
            logging.error(f"Suno generate error: {resp.status_code} {resp.text[:200]}")
            return None, None, None

        data = resp.json()
        # Suno returns list of clips
        clips = data if isinstance(data, list) else data.get("clips", [])
        if not clips:
            logging.error("Suno returned no clips")
            return None, None, None

        clip_id = clips[0].get("id")
        if not clip_id:
            return None, None, None

        logging.info(f"🎵 Suno clip started: {clip_id}")

        # Step 2: Poll for completion (max 5 mins)
        for attempt in range(60):
            __import__("time").sleep(5)
            poll = requests.get(
                f"{SUNO_BASE_URL}/feed/?ids={clip_id}",
                headers=headers,
                timeout=15
            )
            if poll.status_code != 200:
                continue
            feed = poll.json()
            clip = feed[0] if isinstance(feed, list) and feed else feed.get(clip_id)
            if not clip:
                continue

            status = clip.get("status", "")
            logging.info(f"  Suno status: {status} (attempt {attempt+1})")

            if status == "complete":
                audio_url = clip.get("audio_url")
                title     = clip.get("title", prompt[:50])
                tags      = clip.get("tags", "")
                if audio_url:
                    audio_bytes = requests.get(audio_url, timeout=60).content
                    logging.info("✅ Suno song generated!")
                    return audio_bytes, title, tags
                return None, None, None

            elif status in ("error", "failed"):
                logging.error(f"Suno clip failed: {clip.get('error')}")
                return None, None, None

        logging.error("Suno timed out")
        return None, None, None

    except Exception as e:
        logging.error(f"Suno exception: {e}")
        return None, None, None


def _music_beatoven(prompt: str, duration: int = 30, genre: str = "cinematic",
                    mood: str = "happy", tempo: str = "medium") -> bytes | None:
    """Generate music using Beatoven.ai API."""
    import time as _time
    if not BEATOVEN_API_KEY:
        return None
    try:
        headers = {
            "Authorization": f"Bearer {BEATOVEN_API_KEY}",
            "Content-Type": "application/json"
        }
        # Step 1: Create track
        payload = {
            "title": prompt[:80],
            "duration": min(duration, 300),  # max 5 mins
            "genre": genre,
            "mood": mood,
            "tempo": tempo
        }
        resp = requests.post(
            "https://public-api.beatoven.ai/api/v1/tracks",
            headers=headers, json=payload, timeout=30)

        if resp.status_code not in (200, 201):
            logging.error(f"Beatoven create track error: {resp.status_code} {resp.text[:200]}")
            return None

        track_data = resp.json()
        track_id = track_data.get("id") or track_data.get("track_id")
        if not track_id:
            logging.error(f"Beatoven: no track_id in response: {track_data}")
            return None

        # Step 2: Compose the track
        compose_resp = requests.post(
            f"https://public-api.beatoven.ai/api/v1/tracks/{track_id}/compose",
            headers=headers, timeout=30)

        # Step 3: Poll for completion
        for attempt in range(60):  # wait up to 5 mins
            _time.sleep(5)
            status_resp = requests.get(
                f"https://public-api.beatoven.ai/api/v1/tracks/{track_id}",
                headers=headers, timeout=15)
            if status_resp.status_code != 200:
                continue
            data = status_resp.json()
            status = data.get("status", "")
            if status == "composed":
                # Download the audio
                audio_url = data.get("meta", {}).get("composed_at") or data.get("url") or data.get("audio_url")
                if not audio_url:
                    # Try to get download URL
                    dl_resp = requests.get(
                        f"https://public-api.beatoven.ai/api/v1/tracks/{track_id}/download",
                        headers=headers, timeout=15)
                    if dl_resp.status_code == 200:
                        audio_url = dl_resp.json().get("url")
                if audio_url:
                    audio = requests.get(audio_url, timeout=60).content
                    if len(audio) > 1000:
                        return audio
                return None
            elif status in ("failed", "error"):
                logging.error(f"Beatoven composition failed: {data}")
                return None
        return None
    except Exception as e:
        logging.error(f"Beatoven error: {e}")
        return None


def _music_replicate(prompt, duration=10):
    import time as _time
    duration = min(duration, 30)
    try:
        resp = requests.post("https://api.replicate.com/v1/predictions",
            headers={"Authorization":f"Token {REPLICATE_API_TOKEN}","Content-Type":"application/json"},
            json={"version":"671ac645ce5e552cc63a54a2bbff63fcf798043055d2dac5fc9e36a837eedcfb",
                  "input":{"prompt":prompt,"model_version":"stereo-large","output_format":"mp3","duration":duration}}, timeout=30)
        if resp.status_code != 201: return None
        pid = resp.json().get("id")
        if not pid: return None
        for _ in range(36):
            __import__("time").sleep(5)
            poll = requests.get(f"https://api.replicate.com/v1/predictions/{pid}", headers={"Authorization":f"Token {REPLICATE_API_TOKEN}"}, timeout=15).json()
            if poll.get("status") == "succeeded":
                out = poll.get("output")
                url = out[0] if isinstance(out, list) else out
                return requests.get(url, timeout=30).content
            elif poll.get("status") in ("failed","canceled"): return None
        return None
    except Exception as e:
        logging.error(f"Replicate error: {e}"); return None


def _music_huggingface(prompt, duration=10):
    import time as _time
    if not HUGGINGFACE_API_KEY: return None
    try:
        for _ in range(3):
            resp = requests.post("https://router.huggingface.co/hf-inference/models/facebook/musicgen-small",
                headers={"Authorization":f"Bearer {HUGGINGFACE_API_KEY}"},
                json={"inputs":prompt,"parameters":{"max_new_tokens":duration*50}}, timeout=120)
            if resp.status_code == 200 and resp.headers.get("content-type","").startswith("audio"): return resp.content
            elif resp.status_code == 503: _time.sleep(min(resp.json().get("estimated_time",20),30))
            else: return None
        return None
    except Exception as e:
        logging.error(f"HF error: {e}"); return None


def _generate_music(prompt, duration=10, mode="auto"):
    """
    mode: auto | suno | instrumental
    Priority: Suno (vocals) → Replicate (instrumental) → HuggingFace (free)
    """
    # 1️⃣ Try Beatoven.ai first — real AI music!
    if BEATOVEN_API_KEY:
        logging.info("🎵 Trying Beatoven.ai...")
        # Parse mood/genre from prompt
        import re as _re_m
        genre = "cinematic"
        mood  = "happy"
        tempo = "medium"
        prompt_l = prompt.lower()
        for g in ["afrobeats","hiphop","hip-hop","gospel","reggae","jazz",
                  "classical","electronic","pop","rock","blues","lofi","trap"]:
            if g in prompt_l: genre = g.replace("-",""); break
        for m in ["happy","sad","angry","calm","romantic","epic","dark",
                  "uplifting","melancholic","energetic","peaceful"]:
            if m in prompt_l: mood = m; break
        for t in ["fast","slow","medium","upbeat","chill"]:
            if t in prompt_l: tempo = t; break
        audio = _music_beatoven(prompt, duration=30, genre=genre, mood=mood, tempo=tempo)
        if audio:
            return audio, "Beatoven.ai 🎵", prompt[:50], ".mp3"

    # 2️⃣ Try Suno — real songs with vocals!
    if mode in ("auto", "suno") and SUNO_API_KEY:
        with_lyrics = mode != "instrumental"
        logging.info("🎵 Trying Suno AI (real vocals)...")
        audio, title, tags = _music_suno(prompt, with_lyrics=with_lyrics)
        if audio:
            return audio, f"Suno AI 🎤", title or prompt[:50], ".mp3"

    # 2️⃣ Fallback: Replicate MusicGen (instrumental)
    if REPLICATE_API_TOKEN:
        logging.info("🎵 Trying Replicate MusicGen...")
        audio = _music_replicate(prompt, duration)
        if audio:
            return audio, "Replicate MusicGen 🎸", prompt[:50], ".mp3"

    # 3️⃣ Last resort: HuggingFace (free instrumental)
    if HUGGINGFACE_API_KEY:
        logging.info("🎵 Trying HuggingFace MusicGen...")
        audio = _music_huggingface(prompt, duration)
        if audio:
            return audio, "HuggingFace MusicGen 🎵", prompt[:50], ".wav"

    return None, "none", prompt[:50], ".mp3"


