async def cmd_makemusic(update: Update, context: ContextTypes.DEFAULT_TYPE):
    allowed, deny_msg = check_advanced_access(update.effective_user.id, "music_generation")
    if not allowed:
        await update.message.reply_text(f"🔒 {deny_msg}", parse_mode="Markdown"); return
    log_feature_usage(update.effective_user.id, "music_generation")
    args_text = " ".join(context.args).strip() if context.args else ""
    if not args_text:
        has_suno = "✅ Suno AI (vocals+lyrics)" if SUNO_API_KEY else "❌ Suno AI (add key for real songs!)"
        has_rep  = "✅ Replicate (instrumental)" if REPLICATE_API_TOKEN else "❌ Replicate"
        has_beat = "✅ Beatoven.ai (AI music)" if BEATOVEN_API_KEY else "❌ Beatoven.ai"
        has_hf   = "✅ HuggingFace (free)" if HUGGINGFACE_API_KEY else "❌ HuggingFace"
        await update.message.reply_text(
            "🎵 *CineMagic Music Generator*\n\n"
            "Usage: `/makemusic <describe your song>`\n\n"
            "Examples:\n"
            "• `/makemusic sad love song about missing someone`\n"
            "• `/makemusic happy afrobeats Ghana banger`\n"
            "• `/makemusic gospel praise song --vocals`\n"
            "• `/makemusic lo-fi beat --instrumental`\n\n"
            f"🤖 *Active Engines:*\n{has_suno}\n{has_rep}\n{has_hf}\n\n"
            "/musichelp for more ideas 🎼",
            parse_mode="Markdown"
        )
        return

    # Parse flags
    mode = "auto"
    prompt = args_text
    duration = 30

    if "--instrumental" in args_text:
        mode = "instrumental"
        prompt = prompt.replace("--instrumental", "").strip()
    elif "--vocals" in args_text:
        mode = "suno"
        prompt = prompt.replace("--vocals", "").strip()

    if "--duration" in prompt:
        parts = prompt.split("--duration")
        prompt = parts[0].strip()
        try: duration = max(5, min(int(parts[1].strip().split()[0]), 30))
        except: duration = 30

    engine_note = "🎤 Suno AI (real vocals)" if (mode in ("auto","suno") and SUNO_API_KEY) else "🎸 MusicGen (instrumental)"
    loading = await update.message.reply_text(
        f"🎵 *Generating your song...*\n\n"
        f"🎼 _{prompt}_\n"
        f"🤖 Engine: {engine_note}\n\n"
        f"⏳ This takes 1–3 minutes. Hold tight! 🎧",
        parse_mode="Markdown"
    )

    loop = asyncio.get_running_loop()
    result = await loop.run_in_executor(None, _generate_music, prompt, duration, mode)
    audio_bytes, source, title, suffix = result

    try: await loading.delete()
    except: pass

    if not audio_bytes:
        kb = [[InlineKeyboardButton("🎼 Try Again", callback_data="music_retry")]]
        await update.message.reply_text(
            "❌ *Music generation failed.*\n\n"
            "Possible reasons:\n"
            "• Suno API key not set or invalid\n"
            "• Network issue (DNS error)\n"
            "• All engines busy\n\n"
            "💡 Fix DNS:\n`echo 'nameserver 8.8.8.8' > $PREFIX/etc/resolv.conf`\n\n"
            "Or set Suno key:\n`/setsuno YOUR_KEY`",
            parse_mode="Markdown"
        )
        return

    try:
        with tempfile.NamedTemporaryFile(suffix=suffix, delete=False) as tmp:
            tmp.write(audio_bytes)
            tmp_path = tmp.name

        await update.message.reply_audio(
            audio=open(tmp_path, "rb"),
            caption=(
                f"🎵 *{title}*\n\n"
                f"🎼 _{prompt}_\n"
                f"🤖 Generated by: {source}\n\n"
                f"Powered by CineMagic 🎬 @MoveroomBot"
            ),
            parse_mode="Markdown",
            title=title[:64],
            performer="CineMagic AI"
        )
        os.unlink(tmp_path)

    except Exception as e:
        await update.message.reply_text(f"❌ Failed to send audio: {e}")


