import math as _math

_aviator_games = {}  # user_id: current game state

def _avi_get_player(user_id, username):
    conn = _hub_conn(); c = conn.cursor()
    c.execute("SELECT * FROM aviator_players WHERE user_id=?", (user_id,))
    row = c.fetchone()
    if not row:
        c.execute("INSERT INTO aviator_players (user_id,username,balance,created_at) VALUES (?,?,100.0,?)",
                  (user_id, username, datetime.datetime.now().isoformat()))
        conn.commit(); conn.close()
        return {"user_id":user_id,"username":username,"balance":100.0,"total_bets":0,"total_wins":0,
                "total_wagered":0.0,"total_won":0.0,"current_streak":0,"best_multiplier":0.0,
                "auto_bet_active":0,"auto_bet_amount":1.0,"auto_bet_cashout":2.0,"auto_bet_strategy":"fixed"}
    conn.close()
    cols = ["user_id","username","balance","total_bets","total_wins","total_wagered","total_won",
            "current_streak","best_multiplier","auto_bet_active","auto_bet_amount","auto_bet_cashout","auto_bet_strategy","created_at"]
    return dict(zip(cols, row))

def _avi_save_player(p):
    conn = _hub_conn(); c = conn.cursor()
    c.execute("""UPDATE aviator_players SET balance=?,total_bets=?,total_wins=?,total_wagered=?,
                 total_won=?,current_streak=?,best_multiplier=?,auto_bet_active=?,auto_bet_amount=?,
                 auto_bet_cashout=?,auto_bet_strategy=? WHERE user_id=?""",
              (p["balance"],p["total_bets"],p["total_wins"],p["total_wagered"],p["total_won"],
               p["current_streak"],p["best_multiplier"],p["auto_bet_active"],p["auto_bet_amount"],
               p["auto_bet_cashout"],p["auto_bet_strategy"],p["user_id"]))
    conn.commit(); conn.close()

def _avi_log(user_id, bet, cashout_at, crash_at, profit, balance_after):
    conn = _hub_conn(); c = conn.cursor()
    c.execute("INSERT INTO aviator_history (user_id,bet_amount,cashout_at,crash_at,profit,balance_after,timestamp) VALUES (?,?,?,?,?,?,?)",
              (user_id, bet, cashout_at, crash_at, profit, balance_after, datetime.datetime.now().isoformat()))
    conn.commit(); conn.close()

def _avi_generate_crash() -> float:
    """Generate realistic Aviator crash multiplier using house edge algorithm."""
    r = random.random()
    if r < 0.01: return round(random.uniform(1.0, 1.05), 2)  # 1% chance instant crash
    crash = max(1.0, 0.99 / (1.0 - random.random()))
    return round(min(crash, 200.0), 2)

def _avi_recent_history():
    conn = _hub_conn(); c = conn.cursor()
    c.execute("SELECT crash_at FROM aviator_history ORDER BY id DESC LIMIT 10")
    rows = c.fetchall(); conn.close()
    return [row[0] for row in rows]

