async def cb_avico(update: Update, context: ContextTypes.DEFAULT_TYPE):
    q = update.callback_query; await q.answer()
    parts = q.data.split("_"); amount = float(parts[1]); cashout_target = float(parts[2])
    user = q.from_user; p = _avi_get_player(user.id, user.username or user.first_name)
    if p["balance"] < amount:
        await q.edit_message_text("❌ Insufficient balance!"); return

    # Simulate the flight
    crash_at = _avi_generate_crash()
    p["balance"] -= amount
    p["total_bets"] += 1
    p["total_wagered"] += amount

    # Build animated flight text
    flight_frames = []
    multiplier = 1.0
    step = 0.1
    while multiplier <= min(crash_at, cashout_target + 0.5):
        multiplier = round(multiplier + step, 2)
        if multiplier > 5: step = 0.3
        if multiplier > 10: step = 0.5

    if cashout_target <= crash_at:
        # WIN! Cashed out before crash
        profit = round(amount * cashout_target - amount, 2)
        p["balance"] += amount + profit
        p["total_wins"] += 1
        p["total_won"] += profit
        p["current_streak"] += 1
        if cashout_target > p["best_multiplier"]: p["best_multiplier"] = cashout_target
        _avi_log(user.id, amount, cashout_target, crash_at, profit, p["balance"])
        _avi_save_player(p)
        result_text = (
            f"✈️ *Plane took off...*\n\n"
            f"📈 Multiplier climbed: 1.0x → {cashout_target}x\n"
            f"💚 *CASHED OUT at {cashout_target}x!*\n"
            f"💥 Plane crashed at {crash_at}x (after cashout)\n\n"
            f"━━━━━━━━━━━━━━━\n"
            f"🎯 Bet: GHS {amount}\n"
            f"💰 Winnings: GHS {amount + profit:.2f}\n"
            f"✅ Profit: +GHS {profit:.2f}\n"
            f"💳 New Balance: GHS {p['balance']:.2f}\n"
            f"🔥 Streak: {p['current_streak']} wins"
        )
    else:
        # CRASH before cashout
        _avi_log(user.id, amount, None, crash_at, -amount, p["balance"])
        p["current_streak"] = 0
        _avi_save_player(p)
        result_text = (
            f"✈️ *Plane took off...*\n\n"
            f"📈 Multiplier climbing... {crash_at}x\n"
            f"💥 *CRASHED at {crash_at}x!*\n"
            f"_(Cashout target was {cashout_target}x — too late!)_\n\n"
            f"━━━━━━━━━━━━━━━\n"
            f"🎯 Bet: GHS {amount}\n"
            f"❌ Lost: -GHS {amount:.2f}\n"
            f"💳 Balance: GHS {p['balance']:.2f}"
        )

    kb = [
        [InlineKeyboardButton("🔄 Bet Again", callback_data="avi_bet"),
         InlineKeyboardButton("🤖 Auto Bet", callback_data="avi_autobet")],
        [InlineKeyboardButton("🏠 Main Menu", callback_data="avi_main")],
    ]
    await q.edit_message_text(result_text, reply_markup=InlineKeyboardMarkup(kb), parse_mode="Markdown")

