async def cb_avi_autostart(update: Update, context: ContextTypes.DEFAULT_TYPE):
    q = update.callback_query; await q.answer()
    user = q.from_user; p = _avi_get_player(user.id, user.username or user.first_name)
    if p["balance"] < p["auto_bet_amount"]:
        await q.edit_message_text(f"❌ Balance too low!\nNeed at least GHS {p['auto_bet_amount']:.2f}"); return
    p["auto_bet_active"] = 1; _avi_save_player(p)
    # Run 5 auto rounds
    results = []; bet = p["auto_bet_amount"]
    for i in range(5):
        if p["balance"] < bet: break
        crash_at = _avi_generate_crash(); target = p["auto_bet_cashout"]
        p["balance"] -= bet; p["total_bets"] += 1; p["total_wagered"] += bet
        if target <= crash_at:
            profit = round(bet * target - bet, 2); p["balance"] += bet + profit
            p["total_wins"] += 1; p["total_won"] += profit; p["current_streak"] += 1
            results.append(f"✅ Round {i+1}: {target}x → +GHS {profit:.2f}")
            if p["auto_bet_strategy"] == "martingale": bet = p["auto_bet_amount"]  # reset on win
        else:
            results.append(f"💥 Round {i+1}: Crash {crash_at}x → -GHS {bet:.2f}")
            p["current_streak"] = 0
            if p["auto_bet_strategy"] == "martingale": bet = round(bet * 2, 2)  # double on loss
        _avi_log(user.id, bet, target if target<=crash_at else None, crash_at,
                 round(bet*target-bet,2) if target<=crash_at else -bet, p["balance"])
    p["auto_bet_active"] = 0; _avi_save_player(p)
    results_txt = "\n".join(results)
    kb = [[InlineKeyboardButton("🔄 Run Again", callback_data="avi_autostart"),
           InlineKeyboardButton("🏠 Menu", callback_data="avi_main")]]
    await q.edit_message_text(
        f"🤖 *Auto Bet Results (5 rounds)*\n\n{results_txt}\n\n💳 Balance: GHS {p['balance']:.2f}",
        reply_markup=InlineKeyboardMarkup(kb), parse_mode="Markdown"
    )


