#  🌐  FLASK REST API (runs on port 5055)
# ══════════════════════════════════════════════════════════════════════════
_hub_flask = _Flask("cinemagic_hub")

def _hub_require_key(feature):
    def dec(f):
        @wraps(f)
        def wrapped(*args, **kwargs):
            key = _freq.headers.get("X-API-Key") or _freq.args.get("api_key")
            if not key: return _fjson({"error":"Missing X-API-Key header"}), 401
            ok, msg = hub_validate_key(key, feature)
            if not ok: return _fjson({"error": msg}), 403
            return f(*args, **kwargs)
        return wrapped
    return dec

@_hub_flask.route("/")
def _hub_index():
    return _fjson({"name":"🎬 CineMagic API","version":"1.0","by":"@Theolicarl","get_key":"Message @MoveroomBot → /buyapi"})

@_hub_flask.route("/api/status")
def _hub_status():
    key = _freq.headers.get("X-API-Key") or _freq.args.get("api_key")
    if not key: return _fjson({"error":"Missing key"}), 401
    info = hub_get_key_info(key)
    if not info: return _fjson({"error":"Invalid key"}), 404
    return _fjson({"valid":True,"tier":info["tier"],"features":info["features"].split(","),"requests_today":info["requests_used_today"],"daily_limit":info["requests_per_day"],"expires_at":info["expires_at"]})

@_hub_flask.route("/api/chat", methods=["POST"])
@_hub_require_key("ai_chat")
def _hub_chat():
    d = _freq.json or {}; msg = d.get("message","").strip()
    if not msg: return _fjson({"error":"message required"}), 400
    try:
        resp = requests.post(GROQ_BASE, headers=GROQ_HEADERS, json={"model":"llama-3.3-70b-versatile","messages":[{"role":"system","content":"You are CineMagic AI."},{"role":"user","content":msg}],"max_tokens":1024}, timeout=30)
        reply = resp.json()["choices"][0]["message"]["content"]
        return _fjson({"success":True,"reply":reply})
    except Exception as e: return _fjson({"error":str(e)}), 500

@_hub_flask.route("/api/osint/ip", methods=["POST"])
@_hub_require_key("osint")
def _hub_osint_ip():
    d = _freq.json or {}; ip = d.get("ip","").strip()
    if not ip: return _fjson({"error":"ip required"}), 400
    try:
        r = requests.get(f"http://ip-api.com/json/{ip}?fields=status,country,regionName,city,isp,query,lat,lon,proxy", timeout=10)
        return _fjson({"success":True,"data":r.json()})
    except Exception as e: return _fjson({"error":str(e)}), 500

@_hub_flask.route("/oauth/google/callback")
def _hub_google_cb():
    code = _freq.args.get("code"); state = _freq.args.get("state")
    row = hub_get_oauth_state(state)
    if not row: return "❌ Invalid state", 400
    user_id, integration = row
    tr = requests.post("https://oauth2.googleapis.com/token", data={"code":code,"client_id":GOOGLE_CLIENT_ID,"client_secret":GOOGLE_CLIENT_SECRET,"redirect_uri":f"{BASE_URL}/oauth/google/callback","grant_type":"authorization_code"}).json()
    if not tr.get("access_token"): return "❌ Failed to get token", 400
    hub_save_connection(user_id, None, integration, tr["access_token"], tr.get("refresh_token"))
    return "<html><body style='font-family:sans-serif;text-align:center;padding:50px'><h2>✅ Connected! Go back to Telegram.</h2><script>setTimeout(()=>window.close(),3000)</script></body></html>"

@_hub_flask.route("/auth/google")
def _auth_google_start():
    """Redirect to Google OAuth for bot account sign-in."""
    state = _freq.args.get("state", "")
    if not state:
        return "❌ Missing state parameter", 400
    if not GOOGLE_CLIENT_ID:
        return "❌ Google Sign-In is not configured yet. Contact @Theolicarl.", 503
    params = {
        "client_id": GOOGLE_CLIENT_ID,
        "redirect_uri": f"{BASE_URL}/auth/google/callback",
        "response_type": "code",
        "scope": "openid email profile",
        "state": state,
        "access_type": "offline",
        "prompt": "select_account",
    }
    from urllib.parse import urlencode as _ue
    return _fredirect("https://accounts.google.com/o/oauth2/v2/auth?" + _ue(params))

@_hub_flask.route("/auth/google/callback")
def _auth_google_callback():
    """Google returns here after user approves. Create/update CineMagic account."""
    code  = _freq.args.get("code")
    state = _freq.args.get("state")
    error = _freq.args.get("error")

    if error or not code or not state:
        return "<html><body style='font-family:sans-serif;text-align:center;padding:50px'><h2>❌ Sign-in cancelled or failed.</h2><p>Go back to Telegram and try again.</p></body></html>", 400

    # Decode state → Telegram user_id
    try:
        user_id = int(state.split("_")[0])
    except Exception:
        return "❌ Invalid state", 400

    # Exchange code for tokens
    try:
        tr = requests.post(
            "https://oauth2.googleapis.com/token",
            data={
                "code": code,
                "client_id": GOOGLE_CLIENT_ID,
                "client_secret": GOOGLE_CLIENT_SECRET,
                "redirect_uri": f"{BASE_URL}/auth/google/callback",
                "grant_type": "authorization_code",
            },
            timeout=10,
        ).json()
    except Exception:
        return "<html><body style='font-family:sans-serif;text-align:center;padding:50px'><h2>❌ Network error. Please try again.</h2></body></html>", 500

    access_token = tr.get("access_token")
    if not access_token:
        return "<html><body style='font-family:sans-serif;text-align:center;padding:50px'><h2>❌ Failed to get token from Google.</h2></body></html>", 400

    # Get user profile from Google
    try:
        profile = requests.get(
            "https://www.googleapis.com/oauth2/v2/userinfo",
            headers={"Authorization": f"Bearer {access_token}"},
            timeout=10,
        ).json()
    except Exception:
        return "<html><body style='font-family:sans-serif;text-align:center;padding:50px'><h2>❌ Failed to fetch Google profile.</h2></body></html>", 500

    google_email    = profile.get("email", "")
    google_name     = profile.get("name", "")
    google_id       = profile.get("id", "")
    google_picture  = profile.get("picture", "")

    if not google_email:
        return "<html><body style='font-family:sans-serif;text-align:center;padding:50px'><h2>❌ Could not read your Google email.</h2></body></html>", 400

    # Create or update CineMagic account in the accounts SQLite table
    now = datetime.datetime.now().isoformat()
    username = google_email.split("@")[0]
    import sqlite3 as _sl
    conn = _sl.connect(SQLITE_DB)
    c = conn.cursor()
    existing = c.execute("SELECT id FROM accounts WHERE user_id=?", (str(user_id),)).fetchone()
    if existing:
        # Update email/name if they changed
        c.execute(
            "UPDATE accounts SET email=?, full_name=?, last_login=? WHERE user_id=?",
            (google_email, google_name, now, str(user_id))
        )
    else:
        # New account via Google
        c.execute(
            "INSERT OR IGNORE INTO accounts (user_id, username, password_hash, email, full_name, is_verified, created_at, last_login) VALUES (?,?,?,?,?,1,?,?)",
            (str(user_id), username, "GOOGLE_OAUTH", google_email, google_name, now, now)
        )
    conn.commit()
    conn.close()

    # Also store the Google token as a hub integration so they can use Gmail/Calendar
    hub_save_connection(user_id, username, "google_account", access_token, tr.get("refresh_token"), json.dumps({"email": google_email, "picture": google_picture}))

    return f"""<html>
<head><meta charset='utf-8'><title>CineMagic — Sign In</title></head>
<body style='font-family:sans-serif;text-align:center;padding:60px;background:#0d0d0d;color:#fff'>
  <div style='max-width:400px;margin:auto;background:#1a1a2e;padding:40px;border-radius:16px;border:1px solid #ffd700'>
    <div style='font-size:48px'>🎬</div>
    <h2 style='color:#ffd700'>Signed in successfully!</h2>
    <p>Welcome, <b>{google_name}</b> ({google_email})</p>
    <p style='color:#aaa'>Go back to Telegram and press <b>/start</b> to continue.</p>
    <p style='color:#555;font-size:12px'>This tab will close in 5 seconds.</p>
  </div>
  <script>setTimeout(()=>window.close(), 5000)</script>
</body>
</html>"""

def _start_hub_flask():
    Thread(target=lambda: _hub_flask.run(host="0.0.0.0", port=HUB_PORT, debug=False), daemon=True).start()
    logging.info(f"✅ CineMagic REST API on port {HUB_PORT}")




