# Pollinations needs NO API key — completely free!
POLLINATIONS_URL = "https://image.pollinations.ai/prompt/{prompt}?width={w}&height={h}&model={model}&nologo=true&enhance=true"

IMAGINE_MODELS = {
    "flux":       "🔥 Flux (Best Quality)",
    "turbo":      "⚡ Turbo (Fastest)",
    "flux-realism": "📸 Flux Realism (Photo)",
    "dreamshaper": "🎨 Dreamshaper (Artistic)",
}

async def cmd_imagine(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """/imagine <prompt> — Generate AI image FREE"""
    allowed, deny_msg = check_advanced_access(update.effective_user.id, "image_generation")
    if not allowed:
        await update.message.reply_text(f"🔒 {deny_msg}", parse_mode="Markdown"); return
    log_feature_usage(update.effective_user.id, "image_generation", " ".join(context.args)[:80] if context.args else "")
    prompt = " ".join(context.args).strip() if context.args else ""
    if not prompt:
        kb = [[InlineKeyboardButton(f"{v}", callback_data=f"imgmodel:{k}")] for k, v in IMAGINE_MODELS.items()]
        await update.message.reply_text(
            "🖼️ *CineMagic AI Image Generator*\n\n"
            "Usage: `/imagine <describe your image>`\n\n"
            "Examples:\n"
            "• `/imagine a lion wearing a suit in Accra Ghana`\n"
            "• `/imagine beautiful African sunset over the ocean`\n"
            "• `/imagine futuristic city in Ghana 2050`\n\n"
            "🎨 *Available Styles:*\n"
            "Add `--flux` `--turbo` `--realism` `--art` to your prompt\n\n"
            "💡 Completely FREE — no credits needed! 🆓",
            parse_mode="Markdown"
        )
        return

    # Parse model flag
    model = "flux"
    clean_prompt = prompt
    if "--turbo" in prompt:   model = "turbo";           clean_prompt = prompt.replace("--turbo","").strip()
    elif "--realism" in prompt: model = "flux-realism";  clean_prompt = prompt.replace("--realism","").strip()
    elif "--art" in prompt:   model = "dreamshaper";     clean_prompt = prompt.replace("--art","").strip()
    elif "--flux" in prompt:  model = "flux";            clean_prompt = prompt.replace("--flux","").strip()

    loading = await update.message.reply_text(
        f"🖼️ *Generating your image...*\n\n"
        f"✏️ _{clean_prompt}_\n"
        f"🎨 Model: {IMAGINE_MODELS.get(model,'Flux')}\n\n"
        f"⏳ Takes 5–15 seconds... 🎨",
        parse_mode="Markdown"
    )

    try:
        from urllib.parse import quote as _quote
        encoded = _quote(clean_prompt)
        img_url = POLLINATIONS_URL.format(
            prompt=encoded, w=1024, h=1024, model=model
        )
        img_resp = requests.get(img_url, timeout=60)
        if img_resp.status_code == 200 and img_resp.headers.get("content-type","").startswith("image"):
            try: await loading.delete()
            except: pass
            await update.message.reply_photo(
                photo=img_resp.content,
                caption=(
                    f"🖼️ *AI Generated Image*\n\n"
                    f"✏️ _{clean_prompt}_\n"
                    f"🎨 {IMAGINE_MODELS.get(model,'Flux')}\n"
                    f"🆓 Powered by Pollinations AI\n\n"
                    f"🎬 CineMagic @MoveroomBot"
                ),
                parse_mode="Markdown"
            )
        else:
            await loading.edit_text(f"❌ Image generation failed. Try again with a different prompt!")
    except Exception as e:
        logging.error(f"Image gen error: {e}")
        await loading.edit_text(f"❌ Error: {str(e)[:100]}\n\nTry again!")


