#  💬  GROUP CHAT AI MODE
# ══════════════════════════════════════════════════════════════════

# Store which groups have AI mode enabled
_group_ai_enabled = {}   # chat_id: True/False
_group_ai_name    = {}   # chat_id: bot name in group
_group_ai_persona = {}   # chat_id: persona

async def cmd_groupai(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """/groupai on|off|status|name <name>"""
    chat = update.effective_chat
    user = update.effective_user

    # Only work in groups
    if chat.type not in ("group", "supergroup"):
        await update.message.reply_text("❌ This command only works in groups!\n\nAdd me to a group and try again.")
        return

    args = context.args
    if not args:
        status = "🟢 ON" if _group_ai_enabled.get(chat.id) else "🔴 OFF"
        name   = _group_ai_name.get(chat.id, "CineMagic")
        await update.message.reply_text(
            f"💬 *Group AI Mode*\n\n"
            f"Status: {status}\n"
            f"Name: {name}\n\n"
            f"Commands:\n"
            f"`/groupai on` — Enable AI in this group\n"
            f"`/groupai off` — Disable AI\n"
            f"`/groupai name YourName` — Set AI name\n"
            f"`/groupai persona friendly` — Set personality\n\n"
            f"When ON — mention @{context.bot.username} or reply to the bot to chat!",
            parse_mode="Markdown"
        )
        return

    cmd = args[0].lower()
    if cmd == "on":
        _group_ai_enabled[chat.id] = True
        name = _group_ai_name.get(chat.id, "CineMagic")
        await update.message.reply_text(
            f"🟢 *Group AI Mode ON!*\n\n"
            f"I'm now active as *{name}* in this group!\n"
            f"Mention me @{context.bot.username} or reply to my messages to chat 💬",
            parse_mode="Markdown"
        )
    elif cmd == "off":
        _group_ai_enabled[chat.id] = False
        await update.message.reply_text("🔴 Group AI Mode disabled.")
    elif cmd == "name" and len(args) > 1:
        new_name = " ".join(args[1:])
        _group_ai_name[chat.id] = new_name
        await update.message.reply_text(f"✅ AI name set to *{new_name}* in this group!", parse_mode="Markdown")
    elif cmd == "persona" and len(args) > 1:
        persona = args[1].lower()
        _group_ai_persona[chat.id] = persona
        personas = {"friendly":"😊 Friendly","savage":"🔥 Savage & Roasting","professional":"💼 Professional","funny":"😂 Comedian"}
        await update.message.reply_text(f"✅ Persona set to {personas.get(persona, persona)}!", parse_mode="Markdown")
    elif cmd == "status":
        status = "🟢 ON" if _group_ai_enabled.get(chat.id) else "🔴 OFF"
        await update.message.reply_text(f"Group AI Status: {status}")


async def handle_group_ai(update: Update, context: ContextTypes.DEFAULT_TYPE) -> bool:
    """
    Handle group messages — returns True if handled.
    Call this from handle_message().
    """
    chat = update.effective_chat
    msg  = update.message
    if not msg or not msg.text: return False
    if chat.type not in ("group","supergroup"): return False
    if not _group_ai_enabled.get(chat.id): return False

    bot_username = context.bot.username or "MoveroomBot"
    text = msg.text

    # Trigger if: mentioned, reply to bot, or starts with bot name
    ai_name = _group_ai_name.get(chat.id, "CineMagic")
    is_mentioned = f"@{bot_username}" in text
    is_reply     = msg.reply_to_message and msg.reply_to_message.from_user and msg.reply_to_message.from_user.username == bot_username
    is_named     = text.lower().startswith(ai_name.lower())

    if not (is_mentioned or is_reply or is_named):
        return False

    # Clean the prompt
    clean = text.replace(f"@{bot_username}", "").replace(ai_name, "").strip()
    if not clean: return False

    persona = _group_ai_persona.get(chat.id, "friendly")
    persona_prompts = {
        "friendly":     f"You are {ai_name}, a friendly and helpful AI assistant in a Telegram group. Be warm, helpful and engaging.",
        "savage":       f"You are {ai_name}, a funny and savage AI that loves to roast people playfully. Keep it fun not mean.",
        "professional": f"You are {ai_name}, a professional AI assistant. Give precise, helpful answers.",
        "funny":        f"You are {ai_name}, a hilarious comedian AI. Make people laugh with every response.",
    }
    system = persona_prompts.get(persona, persona_prompts["friendly"])

    try:
        await context.bot.send_chat_action(chat.id, "typing")
        resp = requests.post(GROQ_BASE, headers=GROQ_HEADERS, json={
            "model": "llama-3.3-70b-versatile",
            "messages": [
                {"role": "system", "content": system},
                {"role": "user", "content": f"{update.effective_user.first_name} says: {clean}"}
            ],
            "max_tokens": 512
        }, timeout=30)
        reply = resp.json()["choices"][0]["message"]["content"]
        await msg.reply_text(reply)
        return True
    except Exception as e:
        logging.error(f"Group AI error: {e}")
        return False


