async def handle_video_photo(update: Update, context: ContextTypes.DEFAULT_TYPE) -> bool:
    """
    Called from handle_photo. If user is in image-to-video mode,
    capture the image and generate video. Returns True if consumed.
    """
    if not context.user_data.get("vid_awaiting_image"):
        return False

    user_id = update.effective_user.id
    allowed, deny_msg = check_advanced_access(user_id, "video_generation")
    if not allowed:
        await update.message.reply_text(f"🔒 {deny_msg}", parse_mode="Markdown")
        context.user_data.pop("vid_awaiting_image", None)
        return True

    context.user_data.pop("vid_awaiting_image", None)

    # Get the best quality photo
    photo  = update.message.photo[-1]
    caption = update.message.caption or ""
    # Strip /video or /vid from caption if present
    prompt = caption.replace("/video", "").replace("/vid", "").strip()

    await update.message.reply_text(
        "🖼️ *Image received!* Processing...\n\n"
        f"🎬 Motion prompt: _{prompt or 'natural cinematic motion'}_",
        parse_mode="Markdown"
    )

    try:
        tg_file    = await context.bot.get_file(photo.file_id)
        img_bytes  = await tg_file.download_as_bytearray()
        image_b64  = base64.b64encode(img_bytes).decode()
        await _do_image_to_video(update, context, image_b64, prompt)
    except Exception as e:
        await update.message.reply_text(f"❌ Error processing image: {str(e)[:100]}")
    return True


