NEWS_CATEGORIES = {
    "ghana":       "Ghana News",
    "africa":      "Africa News",
    "world":       "World News",
    "tech":        "Technology",
    "crypto":      "Crypto & Finance",
    "entertainment":"Entertainment",
    "sports":      "Sports",
}

NEWS_RSS_FEEDS = {
    "ghana":        "https://www.ghanaweb.com/GhanaHomePage/rss/rss.xml",
    "africa":       "https://feeds.bbci.co.uk/news/world/africa/rss.xml",
    "world":        "https://feeds.bbci.co.uk/news/world/rss.xml",
    "tech":         "https://feeds.feedburner.com/TechCrunch",
    "crypto":       "https://cointelegraph.com/rss",
    "entertainment":"https://feeds.bbci.co.uk/news/entertainment_and_arts/rss.xml",
    "sports":       "https://feeds.bbci.co.uk/sport/rss.xml",
}

def _fetch_news(category="ghana", limit=5) -> list:
    """Fetch RSS news for a category."""
    import xml.etree.ElementTree as ET
    url = NEWS_RSS_FEEDS.get(category, NEWS_RSS_FEEDS["world"])
    try:
        resp = requests.get(url, timeout=15, headers={"User-Agent":"Mozilla/5.0"})
        root = ET.fromstring(resp.content)
        items = root.findall(".//item")[:limit]
        news = []
        for item in items:
            title = item.findtext("title","").strip()
            link  = item.findtext("link","").strip()
            desc  = item.findtext("description","").strip()[:150]
            # Clean HTML tags from description
            import re
            desc = re.sub(r'<[^>]+>', '', desc).strip()
            if title:
                news.append({"title": title, "link": link, "desc": desc})
        return news
    except Exception as e:
        logging.error(f"News fetch error: {e}")
        return []


async def cmd_news(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """/news [category] — Get latest news"""
    cat = context.args[0].lower() if context.args else "ghana"
    if cat not in NEWS_CATEGORIES:
        cats = "\n".join([f"• `{k}` — {v}" for k, v in NEWS_CATEGORIES.items()])
        await update.message.reply_text(
            f"📰 *CineMagic News Digest*\n\n"
            f"Usage: `/news [category]`\n\n"
            f"📋 *Categories:*\n{cats}\n\n"
            f"Example: `/news ghana` or `/news crypto`",
            parse_mode="Markdown"
        )
        return

    loading = await update.message.reply_text(f"📰 Fetching {NEWS_CATEGORIES[cat]}...", parse_mode="Markdown")
    news = _fetch_news(cat, limit=7)

    if not news:
        await loading.edit_text("❌ Could not fetch news. Try again later!")
        return

    now = datetime.datetime.now().strftime("%d %B %Y, %I:%M %p")
    msg = f"📰 *{NEWS_CATEGORIES[cat]}*\n🕐 {now}\n\n"
    for i, item in enumerate(news, 1):
        msg += f"*{i}.* {item['title']}\n"
        if item['desc']:
            msg += f"_{item['desc'][:100]}..._\n"
        if item['link']:
            msg += f"[Read more]({item['link']})\n"
        msg += "\n"

    msg += f"🎬 Powered by CineMagic @MoveroomBot"

    kb = [[InlineKeyboardButton(f"🔄 Refresh", callback_data=f"news_refresh_{cat}"),
           InlineKeyboardButton(f"📋 Categories", callback_data="news_cats")]]

    try:
        await loading.edit_text(msg, parse_mode="Markdown",
                                reply_markup=InlineKeyboardMarkup(kb),
                                disable_web_page_preview=True)
    except Exception:
        await loading.edit_text(msg[:4000], parse_mode="Markdown",
                                disable_web_page_preview=True)


