#  🎵  MUSIC FIX — Better HuggingFace URL + Quality Boost
# ══════════════════════════════════════════════════════════════════

# Updated HuggingFace router URL (fixes 404 error)
HF_MUSIC_URLS = [
    "https://router.huggingface.co/hf-inference/models/facebook/musicgen-small",
    "https://api-inference.huggingface.co/models/facebook/musicgen-melody",
    "https://api-inference.huggingface.co/models/facebook/musicgen-large",
]

def _music_huggingface_v2(prompt, duration=15):
    """Fixed HuggingFace music generation with multiple model fallbacks."""
    import time as _time
    if not HUGGINGFACE_API_KEY: return None
    headers = {"Authorization": f"Bearer {HUGGINGFACE_API_KEY}"}

    for url in HF_MUSIC_URLS:
        try:
            logging.info(f"🎵 Trying HF URL: {url}")
            for attempt in range(3):
                resp = requests.post(
                    url, headers=headers,
                    json={"inputs": prompt, "parameters": {"max_new_tokens": duration * 51}},
                    timeout=120
                )
                if resp.status_code == 200:
                    ct = resp.headers.get("content-type","")
                    if "audio" in ct or len(resp.content) > 1000:
                        logging.info(f"✅ HF music success from {url}")
                        return resp.content
                elif resp.status_code == 503:
                    wait = min(resp.json().get("estimated_time", 20), 30)
                    logging.info(f"  Model loading, waiting {wait}s...")
                    _time.sleep(wait)
                elif resp.status_code == 404:
                    logging.warning(f"  404 on {url}, trying next...")
                    break
                else:
                    logging.error(f"  HF error {resp.status_code}: {resp.text[:100]}")
                    break
        except Exception as e:
            logging.error(f"HF error on {url}: {e}")
            continue
    return None


