PAYSTACK_SECRET = os.getenv("PAYSTACK_SECRET_KEY", "")
PAYSTACK_PUBLIC = os.getenv("PAYSTACK_PUBLIC_KEY", "")

def paystack_init_payment(email: str, amount_ghs: float, ref: str, metadata: dict = None) -> dict:
    """Initialize Paystack payment. Amount in GHS (will convert to pesewas)."""
    if not PAYSTACK_SECRET:
        return {"error": "Paystack not configured"}
    amount_pesewas = int(amount_ghs * 100)
    try:
        resp = requests.post(
            "https://api.paystack.co/transaction/initialize",
            headers={"Authorization": f"Bearer {PAYSTACK_SECRET}", "Content-Type": "application/json"},
            json={
                "email": email,
                "amount": amount_pesewas,
                "currency": "GHS",
                "reference": ref,
                "callback_url": f"{BASE_URL}/paystack/callback",
                "metadata": metadata or {}
            },
            timeout=15
        )
        return resp.json()
    except Exception as e:
        return {"error": str(e)}


def paystack_verify(reference: str) -> dict:
    """Verify a Paystack payment."""
    if not PAYSTACK_SECRET:
        return {"error": "Paystack not configured"}
    try:
        resp = requests.get(
            f"https://api.paystack.co/transaction/verify/{reference}",
            headers={"Authorization": f"Bearer {PAYSTACK_SECRET}"},
            timeout=15
        )
        return resp.json()
    except Exception as e:
        return {"error": str(e)}


