async def cmd_wa_send(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """/wasend <phone> <message> — Send WhatsApp via connected account"""
    user = update.effective_user
    conn = hub_get_connection(user.id, "whatsapp")
    if not conn:
        await update.message.reply_text(
            "❌ WhatsApp not connected!\n\n"
            "Use /connect → 💬 WhatsApp Business → paste your token"
        ); return
    if len(context.args) < 2:
        await update.message.reply_text("Usage: `/wasend 233XXXXXXXXX Your message here`", parse_mode="Markdown")
        return
    phone = context.args[0]; message = " ".join(context.args[1:])
    try:
        r = requests.post(
            f"https://graph.facebook.com/v18.0/{WHATSAPP_PHONE_ID}/messages",
            headers={"Authorization": f"Bearer {conn['access_token']}", "Content-Type": "application/json"},
            json={"messaging_product":"whatsapp","to":phone,"type":"text","text":{"body":message}},
            timeout=10
        )
        result = r.json()
        if "messages" in result:
            await update.message.reply_text(f"✅ WhatsApp message sent to {phone}!")
        else:
            await update.message.reply_text(f"❌ Failed: {result.get('error',{}).get('message','Unknown error')}")
    except Exception as e:
        await update.message.reply_text(f"❌ Error: {e}")


