# ════════════════════════════════════════════════════════════════
#  🖼️  PDF IMAGE ENGINE
#  Priority: 1) DALL-E generated  2) Pillow art  3) Skip image
# ════════════════════════════════════════════════════════════════

_PDF_THEMES_RGB = {
    "red":    [(26,26,46),   (233,69,96),   (255,100,120)],
    "blue":   [(15,52,96),   (26,33,46),    (100,150,255)],
    "green":  [(26,47,26),   (39,174,96),   (80,220,140)],
    "gold":   [(26,26,10),   (243,156,18),  (255,200,60)],
    "purple": [(26,10,46),   (142,68,173),  (180,100,220)],
    "dark":   [(26,26,46),   (15,52,96),    (233,69,96)],
    "teal":   [(10,40,50),   (22,160,133),  (100,220,200)],
}

def _pillow_header(title: str, subtitle: str = "", width: int = 800,
                   height: int = 320, theme: str = "dark") -> bytes | None:
    """Create a beautiful gradient header image with Pillow. Returns PNG bytes.
    NOTE: No text is drawn — the PDF builders add their own text on top."""
    if not PILLOW_OK:
        return None
    try:
        t = _PDF_THEMES_RGB.get(theme, _PDF_THEMES_RGB["dark"])
        bg1, bg2, accent = t[0], t[1], t[2]

        img = Image.new("RGB", (width, height), bg1)
        draw = ImageDraw.Draw(img)

        # Gradient background
        for y in range(height):
            r = int(bg1[0] + (bg2[0]-bg1[0]) * y/height)
            g = int(bg1[1] + (bg2[1]-bg1[1]) * y/height)
            b = int(bg1[2] + (bg2[2]-bg1[2]) * y/height)
            draw.line([(0,y),(width,y)], fill=(r,g,b))

        # Decorative circles only — NO TEXT
        draw.ellipse([width-280, -140, width+140, 220], fill=accent)
        draw.ellipse([-140, height-120, 220, height+220], fill=accent)
        draw.ellipse([width-200, -60, width+60, 200], fill=bg1)
        draw.ellipse([-80, height-80, 160, height+120], fill=bg1)

        # Subtle accent shapes
        for i in range(3):
            alpha_col = tuple(min(255, c+30) for c in accent)
            draw.ellipse([width//2-60+i*40, height//3-40+i*20,
                          width//2+60+i*40, height//3+60+i*20], fill=accent)

        # Accent bar on left
        draw.rectangle([0, 0, 10, height], fill=accent)
        # Bottom accent strip
        draw.rectangle([0, height-8, width, height], fill=accent)

        buf = io.BytesIO()
        img.save(buf, format="PNG", optimize=True)
        return buf.getvalue()
    except Exception as e:
        logging.error(f"_pillow_header error: {e}")
        return None


def _dalle_image(prompt: str, size: str = "512x512") -> bytes | None:
    """Try DALL-E image generation. Returns PNG bytes or None."""
    try:
        import urllib.request as _ur
        payload = {"model": "dall-e-2", "prompt": prompt[:400],
                   "n": 1, "size": size, "response_format": "url"}
        import json as _j, urllib.request as _ur2
        req = _ur2.Request(
            "https://api.openai.com/v1/images/generations",
            data=_j.dumps(payload).encode(),
            headers={"Authorization": f"Bearer {OPENAI_API_KEY}",
                     "Content-Type": "application/json"},
            method="POST"
        )
        with _ur2.urlopen(req, timeout=25) as resp:
            data = _j.loads(resp.read())
        url = data["data"][0]["url"]
        with _ur2.urlopen(url, timeout=20) as r:
            img_bytes = r.read()
        # Resize to desired width using Pillow if available
        if PILLOW_OK:
            img = Image.open(io.BytesIO(img_bytes)).convert("RGB")
            img = img.resize((800, 320), Image.LANCZOS)
            buf = io.BytesIO(); img.save(buf, "PNG"); return buf.getvalue()
        return img_bytes
    except Exception as e:
        logging.warning(f"DALL-E image skip: {e}")
        return None


def _get_pdf_image(topic: str, theme: str = "dark",
                   use_dalle: bool = True, width: int = 800, height: int = 320) -> bytes | None:
    """
    Get a header image for PDFs.
    1. Try DALL-E for a real topic image.
    2. Fall back to Pillow gradient art.
    3. Return None if nothing works.
    """
    # Try DALL-E
    if use_dalle and OPENAI_API_KEY and OPENAI_API_KEY.startswith("sk-"):
        dalle_prompt = (
            f"A visually appealing, professional, colorful illustration representing: {topic}. "
            f"Wide banner style, modern flat design, vibrant colors, no text."
        )
        img = _dalle_image(dalle_prompt)
        if img:
            return img

    # Fall back to Pillow art
    return _pillow_header(topic, subtitle="CineMagic AI Bot", width=width, height=height, theme=theme)


def _embed_image_in_canvas(c, img_bytes: bytes, x: float, y: float,
                            width: float, height: float):
    """Draw an image onto a ReportLab canvas at position (x,y) with given size."""
    try:
        from reportlab.lib.utils import ImageReader
        reader = ImageReader(io.BytesIO(img_bytes))
        c.drawImage(reader, x, y, width=width, height=height,
                    preserveAspectRatio=True, mask="auto")
    except Exception as e:
        logging.warning(f"_embed_image_in_canvas error: {e}")


def _check_libs(update_obj=None) -> str | None:
    """Return an error string if required libs are missing, else None."""
    missing = []
    if not PYPDF_OK:       missing.append("pypdf")
    if not PDFPLUMBER_OK:  missing.append("pdfplumber")
    if not REPORTLAB_OK:   missing.append("reportlab")
    if missing:
        return (
            f"⚠️ Missing PDF libraries: `{', '.join(missing)}`\n\n"
            f"Install in Termux:\n"
            f"`pip install {' '.join(missing)} --break-system-packages`"
        )
    return None


def _extract_pdf_text(pdf_bytes: bytes) -> str:
    """Extract all text from PDF bytes using pdfplumber (best quality)."""
    if not PDFPLUMBER_OK:
        return ""
    try:
        with pdfplumber.open(io.BytesIO(pdf_bytes)) as pdf:
            pages_text = []
            for i, page in enumerate(pdf.pages, 1):
                t = page.extract_text() or ""
                if t.strip():
                    pages_text.append(f"[Page {i}]\n{t}")
            return "\n\n".join(pages_text)
    except Exception as e:
        logger.error(f"PDF text extract error: {e}")
        return ""


def _extract_pdf_tables(pdf_bytes: bytes) -> list:
    """Extract all tables from PDF bytes. Returns list of tables."""
    if not PDFPLUMBER_OK:
        return []
    try:
        all_tables = []
        with pdfplumber.open(io.BytesIO(pdf_bytes)) as pdf:
            for page in pdf.pages:
                tables = page.extract_tables()
                for t in tables:
                    if t:
                        all_tables.append(t)
        return all_tables
    except Exception as e:
        logger.error(f"PDF table extract error: {e}")
        return []


def _build_report_pdf(title: str, content: str, author: str = "CineMagic Bot",
                      header_image: bytes = None) -> bytes:
    """Generate a nicely formatted PDF report using ReportLab. Returns bytes."""
    import datetime as _dt_pdf
    from reportlab.platypus import Image as RLImage
    buf = io.BytesIO()
    doc = SimpleDocTemplate(
        buf, pagesize=A4,
        rightMargin=2*cm, leftMargin=2*cm,
        topMargin=1.5*cm, bottomMargin=2*cm
    )
    styles = getSampleStyleSheet()
    title_style = ParagraphStyle(
        "CineTitle", parent=styles["Title"],
        fontSize=22, textColor=colors.HexColor("#1a1a2e"),
        spaceAfter=6, leading=28
    )
    subtitle_style = ParagraphStyle(
        "CineSub", parent=styles["Normal"],
        fontSize=10, textColor=colors.HexColor("#e94560"),
        spaceAfter=4
    )
    heading1_style = ParagraphStyle(
        "CineH1", parent=styles["Heading1"],
        fontSize=14, textColor=colors.HexColor("#16213e"),
        spaceBefore=14, spaceAfter=6
    )
    heading2_style = ParagraphStyle(
        "CineH2", parent=styles["Heading2"],
        fontSize=12, textColor=colors.HexColor("#0f3460"),
        spaceBefore=10, spaceAfter=4
    )
    body_style = ParagraphStyle(
        "CineBody", parent=styles["Normal"],
        fontSize=10, leading=16,
        textColor=colors.HexColor("#2d2d2d"),
        spaceAfter=8
    )
    bullet_style = ParagraphStyle(
        "CineBullet", parent=styles["Normal"],
        fontSize=10, leading=15,
        leftIndent=18, bulletIndent=6,
        textColor=colors.HexColor("#2d2d2d"),
        spaceAfter=4
    )
    story = []
    # ── Header image ──────────────────────────────────────────────
    if header_image:
        try:
            from reportlab.lib.utils import ImageReader
            rl_img = RLImage(io.BytesIO(header_image), width=17*cm, height=6.5*cm)
            rl_img.hAlign = "CENTER"
            story.append(rl_img)
            story.append(Spacer(1, 10))
        except Exception:
            pass
    story.append(Paragraph("🎬 CineMagic AI Bot", subtitle_style))
    story.append(Paragraph(title, title_style))
    story.append(Paragraph(
        f"Generated by {author}  •  {_dt_pdf.datetime.now().strftime('%d %B %Y, %H:%M')}",
        subtitle_style
    ))
    story.append(HRFlowable(width="100%", thickness=2,
                             color=colors.HexColor("#e94560"), spaceAfter=14))
    import re as _re_pdf
    for line in content.split("\n"):
        stripped = line.strip()
        if not stripped:
            story.append(Spacer(1, 6)); continue
        if stripped.startswith("### "):
            story.append(Paragraph(stripped[4:], heading2_style))
        elif stripped.startswith("## ") or stripped.startswith("# "):
            story.append(Paragraph(stripped.lstrip("#").strip(), heading1_style))
        elif stripped.startswith(("- ", "• ", "* ")):
            text = _re_pdf.sub(r'\*\*(.+?)\*\*', r'<b>\1</b>', stripped[2:].strip())
            story.append(Paragraph(f"• {text}", bullet_style))
        elif _re_pdf.match(r'^\d+[\.\)]\s', stripped):
            text = _re_pdf.sub(r'^\d+[\.\)]\s+', '', stripped)
            text = _re_pdf.sub(r'\*\*(.+?)\*\*', r'<b>\1</b>', text)
            story.append(Paragraph(f"  {stripped[:2]} {text}", bullet_style))
        elif stripped.startswith("**") and stripped.endswith("**"):
            story.append(Paragraph(f"<b>{stripped[2:-2]}</b>", heading2_style))
        else:
            text = _re_pdf.sub(r'\*\*(.+?)\*\*', r'<b>\1</b>', stripped)
            text = _re_pdf.sub(r'\*(.+?)\*', r'<i>\1</i>', text)
            story.append(Paragraph(text, body_style))
    story.append(Spacer(1, 20))
    story.append(HRFlowable(width="100%", thickness=1,
                             color=colors.HexColor("#cccccc"), spaceAfter=6))
    story.append(Paragraph(
        "Generated by CineMagic AI Bot  •  Powered by Anthropic Claude",
        ParagraphStyle("footer", parent=styles["Normal"],
                       fontSize=8, textColor=colors.grey, alignment=TA_CENTER)
    ))
    doc.build(story)
    return buf.getvalue()


"""
Publisher-style PDF engine — injected into cinemagic_bot-v17.py
All functions use ReportLab canvas for precise pixel-perfect layouts.
"""

# ════════════════════════════════════════════════════════════════
#  🖨️  PUBLISHER ENGINE — Microsoft Publisher-style PDF features
# ════════════════════════════════════════════════════════════════

import math as _pub_math

# ── Design helpers ───────────────────────────────────────────────

def _pub_rounded_rect(c, x, y, w, h, r=8, fill_color=None, stroke_color=None, lw=1):
    from reportlab.lib.utils import simpleSplit
    if fill_color:
        c.setFillColor(fill_color)
    if stroke_color:
        c.setStrokeColor(stroke_color)
        c.setLineWidth(lw)
    c.roundRect(x, y, w, h, r, fill=1 if fill_color else 0, stroke=1 if stroke_color else 0)

def _pub_gradient_rect(c, x, y, w, h, col1, col2, steps=40, horizontal=False):
    """Draw a gradient rectangle by stacking thin strips."""
    for i in range(steps):
        t = i / steps
        r = int(col1[0] + (col2[0]-col1[0])*t)
        g = int(col1[1] + (col2[1]-col1[1])*t)
        b = int(col1[2] + (col2[2]-col1[2])*t)
        c.setFillColorRGB(r/255, g/255, b/255)
        if horizontal:
            c.rect(x + w*i/steps, y, w/steps+1, h, fill=1, stroke=0)
        else:
            c.rect(x, y + h*i/steps, w, h/steps+1, fill=1, stroke=0)

def _pub_decorative_border(c, x, y, w, h, color, style="double", lw=2):
    """Draw decorative borders around a rectangle."""
    c.setStrokeColor(color); c.setLineWidth(lw)
    c.rect(x, y, w, h, fill=0, stroke=1)
    if style == "double":
        gap = lw + 3
        c.setLineWidth(max(1, lw-1))
        c.rect(x+gap, y+gap, w-gap*2, h-gap*2, fill=0, stroke=1)
    elif style == "thick_thin":
        c.setLineWidth(1)
        c.rect(x+lw+4, y+lw+4, w-(lw+4)*2, h-(lw+4)*2, fill=0, stroke=1)

def _pub_corner_ornaments(c, x, y, w, h, color, size=18):
    """Draw decorative corner ornaments."""
    c.setFillColor(color)
    corners = [(x, y+h), (x+w, y+h), (x, y), (x+w, y)]
    for cx2, cy2 in corners:
        c.circle(cx2, cy2, size//3, fill=1, stroke=0)
        c.setFillColor(colors.white)
        c.circle(cx2, cy2, size//6, fill=1, stroke=0)
        c.setFillColor(color)

def _pub_watermark_diagonal(c, text, W, H, col=None):
    """Diagonal watermark text across the page."""
    if col is None:
        col = colors.Color(0.85, 0.85, 0.85, 0.3)
    c.saveState()
    c.setFillColor(col)
    c.setFont("Helvetica-Bold", 52)
    c.translate(W/2, H/2)
    c.rotate(35)
    c.drawCentredString(0, 0, text.upper())
    c.restoreState()

def _pub_divider_line(c, x, y, w, color, style="solid", lw=1):
    c.setStrokeColor(color); c.setLineWidth(lw)
    if style == "dashed":
        c.setDash(6, 4)
    elif style == "dotted":
        c.setDash(2, 4)
    c.line(x, y, x+w, y)
    c.setDash()

def _pub_text_box(c, text, x, y, w, h, font="Helvetica", size=11,
                  color=colors.black, align="left", bg=None, padding=6,
                  border_color=None, border_w=1, bold=False):
    from reportlab.lib.utils import simpleSplit
    if bg:
        c.setFillColor(bg)
        c.rect(x, y, w, h, fill=1, stroke=0)
    if border_color:
        c.setStrokeColor(border_color); c.setLineWidth(border_w)
        c.rect(x, y, w, h, fill=0, stroke=1)
    font_name = f"Helvetica-Bold" if bold else font
    c.setFont(font_name, size)
    c.setFillColor(color)
    lines = simpleSplit(text, font_name, size, w - padding*2)
    ty = y + h - padding - size
    for ln in lines:
        if ty < y + padding: break
        if align == "center":
            c.drawCentredString(x + w/2, ty, ln)
        elif align == "right":
            c.drawRightString(x + w - padding, ty, ln)
        else:
            c.drawString(x + padding, ty, ln)
        ty -= size * 1.3

def _pub_star(c, cx, cy, r_outer, r_inner, points=5, fill_color=None):
    """Draw a star shape."""
    import math
    path = c.beginPath()
    for i in range(points * 2):
        angle = math.pi * i / points - math.pi/2
        r = r_outer if i % 2 == 0 else r_inner
        px = cx + r * math.cos(angle)
        py = cy + r * math.sin(angle)
        if i == 0: path.moveTo(px, py)
        else: path.lineTo(px, py)
    path.close()
    if fill_color:
        c.setFillColor(fill_color)
        c.drawPath(path, fill=1, stroke=0)

def _pub_ribbon_banner(c, text, x, y, w, h, bg_color, text_color=colors.white, fold=10):
    """Draw a ribbon/banner shape with folded ends."""
    c.setFillColor(bg_color)
    path = c.beginPath()
    path.moveTo(x, y + h/2)
    path.lineTo(x + fold, y + h)
    path.lineTo(x + w - fold, y + h)
    path.lineTo(x + w, y + h/2)
    path.lineTo(x + w - fold, y)
    path.lineTo(x + fold, y)
    path.close()
    c.drawPath(path, fill=1, stroke=0)
    c.setFillColor(text_color)
    c.setFont("Helvetica-Bold", min(h*0.55, 14))
    c.drawCentredString(x + w/2, y + h*0.28, text[:40])

def _pub_badge(c, text, cx, cy, radius, bg, fg=colors.white):
    c.setFillColor(bg); c.circle(cx, cy, radius, fill=1, stroke=0)
    c.setFillColor(fg); c.setFont("Helvetica-Bold", min(radius*0.55, 13))
    c.drawCentredString(cx, cy - min(radius*0.2, 5), text[:12])

def _pub_image_frame(c, img_bytes, x, y, w, h, radius=0, shadow=True):
    """Draw image with optional rounded frame and shadow."""
    if shadow:
        c.setFillColor(colors.Color(0,0,0,0.15))
        c.rect(x+4, y-4, w, h, fill=1, stroke=0)
    if img_bytes:
        try:
            from reportlab.lib.utils import ImageReader
            c.drawImage(ImageReader(io.BytesIO(img_bytes)), x, y,
                        width=w, height=h, preserveAspectRatio=True, mask='auto')
        except Exception:
            pass
    c.setStrokeColor(colors.white); c.setLineWidth(2)
    c.rect(x, y, w, h, fill=0, stroke=1)


# ════════════════════════════════════════════════════════════════
#  💼  BUSINESS CARD PDF
# ════════════════════════════════════════════════════════════════

def _build_businesscard_pdf(name: str, title: str, company: str,
                             phone: str, email: str, website: str = "",
                             tagline: str = "", theme: str = "dark") -> bytes:
    from reportlab.pdfgen import canvas as rl_c
    # Standard business card: 3.5 x 2 inches = 252 x 144 pt
    # Print 8 cards per A4 page (2 cols x 4 rows)
    W, H = A4
    BW, BH = 252, 144  # business card dimensions
    MARGIN_X = (W - BW*2 - 20) / 2
    MARGIN_Y = (H - BH*4 - 30) / 2

    THEMES = {
        "dark":   ((26,26,46),   (233,69,96),  (255,255,255)),
        "blue":   ((15,52,96),   (100,180,255),(255,255,255)),
        "green":  ((20,80,40),   (46,204,113), (255,255,255)),
        "gold":   ((26,20,5),    (212,175,55), (255,255,255)),
        "white":  ((255,255,255),(233,69,96),  (30,30,30)),
        "purple": ((40,10,80),   (155,89,182), (255,255,255)),
    }
    bg_rgb, ac_rgb, txt_rgb = THEMES.get(theme, THEMES["dark"])

    buf = io.BytesIO()
    c = rl_c.Canvas(buf, pagesize=A4)

    def _draw_card(ox, oy):
        # Background
        c.setFillColorRGB(*[v/255 for v in bg_rgb])
        c.rect(ox, oy, BW, BH, fill=1, stroke=0)
        # Accent strip top
        c.setFillColorRGB(*[v/255 for v in ac_rgb])
        c.rect(ox, oy+BH-12, BW, 12, fill=1, stroke=0)
        # Accent strip bottom
        c.rect(ox, oy, BW, 8, fill=1, stroke=0)
        # Left accent bar
        c.rect(ox, oy, 5, BH, fill=1, stroke=0)
        # Decorative circle
        c.setFillColorRGB(*[v/255 for v in ac_rgb])
        c.setFillColor(colors.Color(ac_rgb[0]/255, ac_rgb[1]/255, ac_rgb[2]/255, 0.18))
        c.circle(ox+BW-30, oy+BH/2, 55, fill=1, stroke=0)
        c.setFillColor(colors.Color(ac_rgb[0]/255, ac_rgb[1]/255, ac_rgb[2]/255, 0.12))
        c.circle(ox+BW-15, oy+15, 38, fill=1, stroke=0)

        tx_col = colors.Color(txt_rgb[0]/255, txt_rgb[1]/255, txt_rgb[2]/255)
        ac_col = colors.Color(ac_rgb[0]/255, ac_rgb[1]/255, ac_rgb[2]/255)

        # Name
        c.setFillColor(tx_col); c.setFont("Helvetica-Bold", 15)
        c.drawString(ox+14, oy+BH-32, name[:30])
        # Title
        c.setFillColor(ac_col); c.setFont("Helvetica-Oblique", 9)
        c.drawString(ox+14, oy+BH-45, title[:40])
        # Company
        c.setFillColor(tx_col); c.setFont("Helvetica-Bold", 11)
        c.drawString(ox+14, oy+BH-62, company[:35])
        # Divider
        c.setStrokeColor(ac_col); c.setLineWidth(0.8)
        c.line(ox+14, oy+BH-68, ox+BW-14, oy+BH-68)
        # Contact info
        y_off = oy+BH-82
        for icon, val in [("📞", phone), ("✉", email), ("🌐", website)]:
            if val:
                c.setFont("Helvetica", 8); c.setFillColor(tx_col)
                c.drawString(ox+14, y_off, f"{icon}  {val[:38]}")
                y_off -= 13
        # Tagline
        if tagline:
            c.setFillColor(ac_col); c.setFont("Helvetica-Oblique", 7.5)
            c.drawString(ox+14, oy+14, f'"{tagline[:45]}"')

    # Draw 8 cards (2x4)
    for row in range(4):
        for col in range(2):
            ox = MARGIN_X + col*(BW+20)
            oy = MARGIN_Y + row*(BH+10)
            _draw_card(ox, oy)

    # Page title
    c.setFillColor(colors.HexColor("#888888")); c.setFont("Helvetica", 8)
    c.drawCentredString(W/2, H-20, "Business Cards — Print and cut along edges — CineMagic AI Bot")
    c.showPage(); c.save()
    return buf.getvalue()


async def cmd_businesscard(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """/businesscard Name | Title | Company | Phone | Email | Website | Tagline"""
    err = _check_libs()
    if err: await update.message.reply_text(err, parse_mode="Markdown"); return
    args_text = " ".join(context.args).strip() if context.args else ""
    if not args_text or "|" not in args_text:
        await update.message.reply_text(
            "💼 *Business Card Generator*\n\n"
            "Usage:\n`/businesscard Name | Title | Company | Phone | Email`\n\n"
            "Full example:\n"
            "`/businesscard John Doe | CEO & Founder | TechCorp Ltd | +233201234567 | john@techcorp.com | www.techcorp.com | Innovation is our DNA`\n\n"
            "_Fields: Name | Title | Company | Phone | Email | Website (optional) | Tagline (optional)_",
            parse_mode="Markdown"); return
    parts = [p.strip() for p in args_text.split("|")]
    name    = parts[0] if len(parts) > 0 else "Your Name"
    title   = parts[1] if len(parts) > 1 else "Your Title"
    company = parts[2] if len(parts) > 2 else "Your Company"
    phone   = parts[3] if len(parts) > 3 else ""
    email   = parts[4] if len(parts) > 4 else ""
    website = parts[5] if len(parts) > 5 else ""
    tagline = parts[6] if len(parts) > 6 else ""
    msg = await update.message.reply_text("💼 Designing business cards… ⏳")
    await context.bot.send_chat_action(update.effective_chat.id, "upload_document")
    try:
        pdf_bytes = await asyncio.get_running_loop().run_in_executor(
            None, lambda: _build_businesscard_pdf(name, title, company, phone, email, website, tagline))
        await msg.delete()
        await update.message.reply_document(
            document=io.BytesIO(pdf_bytes),
            filename=f"BusinessCard_{name.replace(' ','_')}.pdf",
            caption=f"💼 *{name}* — Business Cards\n\n8 cards per page, ready to print and cut! ✂️",
            parse_mode="Markdown")
    except Exception as e:
        logger.error(f"cmd_businesscard error: {e}")
        await msg.edit_text(f"⚠️ Failed: `{str(e)[:120]}`", parse_mode="Markdown")


# ════════════════════════════════════════════════════════════════
#  🪧  POSTER PDF — Full-page poster
# ════════════════════════════════════════════════════════════════

def _build_poster_pdf(title: str, subtitle: str, body: str,
                      footer: str, theme: str = "dark",
                      header_image: bytes = None) -> bytes:
    from reportlab.pdfgen import canvas as rl_c
    from reportlab.lib.utils import simpleSplit as ss
    W, H = A4
    buf = io.BytesIO(); c = rl_c.Canvas(buf, pagesize=A4)

    THEMES = {
        "dark":   ((26,26,46),   (15,52,96),   (233,69,96), (255,255,255)),
        "fire":   ((80,10,10),   (180,30,10),  (255,120,0), (255,255,255)),
        "ocean":  ((5,30,70),    (10,80,150),  (0,180,216), (255,255,255)),
        "forest": ((10,40,10),   (20,100,40),  (46,204,113),(255,255,255)),
        "royal":  ((40,0,80),    (80,0,120),   (180,100,255),(255,255,255)),
        "gold":   ((40,25,0),    (100,65,0),   (212,175,55),(255,255,255)),
        "bright": ((255,255,255),(240,240,240),(233,69,96), (20,20,20)),
    }
    bg1, bg2, ac, txt = THEMES.get(theme, THEMES["dark"])

    # Gradient background
    _pub_gradient_rect(c, 0, 0, W, H,
                       (bg1[0],bg1[1],bg1[2]),
                       (bg2[0],bg2[1],bg2[2]), steps=60)

    ac_col  = colors.Color(ac[0]/255,  ac[1]/255,  ac[2]/255)
    txt_col = colors.Color(txt[0]/255, txt[1]/255, txt[2]/255)

    # Top and bottom accent bars
    c.setFillColor(ac_col)
    c.rect(0, H-18, W, 18, fill=1, stroke=0)
    c.rect(0, 0, W, 18, fill=1, stroke=0)
    # Left accent strip
    c.rect(0, 0, 10, H, fill=1, stroke=0)
    # Right accent strip
    c.rect(W-10, 0, 10, H, fill=1, stroke=0)

    # Decorative circles
    c.setFillColor(colors.Color(ac[0]/255, ac[1]/255, ac[2]/255, 0.12))
    c.circle(W-60, H-80, 150, fill=1, stroke=0)
    c.circle(60, 80, 120, fill=1, stroke=0)
    c.setFillColor(colors.Color(1,1,1,0.04))
    c.circle(W/2, H/2, 220, fill=1, stroke=0)

    y_cursor = H - 40

    # Header image
    if header_image:
        img_h = 180
        try:
            from reportlab.lib.utils import ImageReader
            c.drawImage(ImageReader(io.BytesIO(header_image)),
                        20, H-40-img_h, width=W-40, height=img_h,
                        preserveAspectRatio=True, mask='auto')
        except Exception:
            img_h = 0
        y_cursor = H - 40 - img_h - 16
    else:
        y_cursor = H - 55

    # Ribbon banner for title
    ribbon_h = 54
    _pub_ribbon_banner(c, "", 20, y_cursor-ribbon_h, W-40, ribbon_h, ac_col)

    # Title text
    c.setFillColor(txt_col); c.setFont("Helvetica-Bold", 36)
    tlines = ss(title.upper(), "Helvetica-Bold", 36, W-80)
    ty = y_cursor - 16
    for ln in tlines[:2]:
        c.drawCentredString(W/2, ty, ln); ty -= 42
    y_cursor = ty - 10

    # Subtitle
    if subtitle:
        c.setFillColor(ac_col); c.setFont("Helvetica-Bold", 17)
        for ln in ss(subtitle, "Helvetica-Bold", 17, W-80)[:2]:
            c.drawCentredString(W/2, y_cursor, ln); y_cursor -= 24
        y_cursor -= 8

    # Horizontal divider
    _pub_divider_line(c, 40, y_cursor, W-80, ac_col, "solid", 2)
    y_cursor -= 18

    # Body text in two columns
    body_lines = body.split("\n")
    left_lines  = body_lines[:len(body_lines)//2+1]
    right_lines = body_lines[len(body_lines)//2+1:]
    col_w = (W-90)/2

    for col_idx, col_lines in enumerate([left_lines, right_lines]):
        cx = 30 + col_idx*(col_w+30)
        cy = y_cursor
        for line in col_lines:
            s = line.strip()
            if not s: cy -= 8; continue
            if s.startswith(("•","-","*")):
                c.setFillColor(ac_col); c.circle(cx+8, cy+5, 3, fill=1, stroke=0)
                c.setFillColor(txt_col); c.setFont("Helvetica", 12)
                for sub in ss(s.lstrip("•-* "), "Helvetica", 12, col_w-18)[:2]:
                    c.drawString(cx+18, cy, sub); cy -= 17
            elif s.startswith("##"):
                c.setFillColor(ac_col); c.setFont("Helvetica-Bold", 14)
                c.drawString(cx, cy, s.lstrip("# ")[:40]); cy -= 20
            else:
                c.setFillColor(txt_col); c.setFont("Helvetica", 11)
                for sub in ss(s, "Helvetica", 11, col_w)[:3]:
                    c.drawString(cx, cy, sub); cy -= 16
            cy -= 4
            if cy < 50: break

    # Footer
    c.setFillColor(ac_col)
    c.rect(20, 22, W-40, 24, fill=1, stroke=0)
    c.setFillColor(txt_col); c.setFont("Helvetica-Bold", 11)
    c.drawCentredString(W/2, 28, (footer or "Generated by CineMagic AI Bot")[:80])

    # Corner ornaments
    _pub_corner_ornaments(c, 12, 20, W-24, H-40, ac_col, 14)

    c.showPage(); c.save()
    return buf.getvalue()


async def cmd_poster(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """/poster <topic> — Full-page Publisher-style poster."""
    err = _check_libs()
    if err: await update.message.reply_text(err, parse_mode="Markdown"); return
    topic = " ".join(context.args).strip() if context.args else ""
    if not topic:
        await update.message.reply_text(
            "🪧 *Poster Generator*\n\nUsage: `/poster <topic>`\n\n"
            "Examples:\n• `/poster School Science Fair 2025`\n"
            "• `/poster Church Revival Sunday`\n• `/poster Grand Opening Event`",
            parse_mode="Markdown"); return
    msg = await update.message.reply_text("🪧 Designing your poster… ⏳")
    await context.bot.send_chat_action(update.effective_chat.id, "upload_document")
    try:
        prompt = (
            f"Create poster content for: {topic}\n"
            "Return ONLY raw JSON:\n"
            '{"title":"POSTER TITLE","subtitle":"Subtitle line","body":"Content with • bullets and ## headings","footer":"Date/venue/contact","theme":"dark"}\n'
            "title max 5 words ALL CAPS, subtitle 1 line, body 8-12 lines with bullets, "
            "theme: dark/fire/ocean/forest/royal/gold/bright"
        )
        raw = await asyncio.get_running_loop().run_in_executor(None, lambda: call_gemini(prompt, use_cache=False))
        import json as _jj, re as _rr
        m = _rr.search(r'\{.*\}', raw, _rr.DOTALL)
        data = _jj.loads(m.group(0)) if m else {}
        hdr = await asyncio.get_running_loop().run_in_executor(
            None, lambda: _get_pdf_image(topic, theme=data.get("theme","dark")))
        pdf_bytes = await asyncio.get_running_loop().run_in_executor(
            None, lambda: _build_poster_pdf(
                data.get("title", topic.upper()),
                data.get("subtitle",""),
                data.get("body",""),
                data.get("footer","CineMagic AI Bot"),
                data.get("theme","dark"),
                header_image=hdr))
        await msg.delete()
        await update.message.reply_document(
            document=io.BytesIO(pdf_bytes),
            filename=f"Poster_{topic[:25].replace(' ','_')}.pdf",
            caption=f"🪧 *{topic}* — Poster ready! 🎨", parse_mode="Markdown")
    except Exception as e:
        logger.error(f"cmd_poster error: {e}")
        await msg.edit_text(f"⚠️ Poster failed: `{str(e)[:120]}`", parse_mode="Markdown")


