#  🍽️  MENU PDF — Restaurant / food menu
# ════════════════════════════════════════════════════════════════

def _build_menu_pdf(restaurant: str, tagline: str, sections: list,
                    footer: str = "", theme: str = "gold",
                    header_image: bytes = None) -> bytes:
    """
    sections = [{"name":"Category","items":[{"name":"Dish","desc":"desc","price":"$10"}]}]
    """
    from reportlab.pdfgen import canvas as rl_c
    from reportlab.lib.utils import simpleSplit as ss
    W, H = A4
    buf = io.BytesIO(); c = rl_c.Canvas(buf, pagesize=A4)

    THEMES = {
        "gold":   (colors.HexColor("#1a1200"), colors.HexColor("#c9a84c"), colors.white,   colors.HexColor("#f5e6c0")),
        "red":    (colors.HexColor("#1a0000"), colors.HexColor("#c0392b"), colors.white,   colors.HexColor("#ffe0e0")),
        "green":  (colors.HexColor("#001a05"), colors.HexColor("#27ae60"), colors.white,   colors.HexColor("#e0ffe8")),
        "dark":   (colors.HexColor("#0a0a1a"), colors.HexColor("#e94560"), colors.white,   colors.HexColor("#f5f5ff")),
        "elegant":(colors.HexColor("#1a1a1a"), colors.HexColor("#c9a84c"), colors.white,   colors.HexColor("#f9f3e3")),
    }
    BG, AC, LIGHT, CREAM = THEMES.get(theme, THEMES["gold"])

    # Page background
    c.setFillColor(CREAM); c.rect(0, 0, W, H, fill=1, stroke=0)

    # Header area
    hdr_h = 180 if header_image else 130
    c.setFillColor(BG); c.rect(0, H-hdr_h, W, hdr_h, fill=1, stroke=0)
    if header_image:
        try:
            from reportlab.lib.utils import ImageReader
            c.drawImage(ImageReader(io.BytesIO(header_image)),
                        0, H-hdr_h, width=W, height=hdr_h,
                        preserveAspectRatio=False, mask='auto')
            c.setFillColor(colors.Color(0,0,0,0.6)); c.rect(0, H-hdr_h, W, hdr_h, fill=1, stroke=0)
        except Exception:
            pass

    # Restaurant name
    c.setFillColor(AC); c.setFont("Helvetica-Bold", 32)
    c.drawCentredString(W/2, H-55, restaurant[:35])
    # Gold dividers
    _pub_divider_line(c, 40, H-62, W-80, AC, "solid", 1.5)
    _pub_divider_line(c, 40, H-65, W-80, AC, "solid", 0.5)
    # Tagline
    if tagline:
        c.setFillColor(LIGHT); c.setFont("Helvetica-Oblique", 12)
        c.drawCentredString(W/2, H-82, tagline[:60])
    _pub_divider_line(c, 40, H-hdr_h+8, W-80, AC, "solid", 1)

    # Menu content — 2 columns
    COL_W = (W-60)/2; y_left = H-hdr_h-20; y_right = H-hdr_h-20
    left_secs  = sections[:len(sections)//2 + len(sections)%2]
    right_secs = sections[len(sections)//2 + len(sections)%2:]

    def _draw_section(sx, sy, cw, sec):
        # Category header
        c.setFillColor(BG)
        c.roundRect(sx, sy-20, cw, 22, 4, fill=1, stroke=0)
        c.setFillColor(AC); c.setFont("Helvetica-Bold", 12)
        c.drawCentredString(sx+cw/2, sy-14, sec.get("name","").upper()[:30])
        sy -= 28
        for item in sec.get("items",[]):
            iname = item.get("name",""); idesc = item.get("desc",""); iprice = item.get("price","")
            # Item name + price on same line with dots
            name_w = c.stringWidth(iname, "Helvetica-Bold", 11)
            price_w = c.stringWidth(iprice, "Helvetica-Bold", 11)
            dots_w = cw - name_w - price_w - 8
            c.setFillColor(colors.HexColor("#1a1a1a")); c.setFont("Helvetica-Bold", 11)
            c.drawString(sx, sy, iname[:28])
            c.setFillColor(AC); c.setFont("Helvetica-Bold", 11)
            c.drawRightString(sx+cw, sy, iprice)
            # Dotted line between name and price
            c.setStrokeColor(colors.HexColor("#ccbbaa")); c.setLineWidth(0.5); c.setDash(2,3)
            c.line(sx+name_w+4, sy+3, sx+cw-price_w-4, sy+3); c.setDash()
            sy -= 14
            if idesc:
                c.setFillColor(colors.HexColor("#666666")); c.setFont("Helvetica-Oblique", 9)
                for sub in ss(idesc, "Helvetica-Oblique", 9, cw)[:2]:
                    c.drawString(sx+6, sy, sub); sy -= 12
            sy -= 6
            if sy < 50: break
        return sy - 10

    for sec in left_secs:
        if y_left < 60: break
        y_left = _draw_section(22, y_left, COL_W, sec)
    for sec in right_secs:
        if y_right < 60: break
        y_right = _draw_section(22+COL_W+16, y_right, COL_W, sec)

    # Center divider line
    c.setStrokeColor(AC); c.setLineWidth(0.8)
    c.line(W/2, H-hdr_h-10, W/2, 40)

    # Footer
    c.setFillColor(BG); c.rect(0, 0, W, 36, fill=1, stroke=0)
    c.setFillColor(AC); c.setFont("Helvetica-Bold", 10)
    c.drawCentredString(W/2, 12, (footer or f"{restaurant} — Thank you for dining with us!")[:80])

    # Decorative border
    _pub_decorative_border(c, 8, 8, W-16, H-16, AC, "double", 1.5)

    c.showPage(); c.save()
    return buf.getvalue()


