#  🎟️  INVITATION PDF
# ════════════════════════════════════════════════════════════════

def _build_invitation_pdf(event: str, date: str, time: str, venue: str,
                           host: str, message: str, theme: str = "gold",
                           header_image: bytes = None) -> bytes:
    from reportlab.pdfgen import canvas as rl_c
    from reportlab.lib.utils import simpleSplit as ss
    W, H = A4
    buf = io.BytesIO(); c = rl_c.Canvas(buf, pagesize=A4)

    THEMES = {
        "gold":   ((10,8,2),    (212,175,55), (255,255,255),(250,240,210)),
        "pink":   ((45,5,25),   (220,80,120), (255,255,255),(255,230,240)),
        "blue":   ((5,15,45),   (100,160,255),(255,255,255),(220,235,255)),
        "green":  ((5,30,15),   (46,180,96),  (255,255,255),(220,255,235)),
        "purple": ((25,5,45),   (160,80,220), (255,255,255),(240,220,255)),
        "royal":  ((20,10,50),  (180,140,40), (255,255,255),(250,245,220)),
    }
    bg_rgb, ac_rgb, lt_rgb, cream_rgb = THEMES.get(theme, THEMES["gold"])
    BG    = colors.Color(*[v/255 for v in bg_rgb])
    AC    = colors.Color(*[v/255 for v in ac_rgb])
    LIGHT = colors.Color(*[v/255 for v in lt_rgb])
    CREAM = colors.Color(*[v/255 for v in cream_rgb])

    # Parchment/cream background
    c.setFillColor(CREAM); c.rect(0, 0, W, H, fill=1, stroke=0)

    # Decorative border (double)
    _pub_decorative_border(c, 12, 12, W-24, H-24, AC, "double", 2)

    # Corner ornaments
    _pub_corner_ornaments(c, 14, 14, W-28, H-28, AC, 20)

    # Top decorative band
    c.setFillColor(BG); c.rect(20, H-80, W-40, 60, fill=1, stroke=0)
    if header_image:
        try:
            from reportlab.lib.utils import ImageReader
            c.drawImage(ImageReader(io.BytesIO(header_image)),
                        20, H-80, width=W-40, height=60,
                        preserveAspectRatio=False, mask='auto')
            c.setFillColor(colors.Color(0,0,0,0.5))
            c.rect(20, H-80, W-40, 60, fill=1, stroke=0)
        except Exception: pass

    # "You Are Invited" header
    c.setFillColor(AC); c.setFont("Helvetica-BoldOblique", 14)
    c.drawCentredString(W/2, H-38, "✦  You Are Cordially Invited  ✦")
    _pub_divider_line(c, 40, H-84, W-80, AC, "solid", 1)

    # Event name — big
    c.setFillColor(BG); c.setFont("Helvetica-Bold", 34)
    ev_lines = ss(event, "Helvetica-Bold", 34, W-80)
    ey = H-125
    for ln in ev_lines[:2]: c.drawCentredString(W/2, ey, ln); ey -= 42

    # Host line
    if host:
        c.setFillColor(colors.HexColor("#555555")); c.setFont("Helvetica-Oblique", 13)
        c.drawCentredString(W/2, ey-5, f"Hosted by {host}")
        ey -= 26

    # Gold divider with stars
    _pub_divider_line(c, 60, ey-10, W-120, AC, "solid", 1)
    _pub_star(c, W/2, ey-10, 8, 4, 5, AC)
    ey -= 30

    # Date/Time/Venue boxes
    details = [("📅 DATE", date), ("⏰ TIME", time), ("📍 VENUE", venue)]
    box_w = (W-80)/3
    for i, (label, val) in enumerate(details):
        bx = 30 + i*(box_w+10)
        if val:
            _pub_rounded_rect(c, bx, ey-50, box_w, 50, 6, BG, AC, 1.5)
            c.setFillColor(AC); c.setFont("Helvetica-Bold", 8)
            c.drawCentredString(bx+box_w/2, ey-14, label)
            c.setFillColor(LIGHT); c.setFont("Helvetica", 10)
            for sub in ss(val, "Helvetica", 10, box_w-10)[:2]:
                c.drawCentredString(bx+box_w/2, ey-28, sub); ey -= 0
    ey -= 70

    # Personal message
    if message:
        _pub_divider_line(c, 60, ey, W-120, AC, "dashed", 0.8)
        ey -= 20
        c.setFillColor(colors.HexColor("#333333")); c.setFont("Helvetica-Oblique", 11)
        for line in message.split("\n"):
            for sub in ss(line.strip(), "Helvetica-Oblique", 11, W-100)[:3]:
                c.drawCentredString(W/2, ey, sub); ey -= 17
            if ey < 80: break
        ey -= 10

    # RSVP footer
    _pub_divider_line(c, 60, ey, W-120, AC, "solid", 1)
    ey -= 20
    c.setFillColor(BG); c.setFont("Helvetica-Bold", 11)
    c.drawCentredString(W/2, ey, "We look forward to celebrating with you!")
    ey -= 18
    c.setFillColor(colors.HexColor("#888888")); c.setFont("Helvetica", 9)
    c.drawCentredString(W/2, ey, "Generated by CineMagic AI Bot")

    c.showPage(); c.save()
    return buf.getvalue()


async def cmd_invitation(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """/invitation Event | Date | Time | Venue | Host | Message"""
    err = _check_libs()
