# ════════════════════════════════════════════════════════════════
#  📅  CALENDAR PDF
# ════════════════════════════════════════════════════════════════

def _build_calendar_pdf(year: int, month: int, events: dict = None,
                         theme: str = "dark", header_image: bytes = None) -> bytes:
    import calendar as _cal
    from reportlab.pdfgen import canvas as rl_c
    W, H = A4[1], A4[0]  # landscape
    buf = io.BytesIO(); c = rl_c.Canvas(buf, pagesize=(W, H))
    events = events or {}

    THEMES = {
        "dark":   (colors.HexColor("#1a1a2e"), colors.HexColor("#e94560"), colors.white,   colors.HexColor("#f0f0f0")),
        "blue":   (colors.HexColor("#0f3460"), colors.HexColor("#0080ff"), colors.white,   colors.HexColor("#e8f4ff")),
        "green":  (colors.HexColor("#1a3a1a"), colors.HexColor("#27ae60"), colors.white,   colors.HexColor("#e8ffe8")),
        "gold":   (colors.HexColor("#1a1200"), colors.HexColor("#c9a84c"), colors.white,   colors.HexColor("#fdf6e3")),
        "purple": (colors.HexColor("#1a0a2e"), colors.HexColor("#8e44ad"), colors.white,   colors.HexColor("#f5eeff")),
    }
    BG, AC, LIGHT, PALE = THEMES.get(theme, THEMES["dark"])

    # Background
    c.setFillColor(PALE); c.rect(0, 0, W, H, fill=1, stroke=0)

    # Header
    hdr_h = 90
    # Solid dark background first
    c.setFillColor(BG); c.rect(0, H-hdr_h, W, hdr_h, fill=1, stroke=0)
    if header_image:
        try:
            from reportlab.lib.utils import ImageReader
            # Draw image at low opacity by drawing it then covering with near-opaque overlay
            c.drawImage(ImageReader(io.BytesIO(header_image)),
                        0, H-hdr_h, width=W, height=hdr_h,
                        preserveAspectRatio=False, mask='auto')
            # Strong overlay so image text doesn't show through
            c.setFillColor(colors.Color(
                int(str(BG).split('(')[1].split(',')[0].strip())/255 if '(' in str(BG) else 0,
                0, 0, 0.82))
            c.setFillColor(colors.Color(0, 0, 0, 0.82))
            c.rect(0, H-hdr_h, W, hdr_h, fill=1, stroke=0)
        except Exception: pass

    # Accent left bar
    c.setFillColor(AC); c.rect(0, H-hdr_h, 8, hdr_h, fill=1, stroke=0)

    month_name = _cal.month_name[month]
    c.setFillColor(AC); c.setFont("Helvetica-Bold", 36)
    c.drawString(24, H-58, month_name.upper())
    c.setFillColor(LIGHT); c.setFont("Helvetica", 28)
    c.drawString(24 + c.stringWidth(month_name.upper(), "Helvetica-Bold", 36) + 12, H-58, str(year))
    c.setFillColor(colors.Color(1,1,1,0.5)); c.setFont("Helvetica", 10)
    c.drawRightString(W-16, H-34, "Generated by CineMagic AI Bot")
    c.setFillColor(AC); c.rect(0, H-hdr_h, W, 4, fill=1, stroke=0)  # top accent line

    # Day name headers
    days = ["MON","TUE","WED","THU","FRI","SAT","SUN"]
    cell_w = (W-20) / 7
    cell_h = (H-hdr_h-20) / 6
    header_y = H-hdr_h-30
    for i, day in enumerate(days):
        dx = 10 + i*cell_w
        c.setFillColor(AC if day not in ("SAT","SUN") else colors.HexColor("#cc2244"))
        c.rect(dx, header_y, cell_w-2, 22, fill=1, stroke=0)
        c.setFillColor(LIGHT); c.setFont("Helvetica-Bold", 10)
        c.drawCentredString(dx+cell_w/2, header_y+6, day)

    # Calendar grid
    cal = _cal.monthcalendar(year, month)
    # Pad to 6 rows
    while len(cal) < 6: cal.append([0]*7)

    for row_i, week in enumerate(cal):
        for col_i, day_num in enumerate(week):
            cx = 10 + col_i*cell_w
            cy = header_y - 24 - row_i*cell_h
            is_weekend = col_i >= 5
            is_today = False  # Could check real date

            # Cell background
            bg = colors.Color(0.96, 0.94, 0.94) if is_weekend else colors.white
            c.setFillColor(bg)
            c.roundRect(cx, cy-cell_h+4, cell_w-3, cell_h-2, 3, fill=1, stroke=0)
            c.setStrokeColor(colors.HexColor("#dddddd")); c.setLineWidth(0.5)
            c.roundRect(cx, cy-cell_h+4, cell_w-3, cell_h-2, 3, fill=0, stroke=1)

            if day_num > 0:
                # Day number
                num_col = colors.HexColor("#cc2244") if is_weekend else BG
                c.setFillColor(AC)
                c.circle(cx+16, cy-6, 12, fill=1, stroke=0)
                c.setFillColor(LIGHT); c.setFont("Helvetica-Bold", 10)
                c.drawCentredString(cx+16, cy-10, str(day_num))

                # Events for this day
                ev_text = events.get(day_num, "")
                if ev_text:
                    c.setFillColor(colors.HexColor("#333333")); c.setFont("Helvetica", 7)
                    from reportlab.lib.utils import simpleSplit as ss2
                    ev_y = cy-24
                    for ln in ss2(ev_text, "Helvetica", 7, cell_w-8)[:3]:
                        c.drawString(cx+3, ev_y, ln); ev_y -= 10

    # Footer
    c.setFillColor(BG); c.rect(0, 0, W, 18, fill=1, stroke=0)
    c.setFillColor(AC); c.setFont("Helvetica", 8)
    c.drawCentredString(W/2, 5, f"{month_name} {year}  •  CineMagic AI Bot")

    c.showPage(); c.save()
    return buf.getvalue()


async def cmd_calendar(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """/calendar <Month Year> or /calendar <Month Year | Event1 on Day1 | Event2 on Day2>"""
    err = _check_libs()
    if err: await update.message.reply_text(err, parse_mode="Markdown"); return
    import calendar as _cal2
    args_text = " ".join(context.args).strip() if context.args else ""
    if not args_text:
        await update.message.reply_text(
            "📅 *Calendar Generator*\n\nUsage: `/calendar <Month Year>`\n\n"
            "With events:\n`/calendar June 2025 | Birthday on 5 | Meeting on 14 | Holiday on 20`\n\n"
            "Examples:\n• `/calendar August 2025`\n• `/calendar December 2025 | Christmas on 25 | New Year Eve on 31`",
            parse_mode="Markdown"); return
    parts = [p.strip() for p in args_text.split("|")]
    month_year = parts[0].strip()
    events = {}
    for part in parts[1:]:
        try:
            ev_parts = part.strip().rsplit(" on ", 1)
            if len(ev_parts) == 2:
                events[int(ev_parts[1].strip())] = ev_parts[0].strip()
        except Exception: pass
    try:
        import datetime as _dtt
        months = {m.lower():i for i,m in enumerate(_cal2.month_name) if m}
        words = month_year.split()
        month = 0; year = _dtt.datetime.now().year
        for w in words:
            if w.lower() in months: month = months[w.lower()]
            elif w.isdigit() and len(w)==4: year = int(w)
        if not month: month = _dtt.datetime.now().month
    except Exception:
        import datetime as _dtt2
        month = _dtt2.datetime.now().month; year = _dtt2.datetime.now().year

    msg = await update.message.reply_text("📅 Generating your calendar… ⏳")
    await context.bot.send_chat_action(update.effective_chat.id, "upload_document")
    try:
        import calendar as _cal3
        hdr = await asyncio.get_running_loop().run_in_executor(
            None, lambda: _get_pdf_image(f"{_cal3.month_name[month]} {year} calendar", theme="dark"))
        pdf_bytes = await asyncio.get_running_loop().run_in_executor(
            None, lambda: _build_calendar_pdf(year, month, events, header_image=hdr))
        await msg.delete()
        await update.message.reply_document(
            document=io.BytesIO(pdf_bytes),
            filename=f"Calendar_{_cal3.month_name[month]}_{year}.pdf",
            caption=f"📅 *{_cal3.month_name[month]} {year}* Calendar ready! 🗓️",
            parse_mode="Markdown")
    except Exception as e:
        logger.error(f"cmd_calendar error: {e}")
        await msg.edit_text(f"⚠️ Calendar failed: `{str(e)[:120]}`", parse_mode="Markdown")


# ════════════════════════════════════════════════════════════════
#  ⛪  CHURCH PROGRAM PDF
# ════════════════════════════════════════════════════════════════

def _build_churchprogram_pdf(church: str, service_title: str, date: str,
                              theme: str, sections: list,
                              header_image: bytes = None) -> bytes:
    from reportlab.pdfgen import canvas as rl_c
    from reportlab.lib.utils import simpleSplit as ss
    W, H = A4
    buf = io.BytesIO(); c = rl_c.Canvas(buf, pagesize=A4)

    GOLD  = colors.HexColor("#c9a84c")
    DGOLD = colors.HexColor("#8B6914")
    DARK  = colors.HexColor("#1a1a2e")
    WHITE = colors.white
    CREAM = colors.HexColor("#fdf6e3")

    c.setFillColor(CREAM); c.rect(0, 0, W, H, fill=1, stroke=0)
    _pub_decorative_border(c, 10, 10, W-20, H-20, GOLD, "double", 2)
    _pub_corner_ornaments(c, 12, 12, W-24, H-24, GOLD, 18)

    y = H-30
    # Header image
    if header_image:
        try:
            from reportlab.lib.utils import ImageReader
            c.drawImage(ImageReader(io.BytesIO(header_image)),
                        22, H-130, width=W-44, height=100,
                        preserveAspectRatio=True, mask='auto')
            y = H-138
        except Exception:
            y = H-40
    else:
        y = H-40

    # Cross symbol
    c.setFillColor(GOLD); c.setFont("Helvetica-Bold", 28)
    c.drawCentredString(W/2, y, "✝")
    y -= 32

    # Church name
    c.setFillColor(DARK); c.setFont("Helvetica-Bold", 22)
    for ln in ss(church.upper(), "Helvetica-Bold", 22, W-80)[:2]:
        c.drawCentredString(W/2, y, ln); y -= 28

    # Service title
    _pub_divider_line(c, 50, y+2, W-100, GOLD, "solid", 1)
    y -= 12
    c.setFillColor(GOLD); c.setFont("Helvetica-BoldOblique", 15)
    c.drawCentredString(W/2, y, service_title[:50])
    y -= 18

    # Date
    c.setFillColor(colors.HexColor("#555555")); c.setFont("Helvetica", 11)
    c.drawCentredString(W/2, y, date)
    y -= 12
    _pub_divider_line(c, 50, y, W-100, GOLD, "solid", 1.5)
    _pub_divider_line(c, 50, y-4, W-100, GOLD, "solid", 0.5)
    y -= 22

    # Program sections
    for sec in sections:
        heading = sec.get("heading","")
        items   = sec.get("items", [])

        # Section heading with gold background
        c.setFillColor(DARK); c.rect(30, y-16, W-60, 18, fill=1, stroke=0)
        c.setFillColor(GOLD); c.setFont("Helvetica-Bold", 11)
        c.drawCentredString(W/2, y-10, heading.upper()[:50])
        y -= 26

        for item in items:
            it_time  = item.get("time","")
            it_title = item.get("title","")
            it_who   = item.get("who","")
            c.setFillColor(DARK); c.setFont("Helvetica-Bold", 10)
            c.drawString(35, y, it_title[:50])
            if it_time:
                c.setFillColor(GOLD); c.setFont("Helvetica", 9)
                c.drawRightString(W-35, y, it_time)
            if it_who:
                c.setFillColor(colors.HexColor("#666666")); c.setFont("Helvetica-Oblique", 9)
                c.drawString(40, y-11, f"— {it_who[:50]}")
                y -= 10
            # Dotted separator
            c.setStrokeColor(colors.HexColor("#ddd5bb")); c.setLineWidth(0.4)
            c.setDash(2,3); c.line(35, y-4, W-35, y-4); c.setDash()
            y -= 18
            if y < 60: break
        y -= 8
        if y < 60: break

    # Footer
    c.setFillColor(DARK); c.rect(22, 20, W-44, 26, fill=1, stroke=0)
    c.setFillColor(GOLD); c.setFont("Helvetica-Bold", 9)
    c.drawCentredString(W/2, 28, "Welcome! God Bless You  ✝  CineMagic AI Bot")

    c.showPage(); c.save()
    return buf.getvalue()


async def cmd_churchprogram(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """/churchprogram Church Name | Service Title | Date"""
    err = _check_libs()
    if err: await update.message.reply_text(err, parse_mode="Markdown"); return
    args_text = " ".join(context.args).strip() if context.args else ""
    if not args_text:
        await update.message.reply_text(
            "⛪ *Church Program Generator*\n\n"
            "Usage:\n`/churchprogram Church Name | Service Title | Date`\n\n"
            "Example:\n"
            "`/churchprogram Grace Baptist Church | Sunday Worship Service | June 15, 2025`",
            parse_mode="Markdown"); return
    parts = [p.strip() for p in args_text.split("|")]
    church  = parts[0] if len(parts) > 0 else "Our Church"
    service = parts[1] if len(parts) > 1 else "Sunday Service"
    date    = parts[2] if len(parts) > 2 else ""
    msg = await update.message.reply_text("⛪ Generating church program… ⏳")
    await context.bot.send_chat_action(update.effective_chat.id, "upload_document")
    try:
        prompt = (
            f"Create a church program for: {church}, Service: {service}, Date: {date}\n"
            "Return ONLY raw JSON:\n"
            '{"sections":[{"heading":"Section Name","items":[{"time":"9:00 AM","title":"Item","who":"Person"}]}]}\n'
            "4-6 sections like: Opening, Praise & Worship, Tithes & Offering, Scripture Reading, Sermon, Closing. "
            "Each section 2-5 items. Include realistic church program content."
        )
        raw = await asyncio.get_running_loop().run_in_executor(None, lambda: call_gemini(prompt, use_cache=False))
        import json as _jj, re as _rr
        m = _rr.search(r'\{.*\}', raw, _rr.DOTALL)
        data = _jj.loads(m.group(0)) if m else {}
        hdr = await asyncio.get_running_loop().run_in_executor(
            None, lambda: _get_pdf_image(f"{church} church worship", theme="gold"))
        pdf_bytes = await asyncio.get_running_loop().run_in_executor(
            None, lambda: _build_churchprogram_pdf(
                church, service, date, "gold", data.get("sections",[]), header_image=hdr))
        await msg.delete()
        await update.message.reply_document(
            document=io.BytesIO(pdf_bytes),
            filename=f"ChurchProgram_{church[:20].replace(' ','_')}.pdf",
            caption=f"⛪ *{church}*\n{service} — Program ready! ✝️",
            parse_mode="Markdown")
    except Exception as e:
        logger.error(f"cmd_churchprogram error: {e}")
        await msg.edit_text(f"⚠️ Church program failed: `{str(e)[:120]}`", parse_mode="Markdown")


# ════════════════════════════════════════════════════════════════
#  🏷️  LABEL PDF — Multiple labels per page
# ════════════════════════════════════════════════════════════════

def _build_label_pdf(labels: list, cols: int = 3, rows: int = 8,
                     theme: str = "white") -> bytes:
    """
    labels = [{"title":"...", "line1":"...", "line2":"...", "line3":"..."}]
    Prints labels in a grid (cols x rows per page).
    """
    from reportlab.pdfgen import canvas as rl_c
    W, H = A4
    MARGIN = 18
    GAP    = 5
    LW = (W - MARGIN*2 - GAP*(cols-1)) / cols
    LH = (H - MARGIN*2 - GAP*(rows-1)) / rows

    THEMES = {
        "white":  (colors.white,               colors.HexColor("#e94560"), colors.HexColor("#1a1a2e")),
        "dark":   (colors.HexColor("#1a1a2e"), colors.HexColor("#e94560"), colors.white),
        "blue":   (colors.HexColor("#0f3460"), colors.HexColor("#00b4d8"), colors.white),
        "gold":   (colors.HexColor("#fdf6e3"), colors.HexColor("#c9a84c"), colors.HexColor("#1a1200")),
        "green":  (colors.HexColor("#e8ffe8"), colors.HexColor("#27ae60"), colors.HexColor("#1a3a1a")),
    }
    BG, AC, FG = THEMES.get(theme, THEMES["white"])

    buf = io.BytesIO(); c = rl_c.Canvas(buf, pagesize=A4)
    idx = 0; per_page = cols*rows

    while idx < len(labels):
        c.setFillColor(colors.HexColor("#f8f8f8")); c.rect(0, 0, W, H, fill=1, stroke=0)
        for row in range(rows):
            for col in range(cols):
                if idx >= len(labels): break
                lx = MARGIN + col*(LW+GAP)
                ly = H - MARGIN - (row+1)*(LH+GAP) + GAP
                lbl = labels[idx]; idx += 1

                # Label background + border
                _pub_rounded_rect(c, lx, ly, LW, LH, 4, BG, AC, 1)
                # Accent top bar
                c.setFillColor(AC); c.rect(lx, ly+LH-12, LW, 12, fill=1, stroke=0)
                c.setFillColor(BG); c.setFont("Helvetica-Bold", 8)
                c.drawCentredString(lx+LW/2, ly+LH-9, lbl.get("title","")[:25])
                # Lines
                c.setFillColor(FG); c.setFont("Helvetica", 9)
                ty = ly+LH-24
                for key in ["line1","line2","line3"]:
                    if lbl.get(key):
                        c.drawString(lx+6, ty, lbl[key][:32]); ty -= 12
        c.showPage()

    c.save(); return buf.getvalue()


