"""
Book PDF Engine — CineMagic Bot
Generates full multi-chapter books with cover, TOC, chapters, page numbers.
"""

# ════════════════════════════════════════════════════════════════
#  📚  BOOK PDF ENGINE
# ════════════════════════════════════════════════════════════════

def _book_render_page(c, W, H, page_num, book_title, chapter_title,
                      is_chapter_start=False, theme_colors=None):
    """Draw running header and footer with page number."""
    if theme_colors is None:
        theme_colors = (colors.HexColor("#1a1a2e"), colors.HexColor("#e94560"), colors.white)
    BG, AC, LIGHT = theme_colors

    if page_num > 1 and not is_chapter_start:
        # Header
        c.setStrokeColor(colors.HexColor("#dddddd")); c.setLineWidth(0.5)
        c.line(50, H-38, W-50, H-38)
        c.setFillColor(colors.HexColor("#888888")); c.setFont("Helvetica-Oblique", 8)
        c.drawString(52, H-30, book_title[:50])
        c.drawRightString(W-52, H-30, chapter_title[:40])

    # Footer with page number
    c.setStrokeColor(colors.HexColor("#dddddd")); c.setLineWidth(0.5)
    c.line(50, 38, W-50, 38)
    c.setFillColor(AC)
    c.circle(W/2, 24, 12, fill=1, stroke=0)
    c.setFillColor(LIGHT); c.setFont("Helvetica-Bold", 8)
    c.drawCentredString(W/2, 20, str(page_num))


def _build_book_cover(c, W, H, title, subtitle, author, genre,
                      header_image=None, theme="dark"):
    """Draw a full book cover page."""
    from reportlab.lib.utils import simpleSplit as ss

    THEMES = {
        "dark":     ((26,26,46),   (15,52,96),   (233,69,96),  (255,255,255)),
        "story":    ((30,10,10),   (80,20,20),   (220,80,40),  (255,255,255)),
        "children": ((10,50,80),   (20,100,160), (255,180,0),  (255,255,255)),
        "study":    ((10,30,60),   (20,60,100),  (0,180,200),  (255,255,255)),
        "devotion": ((20,15,5),    (60,40,10),   (200,160,40), (255,255,255)),
        "business": ((5,20,40),    (10,40,70),   (0,150,255),  (255,255,255)),
        "novel":    ((20,5,30),    (50,10,70),   (180,80,220), (255,255,255)),
        "bright":   ((240,240,255),(220,220,255),(233,69,96),  (20,20,60)),
    }
    bg1, bg2, ac, txt = THEMES.get(theme, THEMES["dark"])

    # Full gradient background
    _pub_gradient_rect(c, 0, 0, W, H,
                       (bg1[0],bg1[1],bg1[2]),
                       (bg2[0],bg2[1],bg2[2]), steps=80)

    AC_COL  = colors.Color(ac[0]/255, ac[1]/255, ac[2]/255)
    TXT_COL = colors.Color(txt[0]/255, txt[1]/255, txt[2]/255)

    # Big decorative circles
    c.setFillColor(colors.Color(ac[0]/255, ac[1]/255, ac[2]/255, 0.10))
    c.circle(W+80, H-100, 300, fill=1, stroke=0)
    c.circle(-80, 100, 250, fill=1, stroke=0)
    c.setFillColor(colors.Color(1,1,1,0.04))
    c.circle(W/2, H/2, 280, fill=1, stroke=0)

    # Left accent spine
    c.setFillColor(AC_COL)
    c.rect(0, 0, 14, H, fill=1, stroke=0)
    # Right thin line
    c.rect(W-6, 0, 6, H, fill=1, stroke=0)
    # Top bar
    c.rect(0, H-14, W, 14, fill=1, stroke=0)
    # Bottom bar
    c.rect(0, 0, W, 14, fill=1, stroke=0)

    # Header image (top 40% of page)
    img_h = H * 0.40
    if header_image:
        try:
            from reportlab.lib.utils import ImageReader
            c.drawImage(ImageReader(io.BytesIO(header_image)),
                        14, H-14-img_h, width=W-20, height=img_h,
                        preserveAspectRatio=False, mask='auto')
            # Dark overlay so text reads clearly
            c.setFillColor(colors.Color(bg1[0]/255, bg1[1]/255, bg1[2]/255, 0.72))
            c.rect(14, H-14-img_h, W-20, img_h, fill=1, stroke=0)
        except Exception:
            img_h = 0
    else:
        img_h = 0

    # Genre badge
    if genre:
        bw = c.stringWidth(genre.upper(), "Helvetica-Bold", 9) + 20
        c.setFillColor(AC_COL)
        c.roundRect(22, H-14-img_h-30, bw, 20, 4, fill=1, stroke=0)
        c.setFillColor(TXT_COL); c.setFont("Helvetica-Bold", 9)
        c.drawString(32, H-14-img_h-20, genre.upper())

    # Horizontal divider below image
    y_start = H - 14 - img_h - 44
    c.setFillColor(AC_COL)
    c.rect(14, y_start, W-20, 3, fill=1, stroke=0)

    # Title
    y = y_start - 20
    c.setFillColor(TXT_COL); c.setFont("Helvetica-Bold", 44)
    t_lines = ss(title, "Helvetica-Bold", 44, W-80)
    for ln in t_lines[:3]:
        c.drawString(22, y, ln); y -= 52

    # Subtitle
    if subtitle:
        c.setFillColor(AC_COL); c.setFont("Helvetica", 16)
        for ln in ss(subtitle, "Helvetica", 16, W-80)[:2]:
            c.drawString(22, y, ln); y -= 22
    y -= 14

    # Divider
    c.setStrokeColor(colors.Color(1,1,1,0.3)); c.setLineWidth(1)
    c.line(22, y, W-22, y); y -= 24

    # Author
    c.setFillColor(TXT_COL); c.setFont("Helvetica-Bold", 18)
    c.drawString(22, y, f"By {author}"); y -= 22
    c.setFillColor(colors.Color(1,1,1,0.5)); c.setFont("Helvetica", 10)
    c.drawString(22, y, "Generated by CineMagic AI Bot  •  Powered by Claude AI")

    # Bottom publisher line
    c.setFillColor(TXT_COL); c.setFont("Helvetica", 10)
    c.drawCentredString(W/2, 24, "CineMagic Publishing  •  cineMagic AI Bot")


def _build_book_toc(c, W, H, chapters, theme_colors):
    """Draw table of contents page."""
    from reportlab.lib.utils import simpleSplit as ss
    BG, AC, LIGHT = theme_colors

    c.setFillColor(colors.white); c.rect(0, 0, W, H, fill=1, stroke=0)
    # Top accent bar
    c.setFillColor(AC); c.rect(0, H-60, W, 60, fill=1, stroke=0)
    c.setFillColor(LIGHT); c.setFont("Helvetica-Bold", 28)
    c.drawString(50, H-40, "TABLE OF CONTENTS")
    c.setFillColor(AC); c.rect(0, H-64, W, 4, fill=1, stroke=0)

    y = H-100
    for i, ch in enumerate(chapters, 1):
        ch_title = ch.get("title","")
        ch_page  = ch.get("page", i*2+2)
        # Chapter number badge
        c.setFillColor(AC); c.circle(66, y+6, 14, fill=1, stroke=0)
        c.setFillColor(LIGHT); c.setFont("Helvetica-Bold", 10)
        c.drawCentredString(66, y+2, str(i))
        # Title
        c.setFillColor(colors.HexColor("#1a1a2e")); c.setFont("Helvetica-Bold", 13)
        c.drawString(90, y+4, ch_title[:55])
        # Dots
        title_w = c.stringWidth(ch_title[:55], "Helvetica-Bold", 13)
        c.setStrokeColor(colors.HexColor("#cccccc")); c.setLineWidth(0.5)
        c.setDash(2,4); c.line(94+title_w, y+8, W-80, y+8); c.setDash()
        # Page number
        c.setFillColor(AC); c.setFont("Helvetica-Bold", 11)
        c.drawRightString(W-50, y+4, str(ch_page))
        # Sub-line
        if ch.get("summary"):
            c.setFillColor(colors.HexColor("#888888")); c.setFont("Helvetica-Oblique", 9)
            c.drawString(90, y-9, ch["summary"][:70])
            y -= 10
        y -= 36
        if y < 60: break

    c.setFillColor(AC); c.rect(0, 0, W, 14, fill=1, stroke=0)


def _build_chapter_page(c, W, H, chapter_num, chapter_title,
                         chapter_body, theme_colors, is_first_chapter=False):
    """Draw a full chapter with proper typography. May span multiple pages."""
    from reportlab.lib.utils import simpleSplit as ss
    BG, AC, LIGHT = theme_colors
    pages_drawn = 0

    # ── Chapter opener page ───────────────────────────────────────
    c.setFillColor(colors.white); c.rect(0, 0, W, H, fill=1, stroke=0)
    # Accent top strip
    c.setFillColor(AC); c.rect(0, H-80, W, 80, fill=1, stroke=0)
    # Chapter number
    c.setFillColor(colors.Color(1,1,1,0.15)); c.setFont("Helvetica-Bold", 72)
    c.drawRightString(W-40, H-70, str(chapter_num))
    c.setFillColor(LIGHT); c.setFont("Helvetica", 11)
    c.drawString(50, H-38, f"CHAPTER {chapter_num}")
    # Chapter title
    c.setFillColor(colors.HexColor("#1a1a2e")); c.setFont("Helvetica-Bold", 26)
    y = H-110
    for ln in ss(chapter_title, "Helvetica-Bold", 26, W-100)[:2]:
        c.drawString(50, y, ln); y -= 34
    # Accent line under title
    c.setFillColor(AC); c.rect(50, y+8, 80, 3, fill=1, stroke=0)
    y -= 20

    # ── Body text ─────────────────────────────────────────────────
    MARGIN_L, MARGIN_R = 55, 55
    TEXT_W = W - MARGIN_L - MARGIN_R
    BODY_TOP = y
    BODY_BOT = 55
    LINE_H = 17
    FONT_SIZE = 11

    paragraphs = [p.strip() for p in chapter_body.split("\n") if p.strip()]
    first_para = True
    cy = BODY_TOP

    for para in paragraphs:
        # Check if it's a heading
        if para.startswith("## ") or para.startswith("# "):
            heading = para.lstrip("# ").strip()
            # New page if not enough room
            if cy < BODY_BOT + 60:
                c.showPage(); pages_drawn += 1
                c.setFillColor(colors.white); c.rect(0, 0, W, H, fill=1, stroke=0)
                cy = H - 55
            cy -= 8
            c.setFillColor(AC); c.setFont("Helvetica-Bold", 13)
            c.drawString(MARGIN_L, cy, heading[:65]); cy -= 6
            c.setStrokeColor(AC); c.setLineWidth(0.8)
            c.line(MARGIN_L, cy, MARGIN_L+60, cy); cy -= 16
            first_para = False
            continue

        # Normal paragraph
        if para.startswith(("• ","- ","* ")):
            # Bullet
            lines = ss(para[2:].strip(), "Helvetica", FONT_SIZE, TEXT_W-20)
        else:
            lines = ss(para, "Helvetica", FONT_SIZE, TEXT_W)

        # Drop cap for first paragraph of each chapter
        use_dropcap = first_para and not para.startswith(("• ","- ","* "))
        first_para = False

        if use_dropcap and lines:
            first_char = lines[0][0] if lines[0] else ""
            rest_first = lines[0][1:] if lines[0] else ""
            # Draw drop cap
            cap_size = 38
            c.setFillColor(AC); c.setFont("Helvetica-Bold", cap_size)
            c.drawString(MARGIN_L, cy-cap_size+14, first_char)
            cap_w = c.stringWidth(first_char, "Helvetica-Bold", cap_size) + 4
            # Rest of first line beside drop cap
            c.setFillColor(colors.HexColor("#1a1a2e")); c.setFont("Helvetica", FONT_SIZE)
            remaining_w = TEXT_W - cap_w
            rest_lines = ss(rest_first + (" " + " ".join(
                ln for ln in lines[1:3])) if len(lines) > 1 else rest_first,
                "Helvetica", FONT_SIZE, remaining_w)
            rx = MARGIN_L + cap_w
            ry = cy
            for rl in rest_lines[:2]:
                c.drawString(rx, ry, rl); ry -= LINE_H
            cy = min(ry, cy - cap_size - 4)
            remaining_lines = lines[3:]
        else:
            remaining_lines = lines

        for i, ln in enumerate(remaining_lines):
            if cy < BODY_BOT:
                c.showPage(); pages_drawn += 1
                c.setFillColor(colors.white); c.rect(0, 0, W, H, fill=1, stroke=0)
                cy = H - 55
            if para.startswith(("• ","- ","* ")):
                c.setFillColor(AC); c.circle(MARGIN_L+6, cy+4, 3, fill=1, stroke=0)
                c.setFillColor(colors.HexColor("#1a1a2e")); c.setFont("Helvetica", FONT_SIZE)
                c.drawString(MARGIN_L+16, cy, ln)
            else:
                c.setFillColor(colors.HexColor("#1a1a2e")); c.setFont("Helvetica", FONT_SIZE)
                c.drawString(MARGIN_L, cy, ln)
            cy -= LINE_H

        cy -= 8  # paragraph spacing

    return pages_drawn


def _build_book_back_cover(c, W, H, title, author, summary, theme):
    """Draw a back cover page."""
    from reportlab.lib.utils import simpleSplit as ss
    THEMES = {
        "dark":     ((26,26,46),   (15,52,96),   (233,69,96),  (255,255,255)),
        "story":    ((30,10,10),   (80,20,20),   (220,80,40),  (255,255,255)),
        "children": ((10,50,80),   (20,100,160), (255,180,0),  (255,255,255)),
        "study":    ((10,30,60),   (20,60,100),  (0,180,200),  (255,255,255)),
        "devotion": ((20,15,5),    (60,40,10),   (200,160,40), (255,255,255)),
        "business": ((5,20,40),    (10,40,70),   (0,150,255),  (255,255,255)),
        "novel":    ((20,5,30),    (50,10,70),   (180,80,220), (255,255,255)),
        "bright":   ((240,240,255),(220,220,255),(233,69,96),  (20,20,60)),
    }
    bg1, bg2, ac, txt = THEMES.get(theme, THEMES["dark"])
    _pub_gradient_rect(c, 0, 0, W, H, (bg2[0],bg2[1],bg2[2]), (bg1[0],bg1[1],bg1[2]), steps=60)
    AC_COL  = colors.Color(ac[0]/255, ac[1]/255, ac[2]/255)
    TXT_COL = colors.Color(txt[0]/255, txt[1]/255, txt[2]/255)

    c.setFillColor(AC_COL); c.rect(0, 0, 14, H, fill=1, stroke=0)
    c.rect(W-6, 0, 6, H, fill=1, stroke=0)
    c.rect(0, H-14, W, 14, fill=1, stroke=0)
    c.rect(0, 0, W, 14, fill=1, stroke=0)

    y = H-60
    # "About this book"
    c.setFillColor(AC_COL); c.setFont("Helvetica-Bold", 13)
    c.drawString(30, y, "ABOUT THIS BOOK"); y -= 8
    c.setFillColor(AC_COL); c.rect(30, y, 80, 2, fill=1, stroke=0); y -= 24

    # Summary
    c.setFillColor(TXT_COL); c.setFont("Helvetica", 12)
    for line in summary.split("\n"):
        for sub in ss(line.strip(), "Helvetica", 12, W-80)[:3]:
            c.drawString(30, y, sub); y -= 18
        y -= 4
        if y < 180: break

    y -= 20
    # Divider
    c.setStrokeColor(colors.Color(1,1,1,0.3)); c.setLineWidth(0.8)
    c.line(30, y, W-30, y); y -= 30

    # Title + Author again
    c.setFillColor(TXT_COL); c.setFont("Helvetica-Bold", 20)
    c.drawString(30, y, title[:45]); y -= 26
    c.setFillColor(AC_COL); c.setFont("Helvetica", 12)
    c.drawString(30, y, f"By {author}"); y -= 40

    # CineMagic branding bar at bottom
    c.setFillColor(AC_COL); c.rect(14, 20, W-20, 30, fill=1, stroke=0)
    c.setFillColor(TXT_COL); c.setFont("Helvetica-Bold", 10)
    c.drawCentredString(W/2, 30, "🎬 CineMagic AI Bot  •  Powered by Claude AI")


async def _generate_book_content(book_type: str, title: str,
                                  author: str, topic: str,
                                  num_chapters: int = 6) -> dict:
    """Call Gemini to generate full book content. Returns structured dict."""
    type_instructions = {
        "story":    "a compelling fiction story with vivid characters, dialogue, and plot twists",
        "children": "a fun, simple children's storybook with short sentences, repetition, and a moral lesson. Use very simple words a 5-year-old understands",
        "study":    "a comprehensive educational study guide with explanations, examples, key terms, and review questions",
        "devotion": "an inspirational Christian devotional book with Bible verses, prayers, reflections, and daily applications",
        "business": "a practical business/self-help book with actionable advice, real examples, frameworks, and takeaways",
        "novel":    "a dramatic literary novel with rich descriptions, complex characters, and emotional depth",
        "general":  "a well-structured non-fiction book with clear explanations, examples, and insights",
    }
    style = type_instructions.get(book_type, type_instructions["general"])

    prompt = (
        f"Write {style} titled '{title}' about: {topic}\n\n"
        f"Return ONLY raw JSON, no markdown fences:\n"
        f'{{"subtitle":"One line subtitle","genre":"Genre","summary":"2-3 sentence back cover summary",'
        f'"chapters":[{{"title":"Chapter Title","summary":"One line summary",'
        f'"body":"Full chapter text 300-500 words. Use ## for subheadings, • for bullets, natural paragraphs."}}]}}\n\n'
        f"Rules:\n"
        f"- Exactly {num_chapters} chapters\n"
        f"- Each chapter 300-500 words\n"
        f"- Chapters must flow naturally and tell a complete story/book\n"
        f"- Use proper paragraph breaks with \\n\\n between paragraphs\n"
        f"- Author name: {author}\n"
        f"- Make it genuinely good quality writing\n"
        f"- Return ONLY the JSON object, nothing else"
    )

    raw = await asyncio.get_running_loop().run_in_executor(
        None, lambda: call_gemini(prompt, use_cache=False))

    import json as _jj, re as _rr
    # Try to extract JSON
    m = _rr.search(r'\{.*\}', raw, _rr.DOTALL)
    if m:
        try:
            return _jj.loads(m.group(0))
        except Exception:
            pass

    # Fallback structure
    return {
        "subtitle": f"A complete guide to {topic}",
        "genre": book_type.title(),
        "summary": f"A comprehensive {book_type} book about {topic}, written by {author}.",
        "chapters": [{"title": f"Chapter {i}", "summary": "", "body": f"Content for chapter {i} about {topic}."} for i in range(1, num_chapters+1)]
    }


def _assemble_book_pdf(title: str, author: str, book_data: dict,
                        theme: str = "dark",
                        header_image: bytes = None) -> bytes:
    """Assemble the complete book PDF: cover + TOC + chapters + back cover."""
    from reportlab.pdfgen import canvas as rl_c
    W, H = A4

    THEMES_COLORS = {
        "dark":     (colors.HexColor("#1a1a2e"), colors.HexColor("#e94560"), colors.white),
        "story":    (colors.HexColor("#1e0a0a"), colors.HexColor("#dc5028"), colors.white),
        "children": (colors.HexColor("#0a3250"), colors.HexColor("#ffb400"), colors.white),
        "study":    (colors.HexColor("#0a1e3c"), colors.HexColor("#00b4c8"), colors.white),
        "devotion": (colors.HexColor("#14100a"), colors.HexColor("#c8a028"), colors.white),
        "business": (colors.HexColor("#050f28"), colors.HexColor("#0096ff"), colors.white),
        "novel":    (colors.HexColor("#14032e"), colors.HexColor("#b450dc"), colors.white),
        "bright":   (colors.HexColor("#e8e8ff"), colors.HexColor("#e94560"), colors.HexColor("#141428")),
    }
    TC = THEMES_COLORS.get(theme, THEMES_COLORS["dark"])
    BG, AC, LIGHT = TC

    subtitle = book_data.get("subtitle","")
    genre    = book_data.get("genre","")
    summary  = book_data.get("summary","")
    chapters = book_data.get("chapters",[])

    buf = io.BytesIO()
    c  = rl_c.Canvas(buf, pagesize=A4)
    page_num = 1

    # ── Front cover ───────────────────────────────────────────────
    _build_book_cover(c, W, H, title, subtitle, author, genre, header_image, theme)
    c.showPage(); page_num += 1

    # ── Blank verso ───────────────────────────────────────────────
    c.setFillColor(colors.white); c.rect(0, 0, W, H, fill=1, stroke=0)
    c.setFillColor(colors.HexColor("#888888")); c.setFont("Helvetica-Oblique", 9)
    c.drawCentredString(W/2, H/2+20, f'"{title}"')
    c.drawCentredString(W/2, H/2, f"by {author}")
    c.drawCentredString(W/2, H/2-20, "Generated by CineMagic AI Bot")
    c.showPage(); page_num += 1

    # ── Table of Contents ─────────────────────────────────────────
    toc_chapters = []
    pg = page_num + 2
    for i, ch in enumerate(chapters, 1):
        toc_chapters.append({"title": ch.get("title",""), "summary": ch.get("summary",""), "page": pg})
        pg += 2  # rough estimate
    _build_book_toc(c, W, H, toc_chapters, TC)
    _book_render_page(c, W, H, page_num, title, "Contents", True, TC)
    c.showPage(); page_num += 1

    # ── Chapters ──────────────────────────────────────────────────
    for i, ch in enumerate(chapters, 1):
        ch_title = ch.get("title", f"Chapter {i}")
        ch_body  = ch.get("body", "")
        extra = _build_chapter_page(c, W, H, i, ch_title, ch_body, TC, i==1)
        _book_render_page(c, W, H, page_num, title, ch_title, True, TC)
        c.showPage(); page_num += 1
        for ep in range(extra):
            _book_render_page(c, W, H, page_num, title, ch_title, False, TC)
            c.showPage(); page_num += 1

    # ── Back cover ────────────────────────────────────────────────
    _build_book_back_cover(c, W, H, title, author, summary, theme)
    c.showPage()

    c.save()
    return buf.getvalue()


