_BOOK_TYPES = {
    "story":    ("📖 Fiction Story",        "story",    "story"),
    "children": ("🧒 Children's Book",      "children", "children"),
    "study":    ("📚 Study Guide",          "study",    "study"),
    "devotion": ("✝️ Devotional Book",       "devotion", "devotion"),
    "business": ("💼 Business/Self-Help",   "business", "business"),
    "novel":    ("📕 Novel",               "novel",    "novel"),
    "book":     ("📘 General Book",        "general",  "dark"),
}


async def cmd_book(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """/book <type> <Title> | <topic> — Generate a full book PDF.
    Types: story, children, study, devotion, business, novel
    Example: /book story The Lost Kingdom | a prince who discovers magic
    Example: /book devotion Morning Light | daily devotions for strength
    """
    err = _check_libs()
    if err: await update.message.reply_text(err, parse_mode="Markdown"); return

    args_text = " ".join(context.args).strip() if context.args else ""

    # Show menu if no args
    if not args_text:
        buttons = []
        row = []
        for key, (label, _, _) in _BOOK_TYPES.items():
            row.append(InlineKeyboardButton(label, callback_data=f"booktype:{key}"))
            if len(row) == 2: buttons.append(row); row = []
        if row: buttons.append(row)
        await update.message.reply_text(
            "📚 *Book Generator*\n\n"
            "I can write a full book and export it as a beautiful PDF!\n\n"
            "Usage: `/book <type> <Title> | <topic>`\n\n"
            "Examples:\n"
            "• `/book story The Lost Kingdom | a prince who discovers magic`\n"
            "• `/book children The Brave Little Star | a star that was afraid of the dark`\n"
            "• `/book study Python Programming | beginner to advanced guide`\n"
            "• `/book devotion Morning Strength | daily devotions for tough times`\n"
            "• `/book business The Success Formula | how to grow any business`\n"
            "• `/book novel Broken Chains | a woman escaping a painful past`\n\n"
            "Or pick a type below 👇",
            parse_mode="Markdown",
            reply_markup=InlineKeyboardMarkup(buttons))
        return

    # Parse: first word = type (optional), rest = title | topic
    words = args_text.split()
    book_type = "general"; theme = "dark"
    if words[0].lower() in _BOOK_TYPES:
        book_type_key = words[0].lower()
        _, book_type, theme = _BOOK_TYPES[book_type_key]
        rest = " ".join(words[1:])
    else:
        rest = args_text

    # Split title | topic
    if "|" in rest:
        parts = rest.split("|", 1)
        title = parts[0].strip()
        topic = parts[1].strip()
    else:
        title = rest.strip()
        topic = rest.strip()

    if not title:
        await update.message.reply_text("❌ Please provide a title.\nExample: `/book story The Lost Kingdom | a prince who discovers magic`", parse_mode="Markdown"); return

    author = update.effective_user.first_name or "CineMagic Author"

    msg = await update.message.reply_text(
        f"📚 *Writing your book…*\n\n"
        f"📖 Title: *{title}*\n"
        f"✍️ Type: *{book_type.title()}*\n\n"
        f"⏳ This takes 30-60 seconds — generating full chapters…",
        parse_mode="Markdown")
    await context.bot.send_chat_action(update.effective_chat.id, "upload_document")

    try:
        # Generate content
        await msg.edit_text(f"📚 Generating chapters… ✍️ (step 1/3)")
        book_data = await _generate_book_content(book_type, title, author, topic, num_chapters=6)

        # Generate cover image
        await msg.edit_text(f"🎨 Designing cover… (step 2/3)")
        hdr_img = await asyncio.get_running_loop().run_in_executor(
            None, lambda: _get_pdf_image(f"{title} {topic}", theme=theme))

        # Build PDF
        await msg.edit_text(f"📄 Assembling PDF… (step 3/3)")
        pdf_bytes = await asyncio.get_running_loop().run_in_executor(
            None, lambda: _assemble_book_pdf(title, author, book_data, theme, hdr_img))

        num_chapters = len(book_data.get("chapters", []))
        await msg.delete()
        await update.message.reply_document(
            document=io.BytesIO(pdf_bytes),
            filename=f"{title[:40].replace(' ','_')}.pdf",
            caption=(
                f"📚 *{title}*\n"
                f"✍️ by {author}\n\n"
                f"📖 {num_chapters} chapters\n"
                f"🎨 {book_type.title()} style\n\n"
                f"Generated by CineMagic AI Bot ✨"
            ),
            parse_mode="Markdown")

    except Exception as e:
        logger.error(f"cmd_book error: {e}")
        await msg.edit_text(f"⚠️ Book generation failed: `{str(e)[:150]}`", parse_mode="Markdown")


async def cb_booktype(update: Update, context: ContextTypes.DEFAULT_TYPE):
    query = update.callback_query
    await query.answer()
    key = query.data.replace("booktype:", "")
