# ════════════════════════════════════════════════════════════════
#  🎞️  SLIDESHOW PDF — PowerPoint-style slide deck
# ════════════════════════════════════════════════════════════════

def _build_slides_pdf(title: str, slides: list, author: str = "CineMagic Bot") -> bytes:
    import datetime as _dt_s
    from reportlab.pdfgen import canvas as rl_canvas_s
    from reportlab.lib.utils import simpleSplit as ss_s
    W, H = A4[1], A4[0]
    buf = io.BytesIO()
    c = rl_canvas_s.Canvas(buf, pagesize=(W, H))
    ACCENT = colors.HexColor("#e94560"); DARK = colors.HexColor("#1a1a2e")
    WHITE = colors.white; LIGHT = colors.HexColor("#f5f5f5"); SUBTEXT = colors.HexColor("#888888")

    def _slide_bg(col):
        c.setFillColor(col); c.rect(0, 0, W, H, fill=1, stroke=0)
        c.setFillColor(ACCENT); c.rect(0, 0, 8, H, fill=1, stroke=0)

    def _title_slide(t, sub):
        _slide_bg(DARK)
        c.setFillColor(colors.HexColor("#0f3460")); c.circle(W-120, H-80, 180, fill=1, stroke=0)
        c.setFillColor(ACCENT); c.circle(W-120, H-80, 120, fill=1, stroke=0)
        c.setFillColor(WHITE); c.setFont("Helvetica-Bold", 42)
        lns = ss_s(t, "Helvetica-Bold", 42, W-260); y = H/2+40+(len(lns)-1)*24
        for ln in lns[:3]: c.drawString(50, y, ln); y -= 52
        c.setFillColor(ACCENT); c.setFont("Helvetica", 18); c.drawString(50, y-10, sub)
        c.setFillColor(SUBTEXT); c.setFont("Helvetica", 11)
        c.drawString(50, 30, f"{author}  •  {_dt_s.datetime.now().strftime('%B %Y')}")

    def _content_slide(num, st, bullets, note=""):
        _slide_bg(LIGHT)
        c.setFillColor(DARK); c.rect(0, H-90, W, 90, fill=1, stroke=0)
        c.setFillColor(ACCENT); c.rect(0, H-90, 8, 90, fill=1, stroke=0)
        c.setFillColor(ACCENT); c.circle(W-40, H-45, 22, fill=1, stroke=0)
        c.setFillColor(WHITE); c.setFont("Helvetica-Bold", 14); c.drawCentredString(W-40, H-51, str(num))
        c.setFillColor(WHITE); c.setFont("Helvetica-Bold", 26); c.drawString(30, H-68, st[:60])
        y = H-130
        for bullet in bullets[:7]:
            c.setFillColor(ACCENT); c.circle(32, y+5, 5, fill=1, stroke=0)
            c.setFillColor(DARK); c.setFont("Helvetica", 16)
            lns = ss_s(bullet, "Helvetica", 16, W-110)
            for ln in lns[:2]: c.drawString(50, y, ln); y -= 20
            y -= 14
            if y < 60: break
        if note:
            c.setFillColor(SUBTEXT); c.setFont("Helvetica-Oblique", 10)
            c.drawString(30, 18, f"💡 {note[:110]}")
        c.setFillColor(DARK); c.rect(0, 0, W, 12, fill=1, stroke=0)

    def _end_slide(t):
        _slide_bg(DARK)
        c.setFillColor(ACCENT); c.circle(W/2, H/2, 200, fill=1, stroke=0)
        c.setFillColor(DARK); c.circle(W/2, H/2, 160, fill=1, stroke=0)
        c.setFillColor(WHITE); c.setFont("Helvetica-Bold", 36); c.drawCentredString(W/2, H/2+10, "Thank You!")
        c.setFillColor(ACCENT); c.setFont("Helvetica", 16); c.drawCentredString(W/2, H/2-30, t[:50])
        c.setFillColor(SUBTEXT); c.setFont("Helvetica", 11); c.drawCentredString(W/2, 30, "Generated by CineMagic AI Bot")

    _title_slide(title, f"{len(slides)} slides  •  CineMagic Bot"); c.showPage()
    for i, slide in enumerate(slides, 1):
        _content_slide(i, slide.get("title",""), slide.get("bullets",[]), slide.get("note","")); c.showPage()
    _end_slide(title); c.showPage(); c.save()
    return buf.getvalue()


async def cmd_pdfslides(update: Update, context: ContextTypes.DEFAULT_TYPE):
    err = _check_libs()
    if err: await update.message.reply_text(err, parse_mode="Markdown"); return
    topic = " ".join(context.args).strip() if context.args else ""
    if not topic:
        await update.message.reply_text(
            "🎞️ *Slide Deck Generator*\n\nUsage: `/pdfslides <topic>`\n\n"
            "Examples:\n• `/pdfslides Climate Change`\n• `/pdfslides Business Plan 2025`", parse_mode="Markdown"); return
    msg = await update.message.reply_text("🎞️ Building your slide deck… ⏳")
    await context.bot.send_chat_action(update.effective_chat.id, "upload_document")
    try:
        prompt = (
            f"Create a professional slide deck outline for: {topic}\n"
            "Return ONLY a JSON array. No explanation. No markdown. Raw JSON only:\n"
            '[{"title":"Slide Title","bullets":["Point 1","Point 2","Point 3"],"note":"Speaker note"}]\n'
            "Rules: exactly 8 slides, each with title (max 6 words), 3-5 bullets (max 12 words each), optional note."
        )
        raw = await asyncio.get_running_loop().run_in_executor(None, lambda: call_gemini(prompt, use_cache=False))
        import json as _json_s, re as _re_s
        m = _re_s.search(r'\[.*\]', raw, _re_s.DOTALL)
        slides = _json_s.loads(m.group(0)) if m else []
        if len(slides) < 2:
            slides = [{"title":"Overview","bullets":[f"Introduction to {topic}","Key concepts","What we cover"],"note":""},
                      {"title":"Background","bullets":["Context","History","Why it matters"],"note":""},
                      {"title":"Key Points","bullets":["Main idea 1","Main idea 2","Main idea 3"],"note":""},
                      {"title":"Details","bullets":["Supporting point 1","Supporting point 2","Evidence"],"note":""},
                      {"title":"Analysis","bullets":["Critical view","Data insights","Expert opinions"],"note":""},
                      {"title":"Benefits","bullets":["Real-world impact","Practical value","Opportunities"],"note":""},
                      {"title":"Challenges","bullets":["Common obstacles","How to overcome","Lessons learned"],"note":""},
                      {"title":"Key Takeaways","bullets":["Summary point 1","Action steps","Next steps"],"note":""}]
        await msg.edit_text(f"🎞️ Generating slide images… ⏳")
        hdr_img = await asyncio.get_running_loop().run_in_executor(
            None, lambda: _get_pdf_image(topic, theme='dark'))
        pdf_bytes = await asyncio.get_running_loop().run_in_executor(
            None, lambda: _build_slides_pdf(topic, slides,
                author=update.effective_user.first_name or "CineMagic",
                header_image=hdr_img))
        await msg.delete()
        await update.message.reply_document(
            document=io.BytesIO(pdf_bytes),
            filename=f"Slides_{topic[:30].replace(' ','_')}.pdf",
            caption=f"🎞️ *{topic}*\n\n{len(slides)} slides generated ✨\n_PowerPoint-style slide deck_",
            parse_mode="Markdown")
    except Exception as e:
        logger.error(f"cmd_pdfslides error: {e}")
        await msg.edit_text(f"⚠️ Slide generation failed: `{str(e)[:120]}`", parse_mode="Markdown")


# ════════════════════════════════════════════════════════════════
#  📰  FLYER PDF — Eye-catching poster/flyer
# ════════════════════════════════════════════════════════════════

def _build_flyer_pdf(title: str, body_lines: list, footer: str = "", theme: str = "red") -> bytes:
    from reportlab.pdfgen import canvas as rl_canvas_f
    from reportlab.lib.utils import simpleSplit as ss_f
    THEMES = {
        "red":    (colors.HexColor("#e94560"), colors.HexColor("#1a1a2e"), colors.white),
        "blue":   (colors.HexColor("#0f3460"), colors.HexColor("#16213e"), colors.white),
        "green":  (colors.HexColor("#27ae60"), colors.HexColor("#1a2f1a"), colors.white),
        "gold":   (colors.HexColor("#f39c12"), colors.HexColor("#1a1a0a"), colors.white),
        "purple": (colors.HexColor("#8e44ad"), colors.HexColor("#1a0a2e"), colors.white),
    }
    ACCENT, BG, FG = THEMES.get(theme, THEMES["red"])
    W, H = A4
    buf = io.BytesIO(); c = rl_canvas_f.Canvas(buf, pagesize=A4)
    c.setFillColor(BG); c.rect(0, 0, W, H, fill=1, stroke=0)
    c.setFillColor(ACCENT); c.rect(0, H-180, W, 180, fill=1, stroke=0)
    c.setFillColor(colors.Color(1,1,1,0.07)); c.circle(W+60, H+60, 220, fill=1, stroke=0)
    c.setFillColor(colors.Color(1,1,1,0.05)); c.circle(-60, H-60, 180, fill=1, stroke=0)
    c.setFillColor(ACCENT); c.rect(0, 0, W, 60, fill=1, stroke=0)
    c.setFillColor(FG); c.setFont("Helvetica-Bold", 38)
    tlines = ss_f(title.upper(), "Helvetica-Bold", 38, W-60); ty = H-60
    for ln in tlines[:3]: c.drawCentredString(W/2, ty, ln); ty -= 50
    c.setFillColor(FG); c.setLineWidth(2); c.setStrokeColor(FG); c.line(40, H-195, W-40, H-195)
    y = H-230
    for line in body_lines[:14]:
        s = line.strip()
        if not s: y -= 10; continue
        if s.startswith(("•","-","*")):
            c.setFillColor(ACCENT); c.circle(52, y+5, 4, fill=1, stroke=0)
            c.setFillColor(FG); c.setFont("Helvetica", 14); txt = s.lstrip("•-* ").strip()
            for sub in ss_f(txt, "Helvetica", 14, W-100)[:2]: c.drawString(65, y, sub); y -= 20
        elif s.startswith("##"):
            c.setFillColor(ACCENT); c.setFont("Helvetica-Bold", 17); c.drawString(40, y, s.lstrip("# ")[:50]); y -= 26
        else:
            c.setFillColor(FG); c.setFont("Helvetica", 13)
            for sub in ss_f(s, "Helvetica", 13, W-80)[:2]: c.drawString(40, y, sub); y -= 20
        y -= 4
        if y < 80: break
    c.setFillColor(FG); c.setFont("Helvetica-Bold", 13); c.drawCentredString(W/2, 22, (footer or "Generated by CineMagic AI Bot")[:80])
    c.save(); return buf.getvalue()


