#  📋  BROCHURE PDF — 2-column layout
# ════════════════════════════════════════════════════════════════

def _build_brochure_pdf(title: str, sections: list, tagline: str = "") -> bytes:
    import datetime as _dt_b
    from reportlab.pdfgen import canvas as rl_canvas_b
    from reportlab.lib.utils import simpleSplit as ss_b
    W, H = A4; buf = io.BytesIO(); c = rl_canvas_b.Canvas(buf, pagesize=A4)
    ACCENT = colors.HexColor("#e94560"); DARK = colors.HexColor("#1a1a2e")
    WHITE = colors.white; MGRAY = colors.HexColor("#cccccc")
    c.setFillColor(WHITE); c.rect(0, 0, W, H, fill=1, stroke=0)
    c.setFillColor(DARK); c.rect(0, 0, W/2-10, H, fill=1, stroke=0)
    c.setFillColor(ACCENT); c.rect(0, H-100, W, 100, fill=1, stroke=0)
    c.setFillColor(WHITE); c.setFont("Helvetica-Bold", 28)
    lns = ss_b(title, "Helvetica-Bold", 28, W-40); c.drawCentredString(W/2, H-45, lns[0][:50])
    if tagline: c.setFont("Helvetica", 13); c.drawCentredString(W/2, H-68, tagline[:70])
    c.setFillColor(ACCENT); c.rect(0, 0, W, 30, fill=1, stroke=0)
    c.setFillColor(WHITE); c.setFont("Helvetica", 9)
    c.drawCentredString(W/2, 10, f"CineMagic AI Bot  •  {_dt_b.datetime.now().strftime('%B %Y')}")
    c.setStrokeColor(ACCENT); c.setLineWidth(2); c.line(W/2-10, 35, W/2-10, H-105)
    col_x = [25, W/2+15]; col_fg = [WHITE, DARK]; col_w = W/2-40
    left_secs = sections[:len(sections)//2 + len(sections)%2]
    right_secs = sections[len(sections)//2 + len(sections)%2:]
    for ci, (sx, fg, secs) in enumerate(zip(col_x, col_fg, [left_secs, right_secs])):
        y = H-120
        for sec in secs:
            c.setFillColor(ACCENT); c.setFont("Helvetica-Bold", 13); c.drawString(sx, y, sec.get("heading","")[:45]); y -= 6
            c.setLineWidth(1); c.setStrokeColor(ACCENT); c.line(sx, y, sx+col_w, y); y -= 14
            c.setFillColor(fg); c.setFont("Helvetica", 10)
            for line in sec.get("body","").split("\n"):
                for sub in ss_b(line.strip(), "Helvetica", 10, col_w):
                    c.drawString(sx, y, sub); y -= 14
                    if y < 40: break
                if y < 40: break
            y -= 16
            if y < 40: break
    c.showPage(); c.save(); return buf.getvalue()


