#  🏆  CERTIFICATE PDF
# ════════════════════════════════════════════════════════════════

def _build_certificate_pdf(recipient: str, course: str, issuer: str) -> bytes:
    import datetime as _dt_c
    from reportlab.pdfgen import canvas as rl_canvas_c
    W, H = A4[1], A4[0]; buf = io.BytesIO(); c = rl_canvas_c.Canvas(buf, pagesize=(W, H))
    GOLD = colors.HexColor("#c9a84c"); DGOLD = colors.HexColor("#8B6914")
    DARK = colors.HexColor("#1a1a2e"); WHITE = colors.white
    CREAM = colors.HexColor("#fdf6e3"); ACCENT = colors.HexColor("#e94560")
    c.setFillColor(CREAM); c.rect(0, 0, W, H, fill=1, stroke=0)
    c.setStrokeColor(GOLD); c.setLineWidth(6); c.rect(18, 18, W-36, H-36, fill=0, stroke=1)
    c.setStrokeColor(DGOLD); c.setLineWidth(2); c.rect(28, 28, W-56, H-56, fill=0, stroke=1)
    for cx, cy in [(40,40),(W-40,40),(40,H-40),(W-40,H-40)]:
        c.setFillColor(GOLD); c.circle(cx, cy, 10, fill=1, stroke=0)
        c.setFillColor(CREAM); c.circle(cx, cy, 5, fill=1, stroke=0)
    c.setFillColor(DARK); c.setFont("Helvetica-Bold", 13); c.drawCentredString(W/2, H-60, issuer.upper())
    c.setFillColor(GOLD); c.setLineWidth(1); c.setStrokeColor(GOLD); c.line(W/2-180, H-67, W/2+180, H-67)
    c.setFillColor(DARK); c.setFont("Helvetica", 15); c.drawCentredString(W/2, H-95, "CERTIFICATE OF COMPLETION")
    c.setStrokeColor(GOLD); c.setLineWidth(1.5); c.line(W/2-220, H-105, W/2+220, H-105); c.line(W/2-220, H-110, W/2+220, H-110)
    c.setFillColor(colors.HexColor("#444444")); c.setFont("Helvetica-Oblique", 14); c.drawCentredString(W/2, H-145, "This is to proudly certify that")
    c.setFillColor(ACCENT); c.setFont("Helvetica-Bold", 42); c.drawCentredString(W/2, H-210, recipient)
    nw = c.stringWidth(recipient, "Helvetica-Bold", 42)
    c.setStrokeColor(GOLD); c.setLineWidth(1.5); c.line(W/2-nw/2, H-218, W/2+nw/2, H-218)
    c.setFillColor(colors.HexColor("#444444")); c.setFont("Helvetica", 14); c.drawCentredString(W/2, H-248, "has successfully completed")
    c.setFillColor(DARK); c.setFont("Helvetica-Bold", 22); c.drawCentredString(W/2, H-285, course)
    c.setStrokeColor(GOLD); c.setLineWidth(1); c.line(W/2-220, H-300, W/2+220, H-300); c.line(W/2-220, H-305, W/2+220, H-305)
    now = _dt_c.datetime.now()
    c.setFillColor(DARK); c.setFont("Helvetica", 11); c.drawString(80, 90, "Date of Issue:")
    c.setFont("Helvetica-Bold", 11); c.drawString(80, 73, now.strftime("%d %B, %Y"))
    c.setStrokeColor(DGOLD); c.setLineWidth(1); c.line(70, 68, 230, 68)
    c.setFont("Helvetica", 11); c.setFillColor(DARK); c.drawString(W-240, 90, "Authorized Signature:")
    c.setFont("Helvetica-BoldOblique", 14); c.setFillColor(ACCENT); c.drawString(W-240, 73, issuer)
    c.setStrokeColor(DGOLD); c.line(W-250, 68, W-70, 68)
    c.setFillColor(GOLD); c.circle(W/2, 80, 38, fill=1, stroke=0)
    c.setFillColor(CREAM); c.circle(W/2, 80, 30, fill=1, stroke=0)
    c.setFillColor(GOLD); c.setFont("Helvetica-Bold", 8)
    c.drawCentredString(W/2, 84, "OFFICIAL"); c.drawCentredString(W/2, 74, "SEAL")
    c.save(); return buf.getvalue()


