    label, _ = _PDFWRITE_TYPES[key]
    await query.edit_message_text(
        f"✍️ *{label}* selected!\n\n"
        f"Now send your details:\n`/pdfwrite {key} <your details>`\n\n"
        f"Example: `/pdfwrite {key} to my friend John about our friendship`",
        parse_mode="Markdown")


