async def cmd_invoice(update: Update, context: ContextTypes.DEFAULT_TYPE):
    import datetime as _dt_inv
    user_id = update.effective_user.id
    name = update.effective_user.first_name or "User"
    err = _check_libs()
    if err:
        await update.message.reply_text(err, parse_mode="Markdown"); return
    details = " ".join(context.args).strip() if context.args else ""
    if not details:
        await update.message.reply_text(
            "🧾 *Invoice Generator*\n\nUsage:\n`/invoice <service> <amount> [client name]`\n\n"
            "Example:\n`/invoice Web Design Services $500 for John Doe`",
            parse_mode="Markdown"); return
    msg = await update.message.reply_text("🧾 Building invoice… ⏳")
    await context.bot.send_chat_action(update.effective_chat.id, "upload_document")
    try:
        import re as _re_inv
        buf = io.BytesIO()
        doc_pdf = SimpleDocTemplate(buf, pagesize=A4, rightMargin=2*cm, leftMargin=2*cm, topMargin=2*cm, bottomMargin=2*cm)
        styles = getSampleStyleSheet(); story = []
        story.append(Paragraph("INVOICE", ParagraphStyle("inv_title", fontSize=32, textColor=colors.HexColor("#e94560"), alignment=TA_RIGHT, spaceAfter=4, fontName="Helvetica-Bold")))
        story.append(Paragraph(f"#{random.randint(1000,9999)}", ParagraphStyle("inv_num", fontSize=12, textColor=colors.grey, alignment=TA_RIGHT, spaceAfter=20)))
        story.append(HRFlowable(width="100%", thickness=2, color=colors.HexColor("#e94560"), spaceAfter=16))
        now = _dt_inv.datetime.now(); due = now + _dt_inv.timedelta(days=14)
        info_data = [
            [Paragraph("<b>FROM</b>", styles["Normal"]), Paragraph("<b>BILL TO</b>", styles["Normal"]), Paragraph("<b>INVOICE DATE</b>", styles["Normal"])],
            [Paragraph(name, styles["Normal"]), Paragraph(details.split("for")[-1].strip() if "for" in details.lower() else "Client", styles["Normal"]), Paragraph(now.strftime("%d %b %Y"), styles["Normal"])],
            [Paragraph("CineMagic Bot User", styles["Normal"]), Paragraph("", styles["Normal"]), Paragraph(f"Due: {due.strftime('%d %b %Y')}", styles["Normal"])],
        ]
        info_table = Table(info_data, colWidths=[5.5*cm, 8*cm, 4*cm])
        info_table.setStyle(TableStyle([("FONTSIZE",(0,0),(-1,-1),9),("TOPPADDING",(0,0),(-1,-1),4),("BOTTOMPADDING",(0,0),(-1,-1),4),("TEXTCOLOR",(0,0),(-1,0),colors.HexColor("#1a1a2e"))]))
        story.append(info_table); story.append(Spacer(1, 20))
        service_desc = details.split("for")[0].strip() if "for" in details.lower() else details
        amt_match = _re_inv.search(r'[\$£€₵]?\s*(\d[\d,\.]*)', details)
        amount = amt_match.group(0).strip() if amt_match else "$0.00"
        items_data = [["#","Description","Qty","Unit Price","Total"],["1", service_desc,"1", amount, amount]]
        items_table = Table(items_data, colWidths=[1*cm,9*cm,2*cm,3.5*cm,3.5*cm])
        items_table.setStyle(TableStyle([("BACKGROUND",(0,0),(-1,0),colors.HexColor("#1a1a2e")),("TEXTCOLOR",(0,0),(-1,0),colors.white),("FONTNAME",(0,0),(-1,0),"Helvetica-Bold"),("FONTSIZE",(0,0),(-1,-1),9),("ROWBACKGROUNDS",(0,1),(-1,-1),[colors.white,colors.HexColor("#f5f5f5")]),("ALIGN",(2,0),(-1,-1),"RIGHT"),("GRID",(0,0),(-1,-1),0.5,colors.HexColor("#dddddd")),("TOPPADDING",(0,0),(-1,-1),6),("BOTTOMPADDING",(0,0),(-1,-1),6),("LEFTPADDING",(0,0),(-1,-1),8)]))
        story.append(items_table); story.append(Spacer(1, 12))
        total_data = [["","","","Subtotal:",amount],["","","","Tax (0%):","$0.00"],["","","",Paragraph("<b>TOTAL</b>",styles["Normal"]),Paragraph(f"<b>{amount}</b>",styles["Normal"])]]
        total_table = Table(total_data, colWidths=[1*cm,9*cm,2*cm,3.5*cm,3.5*cm])
        total_table.setStyle(TableStyle([("FONTSIZE",(0,0),(-1,-1),9),("ALIGN",(3,0),(-1,-1),"RIGHT"),("TOPPADDING",(0,0),(-1,-1),4),("BOTTOMPADDING",(0,0),(-1,-1),4),("LINEABOVE",(3,2),(-1,2),1.5,colors.HexColor("#e94560"))]))
        story.append(total_table); story.append(Spacer(1, 30))
        story.append(HRFlowable(width="100%", thickness=1, color=colors.HexColor("#cccccc"), spaceAfter=10))
        story.append(Paragraph("<b>Payment Information</b>", ParagraphStyle("pinfo", fontSize=10, textColor=colors.HexColor("#1a1a2e"), spaceAfter=6)))
        story.append(Paragraph(f"Mobile Money: {MOMO_NUMBER} ({MOMO_NAME})\nPlease include your invoice number as reference.", ParagraphStyle("pbody", fontSize=9, textColor=colors.grey, leading=14)))
        story.append(Spacer(1, 20))
        story.append(Paragraph("Thank you for your business! 🎬 — CineMagic AI Bot", ParagraphStyle("thanks", fontSize=9, textColor=colors.HexColor("#e94560"), alignment=TA_CENTER)))
        doc_pdf.build(story)
        await msg.delete()
        await update.message.reply_document(
            document=io.BytesIO(buf.getvalue()),
            filename=f"Invoice_{now.strftime('%Y%m%d')}.pdf",
            caption="🧾 *Invoice Generated!*\n\nYour invoice is ready 📄",
            parse_mode="Markdown")
    except Exception as e:
        logger.error(f"cmd_invoice error: {e}")
        await msg.edit_text(f"⚠️ Invoice generation failed: `{str(e)[:120]}`", parse_mode="Markdown")


