async def handle_pdf_document(
    update: Update,
    context: ContextTypes.DEFAULT_TYPE,
    user: dict,
    file_bytes: bytes
) -> bool:
    """
    Handle PDF-specific flows. Returns True if handled (caller should return).
    """
    user_id = update.effective_user.id
    awaiting = user.get("awaiting", "")
    doc = update.message.document
    caption = (update.message.caption or "").strip().lower()

    # ── Collect for merge session ──────────────────────────────────
    if user_id in _pdf_merge_sessions:
        _pdf_merge_sessions[user_id].append(file_bytes)
        count = len(_pdf_merge_sessions[user_id])
        await update.message.reply_text(
            f"✅ PDF {count} added! Send more or tap *Done* to merge.",
            parse_mode="Markdown",
            reply_markup=InlineKeyboardMarkup([[
                InlineKeyboardButton("✅ Done — Merge Now!", callback_data="pdfmerge_done"),
                InlineKeyboardButton("❌ Cancel", callback_data="pdfmerge_cancel"),
            ]]))
        return True

    # ── Split ──────────────────────────────────────────────────────
    if awaiting == "pdf_split" or caption == "/pdfsplit":
        msg = await update.message.reply_text("✂️ Splitting PDF… ⏳")
        try:
            reader = PdfReader(io.BytesIO(file_bytes))
            n = len(reader.pages)
            pages_to_split = list(range(min(n, 20)))
            if n > 20:
                await msg.edit_text(f"⚠️ PDF has {n} pages. Splitting limited to first 20 pages.")
            await msg.edit_text(f"✂️ Sending {len(pages_to_split)} pages… ⏳")
            base_name = (doc.file_name or "document").replace(".pdf", "")
            for i in pages_to_split:
                writer = PdfWriter(); writer.add_page(reader.pages[i])
                out = io.BytesIO(); writer.write(out); out.seek(0)
                await context.bot.send_document(chat_id=update.effective_chat.id, document=out, filename=f"{base_name}_page{i+1}.pdf", caption=f"📄 Page {i+1} of {n}")
                await asyncio.sleep(0.4)
            await msg.delete()
            user["awaiting"] = ""; update_user(user_id, user)
        except Exception as e:
            logger.error(f"pdf_split error: {e}")
            await msg.edit_text(f"⚠️ Split failed: `{str(e)[:120]}`", parse_mode="Markdown")
        return True

    # ── Lock ───────────────────────────────────────────────────────
    if awaiting == "pdf_lock":
        password = user.get("pdf_password", "password123")
        msg = await update.message.reply_text("🔒 Encrypting PDF… ⏳")
        try:
            reader = PdfReader(io.BytesIO(file_bytes)); writer = PdfWriter()
            for page in reader.pages: writer.add_page(page)
            writer.encrypt(password)
            out = io.BytesIO(); writer.write(out); out.seek(0)
            base_name = (doc.file_name or "document").replace(".pdf", "")
            await msg.delete()
            await update.message.reply_document(document=out, filename=f"{base_name}_locked.pdf", caption=f"🔒 *PDF Locked!*\nPassword: `{password}`\n\n_Keep this safe!_", parse_mode="Markdown")
            user["awaiting"] = ""; user.pop("pdf_password", None); update_user(user_id, user)
        except Exception as e:
            logger.error(f"pdf_lock error: {e}")
            await msg.edit_text(f"⚠️ Lock failed: `{str(e)[:120]}`", parse_mode="Markdown")
        return True

    # ── Unlock ─────────────────────────────────────────────────────
    if awaiting == "pdf_unlock":
        password = user.get("pdf_password", "")
        msg = await update.message.reply_text("🔓 Decrypting PDF… ⏳")
        try:
            reader = PdfReader(io.BytesIO(file_bytes))
            if reader.is_encrypted: reader.decrypt(password)
            writer = PdfWriter()
            for page in reader.pages: writer.add_page(page)
            out = io.BytesIO(); writer.write(out); out.seek(0)
            base_name = (doc.file_name or "document").replace(".pdf", "")
            await msg.delete()
            await update.message.reply_document(document=out, filename=f"{base_name}_unlocked.pdf", caption="🔓 *PDF Unlocked!* Password removed successfully ✅", parse_mode="Markdown")
            user["awaiting"] = ""; user.pop("pdf_password", None); update_user(user_id, user)
        except Exception as e:
            logger.error(f"pdf_unlock error: {e}")
            await msg.edit_text(f"⚠️ Unlock failed: `{str(e)[:120]}`\n\n_Wrong password?_", parse_mode="Markdown")
        return True

    # ── Watermark ──────────────────────────────────────────────────
    if awaiting == "pdf_watermark":
        wm_text = user.get("pdf_watermark_text", "CONFIDENTIAL")
        msg = await update.message.reply_text("💧 Adding watermark… ⏳")
        try:
            from reportlab.pdfgen import canvas as rl_canvas
            wm_buf = io.BytesIO()
            c = rl_canvas.Canvas(wm_buf, pagesize=A4)
            c.setFont("Helvetica-Bold", 52)
            c.setFillColor(colors.Color(0.75, 0.75, 0.75, alpha=0.35))
            c.saveState(); c.translate(A4[0]/2, A4[1]/2); c.rotate(45)
            c.drawCentredString(0, 0, wm_text.upper()); c.restoreState(); c.save()
            wm_buf.seek(0)
            wm_reader = PdfReader(wm_buf); wm_page = wm_reader.pages[0]
            reader = PdfReader(io.BytesIO(file_bytes)); writer = PdfWriter()
            for page in reader.pages: page.merge_page(wm_page); writer.add_page(page)
            out = io.BytesIO(); writer.write(out); out.seek(0)
            base_name = (doc.file_name or "document").replace(".pdf", "")
            await msg.delete()
            await update.message.reply_document(document=out, filename=f"{base_name}_watermarked.pdf", caption=f"💧 *Watermark Added!*\nText: `{wm_text}`", parse_mode="Markdown")
            user["awaiting"] = ""; user.pop("pdf_watermark_text", None); update_user(user_id, user)
        except Exception as e:
            logger.error(f"pdf_watermark error: {e}")
            await msg.edit_text(f"⚠️ Watermark failed: `{str(e)[:120]}`", parse_mode="Markdown")
        return True

    # ── PDF Info ───────────────────────────────────────────────────
    if awaiting == "pdf_info" or caption == "/pdfinfo":
        try:
            reader = PdfReader(io.BytesIO(file_bytes)); meta = reader.metadata or {}
            n_pages = len(reader.pages); size_kb = len(file_bytes) // 1024
            encrypted = "🔒 Yes" if reader.is_encrypted else "🔓 No"
            info = (f"ℹ️ *PDF Info: {doc.file_name}*\n\n📄 Pages: `{n_pages}`\n💾 Size: `{size_kb} KB`\n🔒 Encrypted: {encrypted}\n")
            if meta.get("/Title"):  info += f"📌 Title: `{meta['/Title']}`\n"
            if meta.get("/Author"): info += f"✍️ Author: `{meta['/Author']}`\n"
            if meta.get("/Creator"):info += f"🛠 Creator: `{meta['/Creator']}`\n"
            if meta.get("/Subject"):info += f"📝 Subject: `{meta['/Subject']}`\n"
            await update.message.reply_text(info, parse_mode="Markdown")
            user["awaiting"] = ""; update_user(user_id, user)
        except Exception as e:
            await update.message.reply_text(f"⚠️ Could not read PDF info: `{str(e)[:120]}`", parse_mode="Markdown")
        return True

    # ── Extract tables ─────────────────────────────────────────────
    if caption in ("/pdftables", "pdftables", "tables"):
        msg = await update.message.reply_text("📊 Extracting tables… ⏳")
        try:
            tables = _extract_pdf_tables(file_bytes)
            if not tables:
                await msg.edit_text("📊 No tables found in this PDF."); return True
            result = f"📊 *Found {len(tables)} table(s) in {doc.file_name}*\n\n"
            for ti, table in enumerate(tables[:5], 1):
                result += f"*Table {ti}:*\n"
                for row in table[:8]:
                    cleaned = [str(cell or "").strip() for cell in row]
                    result += "| " + " | ".join(cleaned) + " |\n"
                result += "\n"
            if len(result) > 3800: result = result[:3800] + "\n…_(truncated)_"
            await msg.edit_text(result, parse_mode="Markdown")
        except Exception as e:
            await msg.edit_text(f"⚠️ Table extraction failed: `{str(e)[:120]}`", parse_mode="Markdown")
        return True

    # ── Extract text ───────────────────────────────────────────────
    if caption in ("/pdfread", "pdfread", "read", "extract", "text"):
        msg = await update.message.reply_text("📖 Extracting text… ⏳")
        try:
            text = _extract_pdf_text(file_bytes)
            if not text.strip():
                await msg.edit_text("⚠️ No readable text found. This may be a scanned/image PDF."); return True
            preview = text[:3500]
            await msg.edit_text(
                f"📖 *Text from {doc.file_name}*\n\n{preview}"
                + ("\n\n…_(truncated — ask me questions about it!)_" if len(text) > 3500 else ""),
                parse_mode="Markdown")
            user["last_file_summary"] = text[:8000]; user["last_file_name"] = doc.file_name or "document"
            user["awaiting"] = "file_qa"; update_user(user_id, user)
        except Exception as e:
            await msg.edit_text(f"⚠️ Text extraction failed: `{str(e)[:120]}`", parse_mode="Markdown")
        return True

    # ── AI Summarize ───────────────────────────────────────────────
    if caption in ("/pdfsummarize", "pdfsummarize", "summarize", "summary", "sum"):
        msg = await update.message.reply_text("🤖 Reading and summarizing PDF… ⏳")
        try:
            text = _extract_pdf_text(file_bytes)
            if not text.strip():
                await msg.edit_text("⚠️ No readable text found in this PDF."); return True
            summary = await asyncio.get_running_loop().run_in_executor(
                None, lambda: call_gemini(
                    f"Summarize this PDF document clearly. Include:\n- Main topic\n- Key points (bullet list)\n- Conclusions\n\nDocument:\n{text[:6000]}",
                    use_cache=False))
            await msg.delete()
            await update.message.reply_text(
                f"📋 *Summary: {doc.file_name}*\n\n{summary}\n\n💬 _Ask me anything about this document!_",
                parse_mode="Markdown")
            user["last_file_summary"] = text[:8000]; user["last_file_name"] = doc.file_name or "document"
            user["awaiting"] = "file_qa"; update_user(user_id, user)
        except Exception as e:
            await msg.edit_text(f"⚠️ Summarization failed: `{str(e)[:120]}`", parse_mode="Markdown")
        return True

    return False


