async def global_error_handler(update: object, context: ContextTypes.DEFAULT_TYPE) -> None:
    """Global error handler — catches ALL unhandled exceptions, prevents bot crashes."""
    import traceback
    err = context.error
    tb = "".join(traceback.format_exception(type(err), err, err.__traceback__))
    logger.error(f"Unhandled exception:\n{tb}")

    # Try to notify the user
    try:
        if isinstance(update, Update) and update.effective_message:
            await update.effective_message.reply_text(
                "⚠️ Something went wrong on my end. Please try again!\n"
                "_If the issue persists, the bot admin has been notified._",
                parse_mode="Markdown"
            )
    except Exception:
        pass

    # Reset any stuck awaiting state
    try:
        if isinstance(update, Update) and update.effective_user:
            user = get_user(update.effective_user.id)
            if user.get("awaiting"):
                user["awaiting"] = ""
                update_user(update.effective_user.id, user)
    except Exception:
        pass



