async def _ocr_extract(img_bytes: bytes, filename: str = "image.jpg") -> str:
    """Extract text from image using AI vision (Gemini)."""
    try:
        import base64 as _b64
        b64 = _b64.b64encode(img_bytes).decode()
        prompt = (
            "Extract ALL text from this image. Return ONLY the extracted text, "
            "preserving the original formatting, line breaks, and structure as much as possible. "
            "If there is no text, say 'No text found in this image.'"
        )
        # Use Gemini vision
        response = await asyncio.get_running_loop().run_in_executor(
            None, lambda: call_gemini(prompt, image_b64=b64, use_cache=False))
        return response
    except Exception as e:
        return f"OCR failed: {str(e)}"


# ── 2. Web Scraping ───────────────────────────────────────────────────────
async def cmd_scrape(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """/scrape <url> — Extract and summarize content from any webpage."""
    url = " ".join(context.args).strip() if context.args else ""
    if not url:
        await update.message.reply_text(
            "🕷️ *Web Scraper*\n\nUsage: `/scrape <url>`\n\n"
            "Examples:\n• `/scrape https://example.com`\n• `/scrape https://news.bbc.com`\n\n"
            "I'll extract the main content and summarize it for you!",
            parse_mode="Markdown"); return
    if not url.startswith("http"): url = "https://" + url
    msg = await update.message.reply_text("🕷️ Scraping webpage… ⏳")
    try:
        def _fetch_page(url):
            import urllib.request as _ur
            headers = {"User-Agent": "Mozilla/5.0 (compatible; CineMagicBot/1.0)"}
            req = _ur.Request(url, headers=headers)
            with _ur.urlopen(req, timeout=15) as r:
                raw = r.read(50000)  # max 50KB
            try:
                html = raw.decode("utf-8")
            except Exception:
                html = raw.decode("latin-1", errors="ignore")
            # Basic HTML stripping
            import re as _re
            html = _re.sub(r'<script[^>]*>.*?</script>', '', html, flags=_re.DOTALL|_re.IGNORECASE)
            html = _re.sub(r'<style[^>]*>.*?</style>', '', html, flags=_re.DOTALL|_re.IGNORECASE)
            html = _re.sub(r'<[^>]+>', ' ', html)
            html = _re.sub(r'\s+', ' ', html).strip()
            return html[:8000]

        text = await asyncio.get_running_loop().run_in_executor(None, lambda: _fetch_page(url))
        if len(text) < 50:
            await msg.edit_text("⚠️ Couldn't extract content from this page. It may require login or JavaScript.")
            return
        summary = await asyncio.get_running_loop().run_in_executor(
            None, lambda: call_gemini(
                f"Summarize the main content of this webpage clearly:\n\n{text}\n\n"
                "Include: main topic, key points, important data. Be concise.",
                use_cache=False))
        domain = url.split("/")[2] if "/" in url else url
        await msg.edit_text(
            f"🕷️ *Scraped: {domain}*\n\n{summary[:3500]}",
            parse_mode="Markdown")
    except Exception as e:
        await msg.edit_text(f"⚠️ Scraping failed: `{str(e)[:120]}`\n\nThe site may block bots.", parse_mode="Markdown")


# ── 3. Smart Memory System ────────────────────────────────────────────────
def _memory_remember(user: dict, key: str, value: str):
    """Store a named memory for the user."""
    user.setdefault("smart_memory", {})[key.lower().strip()] = value.strip()

def _memory_recall(user: dict, key: str) -> str | None:
    return user.get("smart_memory", {}).get(key.lower().strip())

def _memory_forget(user: dict, key: str):
    user.get("smart_memory", {}).pop(key.lower().strip(), None)

def _memory_list(user: dict) -> dict:
    return user.get("smart_memory", {})

def _memory_inject(user: dict, text: str) -> str:
    """Auto-inject relevant memories into a message for context."""
    memories = user.get("smart_memory", {})
    if not memories: return ""
    relevant = []
    text_lower = text.lower()
    for k, v in memories.items():
        if k in text_lower or any(word in text_lower for word in k.split()):
            relevant.append(f"{k}: {v}")
    if not relevant: return ""
    return "Relevant memories: " + "; ".join(relevant[:5])

async def cmd_remember(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """/remember <key> = <value> — Save a named memory.
    Example: /remember my name = John
    Example: /remember my job = Software Engineer at Google"""
    user_id = update.effective_user.id
    user = get_user(user_id)
    args = " ".join(context.args).strip()
    if not args or "=" not in args:
        await update.message.reply_text(
            "🧠 *Smart Memory*\n\nUsage: `/remember <what> = <value>`\n\n"
            "Examples:\n• `/remember my name = John`\n• `/remember my job = Engineer`\n"
            "• `/remember my city = Accra`\n• `/remember wife name = Sarah`",
            parse_mode="Markdown"); return
    parts = args.split("=", 1)
    key, value = parts[0].strip(), parts[1].strip()
    _memory_remember(user, key, value)
    update_user(user_id, user)
    await update.message.reply_text(
        f"🧠 *Remembered!*\n\n📌 `{key}` = `{value}`\n\n_I'll use this in our future conversations!_",
        parse_mode="Markdown")

async def cmd_recall(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """/recall <key> — Recall a saved memory."""
    user_id = update.effective_user.id
    user = get_user(user_id)
    key = " ".join(context.args).strip()
    if not key:
        # Show all memories
        memories = _memory_list(user)
        if not memories:
            await update.message.reply_text("🧠 You have no saved memories yet.\nUse `/remember <key> = <value>` to save one!", parse_mode="Markdown")
            return
        lines = "\n".join(f"• `{k}` = {v}" for k,v in list(memories.items())[:30])
        await update.message.reply_text(f"🧠 *Your Memories ({len(memories)})*\n\n{lines}", parse_mode="Markdown")
        return
    value = _memory_recall(user, key)
    if value:
        await update.message.reply_text(f"🧠 *{key}* = `{value}`", parse_mode="Markdown")
    else:
        await update.message.reply_text(f"🧠 I don't have a memory for `{key}` yet.\nUse `/remember {key} = <value>` to save it!", parse_mode="Markdown")

async def cmd_forget(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """/forget <key> — Delete a saved memory."""
    user_id = update.effective_user.id
    user = get_user(user_id)
    key = " ".join(context.args).strip()
    if not key:
        await update.message.reply_text("Usage: `/forget <key>`\nExample: `/forget my name`", parse_mode="Markdown"); return
    _memory_forget(user, key)
    update_user(user_id, user)
    await update.message.reply_text(f"🗑️ Forgot: `{key}`", parse_mode="Markdown")


# ── 4. Reminder Background Delivery ──────────────────────────────────────
async def _reminder_delivery_loop(app):
    """Background task: check and deliver due reminders every 60 seconds."""
    import datetime as _dt
    while True:
        try:
            await asyncio.sleep(60)
            conn = sqlite3.connect(SQLITE_DB)
            c = conn.cursor()
            try:
                c.execute("SELECT user_id, reminder_text, remind_at FROM reminders WHERE remind_at <= ? AND delivered = 0",
                          (_dt.datetime.now().isoformat(),))
                due = c.fetchall()
                for user_id, text, remind_at in due:
                    try:
                        await app.bot.send_message(
                            chat_id=user_id,
                            text=f"🔔 *Reminder!*\n\n{text}\n\n_Set for {remind_at[:16]}_",
                            parse_mode="Markdown")
                        c.execute("UPDATE reminders SET delivered = 1 WHERE user_id = ? AND remind_at = ?",
                                  (user_id, remind_at))
                        conn.commit()
                    except Exception:
                        pass
            except Exception:
                # Table may not exist yet — create it
                c.execute('''CREATE TABLE IF NOT EXISTS reminders
                             (id INTEGER PRIMARY KEY AUTOINCREMENT,
                              user_id INTEGER, reminder_text TEXT,
                              remind_at TEXT, delivered INTEGER DEFAULT 0)''')
                conn.commit()
            finally:
                conn.close()
        except Exception as e:
            logger.warning(f"Reminder loop error: {e}")

def init_reminders_table():
    conn = sqlite3.connect(SQLITE_DB)
    c = conn.cursor()
    c.execute('''CREATE TABLE IF NOT EXISTS reminders
                 (id INTEGER PRIMARY KEY AUTOINCREMENT,
                  user_id INTEGER, reminder_text TEXT,
                  remind_at TEXT, delivered INTEGER DEFAULT 0)''')
    conn.commit(); conn.close()

async def cmd_setreminder(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """/setreminder <time> | <message> — Set a reminder with exact time.
    /setreminder 30min | Call John
    /setreminder 2h | Team meeting
    /setreminder tomorrow 9am | Doctor appointment"""
    import datetime as _dt
    import re as _re
    user_id = update.effective_user.id
    args = " ".join(context.args).strip()
    if not args or "|" not in args:
        await update.message.reply_text(
            "🔔 *Set Reminder*\n\nUsage: `/setreminder <when> | <message>`\n\n"
            "Examples:\n• `/setreminder 30min | Call John`\n• `/setreminder 2h | Team meeting`\n"
            "• `/setreminder 1d | Pay rent`\n• `/setreminder 15min | Take medicine`",
            parse_mode="Markdown"); return
    parts = args.split("|", 1)
    when_str = parts[0].strip().lower()
    message  = parts[1].strip()
    now = _dt.datetime.now()
    delta = None
    if m := _re.match(r'(\d+)\s*m(in)?', when_str):
        delta = _dt.timedelta(minutes=int(m.group(1)))
    elif m := _re.match(r'(\d+)\s*h(our)?', when_str):
        delta = _dt.timedelta(hours=int(m.group(1)))
    elif m := _re.match(r'(\d+)\s*d(ay)?', when_str):
        delta = _dt.timedelta(days=int(m.group(1)))
    elif 'tomorrow' in when_str:
        delta = _dt.timedelta(days=1)
    else:
        delta = _dt.timedelta(hours=1)
    remind_at = (now + delta).isoformat()
    try:
        conn = sqlite3.connect(SQLITE_DB)
        c = conn.cursor()
        c.execute("INSERT INTO reminders (user_id, reminder_text, remind_at, delivered) VALUES (?,?,?,0)",
                  (user_id, message, remind_at))
        conn.commit(); conn.close()
        time_str = (now + delta).strftime("%d %b %Y at %H:%M")
        await update.message.reply_text(
            f"✅ *Reminder Set!*\n\n📌 {message}\n⏰ Due: *{time_str}*\n\n_I'll notify you when it's time!_ 🔔",
            parse_mode="Markdown")
    except Exception as e:
        await update.message.reply_text(f"⚠️ Failed to set reminder: `{str(e)[:80]}`", parse_mode="Markdown")

