# ── 5. AI Agent — Autonomous multi-step task executor ─────────────────────
async def cmd_agent(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """/agent <task> — Autonomous AI agent that plans and executes multi-step tasks."""
    task = " ".join(context.args).strip() if context.args else ""
    if not task:
        await update.message.reply_text(
            "🤖 *AI Agent Mode*\n\n"
            "I'll plan and execute complex tasks step by step!\n\n"
            "Usage: `/agent <task>`\n\n"
            "Examples:\n"
            "• `/agent Research climate change and write a report`\n"
            "• `/agent Create a business plan for a coffee shop`\n"
            "• `/agent Plan a 7-day trip to Japan with budget`\n"
            "• `/agent Write, review and improve a cover letter for a software job`",
            parse_mode="Markdown"); return
    msg = await update.message.reply_text(f"🤖 *Agent Mode Active*\n\n📋 Task: _{task}_\n\n⚙️ Planning steps…", parse_mode="Markdown")
    await context.bot.send_chat_action(update.effective_chat.id, "typing")
    try:
        # Step 1: Plan
        plan_prompt = (
            f"You are an autonomous AI agent. Break this task into 3-5 clear execution steps:\n{task}\n\n"
            "Return ONLY a JSON array: "
            '[{"step":1,"action":"What to do","tool":"search|write|analyze|calculate|create"}]'
        )
        import json as _jj, re as _rre
        plan_raw = await asyncio.get_running_loop().run_in_executor(
            None, lambda: call_gemini(plan_prompt, use_cache=False))
        m = _rre.search(r'\[.*\]', plan_raw, _rre.DOTALL)
        steps = _jj.loads(m.group(0)) if m else [{"step":1,"action":task,"tool":"write"}]

        steps_text = "\n".join(f"{s.get('step',i+1)}. {s.get('action','')}" for i,s in enumerate(steps))
        await msg.edit_text(
            f"🤖 *Agent Mode Active*\n\n📋 Task: _{task}_\n\n📝 *Plan:*\n{steps_text}\n\n⚡ Executing…",
            parse_mode="Markdown")

        # Step 2: Execute each step
        results = []
        for i, step in enumerate(steps[:5], 1):
            action = step.get("action","")
            await context.bot.send_chat_action(update.effective_chat.id, "typing")
            result = await asyncio.get_running_loop().run_in_executor(
                None, lambda a=action: call_gemini(
                    f"Complete this task step thoroughly: {a}\nContext: {task}",
                    use_cache=False))
            results.append(f"**Step {i}: {action}**\n{result[:500]}")

        # Step 3: Synthesize
        synthesis_prompt = (
            f"Synthesize these step results into a final comprehensive output for: {task}\n\n"
            + "\n\n".join(results)
        )
        final = await asyncio.get_running_loop().run_in_executor(
            None, lambda: call_gemini(synthesis_prompt, use_cache=False))

        await msg.delete()
        header = f"🤖 *Agent Task Complete!*\n📋 _{task}_\n\n"
        if len(header + final) > 4000:
            await update.message.reply_text(header + final[:3800] + "…", parse_mode="Markdown")
        else:
            await update.message.reply_text(header + final, parse_mode="Markdown")
    except Exception as e:
        logger.error(f"cmd_agent error: {e}")
        await msg.edit_text(f"⚠️ Agent task failed: `{str(e)[:120]}`", parse_mode="Markdown")


