# ── 12. Daily Rewards Upgrade ─────────────────────────────────────────────
async def cmd_daily(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """/daily — Claim your daily reward coins, XP and surprises!"""
    import datetime as _dt
    user_id = update.effective_user.id
    user = get_user(user_id)
    now = _dt.datetime.now()
    last_claim = user.get("last_daily_claim")
    if last_claim:
        try:
            last_dt = _dt.datetime.fromisoformat(last_claim)
            hours_since = (now - last_dt).total_seconds() / 3600
            if hours_since < 22:
                next_claim = last_dt + _dt.timedelta(hours=22)
                remaining = next_claim - now
                hrs = int(remaining.total_seconds() // 3600)
                mins = int((remaining.total_seconds() % 3600) // 60)
                await update.message.reply_text(
                    f"⏳ *Daily reward not ready yet!*\n\nCome back in *{hrs}h {mins}m*\n\n"
                    f"🔥 Current streak: *{user.get('daily_streak',0)} days*",
                    parse_mode="Markdown"); return
        except Exception: pass

    # Calculate reward based on streak
    streak = user.get("daily_streak", 0) + 1
    base_xp = 50
    streak_bonus = min(streak * 10, 200)
    total_xp = base_xp + streak_bonus
    coins = 10 + (streak * 2)

    # Streak milestones
    milestone = ""
    if streak == 7:   milestone = "\n\n🎖️ *7-Day Streak!* Bonus: +100 XP"    ; total_xp += 100
    elif streak == 30: milestone = "\n\n👑 *30-Day Streak!* Bonus: +500 XP"  ; total_xp += 500
    elif streak == 100:milestone = "\n\n💎 *100-Day Streak!* Bonus: +2000 XP"; total_xp += 2000

    # Surprise rewards
    surprises = []
    if streak % 5 == 0: surprises.append("🎁 Mystery bonus activated!")
    if streak % 10 == 0: surprises.append("⭐ Premium feature unlocked for 24h!")

    user["daily_streak"] = streak
    user["last_daily_claim"] = now.isoformat()
    user["coins"] = user.get("coins", 0) + coins
    add_xp(user, total_xp)
    update_user(user_id, user)

    msg = (
        f"🎁 *Daily Reward Claimed!*\n"
        f"━━━━━━━━━━━━━━━━━━━\n"
        f"✨ XP: +{total_xp} (streak bonus: +{streak_bonus})\n"
        f"🪙 Coins: +{coins} → Total: {user.get('coins',0)}\n"
        f"🔥 Streak: *{streak} days* {'🆙' if streak > 1 else ''}\n"
        f"⭐ Level: {user.get('level',1)}{milestone}\n"
        + ("\n" + "\n".join(surprises) if surprises else "") +
        f"\n\n_Come back tomorrow for more rewards!_ 🔔"
    )
    await update.message.reply_text(msg, parse_mode="Markdown")


