def _ie_require_pillow(update_msg=None):
    """Check Pillow is available."""
    if not PILLOW_OK:
        return "⚠️ Image editing requires Pillow.\nInstall: `pip install pillow --break-system-packages`"
    return None

async def _ie_get_image_bytes(update: Update, context) -> bytes | None:
    """Get image bytes from message or reply."""
    msg = update.message
    photo = None
    if msg.photo:
        photo = msg.photo[-1]
    elif msg.reply_to_message and msg.reply_to_message.photo:
        photo = msg.reply_to_message.photo[-1]
    elif msg.reply_to_message and msg.reply_to_message.document:
        doc = msg.reply_to_message.document
        if doc.mime_type and doc.mime_type.startswith("image"):
            file = await context.bot.get_file(doc.file_id)
            return bytes(await file.download_as_bytearray())
    if photo:
        file = await context.bot.get_file(photo.file_id)
        return bytes(await file.download_as_bytearray())
    return None

def _ie_to_pil(img_bytes: bytes):
    from PIL import Image
    return Image.open(io.BytesIO(img_bytes)).convert("RGBA")

def _ie_to_bytes(img, fmt="PNG") -> bytes:
    buf = io.BytesIO()
    if fmt == "JPEG":
        img = img.convert("RGB")
    img.save(buf, format=fmt, quality=92)
    return buf.getvalue()

async def _ie_send_result(update: Update, img_bytes: bytes, caption: str):
    await update.message.reply_photo(
        photo=io.BytesIO(img_bytes),
        caption=caption)

