# ── Apply effect ──────────────────────────────────────────────────
def _ie_apply_effect(img_bytes: bytes, effect: str, param=None) -> bytes:
    from PIL import Image, ImageEnhance, ImageFilter, ImageOps, ImageDraw, ImageFont
    import math as _m

    img = Image.open(io.BytesIO(img_bytes)).convert("RGBA")
    W, H = img.size

    if effect == "brightness":
        enhancer = ImageEnhance.Brightness(img.convert("RGB"))
        img = enhancer.enhance(param or 1.5)
    elif effect == "contrast":
        enhancer = ImageEnhance.Contrast(img.convert("RGB"))
        img = enhancer.enhance(param or 1.5)
    elif effect == "saturation":
        enhancer = ImageEnhance.Color(img.convert("RGB"))
        img = enhancer.enhance(param or 1.8)
    elif effect == "sharpness":
        enhancer = ImageEnhance.Sharpness(img.convert("RGB"))
        img = enhancer.enhance(param or 2.0)
    elif effect == "grayscale":
        img = ImageOps.grayscale(img.convert("RGB")).convert("RGBA")
    elif effect == "bw":
        gray = ImageOps.grayscale(img.convert("RGB"))
        img = gray.point(lambda x: 0 if x < 128 else 255).convert("RGBA")
    elif effect == "invert":
        img = ImageOps.invert(img.convert("RGB")).convert("RGBA")
    elif effect == "rotate":
        img = img.rotate(param or 90, expand=True)
    elif effect == "flip_h":
        img = ImageOps.mirror(img)
    elif effect == "flip_v":
        img = ImageOps.flip(img)
    elif effect == "blur":
        img = img.filter(ImageFilter.GaussianBlur(radius=param or 3))
    elif effect == "sharpen_filter":
        for _ in range(3):
            img = img.filter(ImageFilter.SHARPEN)
    elif effect == "enhance":
        img = img.filter(ImageFilter.DETAIL)
        img = ImageEnhance.Contrast(img).enhance(1.3)
        img = ImageEnhance.Sharpness(img).enhance(1.5)
    elif effect == "sepia":
        rgb = img.convert("RGB")
        r, g, b = rgb.split()
        r = r.point(lambda i: min(255, int(i * 0.393 + 255 * 0.349 + 255 * 0.272)))
        g = g.point(lambda i: min(255, int(i * 0.349 + 255 * 0.686 + 255 * 0.534)))
        b = b.point(lambda i: min(255, int(i * 0.272 + 255 * 0.534 + 255 * 0.131)))
        img = Image.merge("RGB", (r, g, b)).convert("RGBA")
    elif effect == "warm":
        rgb = img.convert("RGB")
        r, g, b = rgb.split()
        r = r.point(lambda i: min(255, i + 30))
        b = b.point(lambda i: max(0, i - 20))
        img = Image.merge("RGB", (r, g, b)).convert("RGBA")
    elif effect == "cool":
        rgb = img.convert("RGB")
        r, g, b = rgb.split()
        r = r.point(lambda i: max(0, i - 20))
        b = b.point(lambda i: min(255, i + 30))
        img = Image.merge("RGB", (r, g, b)).convert("RGBA")
    elif effect == "vivid":
        img = ImageEnhance.Color(img.convert("RGB")).enhance(2.2)
        img = ImageEnhance.Contrast(img).enhance(1.2)
        img = img.convert("RGBA")
    elif effect == "cartoon":
        rgb = img.convert("RGB")
        edges = rgb.filter(ImageFilter.FIND_EDGES)
        edges = ImageOps.invert(edges)
        smooth = rgb.filter(ImageFilter.SMOOTH_MORE)
        smooth = ImageEnhance.Color(smooth).enhance(1.8)
        img = Image.blend(smooth, edges, 0.15).convert("RGBA")
    elif effect == "border":
        border_size = max(8, min(W, H) // 20)
        color = param or (255, 255, 255, 255)
        img = ImageOps.expand(img, border=border_size, fill=color)
    elif effect == "watermark":
        draw = ImageDraw.Draw(img)
        text = param or "CineMagic Bot"
        font_size = max(20, W // 20)
        try:
            font = ImageFont.truetype(
                "/data/data/com.termux/files/usr/share/fonts/TTF/DejaVuSans-Bold.ttf",
                font_size)
        except Exception:
            font = ImageFont.load_default()
        draw.text((W//2, H - font_size*2), text,
                  fill=(255, 255, 255, 160), font=font, anchor="mm")
    elif effect == "addtext":
        draw = ImageDraw.Draw(img)
        text = param or "CineMagic"
        font_size = max(24, W // 15)
        try:
            font = ImageFont.truetype(
                "/data/data/com.termux/files/usr/share/fonts/TTF/DejaVuSans-Bold.ttf",
                font_size)
        except Exception:
            font = ImageFont.load_default()
        # Shadow
        draw.text((W//2+2, H//2+2), text, fill=(0,0,0,180), font=font, anchor="mm")
        draw.text((W//2, H//2), text, fill=(255,255,255,230), font=font, anchor="mm")
    elif effect == "circle_crop":
        size = min(W, H)
        mask = Image.new("L", (size, size), 0)
        draw = ImageDraw.Draw(mask)
        draw.ellipse((0, 0, size, size), fill=255)
        img = img.crop(((W-size)//2, (H-size)//2, (W+size)//2, (H+size)//2))
        img.putalpha(mask)
    elif effect == "square_crop":
        size = min(W, H)
        img = img.crop(((W-size)//2, (H-size)//2, (W+size)//2, (H+size)//2))
    elif effect == "crop":
        margin = min(W, H) // 8
        img = img.crop((margin, margin, W-margin, H-margin))
    elif effect == "resize":
        new_w, new_h = param or (800, int(H * 800/W))
        img = img.resize((new_w, new_h), Image.LANCZOS)
    elif effect == "zoom":
        factor = param or 1.5
        new_w = int(W / factor); new_h = int(H / factor)
        cx, cy = W//2, H//2
        img = img.crop((cx-new_w//2, cy-new_h//2, cx+new_w//2, cy+new_h//2))
        img = img.resize((W, H), Image.LANCZOS)

    return _ie_to_bytes(img, "PNG")


