async def _generate_ssml_voice(text: str, voice_key: str, el_key: str = "") -> bytes | None:
    """Generate emotional voice — ElevenLabs first, edge-tts fallback."""
    api_key = el_key or ELEVENLABS_API_KEY
    if api_key:
        try:
            voice_id = _EL_VOICES.get(voice_key, "21m00Tcm4TlvDq8ikWAM")
            r = requests.post(
                f"https://api.elevenlabs.io/v1/text-to-speech/{voice_id}",
                headers={"xi-api-key": api_key, "Content-Type": "application/json", "Accept": "audio/mpeg"},
                json={"text": text[:4500], "model_id": "eleven_turbo_v2",
                      "voice_settings": {"stability": 0.4, "similarity_boost": 0.8, "style": 0.6}},
                timeout=30)
            if r.status_code == 200 and len(r.content) > 100:
                return r.content
        except Exception as e:
            logger.warning(f"ElevenLabs failed, falling back to edge-tts: {e}")

    # edge-tts fallback
    if voice_key not in EMOTION_VOICES:
        voice_key = "podcast_host"
    _, voice_name, rate, pitch, volume, _ = EMOTION_VOICES[voice_key]
    try:
        import edge_tts
        ssml = (
            f'<speak version="1.0" xmlns="http://www.w3.org/2001/10/synthesis" xml:lang="en-US">'
            f'<voice name="{voice_name}">'
            f'<prosody rate="{rate}" pitch="{pitch}" volume="{volume}">'
            f'{text}'
            f'</prosody></voice></speak>'
        )
        communicate = edge_tts.Communicate(text, voice_name,
                                            rate=rate, pitch=pitch, volume=volume)
        audio_chunks = []
        async for chunk in communicate.stream():
            if chunk["type"] == "audio":
                audio_chunks.append(chunk["data"])
        if audio_chunks:
            return b"".join(audio_chunks)
    except Exception as e:
        logger.error(f"SSML voice error: {e}")
        # Fallback to basic TTS
        return await text_to_voice(text, EMOTION_VOICES[voice_key][1])
    return None


async def _build_podcast_audio(
    script: str, voice_key: str, bg_sound_key: str,
    add_intro: bool = True, add_outro: bool = True
) -> bytes | None:
    """
    Full podcast production pipeline:
    1. Generate voice with emotion
    2. Generate background music
    3. Mix together
    4. Add intro/outro jingle
    """
    try:
        # ── 1. Generate voice ──────────────────────────────────────
        voice_bytes = await _generate_ssml_voice(script, voice_key)
        if not voice_bytes or len(voice_bytes) < 100:
            return None

        # ── 2. If no background, return voice only ─────────────────
        bg_beat_key = PODCAST_SOUNDS.get(bg_sound_key, ("", None))[1]
        if not bg_beat_key:
            return voice_bytes

        # ── 3. Get voice duration ──────────────────────────────────
        with tempfile.NamedTemporaryFile(suffix=".mp3", delete=False) as vf:
            vf.write(voice_bytes); vpath = vf.name

        dur_result = subprocess.run(
            ["ffprobe", "-v", "error", "-show_entries", "format=duration",
             "-of", "default=noprint_wrappers=1:nokey=1", vpath],
            capture_output=True, timeout=10)
        try:
            dur = float(dur_result.stdout.decode().strip()) + 1.5
        except Exception:
            dur = 15.0

        # ── 4. Generate background beat ────────────────────────────
        gen_fn = _VB_GENERATORS.get(bg_beat_key, _vb_gen_lofi)
        beat_samples = gen_fn(dur)
        beat_wav_bytes = _vb_float_to_wav(beat_samples)

        with tempfile.NamedTemporaryFile(suffix=".wav", delete=False) as bf:
            bf.write(beat_wav_bytes); bpath = bf.name

        # ── 5. Mix voice + background ─────────────────────────────
        out_path = vpath.replace(".mp3", "_podcast.mp3")
        filter_c = (
            "[0:a]volume=1.0[voice];"
            "[1:a]volume=0.18[bg];"   # background at 18% — subtle
            "[voice][bg]amix=inputs=2:duration=first:dropout_transition=2[aout]"
        )
        r = subprocess.run(
            ["ffmpeg", "-y", "-i", vpath, "-i", bpath,
             "-filter_complex", filter_c, "-map", "[aout]",
             "-ar", "44100", "-ac", "1", "-b:a", "128k", out_path],
            capture_output=True, timeout=120)

        result = None
        if r.returncode == 0 and os.path.getsize(out_path) > 500:
            with open(out_path, "rb") as f:
                result = f.read()

        for p in [vpath, bpath, out_path]:
            try: os.unlink(p)
            except Exception: pass

        return result or voice_bytes

    except Exception as e:
        logger.error(f"podcast build error: {e}")
        return None


