# ── /emotionvoice — Speak any text with emotion ──────────────────
async def cmd_emotionvoice(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """/emotionvoice <emotion> <text> — Speak text with specific emotion.
    Example: /emotionvoice excited I just won a million dollars!
    Example: /emotionvoice sad I really miss you
    Example: /emotionvoice villain Your destiny is sealed"""
    args = " ".join(context.args).strip() if context.args else ""
    if not args:
        # Show emotion menu
        buttons = []
        row = []
        for key, (label, _, _, _, _, desc) in EMOTION_VOICES.items():
            row.append(InlineKeyboardButton(label, callback_data=f"emv_pick:{key}"))
            if len(row) == 2: buttons.append(row); row = []
        if row: buttons.append(row)

        await update.message.reply_text(
            "🎭 *Emotion Voice Generator*\n\n"
            "Speak any text with a specific emotion!\n\n"
            "Usage: `/emotionvoice <emotion> <your text>`\n\n"
            "Examples:\n"
            "• `/emotionvoice excited I just got the job!`\n"
            "• `/emotionvoice sad This is goodbye`\n"
            "• `/emotionvoice villain You cannot escape me`\n"
            "• `/emotionvoice calm Take a deep breath and relax`\n"
            "• `/emotionvoice inspirational You have the power to change the world`\n\n"
            "Or pick an emotion below 👇",
            parse_mode="Markdown",
            reply_markup=InlineKeyboardMarkup(buttons))
        return

    # Parse emotion + text
    words = args.split(maxsplit=1)
    emotion = words[0].lower()
    text = words[1] if len(words) > 1 else ""

    if emotion not in EMOTION_VOICES:
        # Try fuzzy match
        matches = [k for k in EMOTION_VOICES if emotion in k]
        if matches:
            emotion = matches[0]
        else:
            # Treat whole thing as text with default emotion
            text = args
            emotion = "podcast_host"

    if not text:
        user = get_user(update.effective_user.id)
        user["awaiting"] = f"emv_{emotion}"; update_user(update.effective_user.id, user)
        label = EMOTION_VOICES[emotion][0]
        await update.message.reply_text(
            f"🎭 *{label}* selected!\n\nNow type the text you want me to speak:",
            parse_mode="Markdown"); return

    await _speak_with_emotion(update, context, emotion, text)


