async def _speak_with_emotion(update, context, emotion: str, text: str):
    """Generate and send emotional voice — uses ElevenLabs if key set, else edge-tts."""
    label, voice_name, rate, pitch, volume, desc = EMOTION_VOICES.get(
        emotion, EMOTION_VOICES["podcast_host"])

    msg = await update.message.reply_text(
        f"🎭 Generating *{label}* voice… ⏳", parse_mode="Markdown")
    await context.bot.send_chat_action(update.effective_chat.id, "record_voice")

    try:
        audio = None
        user = get_user(update.effective_user.id)
        el_key = user.get("elevenlabs_key", "") or ELEVENLABS_API_KEY

        # Try ElevenLabs first (real emotions)
        if el_key:
            audio = await asyncio.get_running_loop().run_in_executor(
                None, lambda: requests.post(
                    f"https://api.elevenlabs.io/v1/text-to-speech/{_EL_VOICES.get(emotion,'21m00Tcm4TlvDq8ikWAM')}",
                    headers={"xi-api-key": el_key, "Content-Type": "application/json", "Accept": "audio/mpeg"},
                    json={"text": text[:4500], "model_id": "eleven_turbo_v2",
                          "voice_settings": {"stability": 0.4, "similarity_boost": 0.8, "style": 0.6}},
                    timeout=30).content if requests.get(
                        "https://api.elevenlabs.io/v1/user",
                        headers={"xi-api-key": el_key}, timeout=5).status_code == 200 else None)

        # Fallback to edge-tts
        if not audio or len(audio) < 100:
            audio = await _generate_ssml_voice(text, emotion)

        if not audio or len(audio) < 100:
            audio = await text_to_voice(text, voice_name)

        if audio and len(audio) > 100:
            await msg.delete()
            suffix = "\n🔑 _Add ElevenLabs key with /setelevenkey for real emotions!_" if not el_key else "\n✨ _Powered by ElevenLabs AI_"

            # Send as voice (streamable)
            await update.message.reply_voice(
                voice=io.BytesIO(audio),
                caption=f"🎭 *{label}*\n💬 _{text[:100]}_{suffix}",
                parse_mode="Markdown")

            # Send as downloadable audio file
            safe_text = text[:25].replace(' ','_').replace('/','_')
            await update.message.reply_audio(
                audio=io.BytesIO(audio),
                filename=f"{emotion}_{safe_text}.mp3",
                title=f"{label} — {text[:40]}",
                performer="CineMagic AI Bot",
                caption="💾 *Download audio file*\n_Tap 3 dots → Save to Downloads_",
                parse_mode="Markdown")
        else:
            await msg.edit_text(
                "⚠️ Voice generation failed.\n"
                "Install edge-tts: `pip install edge-tts --break-system-packages`",
                parse_mode="Markdown")
    except Exception as e:
        logger.error(f"emotion voice error: {e}")
        await msg.edit_text(f"⚠️ Failed: `{str(e)[:100]}`", parse_mode="Markdown")


