async def _elevenlabs_tts(text: str, emotion: str, api_key: str) -> bytes | None:
    """Generate truly emotional voice using ElevenLabs API."""
    try:
        voice_id = _EL_VOICES.get(emotion, "21m00Tcm4TlvDq8ikWAM")

        # Emotion-specific settings
        emotion_settings = {
            "excited":       {"stability": 0.25, "similarity_boost": 0.85, "style": 0.8},
            "happy":         {"stability": 0.35, "similarity_boost": 0.80, "style": 0.6},
            "sad":           {"stability": 0.75, "similarity_boost": 0.70, "style": 0.3},
            "angry":         {"stability": 0.20, "similarity_boost": 0.90, "style": 0.9},
            "calm":          {"stability": 0.85, "similarity_boost": 0.75, "style": 0.1},
            "inspirational": {"stability": 0.30, "similarity_boost": 0.85, "style": 0.7},
            "storytelling":  {"stability": 0.55, "similarity_boost": 0.80, "style": 0.5},
            "villain":       {"stability": 0.40, "similarity_boost": 0.85, "style": 0.8},
            "meditation":    {"stability": 0.90, "similarity_boost": 0.70, "style": 0.0},
            "romantic":      {"stability": 0.65, "similarity_boost": 0.80, "style": 0.4},
            "newscast":      {"stability": 0.70, "similarity_boost": 0.85, "style": 0.2},
            "podcast_host":  {"stability": 0.45, "similarity_boost": 0.82, "style": 0.5},
        }
        settings = emotion_settings.get(emotion, {"stability": 0.5, "similarity_boost": 0.8, "style": 0.5})

        payload = {
            "text": text[:4500],
            "model_id": "eleven_turbo_v2",
            "voice_settings": settings
        }
        r = requests.post(
            f"https://api.elevenlabs.io/v1/text-to-speech/{voice_id}",
            headers={
                "xi-api-key": api_key,
                "Content-Type": "application/json",
                "Accept": "audio/mpeg"
            },
            json=payload,
            timeout=30
        )
        if r.status_code == 200:
            return r.content
        else:
            logger.error(f"ElevenLabs error {r.status_code}: {r.text[:200]}")
            return None
    except Exception as e:
        logger.error(f"ElevenLabs TTS error: {e}")
        return None


