import sqlite3 as _gsql

# ── Group DB helpers ──────────────────────────────────────────────
def init_group_tables():
    conn = sqlite3.connect(SQLITE_DB)
    c = conn.cursor()
    c.executescript('''
        CREATE TABLE IF NOT EXISTS group_settings (
            chat_id INTEGER PRIMARY KEY,
            welcome_msg TEXT DEFAULT '',
            goodbye_msg TEXT DEFAULT '',
            rules TEXT DEFAULT '',
            log_channel TEXT DEFAULT '',
            anti_link INTEGER DEFAULT 0,
            anti_forward INTEGER DEFAULT 0,
            anti_bot INTEGER DEFAULT 0,
            captcha INTEGER DEFAULT 0,
            max_warns INTEGER DEFAULT 3,
            flood_limit INTEGER DEFAULT 5,
            flood_time INTEGER DEFAULT 5,
            locked INTEGER DEFAULT 0,
            lang TEXT DEFAULT 'en'
        );
        CREATE TABLE IF NOT EXISTS group_warns (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            chat_id INTEGER,
            user_id INTEGER,
            reason TEXT,
            warn_time TEXT
        );
        CREATE TABLE IF NOT EXISTS group_notes (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            chat_id INTEGER,
            name TEXT,
            content TEXT
        );
        CREATE TABLE IF NOT EXISTS group_filters (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            chat_id INTEGER,
            keyword TEXT,
            reply TEXT
        );
        CREATE TABLE IF NOT EXISTS group_blacklist (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            chat_id INTEGER,
            word TEXT
        );
        CREATE TABLE IF NOT EXISTS group_flood (
            chat_id INTEGER,
            user_id INTEGER,
            count INTEGER DEFAULT 0,
            last_msg_time REAL DEFAULT 0,
            PRIMARY KEY (chat_id, user_id)
        );
        CREATE TABLE IF NOT EXISTS group_captcha (
            chat_id INTEGER,
            user_id INTEGER,
            answer INTEGER,
            verified INTEGER DEFAULT 0,
            joined_time TEXT,
            PRIMARY KEY (chat_id, user_id)
        );
    ''')
    conn.commit(); conn.close()

def get_group_settings(chat_id: int) -> dict:
    conn = sqlite3.connect(SQLITE_DB)
    c = conn.cursor()
    c.execute("SELECT * FROM group_settings WHERE chat_id = ?", (chat_id,))
    row = c.fetchone(); conn.close()
    if not row:
        conn2 = sqlite3.connect(SQLITE_DB)
        c2 = conn2.cursor()
        c2.execute("INSERT OR IGNORE INTO group_settings (chat_id) VALUES (?)", (chat_id,))
        conn2.commit(); conn2.close()
        return {"chat_id": chat_id, "welcome_msg": "", "goodbye_msg": "",
                "rules": "", "log_channel": "", "anti_link": 0,
                "anti_forward": 0, "anti_bot": 0, "captcha": 0,
                "max_warns": 3, "flood_limit": 5, "flood_time": 5,
                "locked": 0, "lang": "en"}
    cols = ["chat_id","welcome_msg","goodbye_msg","rules","log_channel",
            "anti_link","anti_forward","anti_bot","captcha","max_warns",
            "flood_limit","flood_time","locked","lang"]
    return dict(zip(cols, row))

def save_group_settings(chat_id: int, **kwargs):
    conn = sqlite3.connect(SQLITE_DB)
    c = conn.cursor()
    c.execute("INSERT OR IGNORE INTO group_settings (chat_id) VALUES (?)", (chat_id,))
    for k, v in kwargs.items():
        c.execute(f"UPDATE group_settings SET {k} = ? WHERE chat_id = ?", (v, chat_id))
    conn.commit(); conn.close()

async def _is_group_admin(bot, chat_id, user_id) -> bool:
    try:
        member = await bot.get_chat_member(chat_id, user_id)
        return member.status in ("administrator", "creator")
    except Exception:
        return False

async def _log_action(bot, chat_id, action: str, settings: dict = None):
    if not settings:
        settings = get_group_settings(chat_id)
    log_ch = settings.get("log_channel", "")
    if log_ch:
        try:
            await bot.send_message(log_ch, f"📋 {action}", parse_mode="Markdown")
        except Exception:
            pass

# ── Admin check decorator ─────────────────────────────────────────
def group_admin_only(func):
    async def wrapper(update: Update, context: ContextTypes.DEFAULT_TYPE):
        if not update.effective_chat or update.effective_chat.type == "private":
            await update.message.reply_text("⚠️ This command only works in groups!")
            return
        user_id = update.effective_user.id
        if not await _is_group_admin(context.bot, update.effective_chat.id, user_id):
            await update.message.reply_text("❌ You must be an admin to use this command!")
            return
        return await func(update, context)
    wrapper.__name__ = func.__name__
    return wrapper


# ════════════════════════════════════════════════════════════════
#  👋  WELCOME & GOODBYE
# ════════════════════════════════════════════════════════════════

async def handle_new_member(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Handle new members joining — send welcome + CAPTCHA if enabled."""
    chat_id = update.effective_chat.id
    settings = get_group_settings(chat_id)

    for member in update.message.new_chat_members:
        if member.is_bot:
            if settings.get("anti_bot"):
                try:
                    await context.bot.ban_chat_member(chat_id, member.id)
                    await update.message.reply_text(f"🤖 Bot @{member.username} was removed (anti-bot is ON)")
                except Exception:
                    pass
            continue

        name = member.first_name or "Member"
        username = f"@{member.username}" if member.username else name

        # CAPTCHA
        if settings.get("captcha"):
            import random as _r
            a, b = _r.randint(1, 9), _r.randint(1, 9)
            answer = a + b
            conn = sqlite3.connect(SQLITE_DB)
            c = conn.cursor()
            c.execute("INSERT OR REPLACE INTO group_captcha (chat_id, user_id, answer, verified, joined_time) VALUES (?,?,?,0,?)",
                      (chat_id, member.id, answer, datetime.datetime.now().isoformat()))
            conn.commit(); conn.close()
            # Mute until verified
            try:
                from telegram import ChatPermissions
                await context.bot.restrict_chat_member(
                    chat_id, member.id,
                    permissions=ChatPermissions(can_send_messages=False))
            except Exception:
                pass
            buttons = [[InlineKeyboardButton(str(a+b+i-1 if i < 2 else a+b+i), callback_data=f"captcha:{chat_id}:{member.id}:{answer}:{a+b+i-1 if i < 2 else a+b+i}") for i in range(3)]]
            await update.message.reply_text(
                f"👋 Welcome {username}!\n\n"
                f"🔒 Please verify you're human:\n"
                f"*What is {a} + {b}?*",
                parse_mode="Markdown",
                reply_markup=InlineKeyboardMarkup(buttons))
            continue

        # Welcome message
        welcome = settings.get("welcome_msg", "")
        if welcome:
            welcome = welcome.replace("{name}", name).replace("{username}", username).replace("{chat}", update.effective_chat.title or "")
        else:
            welcome = f"👋 Welcome to the group, {name}! 🎉\n\nPlease read the /rules before chatting."

        rules = settings.get("rules", "")
        kb = [[InlineKeyboardButton("📋 Rules", callback_data=f"grp_rules:{chat_id}")]] if rules else []
        await update.message.reply_text(welcome, parse_mode="Markdown",
            reply_markup=InlineKeyboardMarkup(kb) if kb else None)


async def handle_left_member(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Handle members leaving."""
    chat_id = update.effective_chat.id
    settings = get_group_settings(chat_id)
    member = update.message.left_chat_member
    if not member or member.is_bot: return
    name = member.first_name or "Member"
    goodbye = settings.get("goodbye_msg", "")
    if goodbye:
        goodbye = goodbye.replace("{name}", name)
        await update.message.reply_text(goodbye, parse_mode="Markdown")


async def cb_captcha(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Handle CAPTCHA verification."""
    query = update.callback_query; await query.answer()
    parts = query.data.split(":")
    if len(parts) != 5: return
    _, chat_id, user_id, correct_ans, chosen = parts
    chat_id = int(chat_id); user_id = int(user_id)
    correct_ans = int(correct_ans); chosen = int(chosen)

    if query.from_user.id != user_id:
        await query.answer("❌ This CAPTCHA isn't for you!", show_alert=True); return

    if chosen == correct_ans:
        # Unmute
        try:
            from telegram import ChatPermissions
            await context.bot.restrict_chat_member(
                chat_id, user_id,
                permissions=ChatPermissions(
                    can_send_messages=True, can_send_media_messages=True,
                    can_send_polls=True, can_send_other_messages=True))
        except Exception:
            pass
        conn = sqlite3.connect(SQLITE_DB)
        c = conn.cursor()
        c.execute("UPDATE group_captcha SET verified = 1 WHERE chat_id = ? AND user_id = ?", (chat_id, user_id))
        conn.commit(); conn.close()
        await query.edit_message_text(f"✅ Verified! Welcome to the group 🎉")
    else:
        await query.answer("❌ Wrong answer! Try again.", show_alert=True)


