#  ⚠️  WARN SYSTEM
# ════════════════════════════════════════════════════════════════

@group_admin_only
async def cmd_warn(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """/warn @user [reason] — Warn a user. Auto-ban after max warns."""
    chat_id = update.effective_chat.id
    settings = get_group_settings(chat_id)
    max_warns = settings.get("max_warns", 3)

    # Get target user
    target_id = None; target_name = "User"; reason = "No reason given"
    if update.message.reply_to_message:
        target_id = update.message.reply_to_message.from_user.id
        target_name = update.message.reply_to_message.from_user.first_name
        reason = " ".join(context.args) if context.args else reason
    elif context.args:
        try:
            target_id = int(context.args[0].replace("@",""))
            reason = " ".join(context.args[1:]) if len(context.args) > 1 else reason
        except Exception:
            await update.message.reply_text("Usage: Reply to a message + /warn [reason]"); return

    if not target_id:
        await update.message.reply_text("❌ Reply to a user's message to warn them."); return

    # Add warn
    conn = sqlite3.connect(SQLITE_DB)
    c = conn.cursor()
    c.execute("INSERT INTO group_warns (chat_id, user_id, reason, warn_time) VALUES (?,?,?,?)",
              (chat_id, target_id, reason, datetime.datetime.now().isoformat()))
    conn.commit()
    c.execute("SELECT COUNT(*) FROM group_warns WHERE chat_id = ? AND user_id = ?", (chat_id, target_id))
    warn_count = c.fetchone()[0]; conn.close()

    if warn_count >= max_warns:
        try:
            await context.bot.ban_chat_member(chat_id, target_id)
            await update.message.reply_text(
                f"🚫 *{target_name}* has been *banned!*\n"
                f"Reason: {reason}\n"
                f"Warns: {warn_count}/{max_warns} (limit reached)",
                parse_mode="Markdown")
        except Exception as e:
            await update.message.reply_text(f"⚠️ Could not ban: {e}")
    else:
        await update.message.reply_text(
            f"⚠️ *{target_name}* has been warned!\n"
            f"Reason: {reason}\n"
            f"Warns: {warn_count}/{max_warns}",
            parse_mode="Markdown")
    await _log_action(context.bot, chat_id, f"⚠️ Warn: {target_name} ({warn_count}/{max_warns}) — {reason}", settings)


@group_admin_only
async def cmd_unwarn(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """/unwarn — Remove last warning from replied user."""
    chat_id = update.effective_chat.id
    if not update.message.reply_to_message:
        await update.message.reply_text("Reply to a user to remove their warn."); return
    target_id = update.message.reply_to_message.from_user.id
    target_name = update.message.reply_to_message.from_user.first_name
    conn = sqlite3.connect(SQLITE_DB)
    c = conn.cursor()
    c.execute("SELECT id FROM group_warns WHERE chat_id = ? AND user_id = ? ORDER BY id DESC LIMIT 1", (chat_id, target_id))
    row = c.fetchone()
    if row:
        c.execute("DELETE FROM group_warns WHERE id = ?", (row[0],))
        conn.commit()
        c.execute("SELECT COUNT(*) FROM group_warns WHERE chat_id = ? AND user_id = ?", (chat_id, target_id))
        remaining = c.fetchone()[0]
        conn.close()
        await update.message.reply_text(f"✅ Removed 1 warn from *{target_name}*. Remaining: {remaining}", parse_mode="Markdown")
    else:
        conn.close()
        await update.message.reply_text(f"*{target_name}* has no warnings.", parse_mode="Markdown")


@group_admin_only
async def cmd_resetwarns(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """/resetwarns — Clear all warnings for replied user."""
    chat_id = update.effective_chat.id
    if not update.message.reply_to_message:
        await update.message.reply_text("Reply to a user to reset their warns."); return
    target_id = update.message.reply_to_message.from_user.id
    target_name = update.message.reply_to_message.from_user.first_name
    conn = sqlite3.connect(SQLITE_DB)
    c = conn.cursor()
    c.execute("DELETE FROM group_warns WHERE chat_id = ? AND user_id = ?", (chat_id, target_id))
    conn.commit(); conn.close()
    await update.message.reply_text(f"✅ All warns cleared for *{target_name}*.", parse_mode="Markdown")


async def cmd_warns(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """/warns — Check warns for yourself or replied user."""
    chat_id = update.effective_chat.id
    if update.message.reply_to_message:
        target_id = update.message.reply_to_message.from_user.id
        target_name = update.message.reply_to_message.from_user.first_name
    else:
        target_id = update.effective_user.id
        target_name = update.effective_user.first_name
    settings = get_group_settings(chat_id)
    conn = sqlite3.connect(SQLITE_DB)
    c = conn.cursor()
    c.execute("SELECT reason, warn_time FROM group_warns WHERE chat_id = ? AND user_id = ? ORDER BY id DESC", (chat_id, target_id))
    rows = c.fetchall(); conn.close()
    if not rows:
        await update.message.reply_text(f"✅ *{target_name}* has no warnings.", parse_mode="Markdown"); return
    lines = "\n".join(f"{i+1}. {r} — _{t[:10]}_" for i,(r,t) in enumerate(rows))
    await update.message.reply_text(
        f"⚠️ *{target_name}'s Warnings* ({len(rows)}/{settings.get('max_warns',3)})\n\n{lines}",
        parse_mode="Markdown")


