@group_admin_only
async def cmd_gmute(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """/mute [time] — Mute a user. Reply to their message."""
    chat_id = update.effective_chat.id
    if not update.message.reply_to_message:
        await update.message.reply_text("❌ Reply to a message to mute that user."); return
    target = update.message.reply_to_message.from_user
    if await _is_group_admin(context.bot, chat_id, target.id):
        await update.message.reply_text("❌ Cannot mute an admin!"); return
    try:
        from telegram import ChatPermissions
        # Parse duration
        duration = None
        if context.args:
            arg = context.args[0].lower()
            import re as _re
            m = _re.match(r'(\d+)(m|h|d)', arg)
            if m:
                val, unit = int(m.group(1)), m.group(2)
                secs = val * (60 if unit=='m' else 3600 if unit=='h' else 86400)
                duration = datetime.datetime.now() + datetime.timedelta(seconds=secs)
        await context.bot.restrict_chat_member(
            chat_id, target.id,
            permissions=ChatPermissions(can_send_messages=False),
            until_date=duration)
        dur_str = f" for {context.args[0]}" if context.args else " indefinitely"
        await update.message.reply_text(f"🔇 *{target.first_name}* muted{dur_str}.", parse_mode="Markdown")
        await _log_action(context.bot, chat_id, f"🔇 Muted: {target.first_name} ({target.id}){dur_str}")
    except Exception as e:
        await update.message.reply_text(f"⚠️ Could not mute: {e}")


@group_admin_only
async def cmd_gunmute(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """/unmute — Unmute a user."""
    chat_id = update.effective_chat.id
    if not update.message.reply_to_message:
        await update.message.reply_text("❌ Reply to a message to unmute."); return
    target = update.message.reply_to_message.from_user
    try:
        from telegram import ChatPermissions
        await context.bot.restrict_chat_member(
            chat_id, target.id,
            permissions=ChatPermissions(
                can_send_messages=True, can_send_media_messages=True,
                can_send_polls=True, can_send_other_messages=True,
                can_add_web_page_previews=True))
        await update.message.reply_text(f"✅ *{target.first_name}* has been unmuted.", parse_mode="Markdown")
    except Exception as e:
        await update.message.reply_text(f"⚠️ Could not unmute: {e}")


@group_admin_only
async def cmd_gkick(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """/kick — Kick a user from the group."""
    chat_id = update.effective_chat.id
