    name = " ".join(context.args).strip().lower() if context.args else ""
    if not name:
        # List all notes
        conn = sqlite3.connect(SQLITE_DB)
        c = conn.cursor()
        c.execute("SELECT name FROM group_notes WHERE chat_id = ?", (chat_id,))
        rows = c.fetchall(); conn.close()
        if not rows:
            await update.message.reply_text("📝 No notes saved yet."); return
        names = "\n".join(f"• `{r[0]}`" for r in rows)
        await update.message.reply_text(f"📝 *Saved Notes:*\n{names}", parse_mode="Markdown"); return
    conn = sqlite3.connect(SQLITE_DB)
    c = conn.cursor()
    c.execute("SELECT content FROM group_notes WHERE chat_id = ? AND name = ?", (chat_id, name))
    row = c.fetchone(); conn.close()
    if row:
        await update.message.reply_text(f"📝 *{name}:*\n{row[0]}", parse_mode="Markdown")
    else:
        await update.message.reply_text(f"❌ Note `{name}` not found.", parse_mode="Markdown")

