# ── /setmaxwarns command ──────────────────────────────────────────
@group_admin_only
async def cmd_setmaxwarns(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """/setmaxwarns <number> — Set max warns before auto-ban."""
    if not context.args or not context.args[0].isdigit():
        await update.message.reply_text("Usage: /setmaxwarns <number>\nExample: /setmaxwarns 3"); return
    n = max(1, min(10, int(context.args[0])))
    save_group_settings(update.effective_chat.id, max_warns=n)
    await update.message.reply_text(f"✅ Max warns set to *{n}*. Users get banned after {n} warns.", parse_mode="Markdown")


# ── /setflood command ─────────────────────────────────────────────
@group_admin_only
async def cmd_setflood(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """/setflood <messages> <seconds> — Set flood limit."""
    if not context.args or len(context.args) < 2:
        await update.message.reply_text("Usage: /setflood <messages> <seconds>\nExample: /setflood 5 5"); return
    try:
        limit = max(3, min(20, int(context.args[0])))
        secs  = max(3, min(30, int(context.args[1])))
        save_group_settings(update.effective_chat.id, flood_limit=limit, flood_time=secs)
        await update.message.reply_text(f"✅ Flood limit: *{limit} messages* per *{secs} seconds*", parse_mode="Markdown")
    except Exception:
        await update.message.reply_text("❌ Invalid values. Usage: /setflood 5 5")


