async def _generate_african_voice(text: str, lang_key: str) -> bytes | None:
    """Generate voice in African language using edge-tts."""
    lang_data = AFRICAN_LANGUAGES.get(lang_key)
    if not lang_data:
        return None
    _, _, voice_name, _ = lang_data

    try:
        import edge_tts
        communicate = edge_tts.Communicate(text, voice_name)
        audio_chunks = []
        async for chunk in communicate.stream():
            if chunk["type"] == "audio":
                audio_chunks.append(chunk["data"])
        if audio_chunks:
            return b"".join(audio_chunks)
    except Exception as e:
        logger.warning(f"African voice edge-tts error: {e}")

    # Fallback to any available voice
    try:
        return await text_to_voice(text, voice_name)
    except Exception:
        return None


async def cmd_africanvoice(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """/africanvoice <language> <text> — Speak in any African/Ghanaian language.
    Example: /africanvoice twi Akwaaba! Me din de John
    Example: /africanvoice ewe Woezɔ! Ŋdi
    Example: /africanvoice pidgin_gh Chale how far my guy"""
    args_text = " ".join(context.args).strip() if context.args else ""

    if not args_text:
        # Show language menu
        buttons = []
        row = []
        for key, (label, _, _, desc) in AFRICAN_LANGUAGES.items():
            row.append(InlineKeyboardButton(label, callback_data=f"afv_pick:{key}"))
            if len(row) == 2:
                buttons.append(row); row = []
        if row: buttons.append(row)

        await update.message.reply_text(
            "🌍 *African Language Voice*\n\n"
            "Speak in any African or Ghanaian language!\n\n"
            "Usage: `/africanvoice <language> <text>`\n\n"
            "🇬🇭 *Ghanaian Languages:*\n"
            "• `/africanvoice twi Akwaaba! Wo ho te sɛn?`\n"
            "• `/africanvoice ewe Woezɔ! Ɖoŋko`\n"
            "• `/africanvoice ga Ogboo! Jaanɛ`\n"
            "• `/africanvoice pidgin_gh Chale how far!`\n\n"
            "🌍 *Other African Languages:*\n"
            "• `/africanvoice hausa Sannu! Yaya kake?`\n"
            "• `/africanvoice yoruba E kaaro! Bawo ni?`\n"
            "• `/africanvoice swahili Habari yako!`\n\n"
            "Or pick a language below 👇",
            parse_mode="Markdown",
            reply_markup=InlineKeyboardMarkup(buttons))
        return

    # Parse language + text
    words = args_text.split(maxsplit=1)
    lang = words[0].lower()
    text = words[1] if len(words) > 1 else ""

    if lang not in AFRICAN_LANGUAGES:
        # Try partial match
        matches = [k for k in AFRICAN_LANGUAGES if lang in k]
        if matches:
            lang = matches[0]
        else:
            await update.message.reply_text(
                f"❌ Language `{lang}` not found.\n\n"
                f"Available: {', '.join(AFRICAN_LANGUAGES.keys())}",
                parse_mode="Markdown"); return

    if not text:
        user = get_user(update.effective_user.id)
        user["awaiting"] = f"afv_{lang}"; update_user(update.effective_user.id, user)
        label = AFRICAN_LANGUAGES[lang][0]
        await update.message.reply_text(
            f"🌍 *{label}* selected!\n\nType the text to speak:",
            parse_mode="Markdown"); return

    await _send_african_voice(update, context, lang, text)


async def cb_africanvoice_pick(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Handle African language selection."""
    query = update.callback_query; await query.answer()
    lang = query.data.replace("afv_pick:", "")
    if lang not in AFRICAN_LANGUAGES:
        await query.edit_message_text("❌ Unknown language."); return
    label, _, _, desc = AFRICAN_LANGUAGES[lang]
    user = get_user(query.from_user.id)
    user["awaiting"] = f"afv_{lang}"; update_user(query.from_user.id, user)
    await query.edit_message_text(
        f"🌍 *{label}*\n_{desc}_\n\nType the text you want me to speak:",
        parse_mode="Markdown")


async def _send_african_voice(update, context, lang: str, text: str):
    """Generate and send African language voice."""
    lang_data = AFRICAN_LANGUAGES.get(lang)
    if not lang_data:
        await update.message.reply_text("❌ Language not found."); return
    label, lang_code, voice_name, desc = lang_data

    msg = await update.message.reply_text(
        f"🌍 Generating *{label}* voice… ⏳", parse_mode="Markdown")
    await context.bot.send_chat_action(update.effective_chat.id, "record_voice")

    try:
        audio = await _generate_african_voice(text, lang)
        if audio and len(audio) > 100:
            await msg.delete()
            await update.message.reply_voice(
                voice=io.BytesIO(audio),
                caption=f"🌍 *{label}*\n💬 _{text[:100]}_",
                parse_mode="Markdown")
        else:
            await msg.edit_text(
                f"⚠️ Voice generation failed for {label}.\n"
                "Make sure edge-tts is installed:\n"
                "`pip install edge-tts --break-system-packages`",
                parse_mode="Markdown")
    except Exception as e:
        logger.error(f"African voice error: {e}")
        await msg.edit_text(f"⚠️ Failed: `{str(e)[:100]}`", parse_mode="Markdown")


