async def cb_afpod_bg(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Handle African podcast background music + generate."""
    query = update.callback_query; await query.answer()
    bg_key = query.data.replace("afpod_bg:", "")
    user = get_user(query.from_user.id)
    lang  = user.get("afpod_lang", "twi")
    topic = user.get("afpod_topic", "Ghana")

    lang_data  = AFRICAN_LANGUAGES.get(lang, AFRICAN_LANGUAGES["twi"])
    lang_label = lang_data[0]
    bg_label   = PODCAST_SOUNDS.get(bg_key, ("🎵 Music",))[0]
    lang_prompt = LANG_PROMPTS.get(lang, "Write naturally in this language.")

    await query.edit_message_text(
        f"🎙️🌍 *Generating {lang_label} Podcast…*\n\n"
        f"📌 Topic: _{topic}_\n"
        f"🎵 Music: {bg_label}\n\n"
        f"⏳ Writing script and producing audio…",
        parse_mode="Markdown")

    try:
        # Generate podcast script in the African language
        prompt = (
            f"{lang_prompt}\n\n"
            f"Write a podcast episode about: {topic}\n\n"
            "Format:\n"
            "- Start with an engaging intro/greeting in the language\n"
            "- Cover the topic naturally like a radio presenter\n"
            "- Use local expressions and proverbs where appropriate\n"
            "- End with a closing statement\n"
            "- 400-600 words total — make it a FULL broadcast\n"
            "- Write ONLY the spoken text, no stage directions\n"
            "- Sound like Peace FM, Adom FM or Asempa FM presenter\n"
            "- Use Ghanaian expressions, proverbs and local references\n"
            "- Add energy, passion and African rhythm to the delivery\n"
            "- Include audience interaction phrases like calling listeners\n"
            "- Do NOT sound formal or British — be warm, natural, African"
        )
        script = await asyncio.get_running_loop().run_in_executor(
            None, lambda: call_gemini(prompt, use_cache=False))

        await context.bot.send_chat_action(query.message.chat_id, "record_voice")

        # Generate audio
        audio = await _generate_african_voice(script, lang)

        # Mix with background music if selected
        if audio and bg_key != "none":
            bg_beat_key = PODCAST_SOUNDS.get(bg_key, ("", None))[1]
            if bg_beat_key and _VB_GENERATORS.get(bg_beat_key):
                try:
                    dur = len(audio) / 16000 + 2
                    gen_fn = _VB_GENERATORS.get(bg_beat_key, _vb_gen_lofi)
                    beat_samples = gen_fn(dur)
                    beat_wav = _vb_float_to_wav(beat_samples)

                    with tempfile.NamedTemporaryFile(suffix=".mp3", delete=False) as vf:
                        vf.write(audio); vpath = vf.name
                    with tempfile.NamedTemporaryFile(suffix=".wav", delete=False) as bf:
                        bf.write(beat_wav); bpath = bf.name
                    out_path = vpath.replace(".mp3", "_mixed.mp3")

                    r = subprocess.run(
                        ["ffmpeg", "-y", "-i", vpath, "-i", bpath,
                         "-filter_complex",
                         "[0:a]volume=1.0[v];[1:a]volume=0.15[b];[v][b]amix=inputs=2:duration=first[aout]",
                         "-map", "[aout]", "-ar", "44100", "-ac", "1", out_path],
                        capture_output=True, timeout=60)
                    if r.returncode == 0 and os.path.getsize(out_path) > 500:
                        with open(out_path, "rb") as f:
                            audio = f.read()
                    for p in [vpath, bpath, out_path]:
                        try: os.unlink(p)
                        except: pass
                except Exception as _me:
                    logger.warning(f"Music mix error: {_me}")

        if audio and len(audio) > 100:
            safe_topic = topic[:25].replace(' ', '_')
            # Send as voice
            await context.bot.send_voice(
                chat_id=query.message.chat_id,
                voice=io.BytesIO(audio),
                caption=(
                    f"🎙️🌍 *{lang_label} Podcast*\n"
                    f"📌 _{topic}_\n"
                    f"🎵 {bg_label}\n\n"
                    f"Generated by CineMagic AI Bot 🎧"
                ), parse_mode="Markdown")

            # Send as downloadable MP3
            await context.bot.send_audio(
                chat_id=query.message.chat_id,
                audio=io.BytesIO(audio),
                filename=f"Podcast_{lang}_{safe_topic}.mp3",
                title=f"{lang_label} Podcast — {topic[:40]}",
                performer="CineMagic AI Bot",
                caption="💾 *Download MP3*\n_Tap 3 dots → Save to Downloads_",
                parse_mode="Markdown")

            # Send script
            await context.bot.send_message(
                chat_id=query.message.chat_id,
                text=f"📝 *Podcast Script ({lang_label}):*\n\n{script[:3500]}",
                parse_mode="Markdown")
        else:
            await context.bot.send_message(
                query.message.chat_id,
                f"⚠️ Audio failed.\n\n📝 *Script:*\n{script[:3000]}",
                parse_mode="Markdown")

    except Exception as e:
        logger.error(f"African podcast error: {e}")
        await context.bot.send_message(
            query.message.chat_id,
            f"⚠️ Failed: `{str(e)[:150]}`", parse_mode="Markdown")


