async def cmd_africanbroadcast(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """/africanbroadcast <language> <message> — Broadcast a message in African language.
    Like a news anchor or radio presenter.
    Example: /africanbroadcast twi Ghana won the AFCON today!"""
    args_text = " ".join(context.args).strip() if context.args else ""

    if not args_text:
        await update.message.reply_text(
            "📢🌍 *African Broadcast Voice*\n\n"
            "Broadcast any message in an African language — like a news anchor!\n\n"
            "Usage: `/africanbroadcast <language> <your message>`\n\n"
            "Examples:\n"
            "• `/africanbroadcast twi Ghana won the match today!`\n"
            "• `/africanbroadcast ewe Woezɔ na miawoe`\n"
            "• `/africanbroadcast pidgin_gh Big news! Ghana don win!`\n"
            "• `/africanbroadcast hausa Labari mai muhimmanci!`\n"
            "• `/africanbroadcast english_af Welcome to our African broadcast!`",
            parse_mode="Markdown"); return

    words = args_text.split(maxsplit=1)
    lang  = words[0].lower()
    message = words[1] if len(words) > 1 else ""

    if lang not in AFRICAN_LANGUAGES:
        matches = [k for k in AFRICAN_LANGUAGES if lang in k]
        lang = matches[0] if matches else "english_af"

    if not message:
        user = get_user(update.effective_user.id)
        user["awaiting"] = f"afb_{lang}"; update_user(update.effective_user.id, user)
        label = AFRICAN_LANGUAGES[lang][0]
        await update.message.reply_text(
            f"📢 *{label} Broadcast*\n\nType your message to broadcast:",
            parse_mode="Markdown"); return

    lang_data  = AFRICAN_LANGUAGES.get(lang, AFRICAN_LANGUAGES["english_af"])
    lang_label = lang_data[0]
    lang_prompt = LANG_PROMPTS.get(lang, "Write naturally.")

    msg = await update.message.reply_text(
        f"📢 Broadcasting in *{lang_label}*… ⏳", parse_mode="Markdown")
    await context.bot.send_chat_action(update.effective_chat.id, "record_voice")

    try:
        # Translate/rewrite as broadcast announcement in the language
        broadcast_prompt = (
            f"{lang_prompt}\n\n"
            f"Rewrite this as a professional news broadcast/radio announcement:\n"
            f"{message}\n\n"
            "Make it sound like a confident African news anchor or radio presenter. "
            "Make it a FULL broadcast announcement (150-250 words). "
            "Start with a proper African greeting. "
            "Sound like a real Ghanaian/African radio presenter — "
            "warm, energetic, passionate, natural. "
            "Use local expressions and audience engagement. "
            "Do NOT sound British or American. Sound African and authentic."
        )
        script = await asyncio.get_running_loop().run_in_executor(
            None, lambda: call_gemini(broadcast_prompt, use_cache=False))

        audio = await _generate_african_voice(script, lang)

        if audio and len(audio) > 100:
            await msg.delete()
            await update.message.reply_voice(
                voice=io.BytesIO(audio),
                caption=f"📢 *{lang_label} Broadcast*\n💬 _{message[:80]}_",
                parse_mode="Markdown")
            await update.message.reply_text(
                f"📝 *Broadcast Script:*\n\n{script[:1500]}",
                parse_mode="Markdown")
        else:
            await msg.edit_text(
                f"⚠️ Voice failed.\n\n📝 *Script:*\n{script[:1500]}",
                parse_mode="Markdown")

    except Exception as e:
        logger.error(f"African broadcast error: {e}")
        await msg.edit_text(f"⚠️ Failed: `{str(e)[:100]}`", parse_mode="Markdown")


# ════════════════════════════════════════════════════════════════
#  🎤  ELEVENLABS VOICE CLONING ENGINE
#  Clone any real Ghanaian/African voice and use it in the bot
#  Users record 1 min → bot clones it → speaks in that voice
# ════════════════════════════════════════════════════════════════

# Store cloned voices: {user_id: {"voice_id": "...", "name": "..."}}
_CLONED_VOICES: dict = {}

def _el_list_voices(api_key: str) -> list:
    """List all cloned voices from ElevenLabs account."""
    try:
        r = requests.get(
            "https://api.elevenlabs.io/v1/voices",
            headers={"xi-api-key": api_key},
            timeout=15)
        if r.status_code == 200:
            return r.json().get("voices", [])
        return []
    except Exception as e:
        logger.error(f"ElevenLabs list voices error: {e}")
        return []


def _el_clone_voice(api_key: str, name: str, audio_bytes: bytes,
                    description: str = "Ghanaian voice clone") -> str | None:
    """
    Clone a voice using ElevenLabs Instant Voice Cloning.
    Returns voice_id if successful, None if failed.
    """
    try:
        import io as _io
        files = {
            "files": ("voice_sample.mp3", _io.BytesIO(audio_bytes), "audio/mpeg"),
        }
        data = {
            "name": name,
            "description": description,
            "labels": '{"language": "Ghanaian", "accent": "African"}'
        }
        r = requests.post(
            "https://api.elevenlabs.io/v1/voices/add",
            headers={"xi-api-key": api_key},
            files=files,
            data=data,
            timeout=60)
        if r.status_code in (200, 201):
            voice_id = r.json().get("voice_id")
            logger.info(f"✅ Voice cloned: {name} → {voice_id}")
            return voice_id
        else:
            logger.error(f"Voice clone failed {r.status_code}: {r.text[:300]}")
            return None
    except Exception as e:
        logger.error(f"Voice clone error: {e}")
        return None


def _el_speak_cloned(api_key: str, voice_id: str, text: str,
                      stability: float = 0.5,
                      similarity: float = 0.85) -> bytes | None:
    """Speak text using a cloned ElevenLabs voice."""
    try:
        r = requests.post(
            f"https://api.elevenlabs.io/v1/text-to-speech/{voice_id}",
            headers={
                "xi-api-key": api_key,
                "Content-Type": "application/json",
                "Accept": "audio/mpeg"
            },
            json={
                "text": text[:4500],
                "model_id": "eleven_turbo_v2",
                "voice_settings": {
                    "stability": stability,
                    "similarity_boost": similarity,
                    "style": 0.5,
                    "use_speaker_boost": True
                }
            },
            timeout=40)
        if r.status_code == 200 and len(r.content) > 100:
            return r.content
        logger.error(f"Cloned voice speak error {r.status_code}: {r.text[:200]}")
        return None
    except Exception as e:
        logger.error(f"Cloned voice speak error: {e}")
        return None


def _el_delete_voice(api_key: str, voice_id: str) -> bool:
    """Delete a cloned voice from ElevenLabs."""
    try:
        r = requests.delete(
            f"https://api.elevenlabs.io/v1/voices/{voice_id}",
            headers={"xi-api-key": api_key},
            timeout=15)
        return r.status_code == 200
    except Exception:
        return False


