async def handle_voice_clone_sample(update: Update, context: ContextTypes.DEFAULT_TYPE,
                                     user: dict) -> bool:
    """Handle voice message for cloning. Returns True if handled."""
    user_id = update.effective_user.id
    awaiting = user.get("awaiting", "")

    if awaiting != "clone_voice_sample":
        return False

    if not update.message.voice:
        return False

    voice_name = user.get("clone_voice_name", "My Voice")
    el_key = user.get("elevenlabs_key", "") or ELEVENLABS_API_KEY

    msg = await update.message.reply_text(
        f"🎤 Cloning voice: *{voice_name}*… ⏳\n\n"
        f"This takes 10-30 seconds…",
        parse_mode="Markdown")

    try:
        # Download voice message
        file = await context.bot.get_file(update.message.voice.file_id)
        voice_bytes = bytes(await file.download_as_bytearray())

        if len(voice_bytes) < 10000:
            await msg.edit_text(
                "⚠️ Voice message too short!\n"
                "Please send at least 30 seconds of clear speech.")
            user["awaiting"] = ""; update_user(user_id, user)
            return True

        # Clone the voice
        await context.bot.send_chat_action(update.effective_chat.id, "typing")
        voice_id = await asyncio.get_running_loop().run_in_executor(
            None, lambda: _el_clone_voice(
                el_key, voice_name, voice_bytes,
                f"Ghanaian/African voice clone — {voice_name}"))

        if voice_id:
            # Save cloned voice
            user["cloned_voices"] = user.get("cloned_voices", {})
            user["cloned_voices"][voice_name] = voice_id
            user["active_clone_voice"] = voice_name
            user["active_clone_voice_id"] = voice_id
            user["awaiting"] = ""
            update_user(user_id, user)

            # Test with a greeting
            test_text = "Hello! Your voice has been successfully cloned. I can now speak in your voice!"
            test_audio = await asyncio.get_running_loop().run_in_executor(
                None, lambda: _el_speak_cloned(el_key, voice_id, test_text))

            await msg.delete()

            if test_audio:
                await update.message.reply_voice(
                    voice=io.BytesIO(test_audio),
                    caption=f"✅ *Voice Cloned Successfully!*\n\n"
                            f"🎤 Name: *{voice_name}*\n"
                            f"🆔 ID: `{voice_id}`\n\n"
                            f"Now use it with:\n"
                            f"`/clonedpodcast twi Ghana economy`\n"
                            f"`/clonedbroadcast Your message here`",
                    parse_mode="Markdown")
            else:
                await update.message.reply_text(
                    f"✅ *Voice Cloned!* 🎤\n\n"
                    f"Name: *{voice_name}*\n"
                    f"ID: `{voice_id}`\n\n"
                    f"Use it:\n"
                    f"`/clonedpodcast twi Ghana economy`\n"
                    f"`/clonedbroadcast Your message here`",
                    parse_mode="Markdown")
        else:
            await msg.edit_text(
                "⚠️ Voice cloning failed.\n\n"
                "Possible reasons:\n"
                "• Audio too short (need 30+ seconds)\n"
                "• Poor audio quality\n"
                "• ElevenLabs free tier limit reached\n\n"
                "Try recording a longer, clearer voice message.")
            user["awaiting"] = ""; update_user(user_id, user)

    except Exception as e:
        logger.error(f"Voice clone error: {e}")
        await msg.edit_text(f"⚠️ Cloning failed: `{str(e)[:120]}`", parse_mode="Markdown")
        user["awaiting"] = ""; update_user(user_id, user)

    return True


