async def cb_voice_clone_action(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Handle use/delete cloned voice actions."""
    query = update.callback_query; await query.answer()
    user_id = query.from_user.id
    user = get_user(user_id)
    el_key = user.get("elevenlabs_key", "") or ELEVENLABS_API_KEY

    if query.data.startswith("use_clone:"):
        parts = query.data.split(":", 2)
        name, vid = parts[1], parts[2]
        user["active_clone_voice"] = name
        user["active_clone_voice_id"] = vid
        update_user(user_id, user)
        await query.edit_message_text(
            f"✅ *{name}* set as active voice!\n\n"
            f"Now use it:\n"
            f"`/clonedpodcast twi Ghana economy`\n"
            f"`/clonedbroadcast pidgin_gh Big news today!`\n"
            f"`/clonedspeak Hello everyone, this is me!`",
            parse_mode="Markdown")

    elif query.data.startswith("del_clone:"):
        parts = query.data.split(":", 2)
        name, vid = parts[1], parts[2]
        deleted = await asyncio.get_running_loop().run_in_executor(
            None, lambda: _el_delete_voice(el_key, vid))
        if name in user.get("cloned_voices", {}):
            del user["cloned_voices"][name]
        if user.get("active_clone_voice") == name:
            user["active_clone_voice"] = ""
            user["active_clone_voice_id"] = ""
        update_user(user_id, user)
        await query.edit_message_text(
            f"🗑️ Voice *{name}* deleted {'from ElevenLabs ' if deleted else ''}successfully.",
            parse_mode="Markdown")


