async def _speak_cloned_voice(update, context, text: str,
                                voice_id: str, voice_name: str, el_key: str):
    """Generate and send audio using cloned voice."""
    msg = await update.message.reply_text(
        f"🎤 Speaking as *{voice_name}*… ⏳", parse_mode="Markdown")
    await context.bot.send_chat_action(update.effective_chat.id, "record_voice")

    try:
        audio = await asyncio.get_running_loop().run_in_executor(
            None, lambda: _el_speak_cloned(el_key, voice_id, text))

        if audio and len(audio) > 100:
            await msg.delete()
            await update.message.reply_voice(
                voice=io.BytesIO(audio),
                caption=f"🎤 *{voice_name}*\n💬 _{text[:100]}_",
                parse_mode="Markdown")
            # Also send downloadable
            await update.message.reply_audio(
                audio=io.BytesIO(audio),
                filename=f"{voice_name.replace(' ','_')}.mp3",
                title=f"{voice_name} — Cloned Voice",
                performer="CineMagic AI Bot",
                caption="💾 Download audio",
                parse_mode="Markdown")
        else:
            await msg.edit_text(
                "⚠️ Voice generation failed.\n"
                "Check your ElevenLabs credits at elevenlabs.io")
    except Exception as e:
        logger.error(f"Cloned speak error: {e}")
        await msg.edit_text(f"⚠️ Failed: `{str(e)[:100]}`", parse_mode="Markdown")


