# ══════════════════════════════════════════════════════════════════════════
#  📱  VIRTUAL PHONE NUMBER  — Admin-Only  (v18 addition)
#  Uses free public SMS reception services — no API key required
# ══════════════════════════════════════════════════════════════════════════

import re as _re

_VPHONE_HEADERS = {
    "User-Agent": "Mozilla/5.0 (Linux; Android 14; itel A90) AppleWebKit/537.36 "
                  "(KHTML, like Gecko) Chrome/124.0.0.0 Mobile Safari/537.36",
    "Accept": "text/html,application/xhtml+xml,application/xml;q=0.9,*/*;q=0.8",
}
_vphone_session = {}   # admin_id -> {"number": ..., "provider": ..., "provider_idx": ...}


def _vphone_fetch_numbers_quackr() -> list[dict]:
    """Fetch available numbers from quackr.io."""
    try:
        r = requests.get("https://quackr.io/temporary-numbers",
                         headers=_VPHONE_HEADERS, timeout=12)
        numbers = _re.findall(
            r'href="/temporary-numbers/(\+[\d\-]+)"[^>]*>.*?(\+[\d\-]+)',
            r.text, _re.S
        )
        if not numbers:
            numbers = _re.findall(r'(\+1[\s\-]?\d{3}[\s\-]?\d{3}[\s\-]?\d{4})', r.text)
            return [{"number": n.strip(), "country": "🇺🇸 USA", "provider": "Quackr"} for n in numbers[:10]]
        return [{"number": n[1].strip(), "country": "🇺🇸 USA", "provider": "Quackr"} for n in numbers[:10]]
    except Exception:
        return []


def _vphone_fetch_numbers_hs3x() -> list[dict]:
    """Fetch available numbers from hs3x.com."""
    try:
        r = requests.get("https://hs3x.com/", headers=_VPHONE_HEADERS, timeout=12)
        items = _re.findall(
            r'<a[^>]+href="/(\+?[\d\-]+)"[^>]*>\s*(\+?[\d\s\-]+)\s*</a>',
            r.text
        )
        seen = set()
        result = []
        for href, num in items:
            n = num.strip()
            if n and n not in seen and len(n) >= 7:
                seen.add(n)
                result.append({"number": n if n.startswith("+") else "+" + n,
                               "country": "🌍 International", "provider": "HS3x"})
        return result[:10]
    except Exception:
        return []


def _vphone_fetch_numbers_receivesms() -> list[dict]:
    """Fetch available numbers from receivesms.co."""
    try:
        r = requests.get("https://www.receivesms.co/", headers=_VPHONE_HEADERS, timeout=12)
        items = _re.findall(
            r'href="/sms-online/([\+\d\-]+)/"[^>]*>([\+\d\s\-]+)</a>',
            r.text
        )
        return [{"number": n[0].strip(), "country": "🌍 Free Number",
                 "provider": "ReceiveSMS"} for n in items[:10] if len(n[0]) >= 7]
    except Exception:
        return []


def _vphone_fetch_all_numbers() -> list[dict]:
    """Try all providers and return combined list."""
    all_numbers = []
    for fetcher in [_vphone_fetch_numbers_quackr,
                    _vphone_fetch_numbers_receivesms,
                    _vphone_fetch_numbers_hs3x]:
        try:
            nums = fetcher()
            all_numbers.extend(nums)
        except Exception:
            pass
        if len(all_numbers) >= 5:
            break
    # Deduplicate
    seen, result = set(), []
    for n in all_numbers:
        k = n["number"].replace(" ", "").replace("-", "")
        if k not in seen:
            seen.add(k); result.append(n)
    return result


def _vphone_fetch_sms_quackr(number: str) -> list[dict]:
    """Fetch SMS messages for a Quackr number."""
    clean = number.replace(" ", "").replace("-", "")
    try:
        url = f"https://quackr.io/temporary-numbers/{clean}"
        r   = requests.get(url, headers=_VPHONE_HEADERS, timeout=12)
        # Parse messages from HTML
        msgs = _re.findall(
            r'<div[^>]+class="[^"]*message[^"]*"[^>]*>([\s\S]*?)</div>',
            r.text
        )
        result = []
        for m in msgs[:10]:
            text    = _re.sub(r'<[^>]+>', '', m).strip()
            sender  = _re.search(r'From:\s*([\+\d\w]+)', m)
            sender  = sender.group(1) if sender else "Unknown"
            result.append({"sender": sender, "text": text, "time": "Recent"})
        if not result:
            # Try alternative pattern
            texts = _re.findall(r'(?:message|sms|text)["\s>:]+([A-Za-z0-9\s\-\.]{10,200})', r.text, _re.I)
            result = [{"sender": "?", "text": t.strip(), "time": "Recent"} for t in texts[:5]]
        return result
    except Exception:
        return []


def _vphone_fetch_sms_receivesms(number: str) -> list[dict]:
    """Fetch SMS messages from receivesms.co."""
    clean = number.replace(" ", "").replace("-", "")
    try:
        url = f"https://www.receivesms.co/sms-online/{clean}/"
        r   = requests.get(url, headers=_VPHONE_HEADERS, timeout=12)
        rows = _re.findall(
            r'<tr[^>]*>([\s\S]*?)</tr>', r.text
        )
        result = []
        for row in rows:
            cells = _re.findall(r'<td[^>]*>([\s\S]*?)</td>', row)
            cells = [_re.sub(r'<[^>]+>', '', c).strip() for c in cells]
            if len(cells) >= 3:
                result.append({
                    "sender": cells[0],
                    "text":   cells[1] if len(cells) > 1 else "—",
                    "time":   cells[-1]
                })
        return result[:8]
    except Exception:
        return []


def _vphone_fetch_sms(number: str, provider: str) -> list[dict]:
    """Try to fetch SMS from the appropriate provider."""
    if provider == "Quackr":
        msgs = _vphone_fetch_sms_quackr(number)
    elif provider == "ReceiveSMS":
        msgs = _vphone_fetch_sms_receivesms(number)
    else:
        # Try all
        msgs = _vphone_fetch_sms_quackr(number)
        if not msgs:
            msgs = _vphone_fetch_sms_receivesms(number)
    return msgs


def _vphone_numbers_keyboard(numbers: list[dict]) -> InlineKeyboardMarkup:
    kb = []
    for n in numbers[:8]:
        label = f"{n['country']} {n['number']}"
        kb.append([InlineKeyboardButton(label, callback_data=f"vp_select_{n['number']}_{n['provider']}"[:64])])
    kb.append([InlineKeyboardButton("🔄 Refresh List", callback_data="vp_refresh"),
               InlineKeyboardButton("❌ Close",         callback_data="vp_close")])
    return InlineKeyboardMarkup(kb)


async def cmd_vphone(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """/vphone — Admin-only virtual phone number (free shared numbers)."""
    if str(update.effective_user.id) != ADMIN_ID:
        await update.message.reply_text("⛔ This feature is for the bot owner only.")
        return
    msg = await update.message.reply_text(
        "📱 *Virtual Phone Number*\n\n⏳ Fetching available numbers...",
        parse_mode="Markdown"
    )
    numbers = await asyncio.get_event_loop().run_in_executor(None, _vphone_fetch_all_numbers)
    if not numbers:
        await msg.edit_text(
            "❌ *No numbers available right now.*\n\n"
            "The free SMS providers may be temporarily down.\n"
            "Try again in a few minutes.",
            parse_mode="Markdown"
        )
        return
    await msg.edit_text(
        f"📱 *Virtual Phone Numbers*\n\n"
        f"⚠️ *Note:* These are shared numbers — SMS is public on the provider's website.\n"
        f"✅ Good for: OTP codes, signups, verifications\n\n"
        f"Found *{len(numbers)}* available numbers.\n"
        f"Tap a number to select it and read incoming SMS:",
        reply_markup=_vphone_numbers_keyboard(numbers),
        parse_mode="Markdown"
    )


async def cb_vp_refresh(update: Update, context: ContextTypes.DEFAULT_TYPE):
    q = update.callback_query
    await q.answer("🔄 Refreshing...")
    if str(q.from_user.id) != ADMIN_ID:
        await q.answer("⛔ Admin only", show_alert=True); return
    numbers = await asyncio.get_event_loop().run_in_executor(None, _vphone_fetch_all_numbers)
    if not numbers:
        await q.edit_message_text("❌ No numbers found. Try again later.", parse_mode="Markdown"); return
    await q.edit_message_text(
        f"📱 *Virtual Phone Numbers* — Refreshed ✅\n\n"
        f"Found *{len(numbers)}* available numbers.\nTap to select:",
        reply_markup=_vphone_numbers_keyboard(numbers),
        parse_mode="Markdown"
    )


async def cb_vp_select(update: Update, context: ContextTypes.DEFAULT_TYPE):
    q = update.callback_query
    await q.answer("📱 Loading number...")
    if str(q.from_user.id) != ADMIN_ID:
        await q.answer("⛔ Admin only", show_alert=True); return
    # Parse: vp_select_<number>_<provider>
    raw      = q.data[len("vp_select_"):]
    parts    = raw.rsplit("_", 1)
    number   = parts[0] if len(parts) == 2 else raw
    provider = parts[1] if len(parts) == 2 else "Unknown"
    _vphone_session[ADMIN_ID] = {"number": number, "provider": provider}
    kb = InlineKeyboardMarkup([
        [InlineKeyboardButton("📩 Read Incoming SMS",  callback_data="vp_readsms")],
        [InlineKeyboardButton("🔄 Refresh SMS",        callback_data="vp_readsms")],
        [InlineKeyboardButton("📋 Copy Number",        callback_data="vp_copy")],
        [InlineKeyboardButton("🔁 Get Different Number", callback_data="vp_refresh")],
        [InlineKeyboardButton("❌ Close",              callback_data="vp_close")],
    ])
    await q.edit_message_text(
        f"📱 *Your Virtual Number*\n\n"
        f"📞 `{number}`\n"
        f"🌐 Provider: *{provider}*\n\n"
        f"✅ *How to use:*\n"
        f"1. Copy the number above\n"
        f"2. Use it to register on any website/app\n"
        f"3. Tap *Read Incoming SMS* to see your OTP\n\n"
        f"⚠️ _This is a shared number — don't use for private messages_",
        reply_markup=kb, parse_mode="Markdown"
    )


async def cb_vp_readsms(update: Update, context: ContextTypes.DEFAULT_TYPE):
    q = update.callback_query
    await q.answer("📩 Fetching SMS...")
    if str(q.from_user.id) != ADMIN_ID:
        await q.answer("⛔ Admin only", show_alert=True); return
    session  = _vphone_session.get(ADMIN_ID)
    if not session:
        await q.edit_message_text("❌ No number selected. Use /vphone to pick one."); return
    number   = session["number"]
    provider = session["provider"]
    msgs     = await asyncio.get_event_loop().run_in_executor(
        None, lambda: _vphone_fetch_sms(number, provider)
    )
    kb = InlineKeyboardMarkup([
        [InlineKeyboardButton("🔄 Refresh SMS",           callback_data="vp_readsms")],
        [InlineKeyboardButton("🔁 Get Different Number",  callback_data="vp_refresh")],
        [InlineKeyboardButton("◀️ Back",                  callback_data=f"vp_select_{number}_{provider}"[:64])],
    ])
    if not msgs:
        await q.edit_message_text(
            f"📱 *{number}*\n\n"
            f"📩 *No SMS received yet.*\n\n"
            f"_Send an OTP or verification code to this number, then tap Refresh._",
            reply_markup=kb, parse_mode="Markdown"
        )
        return
    sms_text = f"📱 *{number}* — {len(msgs)} Message(s)\n\n"
    for i, m in enumerate(msgs[:6], 1):
        sms_text += (
            f"*{i}.* 📨 From: `{m.get('sender','?')}`\n"
            f"💬 {m.get('text','—')[:200]}\n"
            f"🕐 {m.get('time','?')}\n\n"
        )
    await q.edit_message_text(sms_text[:4000], reply_markup=kb, parse_mode="Markdown")


async def cb_vp_copy(update: Update, context: ContextTypes.DEFAULT_TYPE):
    q = update.callback_query
    session = _vphone_session.get(ADMIN_ID, {})
    number  = session.get("number", "No number selected")
    await q.answer(f"Number: {number}", show_alert=True)


async def cb_vp_close(update: Update, context: ContextTypes.DEFAULT_TYPE):
    q = update.callback_query
    await q.answer("Closed")
    _vphone_session.pop(ADMIN_ID, None)
    try:
        await q.edit_message_text("📱 Virtual Phone session closed.\n\nUse /vphone to start a new session.")
    except Exception:
        pass


